def _safe_value(value: Any) -> Any:
    if isinstance(value, np.generic):
        return value.item()
    if isinstance(value, float) and not np.isfinite(value):
        return None
    return value


def _table_value_to_percent(value: Any) -> str | None:
    if isinstance(value, str):
        stripped = value.strip()
        if not stripped or "%" in stripped:
            return None
        try:
            number = float(stripped)
        except Exception:
            return None
    elif isinstance(value, (int, float, np.generic)):
        number = float(value)
    else:
        return None
    if not np.isfinite(number) or number < -1.000001 or number > 1.000001:
        return None
    return f"{number * 100:.2f}%"


def _should_format_table_value_as_percent(column_name: str) -> bool:
    lowered = str(column_name or "").strip().lower()
    if not lowered:
        return False
    explicit_tokens = {
        "sales_contribution",
        "sales_share",
        "share",
        "share_ratio",
        "share_pct",
        "freight_rate",
        "late_rate",
        "discount_rate",
        "return_rate",
        "low_rating_rate",
        "retention_rate",
        "conversion_rate",
        "ctr",
        "cvr",
        "销售贡献",
        "收入占比",
        "占比",
        "运费率",
        "逾期率",
        "折扣率",
        "退款率",
    }
    if lowered in explicit_tokens:
        return True
    if lowered.endswith("_rate") or lowered.endswith("_share") or lowered.endswith("_ratio"):
        return True
    if "contribution" in lowered and "margin" not in lowered:
        return True
    return False


def _linked_codex_runtime_ids(report: dict[str, Any]) -> tuple[list[str], list[str]]:
    run_ids: list[str] = []
    task_ids: list[str] = []

    requirement_intent = report.get("requirement_intent_runtime") or {}
    if isinstance(requirement_intent, dict):
        run_id = str(requirement_intent.get("run_id") or "").strip()
        if run_id:
            run_ids.append(run_id)

    r_workflow = report.get("r_workflow") or {}
    if isinstance(r_workflow, dict):
        codex_sidecar = r_workflow.get("codex_sidecar") or {}
        if isinstance(codex_sidecar, dict):
            run_id = str(codex_sidecar.get("run_id") or "").strip()
            if run_id:
                run_ids.append(run_id)
            task_id = str(codex_sidecar.get("task_id") or "").strip()
            if task_id:
                task_ids.append(task_id)

    appendix_pipeline = report.get("analyst_appendix_premium_pipeline") or {}
    if isinstance(appendix_pipeline, dict):
        for run_id in appendix_pipeline.get("linked_codex_run_ids") or []:
            run_id_text = str(run_id or "").strip()
            if run_id_text:
                run_ids.append(run_id_text)

    generic_long_pipeline = report.get("generic_long_cli_pipeline") or {}
    if isinstance(generic_long_pipeline, dict):
        for run_id in generic_long_pipeline.get("linked_codex_run_ids") or []:
            run_id_text = str(run_id or "").strip()
            if run_id_text:
                run_ids.append(run_id_text)

    multi_table_pipeline = report.get("multi_table_generic_long_cli_pipeline") or {}
    if isinstance(multi_table_pipeline, dict):
        for run_id in multi_table_pipeline.get("linked_codex_run_ids") or []:
            run_id_text = str(run_id or "").strip()
            if run_id_text:
                run_ids.append(run_id_text)

    deduped_run_ids = list(dict.fromkeys(run_ids))
    deduped_task_ids = list(dict.fromkeys(task_ids))
    return deduped_run_ids, deduped_task_ids


def _report_storage_url_for(path: Path) -> str:
    try:
        relative = path.resolve().relative_to(REPORTS_DIR.parent.resolve()).as_posix()
    except Exception:
        return ""
    return f"/storage/{relative}"


def _copy_text_if_exists(source: Path, target: Path) -> str:
    if not source.exists():
        return ""
    target.parent.mkdir(parents=True, exist_ok=True)
    target.write_text(source.read_text(encoding="utf-8-sig"), encoding="utf-8")
    return str(target.resolve())


def _with_report_design_context(
    context_payload: dict[str, Any],
    *,
    request: SmartReportRequest,
    requirement_intent: dict[str, Any] | None = None,
) -> dict[str, Any]:
    payload = dict(context_payload or {})
    design_spec = build_report_design_spec(
        request=request,
        requirement_intent=requirement_intent or {},
        context_payload=payload,
    )
    payload.update(
        {
            "report_design_spec": design_spec,
            "design_spec": design_spec,
            "report_design_spec_path": "report_design_spec.json",
            "report_design_spec_markdown_path": "report_design_spec.md",
            "chart_palette_preset": design_spec.get("chart_palette_preset", ""),
            "chart_palette_colors": list(design_spec.get("chart_palette_colors") or []),
            "visual_style": design_spec.get("visual_style", ""),
            "color_palette": design_spec.get("color_palette", ""),
            "layout_preference": design_spec.get("layout_preference", ""),
            "pdf_design_brief": design_spec.get("pdf_design_brief", ""),
        }
    )
    return payload


def _prepare_analyst_appendix_premium_workspace(
    *,
    workspace_dir: Path,
    report_dir: Path,
    report_id: str,
    requirement_intent: dict[str, Any],
    context_payload: dict[str, Any],
) -> dict[str, Any]:
    workspace_dir.mkdir(parents=True, exist_ok=True)
    analyst_md = report_dir / f"{report_id}-analyst_appendix.md"
    analyst_html = report_dir / f"{report_id}-analyst_appendix.html"
    management_md = report_dir / f"{report_id}-management_report.md"
    management_html = report_dir / f"{report_id}-management_report.html"
    full_md = report_dir / f"{report_id}.md"
    full_html = report_dir / f"{report_id}.html"

    copied = {
        "analyst_appendix_path": _copy_text_if_exists(analyst_md, workspace_dir / "analyst_appendix.md"),
        "analyst_appendix_html_path": _copy_text_if_exists(analyst_html, workspace_dir / "analyst_appendix.html"),
        "management_report_path": _copy_text_if_exists(management_md, workspace_dir / "management_report.md"),
        "management_report_html_path": _copy_text_if_exists(management_html, workspace_dir / "management_report.html"),
        "full_report_path": _copy_text_if_exists(full_md, workspace_dir / "full_report.md"),
        "full_report_html_path": _copy_text_if_exists(full_html, workspace_dir / "full_report.html"),
    }
    requirement_path = workspace_dir / "requirement_intent.json"
    requirement_path.write_text(json.dumps(requirement_intent, ensure_ascii=False, indent=2), encoding="utf-8")
    context_path = workspace_dir / "pipeline_context.json"
    context_path.write_text(json.dumps(context_payload, ensure_ascii=False, indent=2, default=str), encoding="utf-8")
    design_json_path, design_md_path, _ = write_report_design_spec_files(
        workspace_dir,
        requirement_intent=requirement_intent,
        context_payload=context_payload,
    )
    copied["requirement_intent_path"] = str(requirement_path.resolve())
    copied["pipeline_context_path"] = str(context_path.resolve())
    copied["report_design_spec_path"] = str(design_json_path.resolve())
    copied["report_design_spec_markdown_path"] = str(design_md_path.resolve())
    return copied


def _prepare_internet_ops_long_cli_workspace(
    *,
    workspace_dir: Path,
    report_dir: Path,
    report_id: str,
    frame: pd.DataFrame,
    request: SmartReportRequest,
    requirement_intent: dict[str, Any],
    context_payload: dict[str, Any],
) -> dict[str, Any]:
    workspace_dir.mkdir(parents=True, exist_ok=True)
    source_dataset_path = workspace_dir / "source_dataset.csv"
    frame.to_csv(source_dataset_path, index=False, encoding="utf-8-sig")

    schema_payload = {
        "row_count": int(frame.shape[0]),
        "column_count": int(frame.shape[1]),
        "columns": [str(column) for column in frame.columns],
        "sample_rows": clean_records(frame, limit=12),
        "business_profile": "internet_operations_report",
    }
    source_schema_path = workspace_dir / "source_schema.json"
    source_schema_path.write_text(json.dumps(schema_payload, ensure_ascii=False, indent=2, default=str), encoding="utf-8")
    source_profile_files = _write_generic_long_cli_source_profiles(frame, workspace_dir)
    source_visual_assets = _prepare_generic_long_cli_visual_assets(
        workspace_dir=workspace_dir,
        frame=frame,
        request=request,
    )

    copied = {
        "source_dataset_path": str(source_dataset_path.resolve()),
        "source_schema_path": str(source_schema_path.resolve()),
        "source_profile_files": source_profile_files,
        "source_visual_assets": source_visual_assets,
        "management_report_path": _copy_text_if_exists(report_dir / f"{report_id}-management_report.md", workspace_dir / "management_report.md"),
        "management_report_html_path": _copy_text_if_exists(report_dir / f"{report_id}-management_report.html", workspace_dir / "management_report.html"),
        "analyst_appendix_path": _copy_text_if_exists(report_dir / f"{report_id}-analyst_appendix.md", workspace_dir / "analyst_appendix.md"),
        "analyst_appendix_html_path": _copy_text_if_exists(report_dir / f"{report_id}-analyst_appendix.html", workspace_dir / "analyst_appendix.html"),
        "full_report_path": _copy_text_if_exists(report_dir / f"{report_id}.md", workspace_dir / "full_report.md"),
        "full_report_html_path": _copy_text_if_exists(report_dir / f"{report_id}.html", workspace_dir / "full_report.html"),
        "field_registry_path": _copy_text_if_exists(report_dir / f"{report_id}-internet_ops_field_availability_registry.json", workspace_dir / "internet_ops_field_availability_registry.json"),
        "object_decision_registry_path": _copy_file_if_exists(report_dir / "internet_ops_object_decision_registry.csv", workspace_dir / "internet_ops_object_decision_registry.csv"),
        "object_decision_registry_shadow_path": _copy_file_if_exists(report_dir / f"{report_id}-internet_ops_object_decision_registry.csv", workspace_dir / "internet_ops_object_decision_registry_shadow.csv"),
        "action_table_path": _copy_file_if_exists(report_dir / "internet_ops_action_table.csv", workspace_dir / "internet_ops_action_table.csv"),
        "seven_day_action_table_path": _copy_file_if_exists(report_dir / "7_day_action_table.csv", workspace_dir / "7_day_action_table.csv"),
        "growth_backlog_path": _copy_file_if_exists(report_dir / "30_day_growth_experiment_backlog.csv", workspace_dir / "30_day_growth_experiment_backlog.csv"),
        "quality_gate_result_path": _copy_text_if_exists(report_dir / f"{report_id}-quality_gate_result.json", workspace_dir / "quality_gate_result.json"),
        "report_quality_score_path": _copy_text_if_exists(report_dir / f"{report_id}-report_quality_score.json", workspace_dir / "report_quality_score.json"),
    }

    requirement_path = workspace_dir / "existing_requirement_intent.json"
    requirement_path.write_text(json.dumps(requirement_intent, ensure_ascii=False, indent=2, default=str), encoding="utf-8")
    context_path = workspace_dir / "pipeline_context.json"
    context_path.write_text(json.dumps(context_payload, ensure_ascii=False, indent=2, default=str), encoding="utf-8")
    design_json_path, design_md_path, _ = write_report_design_spec_files(
        workspace_dir,
        request=request,
        requirement_intent=requirement_intent,
        context_payload=context_payload,
    )
    copied["existing_requirement_intent_path"] = str(requirement_path.resolve())
    copied["pipeline_context_path"] = str(context_path.resolve())
    copied["report_design_spec_path"] = str(design_json_path.resolve())
    copied["report_design_spec_markdown_path"] = str(design_md_path.resolve())

    metric_files = _copy_selected_tree(
        report_dir / "outputs" / "metric_mining",
        workspace_dir / "metric_mining",
        suffixes={".json", ".csv", ".md"},
        max_files=40,
    )
    r_files = _copy_selected_tree(
        report_dir / "r-workflow",
        workspace_dir / "r-workflow",
        suffixes={".json", ".csv", ".md", ".xlsx", ".pdf"},
        max_files=80,
    )
    copied["metric_mining_files"] = metric_files
    copied["r_workflow_files"] = r_files
    copied["ops_evidence_pack"] = _write_internet_ops_cli_evidence_pack(
        workspace_dir=workspace_dir,
        frame=frame,
    )
    registry_csv_path = workspace_dir / "internet_ops_object_decision_registry.csv"
    action_csv_path = workspace_dir / "internet_ops_action_table.csv"
    if not registry_csv_path.exists() or not action_csv_path.exists():
        field_registry_payload = internet_ops_field_availability_registry(frame)
        field_registry_path = workspace_dir / "internet_ops_field_availability_registry.json"
        field_registry_path.write_text(
            json.dumps(field_registry_payload, ensure_ascii=False, indent=2, default=str),
            encoding="utf-8",
        )
        analysis_modules_payload = build_internet_operations_analysis_modules(frame, field_registry_payload)
        registry_payload = build_internet_ops_object_decision_registry(
            analysis_modules_payload,
            field_registry_payload,
        )
        registry_artifacts = write_internet_ops_registry_artifacts(workspace_dir, registry_payload)
        copied["field_registry_generated_path"] = str(field_registry_path.resolve())
        copied["object_decision_registry_generated_path"] = registry_artifacts.get("registry_csv_path", "")
        copied["action_table_generated_path"] = registry_artifacts.get("action_csv_path", "")
    return copied


def _internet_ops_numeric_series(frame: pd.DataFrame, column: str) -> pd.Series:
    if column not in frame.columns:
        return pd.Series(np.nan, index=frame.index, dtype="float64")
    return pd.to_numeric(frame[column], errors="coerce")


def _internet_ops_group_summary(frame: pd.DataFrame, group_columns: list[str]) -> pd.DataFrame:
    available_groups = [column for column in group_columns if column in frame.columns]
    if not available_groups:
        return pd.DataFrame()

    working = frame.copy()
    for column in available_groups:
        working[column] = working[column].fillna("UNKNOWN").astype(str)

    for column in [
        "impressions",
        "clicks",
        "registrations",
        "activations",
        "paid_users",
        "revenue",
        "operating_cost",
        "contribution_margin",
        "roi",
        "cac",
        "retention_d7",
        "nps",
        "CTR",
        "CPM",
        "CPC",
        "ROI",
    ]:
        working[column] = _internet_ops_numeric_series(working, column)

    working["__row_count"] = 1
    grouped = (
        working.groupby(available_groups, dropna=False)
        .agg(
            sample_size=("__row_count", "sum"),
            impressions=("impressions", "sum"),
            clicks=("clicks", "sum"),
            registrations=("registrations", "sum"),
            activations=("activations", "sum"),
            paid_users=("paid_users", "sum"),
            revenue=("revenue", "sum"),
            operating_cost=("operating_cost", "sum"),
            contribution_margin=("contribution_margin", "sum"),
            roi_row_mean=("roi", "mean"),
            roi_median=("roi", "median"),
            roi_legacy_avg=("ROI", "mean"),
            cac_row_mean=("cac", "mean"),
            retention_d7_avg=("retention_d7", "mean"),
            nps_avg=("nps", "mean"),
            ctr_row_mean=("CTR", "mean"),
            cpm_source_mean=("CPM", "mean"),
            cpc_source_mean=("CPC", "mean"),
        )
        .reset_index()
    )

    grouped["roi_avg"] = np.where(
        grouped["operating_cost"].fillna(0) > 0,
        grouped["revenue"].fillna(0) / grouped["operating_cost"].fillna(0),
        np.nan,
    )
    grouped["cac_avg"] = np.where(
        grouped["paid_users"].fillna(0) > 0,
        grouped["operating_cost"].fillna(0) / grouped["paid_users"].fillna(0),
        np.nan,
    )
    grouped["ctr_from_volume"] = np.where(
        grouped["impressions"].fillna(0) > 0,
        grouped["clicks"].fillna(0) / grouped["impressions"].fillna(0),
        np.nan,
    )
    grouped["ctr_avg"] = grouped["ctr_from_volume"]
    grouped["cpc_avg"] = np.where(
        grouped["clicks"].fillna(0) > 0,
        grouped["operating_cost"].fillna(0) / grouped["clicks"].fillna(0),
        np.nan,
    )
    grouped["cpm_avg"] = np.where(
        grouped["impressions"].fillna(0) > 0,
        grouped["operating_cost"].fillna(0) * 1000 / grouped["impressions"].fillna(0),
        np.nan,
    )
    grouped["roi"] = grouped["roi_avg"]
    grouped["cac"] = grouped["cac_avg"]
    grouped["CTR"] = grouped["ctr_avg"]
    grouped["CPC"] = grouped["cpc_avg"]
    grouped["CPM"] = grouped["cpm_avg"]
    grouped["retention_d7"] = grouped["retention_d7_avg"]
    grouped["nps"] = grouped["nps_avg"]
    grouped["registration_rate"] = np.where(
        grouped["clicks"].fillna(0) > 0,
        grouped["registrations"].fillna(0) / grouped["clicks"].fillna(0),
        np.nan,
    )
    grouped["activation_rate"] = np.where(
        grouped["registrations"].fillna(0) > 0,
        grouped["activations"].fillna(0) / grouped["registrations"].fillna(0),
        np.nan,
    )
    grouped["paid_rate"] = np.where(
        grouped["activations"].fillna(0) > 0,
        grouped["paid_users"].fillna(0) / grouped["activations"].fillna(0),
        np.nan,
    )
    total_margin = float(grouped["contribution_margin"].fillna(0).sum() or 0.0)
    total_cost = float(grouped["operating_cost"].fillna(0).sum() or 0.0)
    grouped["margin_share"] = np.where(total_margin != 0, grouped["contribution_margin"] / total_margin, np.nan)
    grouped["cost_share"] = np.where(total_cost != 0, grouped["operating_cost"] / total_cost, np.nan)
    grouped["group_key"] = grouped[available_groups].astype(str).agg(" / ".join, axis=1)
    grouped["group_label"] = grouped["group_key"]
    return grouped.round(6)


def _internet_ops_records(frame: pd.DataFrame, *, limit: int | None = None) -> list[dict[str, Any]]:
    if limit is not None:
        frame = frame.head(limit)
    if frame.empty:
        return []
    return json.loads(frame.to_json(orient="records", force_ascii=False))


