def _internet_ops_field_label(field: str) -> str:
    return INTERNET_OPS_FIELD_LABELS.get(field, field)


def _internet_ops_field_type(field: str) -> str:
    if field == "date":
        return "时间字段"
    if field in {"channel", "traffic_source", "city_tier", "user_segment", "content_category", "product_module", "campaign"}:
        return "经营维度"
    if field in {"impressions", "clicks", "registrations", "activations", "paid_users"}:
        return "漏斗规模"
    if field in {"revenue", "operating_cost", "contribution_margin"}:
        return "收入成本"
    if field in {"retention_d7", "nps"}:
        return "质量指标"
    if field == "ROI":
        return "历史兼容"
    return "派生/效率指标"


def _internet_ops_safe_divide(numerator: Any, denominator: Any) -> np.ndarray:
    numerator_array = np.asarray(numerator, dtype="float64")
    denominator_array = np.asarray(denominator, dtype="float64")
    with np.errstate(divide="ignore", invalid="ignore"):
        result = np.divide(
            numerator_array,
            denominator_array,
            out=np.zeros_like(numerator_array, dtype="float64"),
            where=np.isfinite(denominator_array) & (denominator_array != 0),
        )
    return np.nan_to_num(result, nan=0.0, posinf=0.0, neginf=0.0)


def _internet_ops_add_derived_columns(frame: pd.DataFrame) -> pd.DataFrame:
    working = frame.copy()
    for column in [
        "impressions",
        "clicks",
        "registrations",
        "activations",
        "paid_users",
        "revenue",
        "operating_cost",
        "contribution_margin",
        "roi",
        "cac",
        "retention_d7",
        "nps",
        "CTR",
        "CPM",
        "CPC",
        "ROI",
    ]:
        working[column] = _internet_ops_numeric_series(working, column).fillna(0)

    working["点击率"] = _internet_ops_safe_divide(working["clicks"], working["impressions"])
    working["CTR"] = working["点击率"]
    working["点击到注册率"] = _internet_ops_safe_divide(working["registrations"], working["clicks"])
    working["注册到激活率"] = _internet_ops_safe_divide(working["activations"], working["registrations"])
    working["激活到付费率"] = _internet_ops_safe_divide(working["paid_users"], working["activations"])
    working["点击到付费率"] = _internet_ops_safe_divide(working["paid_users"], working["clicks"])
    working["每付费用户收入"] = _internet_ops_safe_divide(working["revenue"], working["paid_users"])
    working["获客成本"] = _internet_ops_safe_divide(working["operating_cost"], working["paid_users"])
    working["cac"] = working["获客成本"]
    working["注册成本"] = _internet_ops_safe_divide(working["operating_cost"], working["registrations"])
    working["激活成本"] = _internet_ops_safe_divide(working["operating_cost"], working["activations"])
    working["毛利率"] = _internet_ops_safe_divide(working["contribution_margin"], working["revenue"])
    working["roi"] = _internet_ops_safe_divide(working["revenue"], working["operating_cost"])
    working["CPC"] = _internet_ops_safe_divide(working["operating_cost"], working["clicks"])
    working["CPM"] = _internet_ops_safe_divide(working["operating_cost"] * 1000, working["impressions"])
    total_cost = float(working["operating_cost"].sum() or 0.0)
    total_margin = float(working["contribution_margin"].sum() or 0.0)
    total_revenue = float(working["revenue"].sum() or 0.0)
    total_paid = float(working["paid_users"].sum() or 0.0)
    working["成本占比"] = working["operating_cost"] / total_cost if total_cost else 0.0
    working["毛利占比"] = working["contribution_margin"] / total_margin if total_margin else 0.0
    working["收入占比"] = working["revenue"] / total_revenue if total_revenue else 0.0
    working["付费用户占比"] = working["paid_users"] / total_paid if total_paid else 0.0
    working["预算效率"] = _internet_ops_safe_divide(working["contribution_margin"], working["operating_cost"])
    retention_min = float(working["retention_d7"].min() or 0.0)
    retention_span = float((working["retention_d7"].max() or 0.0) - retention_min) or 1.0
    nps_min = float(working["nps"].min() or 0.0)
    nps_span = float((working["nps"].max() or 0.0) - nps_min) or 1.0
    working["留存质量分"] = (working["retention_d7"] - retention_min) / retention_span
    working["口碑质量分"] = (working["nps"] - nps_min) / nps_span
    working["增长质量分"] = (
        working["点击率"].rank(pct=True)
        + working["点击到付费率"].rank(pct=True)
        + working["预算效率"].rank(pct=True)
        + working["毛利率"].rank(pct=True)
        + working["留存质量分"].rank(pct=True)
        + working["口碑质量分"].rank(pct=True)
        + (1 - working["获客成本"].rank(pct=True))
    ) / 7
    working["LTV代理"] = working["每付费用户收入"] * (1 + working["retention_d7"].clip(lower=0))
    working["回本周期代理"] = _internet_ops_safe_divide(working["获客成本"], _internet_ops_safe_divide(working["contribution_margin"], working["paid_users"]))
    return working.replace([np.inf, -np.inf], 0).fillna(0)


def _internet_ops_grouped_derived_frame(frame: pd.DataFrame, group_columns: list[str], *, limit: int | None = None) -> pd.DataFrame:
    available_groups = [column for column in group_columns if column in frame.columns]
    working = _internet_ops_add_derived_columns(frame)
    if not available_groups:
        return pd.DataFrame()
    for column in available_groups:
        working[column] = working[column].fillna("UNKNOWN").astype(str)
    grouped = (
        working.groupby(available_groups, dropna=False)
        .agg(
            样本量=("date", "size") if "date" in working.columns else ("impressions", "size"),
            曝光=("impressions", "sum"),
            点击=("clicks", "sum"),
            注册=("registrations", "sum"),
            激活=("activations", "sum"),
            付费用户=("paid_users", "sum"),
            收入=("revenue", "sum"),
            运营成本=("operating_cost", "sum"),
            贡献毛利=("contribution_margin", "sum"),
            点击率=("点击率", "mean"),
            点击到注册率=("点击到注册率", "mean"),
            注册到激活率=("注册到激活率", "mean"),
            激活到付费率=("激活到付费率", "mean"),
            点击到付费率=("点击到付费率", "mean"),
            每付费用户收入=("每付费用户收入", "mean"),
            获客成本=("获客成本", "mean"),
            注册成本=("注册成本", "mean"),
            激活成本=("激活成本", "mean"),
            毛利率=("毛利率", "mean"),
            成本占比=("成本占比", "sum"),
            毛利占比=("毛利占比", "sum"),
            收入占比=("收入占比", "sum"),
            付费用户占比=("付费用户占比", "sum"),
            预算效率=("预算效率", "mean"),
            留存质量分=("留存质量分", "mean"),
            口碑质量分=("口碑质量分", "mean"),
            增长质量分=("增长质量分", "mean"),
            roi=("roi", "mean"),
            cac=("cac", "mean"),
            retention_d7=("retention_d7", "mean"),
            nps=("nps", "mean"),
            CTR=("CTR", "mean"),
            CPM=("CPM", "mean"),
            CPC=("CPC", "mean"),
        )
        .reset_index()
    )
    grouped["对象组合"] = grouped[available_groups].astype(str).agg(" × ".join, axis=1)
    grouped["点击率"] = _internet_ops_safe_divide(grouped["点击"], grouped["曝光"])
    grouped["CTR"] = grouped["点击率"]
    grouped["点击到注册率"] = _internet_ops_safe_divide(grouped["注册"], grouped["点击"])
    grouped["注册到激活率"] = _internet_ops_safe_divide(grouped["激活"], grouped["注册"])
    grouped["激活到付费率"] = _internet_ops_safe_divide(grouped["付费用户"], grouped["激活"])
    grouped["点击到付费率"] = _internet_ops_safe_divide(grouped["付费用户"], grouped["点击"])
    grouped["roi"] = _internet_ops_safe_divide(grouped["收入"], grouped["运营成本"])
    grouped["cac"] = _internet_ops_safe_divide(grouped["运营成本"], grouped["付费用户"])
    grouped["获客成本"] = grouped["cac"]
    grouped["每付费用户收入"] = _internet_ops_safe_divide(grouped["收入"], grouped["付费用户"])
    grouped["注册成本"] = _internet_ops_safe_divide(grouped["运营成本"], grouped["注册"])
    grouped["激活成本"] = _internet_ops_safe_divide(grouped["运营成本"], grouped["激活"])
    grouped["毛利率"] = _internet_ops_safe_divide(grouped["贡献毛利"], grouped["收入"])
    grouped["预算效率"] = _internet_ops_safe_divide(grouped["贡献毛利"], grouped["运营成本"])
    grouped["CPC"] = _internet_ops_safe_divide(grouped["运营成本"], grouped["点击"])
    grouped["CPM"] = _internet_ops_safe_divide(grouped["运营成本"] * 1000, grouped["曝光"])
    retention_min = float(grouped["retention_d7"].min() or 0.0)
    retention_span = float((grouped["retention_d7"].max() or 0.0) - retention_min) or 1.0
    nps_min = float(grouped["nps"].min() or 0.0)
    nps_span = float((grouped["nps"].max() or 0.0) - nps_min) or 1.0
    grouped["留存质量分"] = (grouped["retention_d7"] - retention_min) / retention_span
    grouped["口碑质量分"] = (grouped["nps"] - nps_min) / nps_span
    grouped["增长质量分"] = (
        grouped["点击率"].rank(pct=True)
        + grouped["点击到付费率"].rank(pct=True)
        + grouped["预算效率"].rank(pct=True)
        + grouped["毛利率"].rank(pct=True)
        + grouped["留存质量分"].rank(pct=True)
        + grouped["口碑质量分"].rank(pct=True)
        + (1 - grouped["获客成本"].rank(pct=True))
    ) / 7
    if limit is not None:
        grouped = grouped.sort_values(["贡献毛利", "增长质量分"], ascending=[False, False]).head(limit)
    return grouped.round(6)


