def _build_retrofit_requirement_intent(report_dir: Path, request: SmartReportRequest) -> dict[str, Any]:
    for payload in _load_report_json_payloads(report_dir):
        candidate = _find_first_nested_value(payload, "requirement_intent")
        if isinstance(candidate, dict):
            return candidate
    return {
        "optimized_user_requirement": request.user_requirement,
        "target_audience": request.target_audience,
        "core_purpose": request.core_purpose,
        "expected_result": request.expected_result or "一份通过 generic_long_cli_pipeline 补建的 CLI runtime 长报告。",
        "required_detail_dimensions": [],
        "retrofit_from_completed_report": True,
    }


