def _looks_like_retrofit_report_tabular_name(value: str) -> bool:
    lowered = str(value or "").strip().lower()
    if not lowered:
        return False
    return any(marker in lowered for marker in _RETROFIT_REPORT_TABULAR_MARKERS)


def _read_retrofit_tabular_asset(
    path: Path,
    *,
    preview_rows: int | None = None,
    preferred_sheet: str = "",
) -> tuple[pd.DataFrame, dict[str, Any]]:
    suffix = path.suffix.lower()
    if suffix == ".csv":
        frame = pd.read_csv(path, encoding="utf-8-sig", nrows=preview_rows)
        return frame, {"storage_format": "csv"}
    if suffix == ".tsv":
        frame = pd.read_csv(path, sep="\t", encoding="utf-8-sig", nrows=preview_rows)
        return frame, {"storage_format": "tsv"}
    if suffix == ".dta":
        frame = pd.read_stata(path, convert_categoricals=False)
        if preview_rows is not None:
            frame = frame.head(preview_rows)
        return frame, {"storage_format": "dta"}
    if suffix == ".xlsx":
        try:
            workbook = pd.ExcelFile(path)
            sheet_names = list(workbook.sheet_names)
        except Exception:
            sheet_names = []
        best_frame = pd.DataFrame()
        best_sheet_name = ""
        best_score = float("-inf")
        for sheet_name in sheet_names:
            try:
                loaded = pd.read_excel(path, sheet_name=sheet_name, nrows=preview_rows)
            except Exception:
                continue
            processed = _postprocess_frame(loaded)
            row_count = int(processed.shape[0])
            column_count = int(processed.shape[1])
            score = min(row_count, 500) + column_count * 5
            if any(token in sheet_name.lower() for token in ["source", "dataset", "raw", "input", "extract", "detail", "tableau", "明细", "原始"]):
                score += 320
            if _looks_like_retrofit_report_tabular_name(sheet_name):
                score -= 420
            if row_count >= 40:
                score += 220
            elif row_count >= 10:
                score += 80
            elif row_count <= 5:
                score -= 220
            if column_count >= 6:
                score += 120
            elif column_count >= 3:
                score += 40
            elif column_count <= 1:
                score -= 220
            if preferred_sheet and sheet_name == preferred_sheet:
                score += 10_000
            if score > best_score:
                best_score = score
                best_sheet_name = sheet_name
                best_frame = processed
        if best_sheet_name and preview_rows is None:
            best_frame = _postprocess_frame(pd.read_excel(path, sheet_name=best_sheet_name))
        return best_frame, {
            "storage_format": "xlsx",
            "selected_sheet_name": best_sheet_name,
            "workbook_sheet_count": len(sheet_names),
        }
    raise ValueError(f"Unsupported retrofit tabular asset: {path}")


def _retrofit_csv_asset_class(
    path: Path,
    relative_path: str,
    *,
    preview_meta: dict[str, Any] | None = None,
    row_count: int = 0,
    column_count: int = 0,
) -> dict[str, Any]:
    name = path.name.lower()
    rel = relative_path.lower()
    sheet_name = str((preview_meta or {}).get("selected_sheet_name") or "").lower()
    workbook_sheet_count = int((preview_meta or {}).get("workbook_sheet_count") or 0)
    combined_markers = " ".join(part for part in [name, rel, sheet_name] if part)
    primary_markers = [
        "source_dataset",
        "normalized_dataset",
        "cleaned_dataset",
        "input-data",
        "input_data",
        "public_source",
        "raw_dataset",
        "original_dataset",
    ]
    source_markers = ["source", "dataset", "normalized", "cleaned", "input", "raw", "original", "extract", "detail", "tableau", "明细", "原始"]
    derived_markers = [
        "summary",
        "profile",
        "metric",
        "registry",
        "matrix",
        "correlation",
        "cluster",
        "quantile",
        "anomaly",
        "top_",
        "daily_summary",
        "method_log",
    ]
    looks_like_report_asset = _looks_like_retrofit_report_tabular_name(name) or _looks_like_retrofit_report_tabular_name(sheet_name)
    has_structured_dataset_shape = column_count >= 2 and row_count >= 8
    is_primary = any(marker in combined_markers for marker in primary_markers)
    is_source_like = is_primary or any(marker in combined_markers for marker in source_markers)
    is_derived = any(marker in combined_markers for marker in derived_markers) or looks_like_report_asset
    if is_primary:
        asset_kind = "primary_dataset"
        degraded = False
        rejection_reason = ""
    elif is_source_like and not is_derived:
        asset_kind = "source_like_dataset"
        degraded = False
        rejection_reason = ""
    elif has_structured_dataset_shape and not is_derived:
        asset_kind = "source_like_dataset"
        degraded = False
        rejection_reason = ""
    else:
        asset_kind = "analysis_table"
        degraded = True
        if looks_like_report_asset and workbook_sheet_count > 1:
            rejection_reason = "report_workbook_not_original_dataset"
        else:
            rejection_reason = "analysis_table_not_original_dataset"
    return {
        "asset_kind": asset_kind,
        "is_primary_dataset_candidate": bool(asset_kind in {"primary_dataset", "source_like_dataset"}),
        "source_dataset_degraded": degraded,
        "rejection_reason": rejection_reason,
    }


def _is_retrofit_report_text_asset(path: Path, report_dir: Path, report_id: str) -> bool:
    if path.suffix.lower() not in {".md", ".html"}:
        return False
    try:
        rel = path.relative_to(report_dir).as_posix().lower()
    except Exception:
        rel = path.name.lower()
    name = path.name.lower()
    excluded_markers = [
        "report_design_spec",
        "ai_trace",
        "ai_usage_gate",
        "field_semantic_mapping",
        "runtime",
        "event",
        "session",
        "manifest",
        "ledger",
    ]
    if any(marker in rel for marker in excluded_markers):
        return False
    exact_names = {
        f"{report_id.lower()}.md",
        f"{report_id.lower()}.html",
        f"{report_id.lower()}-management_report.md",
        f"{report_id.lower()}-management_report.html",
        f"{report_id.lower()}-analyst_appendix.md",
        f"{report_id.lower()}-analyst_appendix.html",
        f"{report_id.lower()}-r-interpretation.md",
        f"{report_id.lower()}-r-interpretation.html",
        "report.md",
        "report.html",
        "management_report.md",
        "management_report.html",
        "analyst_appendix.md",
        "analyst_appendix.html",
    }
    if name in exact_names:
        return True
    allowed_markers = ["management_report", "analyst_appendix", "r-interpretation", "revision", "report"]
    return any(marker in name for marker in allowed_markers)


def _is_retrofit_auxiliary_asset(path: Path, report_dir: Path) -> bool:
    if not path.is_file():
        return False
    if path.suffix.lower() not in {".json", ".md", ".html", ".txt", ".log"}:
        return False
    try:
        rel = path.relative_to(report_dir).as_posix().lower()
    except Exception:
        rel = path.name.lower()
    if any(segment in rel for segment in ["codex_runtime_rebuild/", "__pycache__", ".cache/"]):
        return False
    useful_markers = [
        "report_design_spec",
        "ai_trace",
        "ai_traces",
        "usage_gate",
        "field_semantic_mapping",
        "quality/",
        "manifest",
        "session.json",
        "working/report",
        "source/",
    ]
    return any(marker in rel for marker in useful_markers)


def _read_retrofit_asset_excerpt(path: Path, *, max_chars: int = 12000) -> str:
    try:
        if path.suffix.lower() == ".json":
            payload = json.loads(path.read_text(encoding="utf-8", errors="ignore"))
            text = json.dumps(payload, ensure_ascii=False, indent=2, default=str)
        else:
            text = path.read_text(encoding="utf-8", errors="ignore")
    except Exception:
        return ""
    return re.sub(r"\s+", " ", text).strip()[:max_chars]


def _infer_retrofit_mode(source_assets: dict[str, Any]) -> str:
    if bool(source_assets.get("primary_csv_available")) or bool(source_assets.get("r_workflow_available")):
        return "full_retrofit"
    if bool(source_assets.get("usable_report_text_available")) or bool(source_assets.get("analysis_csv_available")) or bool(source_assets.get("metric_mining_available")):
        return "degraded_report_retrofit"
    if bool(source_assets.get("auxiliary_assets")):
        return "evidence_limited_retrofit"
    return "no_readable_assets"


def _scan_retrofit_source_assets(report_dir: Path, report_id: str) -> dict[str, Any]:
    csv_candidates: list[dict[str, Any]] = []
    tabular_paths: list[Path] = []
    seen_tabular_paths: set[str] = set()
    search_roots = [report_dir, report_dir / "outputs", report_dir / "r-workflow"]
    for root in search_roots:
        if not root.exists():
            continue
        pattern = "*" if root == report_dir else "**/*"
        for path in sorted(root.glob(pattern)):
            if not path.is_file() or path.suffix.lower() not in _RETROFIT_TABULAR_SUFFIXES:
                continue
            try:
                resolved_key = str(path.resolve()).lower()
            except Exception:
                resolved_key = str(path).lower()
            if resolved_key in seen_tabular_paths:
                continue
            seen_tabular_paths.add(resolved_key)
            tabular_paths.append(path)
    for path in tabular_paths:
        if not path.is_file():
            continue
        try:
            rel = path.relative_to(report_dir).as_posix()
        except Exception:
            rel = path.name
        lower_name = path.name.lower()
        if any(token in lower_name for token in ["sample", "summary", "profile", "registry", "metric", "object"]):
            base_priority = 10
        else:
            base_priority = 0
        try:
            preview, preview_meta = _read_retrofit_tabular_asset(path, preview_rows=500)
            row_count = int(len(preview))
            column_count = int(len(preview.columns))
        except Exception:
            preview_meta = {}
            row_count = 0
            column_count = 0
        asset_class = _retrofit_csv_asset_class(
            path,
            rel,
            preview_meta=preview_meta,
            row_count=row_count,
            column_count=column_count,
        )
        priority = base_priority
        if asset_class.get("asset_kind") == "primary_dataset":
            priority += 1000
        elif asset_class.get("asset_kind") == "source_like_dataset":
            priority += 800
        else:
            priority += 100
        if _looks_like_retrofit_report_tabular_name(str(preview_meta.get("selected_sheet_name") or path.stem)):
            priority -= 40
        csv_candidates.append(
            {
                "path": str(path.resolve()),
                "relative_path": rel,
                "name": path.name,
                "row_count_preview": row_count,
                "column_count": column_count,
                "storage_format": str(preview_meta.get("storage_format") or path.suffix.lstrip(".").lower()),
                "selected_sheet_name": str(preview_meta.get("selected_sheet_name") or ""),
                "workbook_sheet_count": int(preview_meta.get("workbook_sheet_count") or 0),
                "priority": priority + min(row_count, 500) + column_count * 5,
                **asset_class,
            }
        )
    text_assets: list[dict[str, Any]] = []
    for path in sorted(report_dir.rglob("*.md")) + sorted(report_dir.rglob("*.html")):
        if path.is_file() and _is_retrofit_report_text_asset(path, report_dir, report_id):
            try:
                rel = path.relative_to(report_dir).as_posix()
            except Exception:
                rel = path.name
            text_assets.append({"name": path.name, "path": str(path.resolve()), "relative_path": rel})
    auxiliary_assets: list[dict[str, Any]] = []
    for path in sorted(report_dir.rglob("*")):
        if not _is_retrofit_auxiliary_asset(path, report_dir):
            continue
        try:
            rel = path.relative_to(report_dir).as_posix()
        except Exception:
            rel = path.name
        if any(item.get("relative_path") == rel for item in text_assets):
            continue
        try:
            size_bytes = path.stat().st_size
        except Exception:
            size_bytes = 0
        auxiliary_assets.append(
            {
                "name": path.name,
                "path": str(path.resolve()),
                "relative_path": rel,
                "suffix": path.suffix.lower(),
                "size_bytes": size_bytes,
            }
        )
    metric_dir = report_dir / "outputs" / "metric_mining"
    r_dir = report_dir / "r-workflow"
    primary_csv_available = any(bool(item.get("is_primary_dataset_candidate")) for item in csv_candidates)
    analysis_csv_available = bool(csv_candidates)
    usable_report_text_available = bool(text_assets)
    metric_mining_available = metric_dir.exists() and any(metric_dir.glob("**/*"))
    r_workflow_available = r_dir.exists() and any(r_dir.glob("**/*"))
    auxiliary_assets_available = bool(auxiliary_assets)
    can_retrofit_cli = bool(primary_csv_available or analysis_csv_available or usable_report_text_available or metric_mining_available or r_workflow_available or auxiliary_assets_available)
    missing_required_assets: list[str] = []
    if not primary_csv_available:
        missing_required_assets.append("original_source_dataset")
    if not (usable_report_text_available or analysis_csv_available or metric_mining_available or r_workflow_available):
        missing_required_assets.append("reader_report_or_analysis_outputs")
    retrofit_mode = _infer_retrofit_mode(
        {
            "primary_csv_available": primary_csv_available,
            "analysis_csv_available": analysis_csv_available,
            "usable_report_text_available": usable_report_text_available,
            "metric_mining_available": metric_mining_available,
            "r_workflow_available": r_workflow_available,
            "auxiliary_assets": auxiliary_assets,
        }
    )
    return {
        "tabular_candidates": sorted(csv_candidates, key=lambda item: int(item.get("priority") or 0), reverse=True),
        "csv_candidates": sorted(csv_candidates, key=lambda item: int(item.get("priority") or 0), reverse=True),
        "text_assets": text_assets,
        "auxiliary_assets": auxiliary_assets[:120],
        "metric_mining_available": metric_mining_available,
        "r_workflow_available": r_workflow_available,
        "current_turn_export_manifest_available": (report_dir / f"{report_id}-current_turn_export_manifest.json").exists(),
        "primary_csv_available": primary_csv_available,
        "analysis_csv_available": analysis_csv_available,
        "usable_report_text_available": usable_report_text_available,
        "auxiliary_assets_available": auxiliary_assets_available,
        "retrofit_mode": retrofit_mode,
        "evidence_limited": retrofit_mode == "evidence_limited_retrofit",
        "can_retrofit_cli": can_retrofit_cli,
        "missing_required_assets": missing_required_assets,
    }


def _load_retrofit_frame(report_dir: Path, report_id: str, source_assets: dict[str, Any]) -> tuple[pd.DataFrame, dict[str, Any]]:
    payloads = _load_report_json_payloads(report_dir)
    dataset_id = ""
    sheet_name = ""
    for payload in payloads:
        dataset_candidate = _find_first_nested_value(payload, "dataset_id")
        if isinstance(dataset_candidate, str) and dataset_candidate.strip():
            dataset_id = dataset_candidate.strip()
            sheet_candidate = _find_first_nested_value(payload, "sheet_name")
            sheet_name = str(sheet_candidate or "").strip()
            break
    if dataset_id:
        try:
            frame, metadata, sheet = load_dataset_frame(dataset_id, sheet_name or None)
            return frame, {
                "source_kind": "dataset_service",
                "dataset_id": dataset_id,
                "dataset_name": metadata.get("name", ""),
                "sheet_name": sheet.get("name", sheet_name or "Sheet1"),
                "retrofit_mode": "full_retrofit",
                "evidence_limited": False,
                "source_dataset_degraded": False,
                "missing_required_assets": [],
            }
        except Exception as exc:
            dataset_error = str(exc)
    else:
        dataset_error = ""

    for candidate in list(source_assets.get("tabular_candidates") or source_assets.get("csv_candidates") or []):
        path = Path(str(candidate.get("path") or ""))
        if not path.exists():
            continue
        is_primary_candidate = bool(candidate.get("is_primary_dataset_candidate"))
        row_count_preview = int(candidate.get("row_count_preview") or 0)
        column_count = int(candidate.get("column_count") or 0)
        if (
            not is_primary_candidate
            and bool(source_assets.get("usable_report_text_available"))
            and (row_count_preview < 8 or column_count < 3)
        ):
            continue
        try:
            frame, tabular_meta = _read_retrofit_tabular_asset(
                path,
                preferred_sheet=str(candidate.get("selected_sheet_name") or ""),
            )
        except Exception:
            continue
        if frame.shape[1] >= 2 and frame.shape[0] >= 1:
            degraded = bool(candidate.get("source_dataset_degraded"))
            missing_assets = [] if not degraded else ["original_source_dataset"]
            return frame, {
                "source_kind": "report_tabular_asset",
                "source_csv_path": str(path.resolve()),
                "source_csv_name": path.name,
                "source_csv_relative_path": candidate.get("relative_path") or path.name,
                "source_csv_asset_kind": candidate.get("asset_kind") or "",
                "source_tabular_path": str(path.resolve()),
                "source_tabular_name": path.name,
                "source_tabular_relative_path": candidate.get("relative_path") or path.name,
                "source_file_format": str(tabular_meta.get("storage_format") or candidate.get("storage_format") or path.suffix.lstrip(".").lower()),
                "sheet_name": str(tabular_meta.get("selected_sheet_name") or candidate.get("selected_sheet_name") or ""),
                "retrofit_mode": source_assets.get("retrofit_mode") or ("degraded_report_retrofit" if degraded else "full_retrofit"),
                "evidence_limited": bool(source_assets.get("evidence_limited")),
                "source_dataset_degraded": degraded,
                "missing_required_assets": missing_assets,
                "dataset_error": dataset_error,
            }

    text_rows: list[dict[str, Any]] = []
    for asset in list(source_assets.get("text_assets") or []):
        path = Path(str(asset.get("path") or ""))
        if not path.exists():
            continue
        try:
            text = path.read_text(encoding="utf-8", errors="ignore")
        except Exception:
            continue
        text_rows.append(
            {
                "artifact_name": path.name,
                "artifact_type": path.suffix.lstrip(".") or "text",
                "content_excerpt": re.sub(r"\s+", " ", text).strip()[:12000],
            }
        )
    if not text_rows:
        for asset in list(source_assets.get("auxiliary_assets") or []):
            path = Path(str(asset.get("path") or ""))
            if not path.exists():
                continue
            excerpt = _read_retrofit_asset_excerpt(path)
            if not excerpt:
                continue
            text_rows.append(
                {
                    "artifact_name": path.name,
                    "artifact_type": path.suffix.lstrip(".") or "text",
                    "relative_path": asset.get("relative_path") or path.name,
                    "content_excerpt": excerpt,
                }
            )
    if not text_rows:
        text_rows.append(
            {
                "artifact_name": f"{report_id}-empty-retrofit-context",
                "artifact_type": "fallback",
                "content_excerpt": "该报告目录未找到原始数据快照、分析表或报告文本；无法补建有证据的 CLI 长链。",
            }
        )
    return pd.DataFrame(text_rows), {
        "source_kind": "evidence_inventory" if source_assets.get("evidence_limited") else "report_text_inventory",
        "retrofit_mode": source_assets.get("retrofit_mode") or "degraded_report_retrofit",
        "evidence_limited": bool(source_assets.get("evidence_limited")),
        "source_dataset_degraded": True,
        "missing_required_assets": list(source_assets.get("missing_required_assets") or ["original_source_dataset"]),
        "dataset_error": dataset_error,
    }


def create_generic_long_cli_pipeline_from_completed_report(
    report_id: str,
    *,
    auto_start: bool = True,
) -> dict[str, Any]:
    """Create the routed CLI retrofit pipeline for an already completed report.

    This is intentionally additive: the original report remains read-only and the new
    pipeline writes to `codex_runtime_rebuild/<routed-profile>/<pipeline_job_id>/`.
    """
    clean_report_id = "".join(ch for ch in str(report_id or "") if ch.isalnum() or ch in {"_", "-"})
    report_dir = REPORTS_DIR / f"smart-report-{clean_report_id}"
    if not report_dir.exists():
        raise ValueError(f"Report directory does not exist: {report_dir}")
    source_assets = _scan_retrofit_source_assets(report_dir, clean_report_id)
    if not source_assets.get("can_retrofit_cli"):
        missing = list(source_assets.get("missing_required_assets") or [])
        raise ValueError(
            "completed report does not have enough evidence to start CLI retrofit: "
            + ", ".join(missing or ["reader_report_or_analysis_outputs"])
        )
    frame, source_metadata = _load_retrofit_frame(report_dir, clean_report_id, source_assets)
    retrofit_mode = str(source_metadata.get("retrofit_mode") or source_assets.get("retrofit_mode") or "degraded_report_retrofit")
    evidence_limited = bool(source_metadata.get("evidence_limited") or retrofit_mode == "evidence_limited_retrofit")
    request = _build_retrofit_request_from_completed_report(report_dir, clean_report_id)
    requirement_intent = _build_retrofit_requirement_intent(report_dir, request)
    detail_dimensions = requirement_intent.get("required_detail_dimensions")
    if not isinstance(detail_dimensions, list):
        detail_dimensions = []
    retrofit_route = infer_completed_report_retrofit_route(clean_report_id)
    routed_business_profile = str(retrofit_route.get("business_profile") or GENERIC_BUSINESS_PROFILE)
    routed_report_lens = str(retrofit_route.get("report_lens") or "retrofit_generic_long_cli")
    route_result = retrofit_route.get("route_result") if isinstance(retrofit_route.get("route_result"), dict) else {}
    route_meta = _completed_report_retrofit_route_meta(routed_business_profile, routed_report_lens)
    rebuild_dir_name = str(route_meta.get("rebuild_dir_name") or "generic_long")
    specialized_pipeline_type = str(route_meta.get("specialized_pipeline_type") or "generic_long_cli_pipeline")
    frontend_context_pack = build_frontend_context_pack(request)
    runtime_pipeline_type = (
        "media_campaign_cli_pipeline"
        if specialized_pipeline_type == "media_campaign_cli_pipeline"
        else "generic_long_cli_pipeline"
    )
    pipeline_context = {
        "style_preset": getattr(request, "premium_style_preset", DEFAULT_LAYOUT_PRESET_ID) or DEFAULT_LAYOUT_PRESET_ID,
        "language": request.report_language,
        "report_goal": "retrofit_media_campaign_cli_report"
        if runtime_pipeline_type == "media_campaign_cli_pipeline"
        else "retrofit_generic_long_cli_report",
        "target_audience": request.target_audience or requirement_intent.get("target_audience") or "management",
        "analysis_mode": runtime_pipeline_type,
        "runtime_pipeline_type": runtime_pipeline_type,
        "retrofit_from_completed_report": True,
        "retrofit_mode": retrofit_mode,
        "evidence_limited": evidence_limited,
        "disable_cross_stage_codex_resume": True,
        "stateless_codex_stages": True,
        "source_report_id": clean_report_id,
        "source_report_dir": str(report_dir.resolve()),
        "source_dataset_degraded": bool(source_metadata.get("source_dataset_degraded")),
        "missing_required_assets": list(source_metadata.get("missing_required_assets") or []),
        "available_source_assets": source_assets,
        "source_metadata": source_metadata,
        "enable_generic_business_runtime": True,
        "runtime_result_expectation": "diagnostic_cli_report" if evidence_limited else "generic_long_cli_report",
        "business_focus": request.user_requirement or request.core_purpose or requirement_intent.get("optimized_user_requirement", ""),
        "user_requirement": request.user_requirement,
        "request": request.model_dump(),
        "frontend_context_pack": frontend_context_pack,
        "frontend_context_brief": str(frontend_context_pack.get("context_brief") or ""),
        "requirement_intent": requirement_intent,
        "raw_user_requirement": request.raw_user_requirement,
        "optimized_user_requirement": request.user_requirement or requirement_intent.get("optimized_user_requirement", ""),
        "visual_style": getattr(request, "visual_style_text", "") or requirement_intent.get("visual_style", ""),
        "color_palette": requirement_intent.get("color_palette", getattr(request, "premium_style_preset", DEFAULT_LAYOUT_PRESET_ID)),
        "chart_palette_preset": getattr(request, "chart_palette_preset", "") or requirement_intent.get("chart_palette_preset", ""),
        "chart_palette_colors": getattr(request, "chart_palette_colors", []) or requirement_intent.get("chart_palette_colors", []),
        "required_detail_dimensions": detail_dimensions,
        "source_dataset_path": "source_dataset.csv",
        "source_schema_path": "source_schema.json",
        "source_statistical_summary_path": "source_statistical_summary.json",
        "source_missingness_path": "source_missingness.csv",
        "source_numeric_profile_path": "source_numeric_profile.csv",
        "source_category_profile_path": "source_category_profile.csv",
        "source_correlation_preview_path": "source_correlation_preview.csv",
        "source_visual_assets_dir": "source_visual_assets",
        "source_visual_assets_index_path": "source_visual_assets_index.json",
        "existing_requirement_intent_path": "existing_requirement_intent.json",
        "input_seed_manifest_path": "input_seed_manifest.json",
        "input_seed_brief_path": "input_seed_brief.md",
        "retrofit_source_asset_manifest_path": "retrofit_source_asset_manifest.json",
        "retrofit_evidence_boundary_path": "retrofit_evidence_boundary.json",
        "retrofit_evidence_boundary_markdown_path": "retrofit_evidence_boundary.md",
        "metric_mining_dir": "metric_mining",
        "r_workflow_dir": "r-workflow",
        "existing_main_report_path": "existing_main_report.md",
        "management_report_path": "management_report.md",
        "analyst_appendix_path": "analyst_appendix.md",
        "report_id": clean_report_id,
        "dataset_name": source_metadata.get("dataset_name", "") or "completed report retrofit source",
        "sheet_name": source_metadata.get("sheet_name", request.sheet_name or "Sheet1"),
        "business_profile": routed_business_profile,
        "report_lens": routed_report_lens,
        "specialized_mode": routed_report_lens,
        "detected_business_profile": routed_business_profile,
        "specialized_pipeline_label": route_meta.get("pipeline_label") or "",
        "specialized_pipeline_type": specialized_pipeline_type,
        "resume_strategy": route_meta.get("resume_strategy") or "",
        "retrofit_route_result": route_result,
        "reader_facing_mode": "business_report",
        "internal_grounding_mode": "completed_report_retrofit",
    }
    if evidence_limited:
        pipeline_context["reader_facing_mode"] = "diagnostic_report"
        pipeline_context["business_focus"] = (
            "基于当前报告目录中的 design spec、AI traces、配置和工作副本生成证据盘点、缺失清单、可恢复分析建议；"
            "不得声称已经基于原始数据重算经营指标。"
        )
    pipeline_context = _with_report_design_context(
        pipeline_context,
        request=request,
        requirement_intent=requirement_intent,
    )
    pipeline_manifest = create_pipeline_job(
        pipeline_type=runtime_pipeline_type,
        workspace_path=str(report_dir / "codex_runtime_rebuild" / rebuild_dir_name / "{pipeline_job_id}"),
        linked_report_id=clean_report_id,
        context_payload=pipeline_context,
        auto_start=False,
    )
    pipeline_job_id = str(pipeline_manifest.get("pipeline_job_id") or "")
    workspace_dir = Path(str(pipeline_manifest.get("workspace_path") or ""))
    copied_inputs = _prepare_generic_long_cli_workspace(
        workspace_dir=workspace_dir,
        report_dir=report_dir,
        report_id=clean_report_id,
        frame=frame,
        request=request,
        requirement_intent=requirement_intent,
        context_payload={**pipeline_context, "pipeline_job_id": pipeline_job_id},
    )
    source_asset_manifest = {
        "report_id": clean_report_id,
        "pipeline_job_id": pipeline_job_id,
        "created_at": datetime.utcnow().isoformat() + "Z",
        "selected_source": {
            "source_kind": source_metadata.get("source_kind", ""),
            "source_csv_path": source_metadata.get("source_csv_path", ""),
            "source_csv_name": source_metadata.get("source_csv_name", ""),
            "source_csv_relative_path": source_metadata.get("source_csv_relative_path", ""),
            "source_csv_asset_kind": source_metadata.get("source_csv_asset_kind", ""),
            "retrofit_mode": retrofit_mode,
            "evidence_limited": evidence_limited,
            "source_dataset_degraded": bool(source_metadata.get("source_dataset_degraded")),
        },
        "source_assets": source_assets,
        "evidence_boundary": {
            "retrofit_mode": retrofit_mode,
            "evidence_limited": evidence_limited,
            "source_dataset_degraded": bool(source_metadata.get("source_dataset_degraded")),
            "missing_required_assets": list(source_metadata.get("missing_required_assets") or []),
            "can_claim_raw_recompute": not bool(source_metadata.get("source_dataset_degraded")),
        },
    }
    source_asset_manifest_path = workspace_dir / "retrofit_source_asset_manifest.json"
    source_asset_manifest_path.write_text(
        json.dumps(source_asset_manifest, ensure_ascii=False, indent=2, default=str),
        encoding="utf-8",
    )
    copied_inputs["retrofit_source_asset_manifest_path"] = str(source_asset_manifest_path.resolve())
    evidence_boundary = {
        "report_id": clean_report_id,
        "pipeline_job_id": pipeline_job_id,
        "retrofit_from_completed_report": True,
        "retrofit_mode": retrofit_mode,
        "evidence_limited": evidence_limited,
        "source_dataset_degraded": bool(source_metadata.get("source_dataset_degraded")),
        "source_kind": source_metadata.get("source_kind", ""),
        "available_source_assets": source_assets,
        "missing_required_assets": list(source_metadata.get("missing_required_assets") or []),
        "allowed_uses": [
            "read existing report artifacts",
            "read copied source_dataset.csv when present",
            "read copied metric mining and R workflow outputs when present",
            "write new reader-facing narrative, structure, titles, captions, HTML/CSS and review notes",
            "write a diagnostic evidence-limited report when only design/config/trace assets are present",
        ],
        "forbidden_uses": [
            "do not invent deterministic metric values",
            "do not claim recomputation from raw data when source_dataset_degraded=true",
            "do not present evidence-limited diagnostic outputs as final data analysis",
            "do not describe analysis-table inputs as original transaction-level data",
            "do not overwrite original report downloadables",
            "do not set formal_pdf_allowed",
        ],
        "reader_disclosure_required": bool(source_metadata.get("source_dataset_degraded")),
        "created_at": datetime.utcnow().isoformat() + "Z",
    }
    evidence_boundary_json = workspace_dir / "retrofit_evidence_boundary.json"
    evidence_boundary_json.write_text(
        json.dumps(evidence_boundary, ensure_ascii=False, indent=2, default=str),
        encoding="utf-8",
    )
    evidence_boundary_md = workspace_dir / "retrofit_evidence_boundary.md"
    evidence_boundary_md.write_text(
        "\n".join(
            [
                "# Retrofit Evidence Boundary",
                "",
                f"- source_dataset_degraded: {str(evidence_boundary['source_dataset_degraded']).lower()}",
                f"- retrofit_mode: {retrofit_mode}",
                f"- evidence_limited: {str(evidence_limited).lower()}",
                f"- source_kind: {evidence_boundary['source_kind'] or 'unknown'}",
                f"- missing_required_assets: {', '.join(evidence_boundary['missing_required_assets']) or 'none'}",
                f"- can_claim_raw_recompute: {str(not evidence_boundary['source_dataset_degraded']).lower()}",
                "",
                "## Guardrails",
                "- Codex may reorganize, deepen, title, caption, and package the report from available evidence.",
                "- Codex must not invent deterministic metric values or imply raw-data recomputation when the source dataset is degraded.",
                "- If evidence_limited=true, Codex must produce a diagnostic evidence report with missing inputs and recovery steps, not a final经营结论报告.",
                "- If the selected source is an analysis table, Codex must describe it as existing evidence rather than raw source data.",
                "- New CLI outputs are additive downloadables; the original report remains read-only.",
            ]
        ),
        encoding="utf-8",
    )
    copied_inputs["retrofit_evidence_boundary_path"] = str(evidence_boundary_json.resolve())
    copied_inputs["retrofit_evidence_boundary_markdown_path"] = str(evidence_boundary_md.resolve())
    bootstrap_log = {
        "report_id": clean_report_id,
        "pipeline_job_id": pipeline_job_id,
        "pipeline_type": runtime_pipeline_type,
        "specialized_pipeline_type": specialized_pipeline_type,
        "pipeline_label": route_meta.get("pipeline_label") or "普通报告 CLI 长链",
        "workspace_path": str(workspace_dir.resolve()),
        "specialized_business_profile": routed_business_profile,
        "specialized_report_lens": routed_report_lens,
        "created_from": "retrofit_from_completed_report",
        "source_metadata": source_metadata,
        "available_source_assets": source_assets,
        "copied_inputs": copied_inputs,
        "evidence_boundary_path": str(evidence_boundary_json.resolve()),
        "auto_start": bool(auto_start),
        "created_at": datetime.utcnow().isoformat() + "Z",
    }
    (workspace_dir / "retrofit_bootstrap_log.json").write_text(
        json.dumps(bootstrap_log, ensure_ascii=False, indent=2, default=str),
        encoding="utf-8",
    )
    result: dict[str, Any] = {
        "action": route_meta.get("action") or "start_generic_long_cli_pipeline",
        "pipeline_job_id": pipeline_job_id,
        "pipeline_type": runtime_pipeline_type,
        "specialized_pipeline_type": specialized_pipeline_type,
        "pipeline_label": route_meta.get("pipeline_label") or "普通报告 CLI 长链",
        "resume_strategy": route_meta.get("resume_strategy") or "start_generic_long_cli_pipeline",
        "workspace_path": str(workspace_dir.resolve()),
        "specialized_business_profile": routed_business_profile,
        "specialized_report_lens": routed_report_lens,
        "pipeline_manifest": pipeline_manifest,
        "copied_inputs": copied_inputs,
        "available_source_assets": source_assets,
        "missing_required_assets": list(source_metadata.get("missing_required_assets") or []),
        "bootstrap_log_path": str((workspace_dir / "retrofit_bootstrap_log.json").resolve()),
        "evidence_boundary_path": str(evidence_boundary_json.resolve()),
    }
    if auto_start:
        result["start_result"] = start_pipeline_job(pipeline_job_id)
    return result


def _safe_multi_table_cli_table_id(sheet_name: str, index: int) -> str:
    slug = re.sub(r"[^A-Za-z0-9]+", "_", str(sheet_name or "")).strip("_").lower()
    slug = slug[:48].strip("_")
    return f"sheet_{index:02d}_{slug}" if slug else f"sheet_{index:02d}"


def _prepare_multi_table_generic_long_cli_workspace(
    *,
    workspace_dir: Path,
    report_dir: Path,
    report: dict[str, Any],
    metadata: dict[str, Any],
    request: SmartReportRequest,
    selected_sheet_names: list[str],
    sheet_frames: list[tuple[dict[str, Any], pd.DataFrame]],
    blueprint: dict[str, Any],
    context_payload: dict[str, Any],
) -> dict[str, Any]:
    workspace_dir.mkdir(parents=True, exist_ok=True)
    tables_dir = workspace_dir / "tables"
    tables_dir.mkdir(parents=True, exist_ok=True)

    table_records: list[dict[str, Any]] = []
    copied: dict[str, Any] = {
        "tables": [],
        "seed_report_path": _copy_text_if_exists(
            report_dir / f"{report['report_id']}.md",
            workspace_dir / "deterministic_multi_table_seed.md",
        ),
        "seed_report_html_path": _copy_text_if_exists(
            report_dir / f"{report['report_id']}.html",
            workspace_dir / "deterministic_multi_table_seed.html",
        ),
    }

    for index, (sheet_meta, frame) in enumerate(sheet_frames, 1):
        sheet_name = str(sheet_meta.get("name") or sheet_meta.get("sheet_name") or selected_sheet_names[index - 1] or f"Sheet{index}")
        table_id = _safe_multi_table_cli_table_id(sheet_name, index)
        table_dir = tables_dir / table_id
        table_dir.mkdir(parents=True, exist_ok=True)

        source_table_path = table_dir / "source_table.csv"
        source_sample_path = table_dir / "source_sample.csv"
        schema_path = table_dir / "source_schema.json"
        frame.to_csv(source_table_path, index=False, encoding="utf-8-sig")
        frame.head(120).to_csv(source_sample_path, index=False, encoding="utf-8-sig")
        profile_files = _write_generic_long_cli_source_profiles(frame, table_dir)
        schema_payload = {
            "table_id": table_id,
            "sheet_name": sheet_name,
            "row_count": int(frame.shape[0]),
            "column_count": int(frame.shape[1]),
            "columns": [str(column) for column in frame.columns],
            "dtypes": {str(column): str(dtype) for column, dtype in frame.dtypes.items()},
            "sample_rows": clean_records(frame, limit=12),
            "profile_files": {key: Path(value).name for key, value in profile_files.items()},
        }
        schema_path.write_text(json.dumps(schema_payload, ensure_ascii=False, indent=2, default=str), encoding="utf-8")
        record = {
            "table_id": table_id,
            "sheet_name": sheet_name,
            "source_table_path": str(source_table_path.resolve()),
            "source_sample_path": str(source_sample_path.resolve()),
            "source_schema_path": str(schema_path.resolve()),
            "source_profile_files": profile_files,
            "row_count": int(frame.shape[0]),
            "column_count": int(frame.shape[1]),
            "columns": [str(column) for column in frame.columns],
        }
        table_records.append(record)
        copied["tables"].append(record)

    selected = set(selected_sheet_names)
    relationship_candidates = [
        item
        for item in list((blueprint or {}).get("relationships") or [])
        if str((item or {}).get("left_sheet") or "") in selected and str((item or {}).get("right_sheet") or "") in selected
    ]
    table_inventory_payload = {
        "report_id": report.get("report_id", ""),
        "dataset_id": report.get("dataset_id", ""),
        "dataset_name": metadata.get("name", ""),
        "selected_sheet_names": selected_sheet_names,
        "tables": table_records,
        "relationship_candidates": relationship_candidates,
    }
    (workspace_dir / "table_inventory.json").write_text(
        json.dumps(table_inventory_payload, ensure_ascii=False, indent=2, default=str),
        encoding="utf-8",
    )
    (workspace_dir / "workflow_blueprint.json").write_text(
        json.dumps(blueprint or {}, ensure_ascii=False, indent=2, default=str),
        encoding="utf-8",
    )
    (workspace_dir / "relationship_candidates.json").write_text(
        json.dumps({"relationships": relationship_candidates}, ensure_ascii=False, indent=2, default=str),
        encoding="utf-8",
    )
    multi_context = {
        **context_payload,
        "report": {
            "report_id": report.get("report_id", ""),
            "dataset_name": report.get("dataset_name", ""),
            "sheet_name": report.get("sheet_name", ""),
            "main_downloadable": report.get("main_downloadable") or {},
        },
        "request": request.model_dump(),
        "selected_sheet_names": selected_sheet_names,
        "table_ids": [item["table_id"] for item in table_records],
        "input_files": {
            "table_inventory": "table_inventory.json",
            "workflow_blueprint": "workflow_blueprint.json",
            "relationship_candidates": "relationship_candidates.json",
            "deterministic_multi_table_seed": "deterministic_multi_table_seed.md",
        },
    }
    design_json_path, design_md_path, design_spec = write_report_design_spec_files(
        workspace_dir,
        request=request,
        context_payload=multi_context,
    )
    multi_context.update(
        {
            "report_design_spec": design_spec,
            "design_spec": design_spec,
            "report_design_spec_path": design_json_path.name,
            "report_design_spec_markdown_path": design_md_path.name,
            "chart_palette_preset": design_spec.get("chart_palette_preset", ""),
            "chart_palette_colors": list(design_spec.get("chart_palette_colors") or []),
            "visual_style": design_spec.get("visual_style", ""),
            "color_palette": design_spec.get("color_palette", ""),
            "layout_preference": design_spec.get("layout_preference", ""),
            "pdf_design_brief": design_spec.get("pdf_design_brief", ""),
        }
    )
    (workspace_dir / "multi_table_context.json").write_text(
        json.dumps(multi_context, ensure_ascii=False, indent=2, default=str),
        encoding="utf-8",
    )
    copied.update(
        {
            "table_inventory_path": str((workspace_dir / "table_inventory.json").resolve()),
            "workflow_blueprint_path": str((workspace_dir / "workflow_blueprint.json").resolve()),
            "relationship_candidates_path": str((workspace_dir / "relationship_candidates.json").resolve()),
            "multi_table_context_path": str((workspace_dir / "multi_table_context.json").resolve()),
            "report_design_spec_path": str(design_json_path.resolve()),
            "report_design_spec_markdown_path": str(design_md_path.resolve()),
        }
    )
    return copied


