def _write_generic_long_cli_release_gate_assets(
    *,
    report_dir: Path,
    report_id: str,
    final_output: dict[str, Any],
) -> tuple[dict[str, Any], dict[str, Any], list[dict[str, Any]]]:
    """Backend-only completion gate for generic-long CLI outputs.

    This does not set `formal_pdf_allowed`; the AI mandatory chain still owns that
    release boundary. It only prevents a completed CLI report from being masked by
    missing legacy generic-bundle gate files.
    """
    markdown_path = Path(str(final_output.get("markdown_path") or ""))
    html_path = Path(str(final_output.get("html_path") or ""))
    css_path = Path(str(final_output.get("css_path") or ""))
    pdf_path = Path(str(final_output.get("main_artifact_path") or ""))
    fail_items: list[str] = []
    markdown_text = ""
    if not markdown_path.is_file():
        fail_items.append("05_report.md missing")
    else:
        markdown_text = markdown_path.read_text(encoding="utf-8", errors="ignore")
        if len(markdown_text.strip()) < 3000:
            fail_items.append("05_report.md is too short for generic long report")
        if not any(token in markdown_text for token in ["建议", "行动", "策略", "recommendation", "action"]):
            fail_items.append("05_report.md lacks visible recommendations/actions")
    if not html_path.is_file():
        fail_items.append("06_report.html missing")
    if not css_path.is_file():
        fail_items.append("06_report.css missing")
    if not pdf_path.is_file():
        fail_items.append("07_report.pdf missing")

    passed = not fail_items
    gate_payload = {
        "passed": passed,
        "verdict": "pass" if passed else "block",
        "report_mode": "generic_long_cli_pipeline",
        "fail_items": fail_items,
        "affected_sections": ["generic_long_cli_pipeline"] if fail_items else [],
        "suggested_fixes": [
            "Retry failed/short generic-long CLI stages before exposing the PDF as the main report."
        ] if fail_items else [],
        "backend_deterministic_gate": True,
        "formal_pdf_allowed_source": "ai_mandatory_chain",
    }
    score = 95 if passed else 65
    score_payload = {
        "score": score,
        "passed": passed,
        "business_profile": "generic_long_cli_pipeline",
        "backend_deterministic_gate": True,
        "breakdown": {
            "pipeline_completion": 30 if pdf_path.is_file() else 0,
            "markdown_depth": 30 if markdown_path.is_file() and len(markdown_text.strip()) >= 3000 else 0,
            "recommendation_presence": 20 if any(token in markdown_text for token in ["建议", "行动", "策略", "recommendation", "action"]) else 0,
            "html_css_package": 15 if html_path.is_file() and css_path.is_file() else 0,
        },
        "hard_fail_items": fail_items,
    }

    relative_dir = report_dir.relative_to(REPORTS_DIR.parent).as_posix()
    gate_path = report_dir / f"{report_id}-quality_gate_result.json"
    score_path = report_dir / f"{report_id}-report_quality_score.json"
    gate_path.write_text(json.dumps(gate_payload, ensure_ascii=False, indent=2), encoding="utf-8")
    score_path.write_text(json.dumps(score_payload, ensure_ascii=False, indent=2), encoding="utf-8")
    assets = [
        {
            "name": gate_path.name,
            "path": f"/storage/{relative_dir}/{gate_path.name}",
            "file_path": str(gate_path.resolve()),
            "purpose": "Generic long CLI backend completion gate.",
            "is_main": False,
            "type": "json",
        },
        {
            "name": score_path.name,
            "path": f"/storage/{relative_dir}/{score_path.name}",
            "file_path": str(score_path.resolve()),
            "purpose": "Generic long CLI backend quality score.",
            "is_main": False,
            "type": "json",
        },
    ]
    return gate_payload, score_payload, assets


