def _read_ecommerce_metric_manifest_fields(workspace: Path) -> dict[str, Any]:
    metric_index_path = workspace / "01b_ecommerce_metric_consumption_index.json"
    metric_gate_path = workspace / "05a_data_utilization_gate.json"
    metric_index_payload: dict[str, Any] = {}
    metric_gate_payload: dict[str, Any] = {}
    if metric_index_path.exists():
        try:
            metric_index_payload = json.loads(metric_index_path.read_text(encoding="utf-8"))
        except Exception:
            metric_index_payload = {}
    if metric_gate_path.exists():
        try:
            metric_gate_payload = json.loads(metric_gate_path.read_text(encoding="utf-8"))
        except Exception:
            metric_gate_payload = {}
    return {
        "ecommerce_metric_consumption_index_path": str(metric_index_path.resolve()) if metric_index_path.exists() else "",
        "ecommerce_metric_coverage_summary": metric_gate_payload.get("metric_coverage") or {},
        "ecommerce_metric_universe_count": int(
            metric_gate_payload.get("metric_universe_count")
            or metric_index_payload.get("metric_universe_count")
            or 0
        ),
        "ecommerce_metric_missing_ids": list(metric_gate_payload.get("missing_metric_ids") or []),
    }


