def _dedupe_preserve_order(values: list[Any]) -> list[Any]:
    seen: set[str] = set()
    ordered: list[Any] = []
    for value in values:
        marker = json.dumps(value, ensure_ascii=False, sort_keys=True, default=str) if isinstance(value, (dict, list, tuple, set)) else str(value)
        if marker in seen:
            continue
        seen.add(marker)
        ordered.append(value)
    return ordered


def _flatten_text_items(value: Any) -> list[str]:
    flattened: list[str] = []

    def walk(current: Any) -> None:
        if current is None:
            return
        if isinstance(current, (list, tuple, set)):
            for item in current:
                walk(item)
            return
        text = str(current).strip()
        if text.startswith("[") and text.endswith("]"):
            try:
                parsed = ast.literal_eval(text)
            except Exception:
                parsed = None
            if isinstance(parsed, (list, tuple, set)):
                for item in parsed:
                    walk(item)
                return
        if text:
            flattened.append(text)

    walk(value)
    return flattened


def _write_json_file(path: Path, payload: Any) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(payload, ensure_ascii=False, indent=2, default=_safe_value), encoding="utf-8")


def _append_workflow_log(report_dir: Path, record: dict[str, Any]) -> None:
    path = report_dir / "workflow_log.jsonl"
    path.parent.mkdir(parents=True, exist_ok=True)
    with path.open("a", encoding="utf-8") as handle:
        handle.write(json.dumps(record, ensure_ascii=False, default=_safe_value) + "\n")


