def _runtime_policy(runtime_child_task_creator: Callable[..., dict[str, Any]] | None, *, business_profile: str, report_lens: str) -> dict[str, Any]:
    policy = runtime_policy_for_report(
        business_profile=business_profile,
        report_lens=report_lens,
    )
    policy["runtime_available"] = False
    if runtime_child_task_creator is None:
        return policy
    try:
        settings = load_runtime_settings_raw()
    except Exception:
        return policy
    policy["runtime_available"] = bool(settings.get("codex_runtime_enabled", False))
    return policy


def _normalize_stage_id_for_metadata(stage_id: str) -> str:
    normalized = str(stage_id or "").strip()
    normalized = re.sub(r"_rerun_\d+$", "", normalized)
    return normalized


def _resolve_stage_runner_mode(stage_definition: dict[str, Any], runtime_policy: dict[str, Any]) -> tuple[str, str]:
    if str(stage_definition.get("stage_kind") or "") == "deterministic_stage":
        return str(stage_definition.get("runner_mode") or "deterministic_local"), str(stage_definition.get("fallback_mode") or "none")
    alias = str(stage_definition.get("runtime_policy_alias") or "").strip()
    supports_runtime = bool(stage_definition.get("supports_runtime"))
    enabled_aliases = {str(item).strip().lower() for item in runtime_policy.get("runtime_first_stages") or []}
    alias_enabled = alias.lower() in enabled_aliases if alias else False
    if supports_runtime and alias_enabled and bool(runtime_policy.get("runtime_available")):
        return "runtime_first", str(stage_definition.get("fallback_mode") or "local_fallback")
    if alias_enabled:
        return "local_runner_policy_enabled", "local_only"
    return "local_only", str(stage_definition.get("fallback_mode") or "local_only")


def _build_report_stage_registry(runtime_policy: dict[str, Any]) -> dict[str, dict[str, Any]]:
    registry: dict[str, dict[str, Any]] = {}
    for stage_id, stage_definition in REPORT_STAGE_BLUEPRINTS.items():
        runner_mode, fallback_mode = _resolve_stage_runner_mode(stage_definition, runtime_policy)
        registry[stage_id] = {
            "stage_id": stage_id,
            "stage_kind": str(stage_definition.get("stage_kind") or "deterministic_stage"),
            "runner_mode": runner_mode,
            "fallback_mode": fallback_mode,
            "artifact_contract": copy.deepcopy(stage_definition.get("artifact_contract") or {}),
            "telemetry_fields": list(stage_definition.get("telemetry_fields") or []),
        }
    return registry


def _stage_metadata(stage_id: str, stage_registry: dict[str, dict[str, Any]]) -> dict[str, Any]:
    normalized = _normalize_stage_id_for_metadata(stage_id)
    return dict(stage_registry.get(normalized) or {
        "stage_id": normalized,
        "stage_kind": "deterministic_stage",
        "runner_mode": "deterministic_local",
        "fallback_mode": "none",
        "artifact_contract": {"contract_name": "inline_stage_event", "artifacts": []},
        "telemetry_fields": list(DEFAULT_DETERMINISTIC_TELEMETRY_FIELDS),
    })


def _runtime_stage_enabled(
    stage_name: str,
    *,
    runtime_policy: dict[str, Any],
    runtime_child_task_creator: Callable[..., dict[str, Any]] | None,
) -> bool:
    if runtime_child_task_creator is None:
        return False
    if not bool(runtime_policy.get("runtime_available")):
        return False
    return runtime_stage_enabled(
        stage_name,
        business_profile=str(runtime_policy.get("business_profile") or ""),
        report_lens=str(runtime_policy.get("report_lens") or ""),
    )


def _runtime_child_creator_for_stages(
    runtime_child_task_creator: Callable[..., dict[str, Any]] | None,
    *,
    runtime_policy: dict[str, Any],
    stage_names: list[str],
) -> Callable[..., dict[str, Any]] | None:
    if runtime_child_task_creator is None:
        return None
    if any(_runtime_stage_enabled(stage_name, runtime_policy=runtime_policy, runtime_child_task_creator=runtime_child_task_creator) for stage_name in stage_names):
        return runtime_child_task_creator
    return None


def _runtime_stage_event_prefix(spec: RuntimeStageSpec) -> str:
    stage_id = str(spec.stage_id or "").strip()
    return stage_id if stage_id.endswith("_runtime") else f"{stage_id}_runtime"


def _default_runtime_stage_user_requirement(request: SmartReportRequest, fallback_text: str) -> str:
    return request.user_requirement or request.problem_to_solve or request.core_purpose or fallback_text


def _semantic_layer_payload_compatible(payload: Any) -> bool:
    if not isinstance(payload, dict):
        return False
    for key in SEMANTIC_RUNTIME_REQUIRED_KEYS:
        if key not in payload:
            return False
    list_keys = (
        "content_domains",
        "audience_profile",
        "evidence_points",
        "text_findings",
        "numeric_findings",
        "metric_cards",
        "important_columns",
        "recommended_actions",
    )
    return all(isinstance(payload.get(key), list) for key in list_keys)


def _string_list_from_semantic_items(items: Any, formatter: Callable[[dict[str, Any]], str] | None = None) -> list[str]:
    normalized: list[str] = []
    for item in items or []:
        if isinstance(item, str):
            text = item.strip()
            if text:
                normalized.append(text)
            continue
        if isinstance(item, dict):
            text = formatter(item) if formatter else ""
            text = str(text or "").strip()
            if text:
                normalized.append(text)
            continue
        text = str(item or "").strip()
        if text:
            normalized.append(text)
    return normalized


def _normalize_semantic_layer_runtime_payload(payload: dict[str, Any]) -> dict[str, Any] | None:
    if not isinstance(payload, dict):
        return None
    normalized = dict(payload)

    creator_profile = normalized.get("creator_profile")
    if isinstance(creator_profile, dict):
        creator_profile_parts = [
            f"{str(key).strip()}：{str(value).strip()}"
            for key, value in creator_profile.items()
            if str(key).strip() and str(value).strip()
        ]
        normalized["creator_profile"] = "；".join(creator_profile_parts)
    else:
        normalized["creator_profile"] = str(creator_profile or "").strip()

    audience_profile = normalized.get("audience_profile")
    if isinstance(audience_profile, dict):
        normalized["audience_profile"] = [
            f"{str(key).strip()}：{str(value).strip()}"
            for key, value in audience_profile.items()
            if str(key).strip() and str(value).strip()
        ]
    else:
        normalized["audience_profile"] = _string_list_from_semantic_items(audience_profile)

    normalized["content_domains"] = _string_list_from_semantic_items(normalized.get("content_domains"))
    normalized["evidence_points"] = _string_list_from_semantic_items(
        normalized.get("evidence_points"),
        formatter=lambda item: "；".join(
            filter(
                None,
                [
                    str(item.get("evidence") or "").strip(),
                    (
                        f"判断：{str(item.get('implication') or '').strip()}"
                        if str(item.get("implication") or "").strip()
                        else ""
                    ),
                    (
                        f"置信度：{str(item.get('certainty') or '').strip()}"
                        if str(item.get("certainty") or "").strip()
                        else ""
                    ),
                ],
            )
        ),
    )
    normalized["text_findings"] = _string_list_from_semantic_items(
        normalized.get("text_findings"),
        formatter=lambda item: "；".join(
            filter(
                None,
                [
                    (
                        f"【{str(item.get('theme') or '').strip()}】{str(item.get('interpretation') or '').strip()}"
                        if str(item.get("theme") or "").strip() or str(item.get("interpretation") or "").strip()
                        else ""
                    ),
                    (
                        f"证据：{str(item.get('evidence') or '').strip()}"
                        if str(item.get("evidence") or "").strip()
                        else ""
                    ),
                ],
            )
        ),
    )
    normalized["numeric_findings"] = _string_list_from_semantic_items(
        normalized.get("numeric_findings"),
        formatter=lambda item: "；".join(
            filter(
                None,
                [
                    (
                        f"【{str(item.get('metric') or '').strip()}】{str(item.get('finding') or '').strip()}"
                        if str(item.get("metric") or "").strip() or str(item.get("finding") or "").strip()
                        else ""
                    ),
                    (
                        f"含义：{str(item.get('implication') or '').strip()}"
                        if str(item.get("implication") or "").strip()
                        else ""
                    ),
                ],
            )
        ),
    )
    normalized["important_columns"] = _string_list_from_semantic_items(
        normalized.get("important_columns"),
        formatter=lambda item: "；".join(
            filter(
                None,
                [
                    str(item.get("column") or "").strip(),
                    (
                        f"角色：{str(item.get('semantic_role') or '').strip()}"
                        if str(item.get("semantic_role") or "").strip()
                        else ""
                    ),
                    (
                        f"原因：{str(item.get('why_important') or '').strip()}"
                        if str(item.get("why_important") or "").strip()
                        else ""
                    ),
                ],
            )
        ),
    )
    normalized["recommended_actions"] = _string_list_from_semantic_items(
        normalized.get("recommended_actions"),
        formatter=lambda item: "；".join(
            filter(
                None,
                [
                    (
                        f"{str(item.get('priority') or '').strip()}优先级：{str(item.get('action') or '').strip()}"
                        if str(item.get("action") or "").strip()
                        else ""
                    ),
                    (
                        f"原因：{str(item.get('reason') or '').strip()}"
                        if str(item.get("reason") or "").strip()
                        else ""
                    ),
                ],
            )
        ),
    )

    metric_cards: list[dict[str, Any]] = []
    for item in normalized.get("metric_cards") or []:
        if not isinstance(item, dict):
            continue
        metric = str(item.get("metric") or "").strip()
        if not metric:
            continue
        metric_cards.append(
            {
                "metric": metric,
                "role": str(item.get("role") or "重点指标").strip() or "重点指标",
                "business_meaning": str(item.get("business_meaning") or "").strip(),
                "management_impact": str(item.get("management_impact") or "").strip(),
                "caution": str(item.get("caution") or "").strip(),
            }
        )
    normalized["metric_cards"] = metric_cards
    return normalized


def _business_background_payload_compatible(payload: Any) -> bool:
    if not isinstance(payload, dict):
        return False
    for key in BUSINESS_BACKGROUND_RUNTIME_REQUIRED_KEYS:
        if key not in payload:
            return False
    return isinstance(payload.get("key_points"), list) and isinstance(payload.get("decision_implications"), list)


