def _load_runtime_stage_artifact_payload(
    *,
    workspace_path: Path,
    primary_artifact_name: str,
    spec: RuntimeStageSpec,
) -> tuple[dict[str, Any] | None, str | None]:
    try:
        runtime_payload = load_runtime_json_artifact(workspace_path, primary_artifact_name)
    except FileNotFoundError:
        return None, "runtime_output_missing"
    except ValueError:
        return None, "runtime_output_invalid_json"

    if spec.artifact_normalizer is not None:
        try:
            runtime_payload = spec.artifact_normalizer(runtime_payload) or {}
        except Exception:
            return None, "runtime_output_normalization_failed"

    if not isinstance(runtime_payload, dict):
        return None, "runtime_output_not_object"
    if spec.artifact_validator and not spec.artifact_validator(runtime_payload):
        return None, "runtime_output_incompatible"
    return runtime_payload, None


def _report_dir_workspace_builder(stage_context: dict[str, Any]) -> str:
    return str(Path(stage_context["report_dir"]).resolve())


def _run_runtime_stage_with_spec(
    *,
    spec: RuntimeStageSpec,
    stage_context: dict[str, Any],
    report_id: str,
    dataset_id: str,
    sheet_name: str,
    request: SmartReportRequest,
    runtime_policy: dict[str, Any],
    runtime_child_task_creator: Callable[..., dict[str, Any]] | None,
    coordinator: ReportCoordinator,
) -> dict[str, Any]:
    if spec.fallback_runner is None:
        raise RuntimeError(f"Runtime stage {spec.stage_id} requires a fallback runner.")

    stage_label = str(spec.stage_id or "runtime_stage").replace("_", " ")
    event_prefix = _runtime_stage_event_prefix(spec)

    def _fallback(reason: str) -> dict[str, Any]:
        coordinator.record_stage(
            f"{event_prefix}_fallback",
            f"{stage_label} 回退到本地路径",
            f"{stage_label} runtime 未成功应用，回退原因：{reason}",
            payload={"status": "completed", "fallback_reason": reason},
        )
        fallback_payload = spec.fallback_runner(stage_context)
        if isinstance(fallback_payload, dict):
            fallback_payload = dict(fallback_payload)
            fallback_payload.setdefault("mode", "fallback")
            fallback_payload["unsafe_runtime_output"] = True
            fallback_payload["fallback_reason"] = reason
        return fallback_payload

    if not spec.runtime_allowed:
        return spec.fallback_runner(stage_context)
    if not _runtime_stage_enabled(
        spec.runtime_policy_alias or spec.stage_id,
        runtime_policy=runtime_policy,
        runtime_child_task_creator=runtime_child_task_creator,
    ):
        return spec.fallback_runner(stage_context)
    if not spec.expected_artifact_files:
        return _fallback("runtime_artifact_contract_empty")

    workspace_path = Path(spec.workspace_path_builder(stage_context)).resolve()
    workspace_path.mkdir(parents=True, exist_ok=True)
    primary_artifact_name = spec.expected_artifact_files[0]
    for artifact_name in spec.expected_artifact_files:
        artifact_path = workspace_path / artifact_name
        if artifact_path.exists():
            try:
                artifact_path.unlink()
            except Exception:
                pass

    coordinator.record_stage(
        f"{event_prefix}_start",
        f"启动 {stage_label} runtime 子任务",
        f"正在为 {stage_label} 创建 Codex runtime 子任务。",
        payload={"status": "running"},
    )
    try:
        run_request = build_runtime_stage_request(
            spec,
            stage_context=stage_context,
            report_id=report_id,
            dataset_id=dataset_id,
            sheet_name=sheet_name,
            user_requirement=_default_runtime_stage_user_requirement(request, spec.stage_id),
        )
        child_task = runtime_child_task_creator(
            run_request,
            parent_report_id=report_id,
            parent_stage_id=spec.stage_id,
            stage_id=spec.stage_id,
            purpose=str(spec.purpose or spec.stage_id),
            artifact_source=primary_artifact_name,
            stage_listener=coordinator.attach_external_runtime_event,
        )
    except Exception as exc:
        return _fallback(f"runtime_child_create_failed: {exc}")

    child_job_id = str(child_task.get("job_id") or "").strip()
    if not child_job_id:
        return _fallback("runtime_child_missing_job_id")

    latest = dict(child_task)
    deadline = time.time() + float(max(1, int(spec.timeout_sec or 180)))
    terminal = {"completed", "failed", "cancelled", "timed_out"}
    while time.time() < deadline:
        try:
            snapshot = get_codex_run_task(child_job_id)
        except Exception as exc:
            return _fallback(f"runtime_child_status_failed: {exc}")
        latest = dict(snapshot)
        if str(snapshot.get("status") or "").strip().lower() in terminal:
            break
        time.sleep(0.5)

    final_status = str(latest.get("status") or "").strip().lower()
    if final_status != "completed":
        return _fallback(f"runtime_child_{final_status or 'failed'}")
    try:
        runtime_payload = load_runtime_json_artifact(workspace_path, primary_artifact_name)
    except FileNotFoundError:
        return _fallback("runtime_output_missing")
    except ValueError:
        return _fallback("runtime_output_invalid_json")
    if spec.artifact_validator and not spec.artifact_validator(runtime_payload):
        return _fallback("runtime_output_incompatible")

    runtime_payload = normalize_runtime_telemetry_contract(
        dict(runtime_payload),
        default_artifact_source=primary_artifact_name,
        parent_report_job_id=str(child_task.get("parent_report_job_id") or ""),
        parent_report_id=report_id,
        stage_id=spec.stage_id,
        purpose=str(spec.purpose or spec.stage_id),
    )
    runtime_payload.setdefault("mode", "runtime_child")
    runtime_payload["live_available"] = True
    runtime_payload["runtime_child_job_id"] = child_job_id
    runtime_payload["runtime_child_run_id"] = str(latest.get("run_id") or "")
    coordinator.record_stage(
        f"{event_prefix}_applied",
        f"应用 {stage_label} runtime 结果",
        f"{stage_label} 已使用 runtime 子任务结果回写。",
        payload={"status": "completed", "runtime_child_job_id": child_job_id},
    )
    return runtime_payload


def _execute_runtime_stage_with_fallback(
    *,
    spec: RuntimeStageSpec,
    stage_context: dict[str, Any],
    report_id: str,
    dataset_id: str,
    sheet_name: str,
    request: SmartReportRequest,
    runtime_policy: dict[str, Any],
    runtime_child_task_creator: Callable[..., dict[str, Any]] | None,
    coordinator: ReportCoordinator,
    direct_runtime_runner: Callable[[CodexRunRequest], dict[str, Any]] | None = None,
) -> dict[str, Any]:
    if spec.fallback_runner is None:
        raise RuntimeError(f"Runtime stage {spec.stage_id} requires a fallback runner.")

    stage_label = str(spec.stage_id or "runtime_stage").replace("_", " ")
    event_prefix = _runtime_stage_event_prefix(spec)

    def _fallback(reason: str) -> dict[str, Any]:
        coordinator.record_stage(
            f"{event_prefix}_fallback",
            f"{stage_label} 回退到本地路径",
            f"{stage_label} runtime 未成功应用，回退原因：{reason}",
            payload={"status": "completed", "fallback_reason": reason},
        )
        fallback_payload = spec.fallback_runner(stage_context)
        if isinstance(fallback_payload, dict):
            fallback_payload = dict(fallback_payload)
            fallback_payload.setdefault("mode", "fallback")
            fallback_payload["unsafe_runtime_output"] = True
            fallback_payload["fallback_reason"] = reason
        return fallback_payload

    if not spec.runtime_allowed:
        return spec.fallback_runner(stage_context)

    policy_enabled = runtime_stage_enabled(
        spec.runtime_policy_alias or spec.stage_id,
        business_profile=str(runtime_policy.get("business_profile") or ""),
        report_lens=str(runtime_policy.get("report_lens") or ""),
    )
    if not policy_enabled or not bool(runtime_policy.get("runtime_available")):
        return spec.fallback_runner(stage_context)

    effective_direct_runner = direct_runtime_runner or spec.direct_runtime_runner or run_headless_codex
    use_task_mode = runtime_child_task_creator is not None
    if not use_task_mode and effective_direct_runner is None:
        return spec.fallback_runner(stage_context)
    if not spec.expected_artifact_files:
        return _fallback("runtime_artifact_contract_empty")

    workspace_path = Path(spec.workspace_path_builder(stage_context)).resolve()
    workspace_path.mkdir(parents=True, exist_ok=True)
    primary_artifact_name = spec.expected_artifact_files[0]
    for artifact_name in spec.expected_artifact_files:
        artifact_path = workspace_path / artifact_name
        if artifact_path.exists():
            try:
                artifact_path.unlink()
            except Exception:
                pass

    coordinator.record_stage(
        f"{event_prefix}_start",
        f"启动 {stage_label} runtime 子任务",
        f"正在为 {stage_label} 创建 Codex runtime 执行。",
        payload={"status": "running", "execution_mode": "task" if use_task_mode else "direct"},
    )

    run_request = build_runtime_stage_request(
        spec,
        stage_context=stage_context,
        report_id=report_id,
        report_job_id=str(runtime_policy.get("parent_report_job_id") or ""),
        dataset_id=dataset_id,
        sheet_name=sheet_name,
        user_requirement=_default_runtime_stage_user_requirement(request, spec.stage_id),
    )

    latest: dict[str, Any]
    runtime_child_job_id = ""
    runtime_child_run_id = ""
    created_runtime_handle: dict[str, Any] = {}
    salvaged_terminal_status = ""

    if use_task_mode:
        try:
            child_task = runtime_child_task_creator(
                run_request,
                parent_report_id=report_id,
                parent_stage_id=spec.stage_id,
                stage_id=spec.stage_id,
                purpose=str(spec.purpose or spec.stage_id),
                artifact_source=primary_artifact_name,
                stage_listener=coordinator.attach_external_runtime_event,
            )
        except Exception as exc:
            return _fallback(f"runtime_child_create_failed: {exc}")
        created_runtime_handle = dict(child_task)

        runtime_child_job_id = str(child_task.get("job_id") or "").strip()
        if not runtime_child_job_id:
            return _fallback("runtime_child_missing_job_id")

        latest = dict(child_task)
        deadline = time.time() + float(max(1, int(spec.timeout_sec or 180)))
        terminal = {"completed", "failed", "cancelled", "timed_out"}
        while time.time() < deadline:
            try:
                snapshot = get_codex_run_task(runtime_child_job_id)
            except Exception as exc:
                return _fallback(f"runtime_child_status_failed: {exc}")
            latest = dict(snapshot)
            if str(snapshot.get("status") or "").strip().lower() in terminal:
                break
            time.sleep(0.5)
        runtime_child_run_id = str(latest.get("run_id") or "")
    else:
        try:
            latest = dict(effective_direct_runner(run_request))
        except Exception as exc:
            return _fallback(f"runtime_run_failed: {exc}")
        runtime_child_run_id = str(latest.get("run_id") or "")
        created_runtime_handle = dict(latest)

    final_status = str(latest.get("status") or "").strip().lower()
    runtime_payload, artifact_error = _load_runtime_stage_artifact_payload(
        workspace_path=workspace_path,
        primary_artifact_name=primary_artifact_name,
        spec=spec,
    )
    if final_status != "completed":
        if runtime_payload is None:
            return _fallback(f"unsafe_runtime_output:{artifact_error or final_status or 'failed'}")
        salvaged_terminal_status = final_status or "failed"
        coordinator.record_stage(
            f"{event_prefix}_salvaged",
            f"接纳 {stage_label} runtime 晚到产物",
            f"{stage_label} 的 runtime 任务虽然处于 {salvaged_terminal_status}，但目标产物已完整落盘并通过校验，继续使用 runtime 结果。",
            payload={
                "status": "completed",
                "runtime_child_job_id": runtime_child_job_id,
                "runtime_terminal_status": salvaged_terminal_status,
                "unsafe_runtime_output": False,
            },
        )
    elif runtime_payload is None:
        return _fallback(f"unsafe_runtime_output:{artifact_error or 'runtime_output_missing'}")

    runtime_payload = normalize_runtime_telemetry_contract(
        dict(runtime_payload),
        default_artifact_source=str(spec.result_artifact_source or primary_artifact_name),
        parent_report_job_id=str(latest.get("parent_report_job_id") or created_runtime_handle.get("parent_report_job_id") or ""),
        parent_report_id=report_id,
        parent_stage_id=spec.stage_id,
        child_index=int(latest.get("child_index") or created_runtime_handle.get("child_index") or 0),
        stage_id=spec.stage_id,
        purpose=str(spec.purpose or spec.stage_id),
    )
    runtime_payload.setdefault("mode", "runtime_child")
    runtime_payload["live_available"] = True
    runtime_payload["runtime_child_job_id"] = runtime_child_job_id
    runtime_payload["runtime_child_run_id"] = runtime_child_run_id
    runtime_payload["unsafe_runtime_output"] = False
    if salvaged_terminal_status:
        runtime_payload["runtime_terminal_status"] = salvaged_terminal_status
        runtime_payload["degradation_state"] = f"{salvaged_terminal_status}_artifact_salvaged"
    coordinator.record_stage(
        f"{event_prefix}_applied",
        f"应用 {stage_label} runtime 结果",
        f"{stage_label} 已使用 runtime 结果回写。",
        payload={"status": "completed", "runtime_child_job_id": runtime_child_job_id, "unsafe_runtime_output": False},
    )
    return runtime_payload


def _semantic_layer_with_optional_runtime(
    *,
    report_dir: Path,
    report_id: str,
    dataset_id: str,
    sheet_name: str,
    request: SmartReportRequest,
    semantic_context: dict[str, Any],
    runtime_policy: dict[str, Any],
    runtime_child_task_creator: Callable[..., dict[str, Any]] | None,
    coordinator: ReportCoordinator,
) -> dict[str, Any]:
    return _execute_runtime_stage_with_fallback(
        spec=RuntimeStageSpec(
            stage_id="semantic_layer",
            runtime_allowed=True,
            prompt_builder=_semantic_stage_prompt_builder,
            workspace_path_builder=_report_dir_workspace_builder,
            expected_artifact_files=[SEMANTIC_RUNTIME_OUTPUT_FILENAME],
            fallback_runner=lambda stage_ctx: codex_semantic_analysis(stage_ctx["context_payload"]),
            timeout_sec=180,
            capture_git_diff=False,
            purpose="semantic_layer",
            runtime_policy_alias="semantic",
            result_artifact_source="semantic_layer_runtime_json",
            context_payload_builder=lambda stage_ctx: dict(stage_ctx["context_payload"]),
            artifact_validator=_semantic_layer_payload_compatible,
            artifact_normalizer=_normalize_semantic_layer_runtime_payload,
        ),
        stage_context={"report_dir": report_dir, "context_payload": semantic_context},
        report_id=report_id,
        dataset_id=dataset_id,
        sheet_name=sheet_name,
        request=request,
        runtime_policy=runtime_policy,
        runtime_child_task_creator=runtime_child_task_creator,
        coordinator=coordinator,
    )

    def _local_semantic_layer() -> dict[str, Any]:
        return codex_semantic_analysis(semantic_context)

    def _fallback(reason: str) -> dict[str, Any]:
        coordinator.record_stage(
            "semantic_layer_runtime_fallback",
            "semantic layer 回退到本地路径",
            f"semantic runtime 未成功应用，回退原因：{reason}",
            payload={"status": "completed", "fallback_reason": reason},
        )
        return _local_semantic_layer()

    if not _runtime_stage_enabled(
        "semantic",
        runtime_policy=runtime_policy,
        runtime_child_task_creator=runtime_child_task_creator,
    ):
        return _local_semantic_layer()

    report_dir.mkdir(parents=True, exist_ok=True)
    output_path = report_dir / SEMANTIC_RUNTIME_OUTPUT_FILENAME
    if output_path.exists():
        try:
            output_path.unlink()
        except Exception:
            pass

    prompt_template = (
        "You are Codex running the `semantic_layer` stage for Asteria Analyst.\n"
        "Use only the Context JSON below.\n"
        f"Write exactly one JSON file named `{SEMANTIC_RUNTIME_OUTPUT_FILENAME}` into the current workspace.\n"
        "Do not wrap JSON in markdown fences.\n"
        "The JSON file must contain these keys exactly:\n"
        "title, subject_type, creator_profile, content_domains, audience_profile, evidence_points, "
        "text_findings, numeric_findings, metric_cards, important_columns, recommended_actions.\n"
        "subject_type must be one of: social_account, customer_entity, product_entity, transaction_entity, document_entity, generic_subject.\n"
        "metric_cards must be an array of objects with keys: metric, role, business_meaning, management_impact, caution.\n"
        "All narrative content must be Simplified Chinese.\n"
        "If evidence is uncertain, describe it as likely rather than confirmed.\n"
        "After writing the JSON file, print a short completion note.\n\n"
        "Context JSON:\n{context_json}\n"
    )
    run_request = CodexRunRequest(
        workspace_path=str(report_dir.resolve()),
        prompt_template=prompt_template,
        user_requirement=request.user_requirement or request.problem_to_solve or request.core_purpose or "semantic layer runtime analysis",
        context_payload=semantic_context,
        report_id=report_id,
        dataset_id=dataset_id,
        sheet_name=sheet_name,
        stage_id="semantic_layer",
        purpose="semantic_layer",
        capture_git_diff=False,
    )
    coordinator.record_stage(
        "semantic_layer_runtime_start",
        "启动 semantic runtime 子任务",
        "正在为 semantic_layer 创建 Codex runtime 子任务。",
        payload={"status": "running"},
    )
    try:
        child_task = runtime_child_task_creator(
            run_request,
            parent_report_id=report_id,
            parent_stage_id="semantic_layer",
            stage_id="semantic_layer",
            purpose="semantic_layer",
            artifact_source=SEMANTIC_RUNTIME_OUTPUT_FILENAME,
            stage_listener=coordinator.attach_external_runtime_event,
        )
    except Exception as exc:
        return _fallback(f"runtime_child_create_failed: {exc}")

    child_job_id = str(child_task.get("job_id") or "").strip()
    if not child_job_id:
        return _fallback("runtime_child_missing_job_id")

    latest = dict(child_task)
    deadline = time.time() + 180.0
    terminal = {"completed", "failed", "cancelled", "timed_out"}
    while time.time() < deadline:
        try:
            snapshot = get_codex_run_task(child_job_id)
        except Exception as exc:
            return _fallback(f"runtime_child_status_failed: {exc}")
        latest = dict(snapshot)
        if str(snapshot.get("status") or "").strip().lower() in terminal:
            break
        time.sleep(0.5)

    final_status = str(latest.get("status") or "").strip().lower()
    if final_status != "completed":
        return _fallback(f"runtime_child_{final_status or 'failed'}")
    try:
        runtime_payload = load_runtime_json_artifact(report_dir, SEMANTIC_RUNTIME_OUTPUT_FILENAME)
    except FileNotFoundError:
        return _fallback("runtime_output_missing")
    except ValueError:
        return _fallback("runtime_output_invalid_json")
    if not _semantic_layer_payload_compatible(runtime_payload):
        return _fallback("runtime_output_incompatible")

    runtime_payload = dict(runtime_payload)
    runtime_payload.setdefault("mode", "runtime_child")
    runtime_payload["author_mode"] = "codex_cli_runtime"
    runtime_payload["runtime_state"] = "live"
    runtime_payload["degradation_state"] = "none"
    runtime_payload["artifact_source"] = "semantic_layer_runtime_json"
    runtime_payload["parent_report_job_id"] = str(child_task.get("parent_report_job_id") or "")
    runtime_payload["parent_report_id"] = report_id
    runtime_payload["parent_stage_id"] = str(child_task.get("parent_stage_id") or "semantic_layer")
    runtime_payload["child_index"] = int(child_task.get("child_index") or 0)
    runtime_payload["stage_id"] = "semantic_layer"
    runtime_payload["purpose"] = "semantic_layer"
    runtime_payload["live_available"] = True
    runtime_payload["runtime_child_job_id"] = child_job_id
    runtime_payload["runtime_child_run_id"] = str(latest.get("run_id") or "")
    coordinator.record_stage(
        "semantic_layer_runtime_applied",
        "应用 semantic runtime 结果",
        "semantic_layer 已使用 runtime 子任务结果回写。",
        payload={"status": "completed", "runtime_child_job_id": child_job_id},
    )
    return runtime_payload


