def _content_key(text: str) -> str:
    lowered = str(text or "").strip().lower()
    lowered = re.sub(r"`[^`]+`", "", lowered)
    lowered = re.sub(r"[\s\-\_\|\[\]\(\)\{\}\'\"，。；：、,.!?:]+", "", lowered)
    return lowered


def _looks_meta_or_process_text(text: str) -> bool:
    stripped = str(text or "").strip()
    if not stripped:
        return True
    if "n/a" in stripped.lower():
        return True
    if stripped.endswith("？") or stripped.endswith("?") or stripped.startswith("哪些"):
        return True
    if any(phrase in stripped for phrase in QUALITY_META_PHRASES):
        return True
    return False


def _has_result_signal(text: str) -> bool:
    stripped = str(text or "").strip()
    if not stripped:
        return False
    if re.search(r"\d", stripped):
        return True
    return any(token in stripped for token in SUMMARY_ACTION_TOKENS)


def _summary_priority_score(text: str) -> tuple[int, int, int]:
    stripped = str(text or "").strip()
    action_score = sum(token in stripped for token in SUMMARY_ACTION_TOKENS)
    digit_score = len(re.findall(r"\d", stripped))
    id_penalty = 1 if _is_id_like(stripped) else 0
    return (-action_score, -digit_score, id_penalty)


def _table_result_candidates(section: dict[str, Any]) -> list[str]:
    candidates: list[str] = []
    for table in section.get("tables", []) or []:
        rows = table.get("rows") or []
        if not rows:
            continue
        row = rows[0]
        if isinstance(row, dict):
            if "类别" in row and "占比" in row:
                candidates.append(f"`{row['类别']}` 当前占比约 {row['占比']}，应优先作为头部对象复盘。")
            elif "经营切片" in row and "收入占比" in row:
                candidates.append(f"`{row['经营切片']}` 当前收入占比约 {row['收入占比']}，应优先排查其资源与责任归属。")
            elif "风险类型" in row and "对象" in row and "说明" in row:
                candidates.append(f"当前首要风险是 `{row['对象']}`，因为 {row['说明']}。")
            elif "优先级" in row and "动作" in row:
                candidates.append(f"{row['优先级']}：{row['动作']}")
            elif "对象" in row and "经营判断" in row:
                tail = row.get("销售额占比") or row.get("订单覆盖") or row.get("客户覆盖") or ""
                tail_text = f"，核心量化锚点 {tail}" if tail else ""
                candidates.append(f"`{row['对象']}` 当前经营判断为 `{row['经营判断']}`{tail_text}。")
            elif "segment" in row and ("占比" in row or "share" in row):
                share = row.get("占比") or row.get("share")
                candidates.append(f"`{row['segment']}` 当前占比约 {share}，应优先作为头部对象复盘。")
    return candidates


def _prune_report_for_quality(report: dict[str, Any]) -> None:
    report_lens = str(report.get("report_lens") or "")
    suppressed_ids = set(QUALITY_SUPPRESSED_SECTION_IDS)
    suppressed_ids.update(QUALITY_SUPPRESSED_SECTION_IDS_BY_LENS.get(report_lens, set()))
    seen: set[str] = set()
    pruned_sections: list[dict[str, Any]] = []
    for raw_section in report.get("sections", []):
        section = dict(raw_section)
        section_id = str(section.get("id") or "")
        if section_id in suppressed_ids:
            continue

        summary = str(section.get("summary") or "").strip()
        summary_key = _content_key(summary)
        keep_summary = bool(summary and not _looks_meta_or_process_text(summary))

        bullets: list[str] = []
        local_seen = {summary_key} if keep_summary and summary_key else set()
        for item in section.get("bullets", []) or []:
            for text in _flatten_text_items(item):
                key = _content_key(text)
                if not key or key in local_seen or key in seen:
                    continue
                if _looks_meta_or_process_text(text):
                    continue
                local_seen.add(key)
                bullets.append(text)

        if report_lens == "procurement_sales_review" and section_id in {"business_judgement", "risk_pool"}:
            bullets = [text for text in bullets if re.search(r"\d", str(text or ""))]

        tables = section.get("tables", []) or []
        charts = section.get("charts", []) or []
        if not keep_summary:
            summary = ""

        if not summary and not bullets and not tables and not charts:
            continue

        if summary_key and keep_summary:
            seen.add(summary_key)
        for item in bullets:
            seen.add(_content_key(item))

        section["summary"] = summary
        section["bullets"] = bullets[:8]
        pruned_sections.append(section)

    report["sections"] = pruned_sections

    cleaned_summary: list[str] = []
    summary_seen: set[str] = set()
    for item in report.get("executive_summary", []) or []:
        for text in _flatten_text_items(item):
            key = _content_key(text)
            if not key or key in summary_seen:
                continue
            if _looks_meta_or_process_text(text):
                continue
            if not _has_result_signal(text):
                continue
            summary_seen.add(key)
            cleaned_summary.append(text)
    priority_by_lens = {
        "sales_review": ["business_judgement", "sales_gmv_decomposition", "commercial_dimension_judgement", "sales_product_impact", "sales_sku_impact", "sales_supplier_impact", "sales_service_loop", "action_roadmap", "risk_pool"],
        "media_review": ["business_judgement", "action_matrix", "opportunity_pool", "risk_pool", "action_roadmap"],
        "internet_ops_review": ["business_judgement", "ops_channel_impact", "ops_activity_impact", "ops_content_impact", "ops_combo_impact", "action_roadmap"],
        "management_accounting_review": ["decision_summary", "business_judgement", "procurement_sales_linkage", "sales_gmv_decomposition", "commercial_dimension_judgement", "sales_product_impact", "sales_sku_impact", "sales_supplier_impact", "sales_service_loop", "business_linkage", "management_accounting_budget", "management_accounting_profitability", "category", "temporal", "risk_pool", "action_roadmap", "management_accounting_playbook"],
        "procurement_sales_review": ["procurement_sales_action_chain", "sales_category_impact", "sales_product_impact", "sales_sku_impact", "sales_supplier_impact", "sales_service_loop", "sales_gmv_decomposition", "business_judgement", "risk_pool"],
        "foundation_review": ["business_judgement", "foundation_priority_review", "foundation_top_projects", "action_roadmap", "risk_pool"],
    }
    preferred_summary: list[str] = []
    preferred_seen: set[str] = set()
    section_lookup = {str(section.get("id") or ""): section for section in report["sections"]}
    for section_id in priority_by_lens.get(report_lens, []):
        section = section_lookup.get(section_id)
        if not section:
            continue
        candidates = [section.get("summary"), *(section.get("bullets") or [])]
        candidates = sorted(candidates, key=lambda item: _summary_priority_score(str(item or "")))
        for candidate in candidates:
            for text in _flatten_text_items(candidate):
                key = _content_key(text)
                if not key or key in preferred_seen or _looks_meta_or_process_text(text):
                    continue
                if not _has_result_signal(text):
                    continue
                preferred_seen.add(key)
                preferred_summary.append(text)
                if len(preferred_summary) >= 6:
                    break
            if len(preferred_summary) >= 6:
                break
        if len(preferred_summary) >= 6:
            break
    if preferred_summary:
        merged_summary = preferred_summary + [item for item in cleaned_summary if _content_key(item) not in preferred_seen]
        cleaned_summary = merged_summary[:6]
    if len(cleaned_summary) < 3:
        for section in report["sections"]:
            for candidate in [section.get("summary"), *(section.get("bullets") or [])]:
                for text in _flatten_text_items(candidate):
                    key = _content_key(text)
                    if not key or key in summary_seen or _looks_meta_or_process_text(text):
                        continue
                    if not _has_result_signal(text):
                        continue
                    summary_seen.add(key)
                    cleaned_summary.append(text)
                    if len(cleaned_summary) >= 3:
                        break
                if len(cleaned_summary) >= 3:
                    break
            if len(cleaned_summary) >= 3:
                break
    if len(cleaned_summary) < 3:
        for section in report["sections"]:
            for text in _table_result_candidates(section):
                key = _content_key(text)
                if not key or key in summary_seen or _looks_meta_or_process_text(text):
                    continue
                summary_seen.add(key)
                cleaned_summary.append(text)
                if len(cleaned_summary) >= 3:
                    break
            if len(cleaned_summary) >= 3:
                break
    if len(cleaned_summary) < 3:
        rows_value = next((item.get("value") for item in report.get("key_metrics", []) if str(item.get("label")) == "Rows"), None)
        cols_value = next((item.get("value") for item in report.get("key_metrics", []) if str(item.get("label")) == "Columns"), None)
        if rows_value is not None and cols_value is not None:
            text = f"当前样本规模约 {rows_value} 条记录、{cols_value} 个字段，结论必须围绕头部对象、异常对象和可执行动作来收束。"
            key = _content_key(text)
            if key not in summary_seen:
                summary_seen.add(key)
                cleaned_summary.append(text)
    report["executive_summary"] = _dedupe_preserve_order(cleaned_summary)[:6]


