def _localize_table_column_name(column: str) -> str:
    text = str(column).strip()
    if not text:
        return text
    if _contains_cjk(text):
        return text

    lowered = text.lower()
    if lowered in TABLE_COLUMN_TRANSLATIONS:
        return TABLE_COLUMN_TRANSLATIONS[lowered]

    normalized = re.sub(r"([a-z0-9])([A-Z])", r"\1_\2", text)
    normalized = normalized.replace("-", "_").replace(" ", "_").lower()
    if normalized in TABLE_COLUMN_TRANSLATIONS:
        return TABLE_COLUMN_TRANSLATIONS[normalized]

    parts = [part for part in normalized.split("_") if part]
    translated_parts = [TABLE_COLUMN_TOKEN_TRANSLATIONS.get(part, part.upper() if part.isupper() else part) for part in parts]
    candidate = "".join(translated_parts).strip()
    return candidate if _contains_cjk(candidate) else text


def _localize_table_title(title: str) -> str:
    text = str(title or "").strip()
    if not text or _contains_cjk(text):
        return text
    exact = TABLE_TITLE_TRANSLATIONS.get(text)
    if exact:
        return exact
    lowered = text.lower()
    for source, translated in TABLE_TITLE_TRANSLATIONS.items():
        if lowered == source.lower():
            return translated
    return text


def _table_caption_text(title: str, original_columns: list[str], localized_columns: list[str], rows: list[dict[str, Any]]) -> str:
    parts: list[str] = []
    title_text = str(title or "").strip()
    localized_title = _localize_table_title(title_text)
    if localized_title in TABLE_TITLE_CAPTIONS:
        parts.append(TABLE_TITLE_CAPTIONS[localized_title])

    seen_terms: set[str] = set()
    explain_parts: list[str] = []

    def collect_term(term: Any) -> None:
        text = str(term or "").strip()
        if not text or text in seen_terms:
            return
        explanation = TABLE_CAPTION_EXPLANATIONS.get(text)
        if not explanation:
            explanation = TABLE_CAPTION_EXPLANATIONS.get(_localize_table_column_name(text))
        if not explanation:
            explanation = TABLE_CAPTION_EXPLANATIONS.get(text.replace(" ", ""))
        if explanation:
            seen_terms.add(text)
            explain_parts.append(f"`{text}`={explanation}")

    for column in original_columns:
        collect_term(column)
    for column in localized_columns:
        collect_term(column)

    value_keys = ["字段", "核心结果变量", "指标", "项", "方法", "状态值", "对象"]
    for row in rows[:12]:
        for key in value_keys:
            if key in row:
                collect_term(row.get(key))

    if explain_parts:
        parts.append("字段说明：" + "；".join(explain_parts[:8]) + "。")

    if not parts:
        return ""
    return "图注：" + " ".join(parts).strip()


def _normalize_table_cell_text(value: Any) -> str:
    text = str(value or "").replace("\r\n", "\n").replace("\r", "\n")
    text = re.sub(r"\s+", " ", text).strip().lower()
    return text


def _dedupe_table_rows(columns: list[str], rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
    seen: set[tuple[str, ...]] = set()
    deduped: list[dict[str, Any]] = []
    for row in rows:
        normalized_row = {str(key): _safe_value(value) for key, value in row.items()}
        signature = tuple(
            _normalize_table_cell_text(_display_table_value(column, normalized_row.get(column, "")))
            for column in columns
        )
        if not any(signature):
            continue
        if signature in seen:
            continue
        seen.add(signature)
        deduped.append(normalized_row)
    return deduped


def _resolved_multi_sheet_names(metadata: dict[str, Any], request: SmartReportRequest) -> list[str]:
    available = [str(item["name"]) for item in metadata.get("sheets", [])]
    selected = [name for name in request.selected_sheets if name in available]
    if selected:
        return selected
    if request.sheet_name and request.sheet_name in available:
        return [request.sheet_name]
    if metadata.get("active_sheet") in available:
        return [str(metadata["active_sheet"])]
    return available[:1]


def _selected_sheet_frames(
    dataset_id: str,
    metadata: dict[str, Any],
    selected_sheet_names: list[str],
) -> list[tuple[dict[str, Any], pd.DataFrame]]:
    _, all_frames = load_all_sheet_frames(dataset_id)
    selected_set = set(selected_sheet_names)
    return [(sheet, frame.copy()) for sheet, frame in all_frames if str(sheet["name"]) in selected_set]


def _merge_multi_sheet_frames(
    metadata: dict[str, Any],
    sheet_frames: list[tuple[dict[str, Any], pd.DataFrame]],
) -> tuple[pd.DataFrame, dict[str, Any]]:
    merged_parts: list[pd.DataFrame] = []
    for sheet, frame in sheet_frames:
        working = frame.copy()
        working["来源工作表"] = str(sheet["name"])
        merged_parts.append(working)
    merged = pd.concat(merged_parts, ignore_index=True, sort=False) if merged_parts else pd.DataFrame()
    synthetic_sheet = {
        "name": f"合并分析({'+'.join(str(sheet['name']) for sheet, _ in sheet_frames)})",
        "storage_file": "",
        "rows": int(len(merged)),
        "columns": int(len(merged.columns)),
    }
    synthetic_metadata = dict(metadata)
    synthetic_metadata["active_sheet"] = synthetic_sheet["name"]
    return merged, synthetic_sheet


def _multi_table_overview_rows(
    selected_sheet_names: list[str],
    sheet_frames: list[tuple[dict[str, Any], pd.DataFrame]],
    blueprint: dict[str, Any],
) -> list[dict[str, Any]]:
    profiles = {item["name"]: item for item in blueprint.get("sheet_profiles", [])}
    rows: list[dict[str, Any]] = []
    for sheet, frame in sheet_frames:
        profile = profiles.get(str(sheet["name"]), {})
        rows.append(
            {
                "工作表": str(sheet["name"]),
                "行数": int(len(frame)),
                "列数": int(len(frame.columns)),
                "推断角色": profile.get("role", "analytical_fact"),
                "主键候选数": len(profile.get("candidate_keys", [])),
                "缺失率": profile.get("overall_missing_ratio", 0.0),
            }
        )
    return rows


def _multi_table_relationship_rows(
    selected_sheet_names: list[str],
    blueprint: dict[str, Any],
) -> list[dict[str, Any]]:
    selected = set(selected_sheet_names)
    rows: list[dict[str, Any]] = []
    for item in blueprint.get("relationships", []):
        if item.get("left_sheet") in selected and item.get("right_sheet") in selected:
            rows.append(
                {
                    "左表": item["left_sheet"],
                    "左字段": item["left_column"],
                    "右表": item["right_sheet"],
                    "右字段": item["right_column"],
                    "关系类型": item["relationship_type"],
                    "重合度": item["overlap_ratio"],
                    "置信度": item["confidence_score"],
                }
            )
    return rows[:10]


