def _is_id_like(column_name: str) -> bool:
    lower = column_name.lower()
    return (
        lower == "id"
        or lower.endswith("_id")
        or lower.endswith("id")
        or lower.endswith("no")
        or lower.endswith("number")
        or "reference" in lower
        or "ref" in lower
        or "contract" in lower and "value" not in lower and "amount" not in lower
        or "supplier" in lower and "name" not in lower and "spend" not in lower
        or "code" in lower
        or "invoice" in lower
        or "stockcode" in lower
        or "stock_code" in lower
        or "customerid" in lower
        or "tweet_id" in lower
        or "user_id" in lower
        or "order_id" in lower
        or "account_id" in lower
    )


def _binary_columns(frame: pd.DataFrame) -> list[str]:
    columns: list[str] = []
    for column in frame.columns.astype(str).tolist():
        if frame[column].dropna().nunique() == 2 and not _is_id_like(column):
            columns.append(column)
    return columns


def _date_like_columns(frame: pd.DataFrame) -> list[str]:
    detected = set(datetime_columns(frame))
    for column in frame.columns.astype(str).tolist():
        if column in detected:
            continue
        if pd.api.types.is_numeric_dtype(frame[column]):
            continue
        lower = column.lower()
        if not any(token in lower for token in ["date", "time", "month", "year", "day"]):
            continue
        sample = frame[column].dropna().head(800)
        if sample.empty:
            continue
        parsed = pd.to_datetime(sample, errors="coerce", dayfirst=True)
        if parsed.notna().mean() >= 0.8:
            detected.add(column)
    return list(detected)


def _parse_compact_number(value: Any) -> float | None:
    if value is None or (isinstance(value, float) and np.isnan(value)):
        return None
    text = str(value).strip().replace(",", "")
    if not text:
        return None
    if text.endswith("%"):
        text = text[:-1]
    multiplier = 1.0
    if text.endswith("K"):
        multiplier = 1_000.0
        text = text[:-1]
    elif text.endswith("M"):
        multiplier = 1_000_000.0
        text = text[:-1]
    elif text.endswith("B"):
        multiplier = 1_000_000_000.0
        text = text[:-1]
    try:
        return float(text) * multiplier
    except ValueError:
        return None


def _numeric_like_object_columns(frame: pd.DataFrame) -> dict[str, list[float]]:
    candidates: dict[str, list[float]] = {}
    for column in frame.columns.astype(str).tolist():
        if _is_id_like(column):
            continue
        series = frame[column]
        if pd.api.types.is_numeric_dtype(series):
            continue
        sample = series.dropna().head(1000)
        if sample.empty:
            continue
        parsed = [_parse_compact_number(value) for value in sample]
        usable = [value for value in parsed if value is not None]
        if usable and len(usable) / len(sample) >= 0.8:
            candidates[column] = usable
    return candidates


def _text_candidate_columns(frame: pd.DataFrame) -> list[str]:
    candidates: list[tuple[int, float, str]] = []
    for column in frame.columns.astype(str).tolist():
        if _is_id_like(column):
            continue
        series = frame[column]
        if pd.api.types.is_numeric_dtype(series):
            continue
        sample = series.dropna().astype(str).head(200)
        if sample.empty:
            continue
        avg_length = sample.map(len).mean()
        unique_ratio = sample.nunique() / max(len(sample), 1)
        lower = column.lower()
        priority = 0
        if any(token in lower for token in ["text", "content", "body", "post", "caption", "message", "comment", "title", "description"]):
            priority += 4
        if any(token in lower for token in ["url", "link", "date", "time", "raw"]):
            priority -= 3
        if avg_length >= 24:
            priority += 2
        if unique_ratio >= 0.6:
            priority += 1
        if priority > 0:
            candidates.append((priority, avg_length, column))
    candidates.sort(key=lambda item: (-item[0], -item[1], item[2]))
    return [column for _, _, column in candidates[:3]]


def _top_missing_columns(frame: pd.DataFrame, limit: int = 5) -> list[dict[str, Any]]:
    if len(frame.columns) == 0:
        return []
    ratios = frame.isna().mean().sort_values(ascending=False).head(limit)
    return [
        {
            "column": column,
            "missing_ratio": round(float(ratio), 4),
        }
        for column, ratio in ratios.items()
        if ratio > 0
    ]


def _outlier_table(frame: pd.DataFrame, numeric_cols: list[str], limit: int = 5) -> list[dict[str, Any]]:
    rows: list[dict[str, Any]] = []
    for column in _dedupe_preserve_order(numeric_cols)[:limit]:
        series = pd.to_numeric(frame[column], errors="coerce").dropna()
        if len(series) < 10 or series.nunique() <= 1:
            continue
        q1 = float(series.quantile(0.25))
        q3 = float(series.quantile(0.75))
        iqr = q3 - q1
        if iqr == 0:
            outlier_ratio = 0.0
        else:
            mask = (series < (q1 - 1.5 * iqr)) | (series > (q3 + 1.5 * iqr))
            outlier_ratio = float(mask.mean())
        rows.append(
            {
                "column": column,
                "mean": round(float(series.mean()), 4),
                "median": round(float(series.median()), 4),
                "std": round(float(series.std()), 4),
                "outlier_ratio": round(outlier_ratio, 4),
            }
        )
    return rows


def _correlation_rows(frame: pd.DataFrame, numeric_cols: list[str], limit: int = 6) -> list[dict[str, Any]]:
    numeric_cols = _dedupe_preserve_order(numeric_cols)
    if len(numeric_cols) < 2:
        return []
    items: list[dict[str, Any]] = []
    for left_index, left in enumerate(numeric_cols[:8]):
        for right in numeric_cols[left_index + 1 : 8]:
            payload = _pearson_significance_payload(frame[left], frame[right])
            if not payload:
                continue
            items.append(
                {
                    "left": str(left),
                    "right": str(right),
                    **payload,
                }
            )
    items = _add_bh_q_values(items)
    items.sort(key=lambda row: row["abs_correlation"], reverse=True)
    return items[:limit]


def _statistical_numeric_columns(frame: pd.DataFrame, numeric_cols: list[str], temporal_cols: list[str]) -> list[str]:
    time_like_tokens = ["年度", "年份", "日期", "时间", "month", "year", "date", "time"]
    metric_tokens = ["收入", "支出", "捐赠", "公益", "次数", "占比", "率", "金额", "income", "spend", "revenue", "cost", "donation", "roi"]
    filtered: list[str] = []
    temporal_set = set(temporal_cols)
    for column in numeric_cols:
        if column in temporal_set or _is_id_like(column):
            continue
        lower = str(column).lower()
        if any(token in str(column) or token in lower for token in time_like_tokens) and not any(token in str(column) or token in lower for token in metric_tokens):
            continue
        series = pd.to_numeric(frame[column], errors="coerce").dropna()
        if len(series) < 3 or series.nunique() <= 1:
            continue
        std = float(series.std(ddof=0)) if len(series) > 1 else 0.0
        if not np.isfinite(std) or std == 0.0:
            continue
        filtered.append(column)
    return filtered


def _category_mix_rows(frame: pd.DataFrame, column: str, limit: int | None = None) -> list[dict[str, Any]]:
    counts = frame[column].fillna("Missing").astype(str).value_counts()
    total = max(int(counts.sum()), 1)
    if limit is not None:
        counts = counts.head(limit)
    return [
        {
            "category": str(label),
            "count": int(count),
            "share": round(int(count) / total, 4),
        }
        for label, count in counts.items()
    ]


def _preferred_category_column(categorical_cols: list[str], report_lens: str) -> str | None:
    if not categorical_cols:
        return None
    lowered = {column: str(column).lower() for column in categorical_cols}
    if report_lens == "procurement_sales_review":
        priority_groups = [
            ["category", "类目", "品类"],
            ["sellerstate", "seller state", "卖家省份", "卖家地区"],
            ["orderstatus", "order status", "订单状态"],
        ]
    elif report_lens == "sales_review":
        priority_groups = [
            ["category", "类目", "品类"],
            ["brand", "品牌"],
            ["channel", "渠道"],
            ["orderstatus", "order status", "订单状态"],
        ]
    else:
        priority_groups = []
    for group in priority_groups:
        for column, lowered_name in lowered.items():
            if any(token in lowered_name for token in group):
                return column
    return categorical_cols[0]


def _candidate_category_columns(
    frame: pd.DataFrame,
    categorical_cols: list[str],
    report_lens: str,
    *,
    limit: int = 4,
) -> list[str]:
    if not categorical_cols:
        return []
    priority_groups: list[list[str]]
    if report_lens == "procurement_sales_review":
        priority_groups = [
            ["category", "品类", "类目"],
            ["product", "商品"],
            ["sku", "规格", "货号"],
            ["supplier", "seller", "vendor", "供应商", "卖家"],
            ["responsibility", "department", "center", "责任", "部门", "中心"],
            ["orderstatus", "订单状态", "status"],
            ["brand", "品牌"],
            ["channel", "渠道"],
        ]
    elif report_lens == "sales_review":
        priority_groups = [
            ["category", "品类", "类目"],
            ["product", "商品"],
            ["sku", "规格", "货号"],
            ["brand", "品牌"],
            ["channel", "渠道"],
            ["region", "地区", "区域"],
            ["orderstatus", "订单状态", "status"],
        ]
    else:
        priority_groups = [
            ["category", "group", "segment", "channel", "region", "department", "brand", "类", "组", "渠道", "区域", "部门", "品牌"],
        ]
    scored: list[tuple[float, str]] = []
    for column in categorical_cols:
        if _is_id_like(column):
            continue
        series = frame[column].dropna().astype(str)
        unique_count = int(series.nunique())
        if unique_count < 2:
            continue
        lowered = str(column).lower()
        score = 0.0
        for idx, group in enumerate(priority_groups):
            if any(token in lowered for token in group):
                score += 100 - idx * 10
                break
        if unique_count <= 12:
            score += 12
        elif unique_count <= 30:
            score += 7
        elif unique_count <= 60:
            score += 3
        else:
            score -= 6
        coverage = float(series.notna().mean()) if not series.empty else 0.0
        score += coverage
        scored.append((score, column))
    scored.sort(key=lambda item: (-item[0], item[1]))
    return [column for _, column in scored[:limit]]


def _preferred_temporal_column(temporal_cols: list[str], *, report_lens: str) -> str | None:
    if not temporal_cols:
        return None
    lowered = {column: str(column).lower() for column in temporal_cols}
    if report_lens == "procurement_sales_review":
        priority_groups = [
            ["orderpurchase", "purchase", "下单"],
            ["deliveredcustomer", "delivered", "签收", "送达"],
            ["estimateddelivery", "estimated", "预计"],
        ]
    elif report_lens == "sales_review":
        priority_groups = [
            ["orderpurchase", "purchase", "下单"],
            ["date"],
            ["deliveredcustomer", "delivered"],
            ["estimateddelivery", "estimated"],
        ]
    else:
        priority_groups = []
    for group in priority_groups:
        for column, lowered_name in lowered.items():
            if any(token in lowered_name for token in group):
                return column
    return temporal_cols[0]


def _candidate_temporal_value_columns(
    stat_numeric_cols: list[str],
    metric_interpretation_layer: dict[str, Any],
    *,
    exclude_column: str | None = None,
    limit: int = 4,
) -> list[str]:
    ranked: list[str] = []
    exclude = str(exclude_column or "")
    for card in metric_interpretation_layer.get("metric_cards", []) or []:
        metric = str(card.get("metric") or "").strip()
        if metric and metric in stat_numeric_cols and metric != exclude and metric not in ranked:
            ranked.append(metric)
    priority_tokens = [
        "revenue",
        "gmv",
        "quantity",
        "grossprofit",
        "profit",
        "cost",
        "budget",
        "actual",
        "inventory",
        "roi",
        "sales",
        "销售额",
        "销量",
        "毛利",
        "成本",
        "预算",
        "实际",
        "库存",
    ]
    remaining = []
    for column in stat_numeric_cols:
        if column == exclude or column in ranked:
            continue
        lowered = str(column).lower()
        token_score = sum(1 for token in priority_tokens if token in lowered)
        remaining.append((token_score, column))
    remaining.sort(key=lambda item: (-item[0], item[1]))
    ranked.extend(column for _, column in remaining)
    return ranked[:limit]


def _metric_contract_explanation(
    field_name: str,
    *,
    role: str,
    report_lens: str,
    snapshot_lookup: dict[str, dict[str, Any]],
    formula_text: str,
) -> dict[str, str]:
    snapshot = snapshot_lookup.get(field_name, {})
    total_text = snapshot.get("总量", "")
    mean_text = snapshot.get("均值", "")
    median_text = snapshot.get("中位数", "")
    usage = f"当前主要用它承接 `{role}` 判断，已经不是泛化展示字段。"
    meaning = f"它当前回答的是 `{field_name}` 在这份报告里到底服务哪类经营动作。"
    lower = str(field_name).lower()
    if report_lens == "procurement_sales_review":
        revenue_total_text = str((snapshot_lookup.get("Revenue") or {}).get("总量") or "")
        gmv_total_text = str((snapshot_lookup.get("GMV") or {}).get("总量") or "")
        if lower == "revenue":
            usage = f"当前用它判断品类、商品、SKU、供应商到底做出了多少真实成交盘子。当前累计 {total_text}、均值 {mean_text}，是主推、修复、降权和清理排序的第一结果变量。"
            meaning = "它回答的是卖出去多少钱。采销正文里凡是要决定主推对象、核心合作对象和异常放量对象，第一口径都应先看 Revenue。"
        elif lower == "gmv":
            usage = f"当前用它判断成交总盘子和订单承接强度。当前累计 {total_text}、中位数 {median_text}，会和 Revenue {revenue_total_text or 'n/a'} 一起看是结构放量，还是少数高客单订单把总盘子抬高。"
            meaning = "它回答的是订单层总成交规模。适合和 Revenue 对照，判断当前是结果真实放大，还是只是订单金额结构更重。"
        elif lower == "quantity":
            usage = f"当前用它判断动销件数和走量能力。当前总量 {total_text}、均值 {mean_text}、中位数 {median_text}。如果均值和中位数都接近 1，就说明这份数据更像单件订单盘子，不应再把 Quantity 误写成走量爆发。"
            meaning = "它回答的是卖了多少件。适合和订单覆盖、客户覆盖、复购客户占比一起判断是靠件数走量，还是靠高客单对象撑结果。"
        elif lower == "freightcost":
            usage = f"当前用它判断履约成本压力。当前累计 {total_text}、均值 {mean_text}，会和 GMV {gmv_total_text or 'n/a'}、订单覆盖和客户覆盖一起识别高履约占压对象。"
            meaning = "它回答的是每笔成交背后的履约成本代理。采销里它主要服务两个问题：哪些对象运费侵蚀成交效率，哪些对象不值得继续放量。"
        elif lower == "roi":
            usage = f"当前用它近似比较成交回款与履约成本的比值，口径是 `{formula_text}`。这不是利润率，但能快速给出‘同样成交下谁更值得继续给资源’。"
            meaning = "它回答的是结果和成本代理之间的相对效率。适合在对象级排序里区分‘能放量的对象’和‘越放量越吃成本的对象’，不适合直接当净利润结论。"
    if not usage.strip():
        usage = f"当前主要用它承接 `{role}` 判断。"
    if not meaning.strip():
        meaning = f"它当前回答的是 `{field_name}` 在这份报告里的业务用途。"
    return {"usage": usage, "meaning": meaning}


def _category_business_rows(column_name: str, category_rows: list[dict[str, Any]], *, report_lens: str) -> list[dict[str, Any]]:
    lower = str(column_name).lower()
    if "orderstatus" not in lower and "订单状态" not in lower:
        rows: list[dict[str, Any]] = []
        for index, row in enumerate(category_rows, start=1):
            label = _prettify_slug_label(str(row.get("category") or ""))
            share = float(row.get("share") or 0.0)
            if index == 1:
                meaning = "当前头部结构对象，通常决定复盘应先从哪个品类切入。"
            elif share >= 0.1:
                meaning = "当前属于次头部结构，通常决定资源是否需要继续集中。"
            elif share >= 0.03:
                meaning = "当前属于腰部结构，适合继续看它是承接型还是观察型对象。"
            else:
                meaning = "当前属于长尾结构，更适合放到观察池或清理复核池里看。"
            rows.append(
                {
                    "类别": label,
                    "数量": row.get("count"),
                    "占比": _format_percent(row.get("share")),
                    "业务含义": meaning,
                }
            )
        return rows
    meaning_map = {
        "delivered": ("已签收完成", "订单已完成交付，是当前真正形成成交闭环的状态。"),
        "shipped": ("已发货待签收", "货已发出但尚未完成签收，后续要继续看履约时效和异常签收。"),
        "canceled": ("已取消", "订单在成交闭环前终止，通常要复核商品承接、用户流失或取消原因。"),
        "invoiced": ("已开票待流转", "订单已进入财务/出单环节，但还未完成发货签收。"),
        "processing": ("处理中", "订单仍在系统或仓配处理中，需继续观察是否转成发货或取消。"),
        "unavailable": ("缺货/不可履约", "订单因缺货或异常无法继续履约，通常是重点排查对象。"),
        "approved": ("已审核待发货", "订单已确认，但履约动作尚未真正开始。"),
        "created": ("已创建待确认", "订单刚建立，还未进入稳定履约阶段。"),
    }
    rows: list[dict[str, Any]] = []
    for row in category_rows:
        status = str(row.get("category") or "")
        chinese, meaning = meaning_map.get(status.lower(), (status, "该状态需要结合订单链路进一步解释。"))
        implication = "当前经营含义偏中性。"
        if status.lower() == "delivered" and report_lens == "procurement_sales_review":
            implication = "这说明当前大多数订单已经完成履约，经营关注点应转向签收后的复购和售后。"
        elif status.lower() in {"shipped", "processing", "approved"}:
            implication = "这说明当前仍有在途或处理中订单，后续要继续看是否积压或延迟。"
        elif status.lower() in {"canceled", "unavailable"}:
            implication = "这说明当前存在损失成交的状态，后续应优先排查取消或缺货原因。"
        rows.append(
            {
                "状态值": status,
                "中文含义": chinese,
                "数量": row.get("count"),
                "占比": _format_percent(row.get("share")),
                "业务解释": implication if implication else meaning,
            }
        )
    return rows


def _bar_chart(title: str, rows: list[dict[str, Any]], x_key: str, y_key: str) -> dict[str, Any] | None:
    if not rows:
        return None
    return {
        "kind": "bar",
        "title": title,
        "x": [str(row[x_key]) for row in rows],
        "y": [float(row[y_key]) for row in rows],
    }


def _heatmap_chart(title: str, frame: pd.DataFrame, columns: list[str]) -> dict[str, Any] | None:
    columns = _dedupe_preserve_order(columns)
    if len(columns) < 2:
        return None
    corr = frame[columns[:8]].apply(pd.to_numeric, errors="coerce").corr().round(4)
    return {
        "kind": "heatmap",
        "title": title,
        "labels": corr.columns.astype(str).tolist(),
        "matrix": corr.to_numpy().tolist(),
    }


def _chart_explanation_lines(chart: dict[str, Any]) -> list[str]:
    kind = str(chart.get("kind") or "").strip().lower()
    if kind == "bar":
        x_values = [str(item) for item in (chart.get("x") or [])]
        y_values = [float(item) for item in (chart.get("y") or [])]
        if not x_values or not y_values or len(x_values) != len(y_values):
            return []
        order = sorted(zip(x_values, y_values), key=lambda item: item[1], reverse=True)
        total = sum(value for _, value in order if pd.notna(value))
        top_label, top_value = order[0]
        notes = [f"头部对象是 `{top_label}`，当前值 {top_value:,.2f}。"]
        if len(order) > 1:
            second_label, second_value = order[1]
            notes.append(f"第二名是 `{second_label}`，当前值 {second_value:,.2f}，与头部差值 {(top_value - second_value):,.2f}。")
        if total > 0:
            notes.append(f"头部对象占当前图内总量约 {top_value / total:.1%}。")
        if len(order) <= 2:
            notes.append("当前可比较对象较少，这张图更适合看是否均衡分布，不适合强行放大头部效应。")
        return notes[:4]
    if kind == "heatmap":
        labels = [str(item) for item in (chart.get("labels") or [])]
        matrix = chart.get("matrix") or []
        if len(labels) < 2 or not matrix:
            return []
        pairs: list[tuple[str, str, float]] = []
        for i in range(min(len(labels), len(matrix))):
            row = matrix[i] or []
            for j in range(i + 1, min(len(labels), len(row))):
                value = row[j]
                try:
                    corr = float(value)
                except Exception:
                    continue
                pairs.append((labels[i], labels[j], corr))
        pairs.sort(key=lambda item: abs(item[2]), reverse=True)
        notes: list[str] = []
        for left, right, corr in pairs[:3]:
            direction = "同向联动" if corr >= 0 else "反向联动"
            notes.append(f"`{left}` 与 `{right}` 的相关系数 {corr:.3f}，属于{direction}。")
        return notes[:4]
    return []


def _render_chart_png(report_dir: Path, report_id: str, section_id: str, chart_index: int, chart: dict[str, Any]) -> dict[str, Any] | None:
    try:
        import matplotlib
        matplotlib.use("Agg")
        import matplotlib.pyplot as plt
        from matplotlib import font_manager
        import numpy as np
    except Exception:
        return None

    font_path = _pdf_font_path()
    if font_path:
        try:
            font_manager.fontManager.addfont(font_path)
            font_name = font_manager.FontProperties(fname=font_path).get_name()
            plt.rcParams["font.family"] = font_name
            plt.rcParams["axes.unicode_minus"] = False
        except Exception:
            pass

    kind = str(chart.get("kind") or "").strip().lower()
    asset_name = f"{report_id}-{section_id}-chart-{chart_index + 1}.png"
    asset_path = report_dir / asset_name
    title = str(chart.get("title") or f"{section_id} chart {chart_index + 1}")

    try:
        if kind == "bar":
            x_values = [str(item) for item in (chart.get("x") or [])]
            y_values = [float(item) for item in (chart.get("y") or [])]
            if not x_values or not y_values or len(x_values) != len(y_values):
                return None
            height = max(4.8, min(12.0, 1.0 + 0.55 * len(x_values)))
            fig, ax = plt.subplots(figsize=(11.5, height))
            positions = np.arange(len(x_values))
            ax.barh(positions, y_values, color="#E9C46A", edgecolor="#8D6E00", height=0.46)
            ax.set_yticks(positions)
            ax.set_yticklabels(x_values, fontsize=9)
            ax.invert_yaxis()
            ax.set_xlabel("数值", fontsize=10)
            ax.set_title(title, fontsize=13, loc="left")
            ax.grid(axis="x", linestyle="-", alpha=0.18)
            ax.set_axisbelow(True)
            max_val = max(y_values) if y_values else 0
            if max_val > 0:
                ax.set_xlim(0, max_val * 1.18)
            for pos, value in zip(positions, y_values):
                ax.text(value, pos, f" {value:,.2f}", va="center", ha="left", fontsize=8, color="#333333")
            fig.tight_layout()
            fig.savefig(asset_path, dpi=180, bbox_inches="tight")
            plt.close(fig)
        elif kind == "heatmap":
            labels = [str(item) for item in (chart.get("labels") or [])]
            matrix = chart.get("matrix") or []
            if len(labels) < 2 or not matrix:
                return None
            arr = np.array(matrix, dtype=float)
            fig_w = max(6.5, min(11.5, 1.2 + 0.9 * len(labels)))
            fig_h = max(5.2, min(10.5, 1.2 + 0.75 * len(labels)))
            fig, ax = plt.subplots(figsize=(fig_w, fig_h))
            im = ax.imshow(arr, cmap="RdBu_r", vmin=-1, vmax=1)
            ax.set_xticks(np.arange(len(labels)))
            ax.set_yticks(np.arange(len(labels)))
            ax.set_xticklabels(labels, fontsize=8, rotation=35, ha="right")
            ax.set_yticklabels(labels, fontsize=8)
            ax.set_title(title, fontsize=13, loc="left")
            for i in range(arr.shape[0]):
                for j in range(arr.shape[1]):
                    ax.text(j, i, f"{arr[i, j]:.2f}", ha="center", va="center", fontsize=7, color="#1f2430")
            fig.colorbar(im, ax=ax, fraction=0.046, pad=0.04)
            fig.tight_layout()
            fig.savefig(asset_path, dpi=180, bbox_inches="tight")
            plt.close(fig)
        else:
            return None
    except Exception:
        return None

    return {
        "kind": kind,
        "title": title,
        "filename": asset_name,
        "file_path": str(asset_path.resolve()),
        "notes": _chart_explanation_lines(chart),
    }


def _attach_rendered_section_charts(report_dir: Path, report_id: str, report: dict[str, Any]) -> list[dict[str, Any]]:
    chart_assets: list[dict[str, Any]] = []
    for section in report.get("sections", []):
        rendered: list[dict[str, Any]] = []
        for index, chart in enumerate(section.get("charts", []) or []):
            if not isinstance(chart, dict):
                continue
            asset = _render_chart_png(report_dir, report_id, str(section.get("id") or "section"), index, chart)
            if asset:
                rendered.append(asset)
                chart_assets.append(asset)
        section["rendered_charts"] = rendered
    return chart_assets


def _render_chart_blocks_html(section: dict[str, Any]) -> str:
    blocks: list[str] = []
    for chart in section.get("rendered_charts", []) or []:
        notes_html = ""
        notes = [str(item).strip() for item in (chart.get("notes") or []) if str(item).strip()]
        if notes:
            notes_html = (
                "<div class='chart-notes'><h4>图表解读</h4><ul>"
                + "".join(f"<li>{html.escape(item)}</li>" for item in notes)
                + "</ul></div>"
            )
        blocks.append(
            f"<div class='chart-block'><h3>{html.escape(str(chart.get('title') or '图表'))}</h3>"
            f"<img src='{html.escape(str(chart.get('filename') or ''))}' alt='{html.escape(str(chart.get('title') or '图表'))}' />"
            f"{notes_html}</div>"
        )
    return "".join(blocks)


def _temporal_rows(frame: pd.DataFrame, date_column: str, value_column: str) -> list[dict[str, Any]]:
    subset = frame[[date_column, value_column]].copy()
    subset[date_column] = pd.to_datetime(subset[date_column], errors="coerce", dayfirst=True)
    subset[value_column] = pd.to_numeric(subset[value_column], errors="coerce")
    subset = subset.dropna()
    if subset.empty:
        return []
    span_days = int((subset[date_column].max() - subset[date_column].min()).days) if len(subset) else 0
    unique_days = int(subset[date_column].dt.normalize().nunique())
    if unique_days <= 31 or span_days <= 45:
        subset["period"] = subset[date_column].dt.strftime("%Y-%m-%d")
        window = 14
    elif unique_days <= 120 or span_days <= 180:
        subset["period"] = subset[date_column].dt.to_period("W").astype(str)
        window = 12
    else:
        subset["period"] = subset[date_column].dt.to_period("M").astype(str)
        window = 12
    grouped = subset.groupby("period")[value_column].mean().reset_index().tail(window)
    return [
        {
            "period": str(row["period"]),
            "value": round(float(row[value_column]), 4),
        }
        for _, row in grouped.iterrows()
    ]


def _temporal_trend_bullets(
    temporal_rows: list[dict[str, Any]],
    *,
    metric_label: str,
    report_lens: str,
) -> list[str]:
    if not temporal_rows:
        return []
    if len(temporal_rows) == 1:
        only = temporal_rows[0]
        return [f"`{only['period']}` 的 `{metric_label}` 为 {only['value']:,.2f}，当前时间样本仍不足以判断连续趋势。"]
    values = [float(row["value"]) for row in temporal_rows if row.get("value") is not None]
    periods = [str(row["period"]) for row in temporal_rows if row.get("period") is not None]
    if len(values) < 2:
        return []
    first_value = values[0]
    last_value = values[-1]
    prev_value = values[-2]
    first_period = periods[0]
    last_period = periods[-1]
    prev_period = periods[-2]
    peak_idx = max(range(len(values)), key=lambda idx: values[idx])
    trough_idx = min(range(len(values)), key=lambda idx: values[idx])
    peak_value = values[peak_idx]
    trough_value = values[trough_idx]
    peak_period = periods[peak_idx]
    trough_period = periods[trough_idx]
    overall_change = None if first_value == 0 else (last_value - first_value) / abs(first_value)
    latest_change = None if prev_value == 0 else (last_value - prev_value) / abs(prev_value)
    mean_value = float(np.mean(values))
    std_value = float(np.std(values))
    cv = 0.0 if mean_value == 0 else std_value / abs(mean_value)
    inner_values = values[1:-1] if len(values) > 3 else values
    inner_min = min(inner_values) if inner_values else min(values)
    inner_max = max(inner_values) if inner_values else max(values)
    if overall_change is not None:
        if abs(overall_change) < 0.1:
            trend_label = "高位震荡" if cv >= 0.2 else "窄幅震荡"
        elif overall_change > 0:
            trend_label = "震荡上行" if cv >= 0.2 else "平稳上行"
        else:
            trend_label = "震荡走弱" if cv >= 0.2 else "平稳走弱"
    else:
        trend_label = "波动待判"
    bullets = [
        f"最近 {len(values)} 个时间窗口里，`{metric_label}` 整体呈 `{trend_label}`。起点 `{first_period}` 为 {first_value:,.2f}，最新 `{last_period}` 为 {last_value:,.2f}。"
    ]
    if overall_change is not None:
        bullets.append(
            f"从整体看，`{metric_label}` 相比起点变化 {last_value - first_value:,.2f}，累计 {'上升' if overall_change >= 0 else '下降'} {_format_percent(overall_change)}。"
        )
    if latest_change is not None:
        bullets.append(
            f"最近一个窗口 `{last_period}` 相比 `{prev_period}` {'上升' if latest_change >= 0 else '下降'} {_format_percent(latest_change)}，说明短期节奏正在{'回暖' if latest_change > 0 else '转弱'}。"
        )
    bullets.append(
        f"峰值出现在 `{peak_period}`，`{metric_label}` 为 {peak_value:,.2f}；低谷出现在 `{trough_period}`，为 {trough_value:,.2f}。峰谷差约 {peak_value - trough_value:,.2f}。"
    )
    if trough_value < inner_min * 0.85 and trough_period == prev_period:
        bullets.append(f"`{trough_period}` 是最近窗口里的明显下探点，后续应优先复核当周的商品结构、卖家履约或异常订单。")
    elif peak_value > inner_max * 1.25 and peak_period == last_period:
        bullets.append(f"`{peak_period}` 是最近窗口里的异常放大点，后续应拆开看是头部商品放量、活动刺激，还是少数异常高值订单拉动。")
    else:
        bullets.append(f"除峰值和低谷外，其余窗口大多落在 {inner_min:,.2f} 至 {inner_max:,.2f} 区间，说明常态水平与异常窗口可以分开读。")
    if report_lens == "procurement_sales_review":
        bullets.append("采销复盘里，时间趋势不只用来判断涨跌，还要判断当前更适合加曝光、促转化、补货承接，还是先排查异常窗口。")
    return bullets[:6]


def _first_matching_column(columns: list[str], keyword_groups: list[list[str]]) -> str | None:
    for group in keyword_groups:
        for column in columns:
            name = str(column)
            lowered_name = name.lower()
            if all(str(token).lower() in lowered_name for token in group):
                return name
    return None


def _foundation_review_context(dataset_id: str, frame: pd.DataFrame, metadata: dict[str, Any]) -> dict[str, Any] | None:
    columns = frame.columns.astype(str).tolist()
    foundation_col = _first_matching_column(columns, [["基金会名称"]])
    foundation_type_col = _first_matching_column(columns, [["基金会类型"], ["类型"]])
    province_col = _first_matching_column(columns, [["注册地", "省"], ["省份"]])
    board_col = _first_matching_column(columns, [["理事会", "次数"]])
    total_spend_col = _first_matching_column(columns, [["总支出"]])
    public_spend_col = _first_matching_column(columns, [["公益事业", "支出"], ["公益", "支出"]])
    donation_income_col = _first_matching_column(columns, [["捐赠", "收入"]])
    total_income_col = _first_matching_column(columns, [["收入", "合计"], ["总收入"]])
    year_col = _first_matching_column(columns, [["年度"]])

    if not foundation_col or not total_spend_col:
        return None

    working = frame.copy()
    for column in [board_col, total_spend_col, public_spend_col, donation_income_col, total_income_col, year_col]:
        if column:
            working[column] = pd.to_numeric(working[column], errors="coerce")
    working[foundation_col] = working[foundation_col].fillna("Missing").astype(str)
    if foundation_type_col:
        working[foundation_type_col] = working[foundation_type_col].fillna("Missing").astype(str)
    if province_col:
        working[province_col] = working[province_col].fillna("Missing").astype(str)

    total_income_base = total_income_col or donation_income_col
    public_spend = pd.to_numeric(working[public_spend_col], errors="coerce") if public_spend_col else None
    total_spend = pd.to_numeric(working[total_spend_col], errors="coerce")
    donation_income = pd.to_numeric(working[donation_income_col], errors="coerce") if donation_income_col else None
    total_income = pd.to_numeric(working[total_income_base], errors="coerce") if total_income_base else None

    if public_spend_col:
        ratio = public_spend.astype(float) / total_spend.astype(float)
        ratio = ratio.where(total_spend.astype(float) > 0, np.nan)
        working["公益支出占比"] = ratio
    if donation_income_col and total_income_col:
        ratio = donation_income.astype(float) / total_income.astype(float)
        ratio = ratio.where(total_income.astype(float) > 0, np.nan)
        working["捐赠收入占比"] = ratio
    if total_income_base:
        working["收支结余"] = total_income - total_spend

    foundation_view = pd.DataFrame(
        {
            "基金会名称": working[foundation_col],
            **({"基金会类型": working[foundation_type_col]} if foundation_type_col else {}),
            **({"注册地省份": working[province_col]} if province_col else {}),
            **({"理事会召开次数": working[board_col]} if board_col else {}),
            "本年度总支出": total_spend,
            **({"本年度用于公益事业的支出": public_spend} if public_spend_col else {}),
            **({"本年度捐赠收入合计": donation_income} if donation_income_col else {}),
            **({"本年度收入合计": total_income} if total_income_base else {}),
            **({"公益支出占比": working["公益支出占比"]} if "公益支出占比" in working else {}),
            **({"捐赠收入占比": working["捐赠收入占比"]} if "捐赠收入占比" in working else {}),
            **({"收支结余": working["收支结余"]} if "收支结余" in working else {}),
        }
    )
    foundation_view = foundation_view.sort_values("本年度总支出", ascending=False)

    top_foundations: list[dict[str, Any]] = []
    for _, row in foundation_view.head(12).iterrows():
        top_foundations.append(
            {
                "基金会名称": row["基金会名称"],
                **({"基金会类型": row["基金会类型"]} if foundation_type_col else {}),
                **({"注册地省份": row["注册地省份"]} if province_col else {}),
                "本年度总支出": _display_table_value("本年度总支出", row["本年度总支出"]),
                **(
                    {"本年度用于公益事业的支出": _display_table_value("本年度用于公益事业的支出", row.get("本年度用于公益事业的支出"))}
                    if public_spend_col
                    else {}
                ),
                **({"公益支出占比": _format_percent(float(row["公益支出占比"])) if pd.notna(row.get("公益支出占比")) else "n/a"} if "公益支出占比" in foundation_view else {}),
                **({"本年度收入合计": _display_table_value("本年度收入合计", row.get("本年度收入合计"))} if total_income_base else {}),
                **({"捐赠收入占比": _format_percent(float(row["捐赠收入占比"])) if pd.notna(row.get("捐赠收入占比")) else "n/a"} if "捐赠收入占比" in foundation_view else {}),
                **({"收支结余": _display_table_value("收支结余", row.get("收支结余"))} if "收支结余" in foundation_view else {}),
            }
        )

    type_rows: list[dict[str, Any]] = []
    if foundation_type_col:
        grouped = (
            foundation_view.groupby("基金会类型", dropna=False)
            .agg(
                基金会数=("基金会名称", "count"),
                总支出=("本年度总支出", "sum"),
                公益支出=("本年度用于公益事业的支出", "sum") if public_spend_col else ("本年度总支出", "sum"),
                总收入=("本年度收入合计", "sum") if total_income_base else ("本年度总支出", "sum"),
            )
            .reset_index()
            .sort_values("总支出", ascending=False)
        )
        for _, row in grouped.iterrows():
            payload = {
                "基金会类型": row["基金会类型"],
                "基金会数": int(row["基金会数"]),
                "总支出": _display_table_value("总支出", row["总支出"]),
            }
            if public_spend_col:
                payload["公益支出占比"] = _format_percent(float(row["公益支出"] / row["总支出"])) if row["总支出"] else "n/a"
            if total_income_base:
                payload["收入支出比"] = _format_percent(float(row["总收入"] / row["总支出"])) if row["总支出"] else "n/a"
            type_rows.append(payload)

    province_rows: list[dict[str, Any]] = []
    if province_col:
        grouped = (
            foundation_view.groupby("注册地省份", dropna=False)
            .agg(
                基金会数=("基金会名称", "count"),
                总支出=("本年度总支出", "sum"),
                总收入=("本年度收入合计", "sum") if total_income_base else ("本年度总支出", "sum"),
            )
            .reset_index()
            .sort_values("总支出", ascending=False)
        )
        for _, row in grouped.head(10).iterrows():
            province_rows.append(
                {
                    "注册地省份": row["注册地省份"],
                    "基金会数": int(row["基金会数"]),
                    "总支出": _display_table_value("总支出", row["总支出"]),
                    **({"总收入": _display_table_value("总收入", row["总收入"])} if total_income_base else {}),
                }
            )

    priority_rows: list[dict[str, Any]] = []
    spend_series = foundation_view["本年度总支出"].dropna()
    spend_q50 = float(spend_series.quantile(0.5)) if not spend_series.empty else 0.0
    spend_q75 = float(spend_series.quantile(0.75)) if not spend_series.empty else 0.0
    ratio_series = foundation_view["公益支出占比"].dropna() if "公益支出占比" in foundation_view else pd.Series(dtype=float)
    ratio_q25 = float(ratio_series.quantile(0.25)) if not ratio_series.empty else float("nan")
    ratio_q75 = float(ratio_series.quantile(0.75)) if not ratio_series.empty else float("nan")
    board_series = foundation_view["理事会召开次数"].dropna() if board_col else pd.Series(dtype=float)
    board_q25 = float(board_series.quantile(0.25)) if not board_series.empty else float("nan")
    for _, row in foundation_view.iterrows():
        reasons: list[str] = []
        action = None
        spend_value = float(row["本年度总支出"]) if pd.notna(row["本年度总支出"]) else 0.0
        public_ratio = float(row["公益支出占比"]) if "公益支出占比" in foundation_view and pd.notna(row.get("公益支出占比")) else None
        balance = float(row["收支结余"]) if "收支结余" in foundation_view and pd.notna(row.get("收支结余")) else None
        board_value = float(row["理事会召开次数"]) if board_col and pd.notna(row.get("理事会召开次数")) else None
        if spend_value >= spend_q75:
            reasons.append("支出规模高")
        if public_ratio is not None and not np.isnan(ratio_q25) and public_ratio <= ratio_q25:
            reasons.append("公益支出占比低位")
        if public_ratio is not None and not np.isnan(ratio_q75) and public_ratio >= ratio_q75:
            reasons.append("公益支出占比高位")
        if balance is not None and balance < 0:
            reasons.append("收支倒挂")
        if board_value is not None and not np.isnan(board_q25) and board_value <= board_q25 and spend_value >= spend_q50:
            reasons.append("治理频率偏低")

        if spend_value >= spend_q75 and public_ratio is not None and not np.isnan(ratio_q75) and public_ratio >= ratio_q75 and (balance is None or balance >= 0):
            action = "重点复盘"
        elif spend_value >= spend_q50 and ((public_ratio is not None and not np.isnan(ratio_q25) and public_ratio <= ratio_q25) or (balance is not None and balance < 0)):
            action = "优先排查"
        elif spend_value >= spend_q50 and board_value is not None and not np.isnan(board_q25) and board_value <= board_q25:
            action = "治理关注"

        if action:
            priority_rows.append(
                {
                    "基金会名称": row["基金会名称"],
                    **({"基金会类型": row["基金会类型"]} if foundation_type_col else {}),
                    "建议动作": action,
                    "原因": "；".join(reasons) or "需要进一步复核",
                    "本年度总支出": _display_table_value("本年度总支出", row["本年度总支出"]),
                    **({"公益支出占比": _format_percent(public_ratio) if public_ratio is not None else "n/a"} if "公益支出占比" in foundation_view else {}),
                    **({"收支结余": _display_table_value("收支结余", balance)} if "收支结余" in foundation_view else {}),
                }
            )
    priority_rows = priority_rows[:12]

    project_rows: list[dict[str, Any]] = []
    try:
        _, _, project_sheet = load_dataset_frame(dataset_id, "Sheet1")
        project_frame = project_sheet if isinstance(project_sheet, pd.DataFrame) else None
    except Exception:
        project_frame = None
    if project_frame is None:
        try:
            project_frame, _, _ = load_dataset_frame(dataset_id, "Sheet1")
        except Exception:
            project_frame = None
    if project_frame is not None:
        pcols = project_frame.columns.astype(str).tolist()
        p_foundation_col = _first_matching_column(pcols, [["基金会名称"]])
        p_project_col = _first_matching_column(pcols, [["项目名称"]])
        p_spend_col = _first_matching_column(pcols, [["项目支出"], ["支出"]])
        p_income_col = _first_matching_column(pcols, [["项目收入"], ["收入"]])
        p_domain_col = _first_matching_column(pcols, [["服务领域"], ["领域"]])
        if p_foundation_col and p_project_col and p_spend_col:
            p = project_frame.copy()
            p[p_spend_col] = pd.to_numeric(p[p_spend_col], errors="coerce")
            if p_income_col:
                p[p_income_col] = pd.to_numeric(p[p_income_col], errors="coerce")
            p = p.dropna(subset=[p_spend_col]).sort_values(p_spend_col, ascending=False)
            for _, row in p.head(12).iterrows():
                project_rows.append(
                    {
                        "基金会名称": row[p_foundation_col],
                        "项目名称": row[p_project_col],
                        "项目支出": _display_table_value("项目支出", row[p_spend_col]),
                        **({"项目收入": _display_table_value("项目收入", row[p_income_col])} if p_income_col else {}),
                        **({"服务领域": row[p_domain_col]} if p_domain_col else {}),
                    }
                )

    total_public_spend = float(public_spend.dropna().sum()) if public_spend_col and public_spend is not None else None
    total_total_spend = float(total_spend.dropna().sum()) if total_spend is not None else None
    public_spend_ratio = (total_public_spend / total_total_spend) if total_public_spend is not None and total_total_spend not in (None, 0) else None
    total_income_sum = float(total_income.dropna().sum()) if total_income_base and total_income is not None else None
    summary_bullets = []
    if top_foundations:
        leaders = "、".join(str(row["基金会名称"]) for row in top_foundations[:3])
        summary_bullets.append(f"当前支出规模最大的基金会主要集中在：{leaders}。这批主体应作为第一优先复盘对象。")
    if public_spend_ratio is not None:
        summary_bullets.append(f"样本内公益支出合计约占总支出的 {_format_percent(public_spend_ratio)}。这决定了当前更像公益执行导向还是行政/其他支出导向。")
    if priority_rows:
        summary_bullets.append(f"当前已有 {len(priority_rows)} 家基金会进入优先复盘或排查名单，建议在会前单独准备。")

    return {
        "top_foundations": top_foundations,
        "type_rows": type_rows,
        "province_rows": province_rows,
        "priority_rows": priority_rows,
        "project_rows": project_rows,
        "summary_bullets": summary_bullets,
        "public_spend_ratio": public_spend_ratio,
    }


def _foundation_sections_from_context(context: dict[str, Any] | None) -> list[dict[str, Any]]:
    if not context:
        return []
    sections: list[dict[str, Any]] = []
    if context.get("top_foundations"):
        sections.append(
            _section(
                "foundation_top_funds",
                "重点基金会清单",
                "这部分直接回答哪些基金会承担了主要公益支出与收入规模，是基金会复盘里最先要看的主体层清单。",
                context.get("summary_bullets", [])[:2],
                tables=[_table("重点基金会清单", context["top_foundations"])],
            )
        )
    if context.get("type_rows") or context.get("province_rows"):
        tables = []
        if context.get("type_rows"):
            tables.append(_table("基金会类型结构", context["type_rows"]))
        if context.get("province_rows"):
            tables.append(_table("地区结构", context["province_rows"]))
        sections.append(
            _section(
                "foundation_structure",
                "公益支出占比与结构健康度",
                "这部分把基金会类型、地区和公益支出占比放在一起看，帮助判断收支结构是否健康、资源是否过于集中。",
                [
                    f"样本内公益支出占总支出约为 {_format_percent(context.get('public_spend_ratio'))}。" if context.get("public_spend_ratio") is not None else "当前无法稳定计算整体公益支出占比。",
                    "优先用结构占比、收支关系和集中度一起判断，而不是只看单个总额。",
                ],
                tables=tables,
            )
        )
    if context.get("priority_rows"):
        sections.append(
            _section(
                "foundation_priority_review",
                "优先复盘与排查名单",
                "这部分把支出规模高、公益支出占比偏低、收支倒挂或治理频率偏低的基金会单独列出来，方便直接进入管理动作。",
                [
                    "重点复盘对象通常同时具备规模高、公益投入高位或收支相对健康等特征。",
                    "优先排查对象通常表现为规模不低但公益支出占比偏低、收支倒挂或治理信号偏弱。",
                ],
                tables=[_table("优先复盘与排查名单", context["priority_rows"])],
            )
        )
    if context.get("project_rows"):
        sections.append(
            _section(
                "foundation_top_projects",
                "重点项目清单",
                "这部分从项目明细层补充当前最值得关注的重点项目，避免基金会主体层结论缺少落地项目支撑。",
                [
                    "基金会主体判断必须能落到项目层，否则很容易只看到总盘子，看不到具体执行对象。",
                ],
                tables=[_table("重点项目清单", context["project_rows"])],
            )
        )
    return sections


def _management_accounting_sections_from_context(context: dict[str, Any] | None) -> list[dict[str, Any]]:
    if not context:
        return []
    sections: list[dict[str, Any]] = []
    agent_layer = context.get("agent_layer") or {}

    if context.get("totals_rows") or context.get("margin_rows"):
        tables = []
        if context.get("totals_rows"):
            tables.append(_table("经营结果与利润盘子", context["totals_rows"]))
        if context.get("margin_rows"):
            tables.append(_table("利润质量指标", context["margin_rows"]))
        sections.append(
            _section(
                "management_accounting_profitability",
                "经营结果与利润质量",
                "这部分先回答盘子有多大、利润有多少、利润率如何变化，避免只看收入规模不看质量。",
                [
                    *(agent_layer.get("key_findings") or [])[:2],
                    *(agent_layer.get("metric_interpretations") or [])[:2],
                ],
                tables=tables,
            )
        )

    if context.get("budget_rows"):
        sections.append(
            _section(
                "management_accounting_budget",
                "预算执行与偏差归因",
                "这部分优先看预算值、实际值、偏差额和偏差率，帮助判断偏差到底来自结构问题还是执行问题。",
                [
                    *(agent_layer.get("managerial_actions") or [])[:2],
                    "预算偏差排序优先看偏差额和偏差率一起看，防止只被比例最高但体量很小的科目带偏。",
                ],
                tables=[_table("预算与实际偏差", context["budget_rows"])],
            )
        )

    capital_tables = []
    if context.get("working_capital_rows"):
        capital_tables.append(_table("营运资本与现金占用", context["working_capital_rows"]))
    if context.get("leverage_rows"):
        capital_tables.append(_table("资产负债与杠杆", context["leverage_rows"]))
    if capital_tables:
        sections.append(
            _section(
                "management_accounting_capital",
                "营运资本、现金与财务压力",
                "这部分把应收、存货、应付、现金和杠杆放在一起看，回答利润是否真的转成现金，增长是否在吞噬资金。",
                [
                    *(agent_layer.get("risk_flags") or [])[:3],
                ],
                tables=capital_tables,
            )
        )

    if context.get("slice_rows"):
        sections.append(
            _section(
                "management_accounting_responsibility",
                "责任中心与经营切片",
                "这部分把收入、利润或资源占用放回责任中心、业务单元或产品线里，帮助管理层直接定位谁在拉动、谁在拖累。",
                [
                    "责任中心分析不能只看收入，还要和利润、预算偏差、资金占用一起看。",
                    "头部切片优先进入深挖，尾部切片优先看是否存在低效占用。",
                ],
                tables=[_table("经营切片表现", context["slice_rows"])],
            )
        )

    if context.get("cards"):
        card_rows = [
            {
                "知识卡": card["title"],
                "来源": card["source_name"],
                "先看问题": "；".join(card.get("key_questions", [])[:2]),
                "重点指标": "、".join(card.get("metrics", [])[:3]),
            }
            for card in context["cards"][:5]
        ]
        sections.append(
            _section(
                "management_accounting_playbook",
                "管理会计知识库镜头",
                "这部分把当前最匹配的管理会计框架列出来，方便报告从数字解释继续走向经营动作。",
                [
                    agent_layer.get("management_summary", "当前样本更适合按管理会计口径做利润、预算、现金和责任中心复盘。"),
                ],
                tables=[_table("管理会计知识卡", card_rows)],
            )
        )

    return sections


def _method_run_by_id(method_runs: list[dict[str, Any]], method_id: str) -> dict[str, Any] | None:
    return next((run for run in method_runs if str(run.get("method_id")) == method_id), None)


def _safe_float(value: Any) -> float | None:
    try:
        if value is None or value == "":
            return None
        numeric = float(value)
        if np.isnan(numeric):
            return None
        return numeric
    except (TypeError, ValueError):
        return None


def _distribution_signal(rows: list[dict[str, Any]]) -> dict[str, Any] | None:
    if not rows:
        return None
    top_name = str(rows[0].get("segment") or rows[0].get("category") or rows[0].get("组合") or rows[0].get("对象") or "")
    top_share = _safe_float(rows[0].get("share") if "share" in rows[0] else rows[0].get("reach_share"))
    if top_share is None:
        return None
    second_share = 0.0
    if len(rows) > 1:
        second_share = _safe_float(rows[1].get("share") if "share" in rows[1] else rows[1].get("reach_share")) or 0.0
    gap = max(top_share - second_share, 0.0)
    if top_share >= 0.25 and gap >= 0.05:
        status = "头部明确"
    elif top_share >= 0.18 and gap >= 0.02:
        status = "轻度领先"
    else:
        status = "分布接近均匀"
    return {
        "top_name": top_name,
        "top_share": top_share,
        "second_share": second_share,
        "gap": gap,
        "status": status,
    }


def _distribution_priority_sentence(
    rows: list[dict[str, Any]],
    *,
    subject: str,
    strong_tail: str,
    balanced_tail: str,
) -> str | None:
    signal = _distribution_signal(rows)
    if not signal:
        return None
    share_text = _format_percent(signal["top_share"])
    gap_text = _format_percent(signal["gap"])
    if signal["status"] == "头部明确":
        return f"当前{subject}明显集中在 `{signal['top_name']}`，份额约 {share_text}，领先第二名约 {gap_text}。{strong_tail}"
    if signal["status"] == "轻度领先":
        return f"当前{subject}由 `{signal['top_name']}` 轻度领先，份额约 {share_text}，领先第二名约 {gap_text}。{strong_tail}"
    return f"当前{subject}最高的是 `{signal['top_name']}`，份额约 {share_text}，与第二名差距仅 {gap_text}。{balanced_tail}"


def _distribution_concentration_sentence(top3_share: Any, hhi: Any) -> str | None:
    top3 = _safe_float(top3_share)
    hhi_value = _safe_float(hhi)
    if top3 is None and hhi_value is None:
        return None
    top3_text = _format_percent(top3) if top3 is not None else "n/a"
    hhi_text = f"{hhi_value:.1f}" if hhi_value is not None else "n/a"
    if (top3 is not None and top3 >= 0.7) or (hhi_value is not None and hhi_value >= 2500):
        return f"前 3 个切片合计占比约 {top3_text}，HHI 约 {hhi_text}，说明样本内资源集中度偏高。"
    if (top3 is not None and top3 >= 0.5) or (hhi_value is not None and hhi_value >= 1500):
        return f"前 3 个切片合计占比约 {top3_text}，HHI 约 {hhi_text}，说明资源有一定集中度，但还没有形成绝对垄断结构。"
    return f"前 3 个切片合计占比约 {top3_text}，HHI 约 {hhi_text}，说明资源分布较分散，正文更该优先看效率差和异常差。"


def _correlation_signal(correlation: Any) -> dict[str, Any]:
    corr = _safe_float(correlation) or 0.0
    abs_corr = abs(corr)
    if abs_corr >= 0.8:
        strength = "强相关"
        interpretation = "这两个指标同步变化明显，可以放在同一条监控链路里联合观察。"
    elif abs_corr >= 0.5:
        strength = "中等相关"
        interpretation = "这两个指标存在明显联动，适合联合复盘，但还需要结合口径和时间拆解。"
    elif abs_corr >= 0.3:
        strength = "弱相关"
        interpretation = "这两个指标只有有限联动，只适合作为辅证，不足以单独支撑驱动判断。"
    else:
        strength = "几乎无相关"
        interpretation = "这两个指标当前几乎没有稳定联动，不适合据此推导共同驱动关系。"
    return {
        "value": corr,
        "abs_value": abs_corr,
        "strength": strength,
        "interpretation": interpretation,
    }


def _procurement_coverage_status(frame: pd.DataFrame) -> dict[str, Any]:
    columns = [str(column) for column in frame.columns.astype(str).tolist()]
    lowered = [column.lower() for column in columns]

    def has_any(tokens: tuple[str, ...]) -> bool:
        return any(any(token in column for token in tokens) for column in lowered)

    status = {
        "has_supplier": has_any(("supplier", "seller", "vendor", "merchant", "shop", "供应商", "卖家")),
        "has_inventory": has_any(("inventory", "stock", "warehouse", "库存", "可售", "在库", "周转")),
        "has_procurement_cost": has_any(("purchasecost", "purchase_cost", "purchase price", "cost", "supplyprice", "供货价", "采购价", "采购成本", "进货价")),
        "has_profit": has_any(("profit", "margin", "grossprofit", "gross margin", "毛利", "净利", "利润率")),
        "has_settlement": has_any(("payable", "receivable", "账期", "结算", "付款", "应收", "应付")),
        "has_procurement_cycle": has_any(("leadtime", "lead_time", "采购周期", "交期", "交付", "到货", "补货周期")),
    }
    strong_keys = ["has_supplier", "has_inventory", "has_procurement_cost", "has_profit", "has_procurement_cycle"]
    coverage_score = sum(1 for key in strong_keys if status[key])
    missing_labels = []
    label_map = {
        "has_supplier": "供应商主数据",
        "has_inventory": "库存/周转",
        "has_procurement_cost": "采购价/采购成本",
        "has_profit": "毛利/利润",
        "has_settlement": "账期/结算",
        "has_procurement_cycle": "采购周期/交付周期",
    }
    for key, label in label_map.items():
        if not status[key]:
            missing_labels.append(label)
    status["coverage_score"] = coverage_score
    status["is_full_procurement"] = coverage_score >= 4
    status["missing_labels"] = missing_labels
    return status

def _procurement_coverage_status(frame: pd.DataFrame) -> dict[str, Any]:
    registry = field_availability_registry(frame)
    return {
        "has_supplier": bool(registry.get("has_supplier_delivery_fields")),
        "has_inventory": bool(registry.get("has_inventory_fields")),
        "has_procurement_cost": bool(registry.get("has_procurement_price_fields")),
        "has_profit": bool(registry.get("has_profit_fields")),
        "has_settlement": bool(registry.get("has_payment_term_fields")),
        "has_procurement_cycle": bool(registry.get("has_supplier_delivery_fields")),
        "coverage_score": sum(
            1
            for value in [
                registry.get("has_supplier_delivery_fields"),
                registry.get("has_inventory_fields"),
                registry.get("has_procurement_price_fields"),
                registry.get("has_profit_fields"),
                registry.get("has_payment_term_fields"),
            ]
            if value
        ),
        "is_full_procurement": str(registry.get("report_mode") or "") == "full_procurement_sales_decision_report",
        "missing_labels": list(registry.get("missing_field_groups") or []),
    }


