def _procurement_sales_readiness_section(readiness: dict[str, Any]) -> dict[str, Any] | None:
    if not readiness:
        return None
    mode = str(readiness.get("mode") or "insufficient_for_decision")
    labels = {
        "full_procurement_sales_decision_report": "完整采销决策报告",
        "sales_fulfillment_product_report": "销售履约与商品经营复盘",
        "sales_structure_report": "销售结构分析",
        "insufficient_for_decision": "数据诊断与补字段清单",
    }
    flags = readiness.get("field_coverage_flags") or {}
    coverage = readiness.get("field_coverage") or {}
    missing = "、".join(readiness.get("missing_domains") or [])
    allowed: list[str] = []
    forbidden: list[str] = []
    if mode == "full_procurement_sales_decision_report":
        allowed = [
            "允许输出完整采销动作：补货、减采、清仓、价格谈判、供应商治理。",
            "允许把销售、采购、利润、库存、供应商链条压成完整管理结论。",
        ]
    elif mode == "sales_fulfillment_product_report":
        allowed = [
            "允许输出销售、履约、售后和商品经营动作。",
            "允许写主推候选、履约修复、口碑修复、销侧观察。",
        ]
        forbidden = [
            "禁止直接输出补货、减采、清仓、价格谈判、账期谈判等采购侧强动作。",
            "禁止把销售履约复盘包装成完整采销拍板报告。",
        ]
    elif mode == "sales_structure_report":
        allowed = [
            "允许输出品类、商品、地区、时间结构分析。",
            "允许给出资源候选池和结构观察结论。",
        ]
        forbidden = [
            "禁止输出补货、清仓、供应商谈判、主推加码等强动作。",
        ]
    else:
        forbidden = [
            "字段不足，当前只能输出数据诊断与补字段清单。",
        ]
    rows = [
        {"字段域": "销售侧", "字段覆盖": "有" if flags.get("sales") else "缺", "命中字段": " / ".join(coverage.get("sales") or [])[:240] or "n/a"},
        {"字段域": "采购侧", "字段覆盖": "有" if flags.get("procurement") else "缺", "命中字段": " / ".join(coverage.get("procurement") or [])[:240] or "n/a"},
        {"字段域": "利润侧", "字段覆盖": "有" if flags.get("profit") else "缺", "命中字段": " / ".join(coverage.get("profit") or [])[:240] or "n/a"},
        {"字段域": "库存侧", "字段覆盖": "有" if flags.get("inventory") else "缺", "命中字段": " / ".join(coverage.get("inventory") or [])[:240] or "n/a"},
        {"字段域": "供应商侧", "字段覆盖": "有" if flags.get("supplier") else "缺", "命中字段": " / ".join(coverage.get("supplier") or [])[:240] or "n/a"},
        {"字段域": "价格力侧", "字段覆盖": "有" if flags.get("price_power") else "缺", "命中字段": " / ".join(coverage.get("price_power") or [])[:240] or "n/a"},
        {"字段域": "售后质量侧", "字段覆盖": "有" if flags.get("after_sales") else "缺", "命中字段": " / ".join(coverage.get("after_sales") or [])[:240] or "n/a"},
    ]
    bullets = [
        f"当前报告模式：`{labels.get(mode, mode)}`。",
        f"当前缺失字段域包括：`{missing or '无'}`。",
        *allowed[:2],
        *forbidden[:2],
    ]
    return _section(
        "procurement_sales_readiness",
        "采销可决策性检查",
        "这部分先判断当前数据到底能不能支撑采销拍板，防止把销售履约复盘误写成完整采销决策报告。",
        bullets,
        tables=[_table("字段域覆盖情况", rows)],
    )


