def _generic_role_guide_rows(
    *,
    request: SmartReportRequest,
    report_lens: str,
    analysis_program: dict[str, Any],
) -> list[dict[str, str]]:
    audience_text = f"{request.target_audience} {request.core_purpose} {request.problem_to_solve}".lower()
    outcomes = "、".join(analysis_program.get("core_outcomes", [])[:3]) or "核心结果变量"
    slices = "、".join(analysis_program.get("explanatory_slices", [])[:3]) or "关键切片"

    def priority(role: str) -> str:
        if role == "管理层" and any(token in audience_text for token in ["管理", "老板", "负责人", "高层", "决策"]):
            return "当前主受众"
        if role == "执行层" and any(token in audience_text for token in ["运营", "执行", "渠道", "媒介", "项目", "内容", "增长"]):
            return "当前主受众"
        if role == "分析层" and any(token in audience_text for token in ["分析", "研究", "数据", "策略"]):
            return "当前主受众"
        return "建议同步阅读"

    return [
        {
            "角色": "管理层",
            "阅读优先级": priority("管理层"),
            "建议先看": "决策摘要 -> 一页式管理判断 -> 结论证据链",
            "最关心的问题": f"{outcomes} 当前表现如何，是否需要调整方向",
            "使用方式": "用于快速做资源、策略或优先级判断",
        },
        {
            "角色": "执行层",
            "阅读优先级": priority("执行层"),
            "建议先看": "执行翻译层 -> 情景动作矩阵 -> 行动路线图",
            "最关心的问题": f"{slices} 哪些对象要保留、修复、验证或排查",
            "使用方式": "用于拆动作、排优先级和安排本周执行",
        },
        {
            "角色": "分析层",
            "阅读优先级": priority("分析层"),
            "建议先看": "关键口径与业务指标 -> 结论证据链 -> 学习议程",
            "最关心的问题": "哪些结论最强、哪些还要补证据",
            "使用方式": "用于复核口径、继续深挖和准备下一轮分析",
        },
    ]


