def _media_gap_review(frame: pd.DataFrame) -> dict[str, Any] | None:
    required = ["媒体", "终端", "点位", "预估曝光", "监测曝光", "预估点击", "监测点击"]
    if any(column not in frame.columns for column in required):
        return None

    working = frame[required].copy()
    for column in ["预估曝光", "监测曝光", "预估点击", "监测点击"]:
        working[column] = pd.to_numeric(working[column], errors="coerce")
    working = working.dropna(subset=["预估曝光", "监测曝光"])
    if working.empty:
        return None

    working["曝光偏差率"] = np.where(
        working["预估曝光"] > 0,
        (working["监测曝光"] - working["预估曝光"]) / working["预估曝光"],
        np.nan,
    )
    working["点击偏差率"] = np.where(
        working["预估点击"] > 0,
        (working["监测点击"] - working["预估点击"]) / working["预估点击"],
        np.nan,
    )
    working["组合"] = working["媒体"].astype(str) + " / " + working["终端"].astype(str)

    combo = (
        working.groupby("组合")[["预估曝光", "监测曝光", "曝光偏差率"]]
        .agg({"预估曝光": "sum", "监测曝光": "sum", "曝光偏差率": "mean"})
        .reset_index()
        .sort_values("曝光偏差率", ascending=False)
    )
    placement = (
        working.groupby("点位")[["预估曝光", "监测曝光", "曝光偏差率"]]
        .agg({"预估曝光": "sum", "监测曝光": "sum", "曝光偏差率": "mean"})
        .reset_index()
        .sort_values("曝光偏差率", ascending=False)
    )

    combo_rows = [
        {
            "组合": str(row["组合"]),
            "预估曝光": round(float(row["预估曝光"]), 2),
            "监测曝光": round(float(row["监测曝光"]), 2),
            "曝光偏差率": round(float(row["曝光偏差率"]), 4),
        }
        for _, row in combo.iterrows()
    ]
    placement_rows = [
        {
            "点位": str(row["点位"]),
            "预估曝光": round(float(row["预估曝光"]), 2),
            "监测曝光": round(float(row["监测曝光"]), 2),
            "曝光偏差率": round(float(row["曝光偏差率"]), 4),
        }
        for _, row in placement.iterrows()
    ]
    if not combo_rows and not placement_rows:
        return None

    bullets = []
    if combo_rows:
        bullets.append(
            f"曝光兑现偏差最高的媒体/终端组合是 `{combo_rows[0]['组合']}`，平均偏差率约 {combo_rows[0]['曝光偏差率']:.1%}。"
        )
    if placement_rows:
        bullets.append(
            f"曝光兑现偏差最高的点位是 `{placement_rows[0]['点位']}`，平均偏差率约 {placement_rows[0]['曝光偏差率']:.1%}。"
        )
        bullets.append("这部分直接回答预估与监测差异落在哪些执行单元，是投放复盘里比总体相关性更重要的内容。")

    return {
        "bullets": bullets,
        "tables": [
            _table("媒体/终端组合偏差", combo_rows),
            _table("点位偏差排名", placement_rows),
        ],
        "charts": [
            _bar_chart("媒体/终端曝光偏差", combo_rows[:6], "组合", "曝光偏差率"),
            _bar_chart("点位曝光偏差", placement_rows[:6], "点位", "曝光偏差率"),
        ],
    }


def _choose_continuous_target(frame: pd.DataFrame, numeric_cols: list[str]) -> tuple[str | None, list[str]]:
    if len(numeric_cols) < 3:
        return None, []
    corr = frame[numeric_cols[:8]].apply(pd.to_numeric, errors="coerce").corr().abs().fillna(0)
    best_target = None
    best_score = -1.0
    for column in corr.columns:
        score = float(corr[column].drop(labels=[column]).mean())
        if score > best_score:
            best_target = str(column)
            best_score = score
    if best_target is None:
        return None, []
    features = [column for column in numeric_cols if column != best_target][:4]
    return best_target, features


def _choose_binary_target(frame: pd.DataFrame) -> str | None:
    preferred_keywords = ["revenue", "default", "survived", "clicked", "converted", "income", "y", "target"]
    binaries = _binary_columns(frame)
    if not binaries:
        return None
    for keyword in preferred_keywords:
        for column in binaries:
            if keyword in column.lower():
                return column
    return binaries[0]


def _choose_binary_group(frame: pd.DataFrame, exclude: set[str] | None = None) -> tuple[str | None, list[str]]:
    exclude = exclude or set()
    for column in _binary_columns(frame):
        if column not in exclude:
            values = frame[column].dropna().astype(str).value_counts().index.tolist()
            if len(values) == 2:
                return column, values[:2]
    return None, []


def _predictive_target_label(target: str) -> str:
    lowered = str(target or "").strip().lower()
    alias_map = {
        "revenue": "销售额",
        "gmv": "成交额",
        "quantity": "销量",
        "freightcost": "履约成本",
        "roi": "履约效率",
        "islate": "逾期",
        "late": "逾期",
        "delayed": "延迟履约",
        "default": "违约",
        "converted": "转化",
        "clicked": "点击",
    }
    return alias_map.get(lowered, _prettify_slug_label(str(target or "")))


def _predictive_term_label(term: str) -> str:
    text = str(term or "").strip()
    if not text:
        return text
    lowered = text.lower()
    alias_map = {
        "const": "常数项",
        "revenue": "Revenue",
        "gmv": "GMV",
        "quantity": "Quantity",
        "freightcost": "FreightCost",
        "islate": "IsLate",
        "deliverydays": "DeliveryDays",
        "delaydays": "DelayDays",
        "reviewscore": "ReviewScore",
    }
    if lowered in alias_map:
        return alias_map[lowered]
    if text.lower() == "const":
        return "常数项"
    return _prettify_slug_label(text)


def _predictive_overlap_note(term: str, target: str) -> str:
    term_lower = str(term or "").strip().lower()
    target_lower = str(target or "").strip().lower()
    if not term_lower or not target_lower:
        return ""
    if term_lower == target_lower:
        return "该字段和目标字段完全同源，只能说明口径重合，不能当成独立驱动。"
    money_terms = {"revenue", "gmv", "sales", "amount", "price"}
    if term_lower in money_terms and target_lower in money_terms:
        return "该字段和目标字段都属于金额结果口径，更像同步指标，不适合直接写成因果驱动。"
    return ""


def _predictive_linear_term_meaning(
    term: str,
    coefficient: Any,
    p_value: Any,
    target: str,
    *,
    report_lens: str,
) -> str:
    term_text = str(term or "").strip()
    if term_text.lower() == "const":
        return "常数项只代表模型基线，不对应具体经营动作。"

    overlap_note = _predictive_overlap_note(term_text, target)
    if overlap_note:
        return overlap_note

    coefficient_value = _safe_float(coefficient)
    p_value_float = _safe_float(p_value)
    target_label = _predictive_target_label(target)

    if coefficient_value is None:
        base = f"该字段与 `{target_label}` 存在方向关系，但当前系数不可稳定解释。"
    elif abs(coefficient_value) < 0.001:
        base = f"该字段的边际系数接近 0，说明它对 `{target_label}` 的直接解释力很弱。"
    elif coefficient_value > 0:
        base = f"系数为正，说明该字段上升时，`{target_label}` 通常同步抬升。"
    else:
        base = f"系数为负，说明该字段上升时，`{target_label}` 往往承压回落。"

    if report_lens == "procurement_sales_review":
        lowered = term_text.lower()
        if lowered == "freightcost":
            base = "它主要在提示履约成本和结果是否同步放大，要继续拆品类、区域或重量结构，判断是正常远距离重货，还是履约效率恶化。"
        elif lowered == "quantity":
            base = f"它更像走量驱动信号，适合继续和订单覆盖、复购承接一起看，判断 `{target_label}` 是靠件数放大还是靠客单价拉升。"
        elif lowered in {"revenue", "gmv"}:
            base = f"它和 `{target_label}` 高度贴近，更适合当结果同步信号，而不是单独写成经营驱动。"

    if p_value_float is not None and p_value_float > 0.05:
        return f"{base} 但当前 p 值偏高，先把它当排查线索，不要直接下动作结论。"
    return base


def _predictive_logit_term_meaning(
    term: str,
    odds_ratio: Any,
    p_value: Any,
    target: str,
    *,
    report_lens: str,
) -> str:
    term_text = str(term or "").strip()
    if term_text.lower() == "const":
        return "常数项只代表模型基线，不对应具体经营动作。"

    overlap_note = _predictive_overlap_note(term_text, target)
    if overlap_note:
        return overlap_note

    odds_ratio_value = _safe_float(odds_ratio)
    p_value_float = _safe_float(p_value)
    target_label = _predictive_target_label(target)

    if odds_ratio_value is None:
        base = f"该字段对 `{target_label}` 概率的影响当前不可稳定解释。"
    elif odds_ratio_value > 1.05:
        base = f"优势比大于 1，说明该字段抬升时，`{target_label}` 发生概率更高。"
    elif odds_ratio_value < 0.95:
        base = f"优势比小于 1，说明该字段抬升时，`{target_label}` 发生概率更低。"
    else:
        base = f"优势比接近 1，说明该字段对 `{target_label}` 的概率影响偏弱。"

    if report_lens == "procurement_sales_review":
        lowered = term_text.lower()
        if lowered == "quantity":
            base = f"它更像订单结构信号，适合继续看件数变化是否在推高或压低 `{target_label}` 风险。"
        elif lowered == "freightcost":
            base = f"它更像履约难度代理，适合继续排查高运费对象是否更容易出现 `{target_label}`。"

    if p_value_float is not None and p_value_float > 0.05:
        return f"{base} 但当前 p 值偏高，只适合作为弱信号排查。"
    return base


def _localized_predictive_table(
    table: dict[str, Any],
    *,
    analysis_type: str,
    target: str,
    report_lens: str,
) -> dict[str, Any]:
    rows: list[dict[str, Any]] = []
    for raw_row in table.get("rows", []) or []:
        if not isinstance(raw_row, dict):
            continue
        row = {str(key): _safe_value(value) for key, value in raw_row.items()}
        term = str(row.get("term") or row.get("项") or "")
        if term:
            row["term"] = _predictive_term_label(term)
        if analysis_type == "ols":
            row["business_meaning"] = _predictive_linear_term_meaning(
                term,
                row.get("coefficient"),
                row.get("p_value"),
                target,
                report_lens=report_lens,
            )
        elif analysis_type == "logit":
            row["business_meaning"] = _predictive_logit_term_meaning(
                term,
                row.get("odds_ratio"),
                row.get("p_value"),
                target,
                report_lens=report_lens,
            )
        rows.append(row)
    return _table(_localize_table_title(str(table.get("title") or "")), rows)


def _localized_predictive_chart(chart: dict[str, Any] | None) -> dict[str, Any] | None:
    if not chart:
        return None
    localized = dict(chart)
    localized["title"] = _localize_table_title(str(chart.get("title") or ""))
    x_values = chart.get("x")
    if isinstance(x_values, list):
        localized["x"] = [_predictive_term_label(str(item)) for item in x_values]
    return localized


def _predictive_bullet_cn(
    result: dict[str, Any],
    *,
    analysis_type: str,
    target: str,
    report_lens: str,
) -> str:
    metrics = result.get("metrics", {}) or {}
    strongest_term = str(metrics.get("strongest_term") or "").strip()
    strongest_row = None
    for row in result.get("tables", [{}])[0].get("rows", []) if result.get("tables") else []:
        if str(row.get("term") or "").strip() == strongest_term:
            strongest_row = row
            break

    target_label = _predictive_target_label(target)
    strongest_label = _predictive_term_label(strongest_term) if strongest_term else "当前最强字段"

    if analysis_type == "ols":
        adjusted_r_squared = _safe_float(metrics.get("adjusted_r_squared"))
        observations = metrics.get("observations")
        coefficient = _safe_float((strongest_row or {}).get("coefficient"))
        overlap_note = _predictive_overlap_note(strongest_term, target)
        head = f"线性模型在 {observations:,} 条完整样本上对 `{target_label}` 的调整后 R² 为 {adjusted_r_squared:.3f}。"
        if strongest_term and coefficient is not None:
            if overlap_note:
                tail = f"当前绝对值最大的系数来自 `{strongest_label}`（{coefficient:.4f}），但它和目标口径高度同源，更像结果同步，不应直接写成业务驱动。"
            else:
                tail = f"当前绝对值最大的系数来自 `{strongest_label}`（{coefficient:.4f}），它是现阶段最值得继续追踪的变化信号。"
        else:
            tail = "当前模型能提供方向参考，但最强驱动项还需要结合表中系数进一步复核。"
        return f"{head} {tail}"

    pseudo_r_squared = _safe_float(metrics.get("pseudo_r_squared"))
    odds_ratio = _safe_float((strongest_row or {}).get("odds_ratio"))
    if pseudo_r_squared is not None and pseudo_r_squared < 0.05:
        strength_text = f"概率模型对 `{target_label}` 的解释力偏弱（McFadden 伪 R²={pseudo_r_squared:.3f}）"
    else:
        strength_text = f"概率模型对 `{target_label}` 的解释力尚可（McFadden 伪 R²={pseudo_r_squared:.3f}）" if pseudo_r_squared is not None else f"概率模型给出了 `{target_label}` 的方向线索"
    if strongest_term and odds_ratio is not None:
        tail = f"，当前最强信号是 `{strongest_label}` 的优势比 {odds_ratio:.3f}。这更适合当风险排查线索，不宜单独当成经营结论。"
    else:
        tail = "，但当前最强信号仍需结合表中系数进一步复核。"
    return f"{strength_text}{tail}"


def _layer_runtime_state(layer: Any) -> str:
    if not isinstance(layer, dict):
        return "missing"
    state = str(layer.get("runtime_state") or "").strip().lower()
    if state in {"live", "fallback"}:
        return state
    mode = str(layer.get("mode") or "").strip().lower()
    if mode.startswith("live_codex"):
        return "live"
    if mode == "fallback":
        return "fallback"
    return "unknown"


def _build_intelligence_runtime_status(
    *,
    report_lens: str,
    semantic_layer: dict[str, Any],
    metric_interpretation_layer: dict[str, Any],
    method_review_layer: dict[str, Any],
    codex_layer: dict[str, Any],
    semantic_expansion: dict[str, Any],
    business_background_layer: dict[str, Any],
    business_object_layer: dict[str, Any],
    commercial_dimension_layer: dict[str, Any],
    reasoning_layers: dict[str, Any],
    followup_mining_layer: dict[str, Any] | None,
) -> dict[str, Any]:
    layers = [
        {"layer": "semantic_layer", "runtime_state": _layer_runtime_state(semantic_layer), "mode": semantic_layer.get("mode"), "fallback_reason": semantic_layer.get("fallback_reason") or semantic_layer.get("reason")},
        {"layer": "metric_interpretation", "runtime_state": _layer_runtime_state(metric_interpretation_layer), "mode": metric_interpretation_layer.get("mode"), "fallback_reason": metric_interpretation_layer.get("fallback_reason") or metric_interpretation_layer.get("reason")},
        {"layer": "method_review", "runtime_state": _layer_runtime_state(method_review_layer), "mode": method_review_layer.get("mode"), "fallback_reason": method_review_layer.get("fallback_reason") or method_review_layer.get("reason")},
        {"layer": "codex_layer", "runtime_state": _layer_runtime_state(codex_layer), "mode": codex_layer.get("mode"), "fallback_reason": codex_layer.get("fallback_reason") or codex_layer.get("reason")},
        {"layer": "semantic_expansion", "runtime_state": _layer_runtime_state(semantic_expansion), "mode": semantic_expansion.get("mode"), "fallback_reason": semantic_expansion.get("fallback_reason") or semantic_expansion.get("reason")},
        {"layer": "business_background", "runtime_state": _layer_runtime_state(business_background_layer), "mode": business_background_layer.get("mode"), "fallback_reason": business_background_layer.get("fallback_reason") or business_background_layer.get("reason")},
        {"layer": "business_object", "runtime_state": _layer_runtime_state(business_object_layer), "mode": business_object_layer.get("mode"), "fallback_reason": business_object_layer.get("fallback_reason") or business_object_layer.get("reason")},
        {"layer": "commercial_dimension", "runtime_state": _layer_runtime_state(commercial_dimension_layer), "mode": commercial_dimension_layer.get("mode"), "fallback_reason": commercial_dimension_layer.get("fallback_reason") or commercial_dimension_layer.get("reason")},
        {"layer": "evidence_digest", "runtime_state": _layer_runtime_state(reasoning_layers.get("evidence_digest_layer", {})), "mode": (reasoning_layers.get("evidence_digest_layer", {}) or {}).get("mode"), "fallback_reason": (reasoning_layers.get("evidence_digest_layer", {}) or {}).get("fallback_reason") or (reasoning_layers.get("evidence_digest_layer", {}) or {}).get("reason")},
        {"layer": "insight_mining", "runtime_state": _layer_runtime_state(reasoning_layers.get("insight_mining_layer", {})), "mode": (reasoning_layers.get("insight_mining_layer", {}) or {}).get("mode"), "fallback_reason": (reasoning_layers.get("insight_mining_layer", {}) or {}).get("fallback_reason") or (reasoning_layers.get("insight_mining_layer", {}) or {}).get("reason")},
        {"layer": "business_synthesis", "runtime_state": _layer_runtime_state(reasoning_layers.get("business_judgement_layer", {})), "mode": (reasoning_layers.get("business_judgement_layer", {}) or {}).get("mode"), "fallback_reason": (reasoning_layers.get("business_judgement_layer", {}) or {}).get("fallback_reason") or (reasoning_layers.get("business_judgement_layer", {}) or {}).get("reason")},
        {"layer": "decision_design", "runtime_state": _layer_runtime_state(reasoning_layers.get("decision_design_layer", {})), "mode": (reasoning_layers.get("decision_design_layer", {}) or {}).get("mode"), "fallback_reason": (reasoning_layers.get("decision_design_layer", {}) or {}).get("fallback_reason") or (reasoning_layers.get("decision_design_layer", {}) or {}).get("reason")},
        {"layer": "anti_generic_review", "runtime_state": _layer_runtime_state(reasoning_layers.get("anti_generic_layer", {})), "mode": (reasoning_layers.get("anti_generic_layer", {}) or {}).get("mode"), "fallback_reason": (reasoning_layers.get("anti_generic_layer", {}) or {}).get("fallback_reason") or (reasoning_layers.get("anti_generic_layer", {}) or {}).get("reason")},
        {"layer": "final_polish", "runtime_state": _layer_runtime_state(reasoning_layers.get("final_polish_layer", {})), "mode": (reasoning_layers.get("final_polish_layer", {}) or {}).get("mode"), "fallback_reason": (reasoning_layers.get("final_polish_layer", {}) or {}).get("fallback_reason") or (reasoning_layers.get("final_polish_layer", {}) or {}).get("reason")},
        {"layer": "judge_feedback", "runtime_state": _layer_runtime_state(reasoning_layers.get("judge_feedback_layer", {})), "mode": (reasoning_layers.get("judge_feedback_layer", {}) or {}).get("mode"), "fallback_reason": (reasoning_layers.get("judge_feedback_layer", {}) or {}).get("fallback_reason") or (reasoning_layers.get("judge_feedback_layer", {}) or {}).get("reason")},
        {"layer": "followup_mining", "runtime_state": _layer_runtime_state(followup_mining_layer or {}), "mode": (followup_mining_layer or {}).get("mode"), "fallback_reason": (followup_mining_layer or {}).get("fallback_reason") or (followup_mining_layer or {}).get("reason")},
    ]
    critical_by_lens = {
        "procurement_sales_review": ["semantic_layer", "metric_interpretation", "method_review", "semantic_expansion", "evidence_digest", "insight_mining", "business_synthesis", "anti_generic_review", "followup_mining"],
        "sales_review": ["semantic_layer", "metric_interpretation", "method_review", "semantic_expansion", "evidence_digest", "insight_mining", "business_synthesis", "anti_generic_review"],
        "management_accounting_review": ["semantic_layer", "metric_interpretation", "method_review", "semantic_expansion", "evidence_digest", "insight_mining", "business_synthesis", "anti_generic_review"],
        "mixed_business_review": ["semantic_layer", "metric_interpretation", "semantic_expansion", "evidence_digest", "insight_mining", "business_synthesis", "anti_generic_review", "followup_mining"],
    }
    critical_names = set(critical_by_lens.get(report_lens, ["semantic_layer", "metric_interpretation", "business_synthesis"]))
    critical_layers = [layer for layer in layers if layer["layer"] in critical_names]
    fallback_layers = [layer for layer in critical_layers if layer["runtime_state"] == "fallback"]
    overall_state = "live" if not fallback_layers else "fallback_detected"
    return {
        "overall_state": overall_state,
        "layers": layers,
        "critical_layers": critical_layers,
        "fallback_layers": fallback_layers,
        "hard_degraded": bool(fallback_layers),
    }


def _section(
    section_id: str,
    title: str,
    summary: str,
    bullets: list[str],
    tables: list[dict[str, Any]] | None = None,
    charts: list[dict[str, Any]] | None = None,
) -> dict[str, Any]:
    return {
        "id": section_id,
        "title": title,
        "summary": summary,
        "bullets": bullets,
        "tables": tables or [],
        "charts": [chart for chart in (charts or []) if chart],
    }


def _recommended_methods(numeric_cols: list[str], categorical_cols: list[str], temporal_cols: list[str]) -> list[dict[str, Any]]:
    catalog = get_statistical_catalog()
    recommendations: list[dict[str, Any]] = []
    for item in catalog:
        variable_types = set(item["variable_types"])
        score = 0
        if "multi_numeric" in variable_types or "numeric" in variable_types or "numeric_or_binary" in variable_types:
            if numeric_cols:
                score += 2
        if "categorical" in variable_types or "binary_group" in variable_types:
            if categorical_cols:
                score += 2
        if "time" in variable_types or "time_to_event" in variable_types:
            if temporal_cols:
                score += 2
        if item["status"] == "live":
            score += 2
        if score >= 4:
            recommendations.append(
                {
                    "id": item["id"],
                    "method": item["name"],
                    "family": item["family"],
                    "status": item["status"],
                    "goal": item["goal"],
                    "score": score,
                }
            )
    recommendations.sort(key=lambda item: (item["status"] != "live", -item["score"], item["family"], item["method"]))
    return recommendations[:20]


def _build_statistical_method_selection_context(
    *,
    report_lens: str,
    request: SmartReportRequest,
    numeric_cols: list[str],
    categorical_cols: list[str],
    temporal_cols: list[str],
    candidate_methods: list[dict[str, Any]],
    catalog_summary: dict[str, Any],
) -> dict[str, Any]:
    return {
        "report_lens": report_lens,
        "user_requirement": request.user_requirement,
        "problem_to_solve": request.problem_to_solve,
        "target_audience": request.target_audience,
        "core_purpose": request.core_purpose,
        "expected_result": request.expected_result,
        "numeric_columns": numeric_cols[:12],
        "categorical_columns": categorical_cols[:12],
        "temporal_columns": temporal_cols[:8],
        "candidate_methods": candidate_methods[:20],
        "catalog_summary": catalog_summary,
    }


def _table(title: str, rows: list[dict[str, Any]], note: str | None = None) -> dict[str, Any]:
    original_columns: list[str] = []
    for row in rows:
        for key in row.keys():
            key_text = str(key)
            if key_text not in original_columns:
                original_columns.append(key_text)
    localized_columns: list[str] = []
    column_map: dict[str, str] = {}
    used_columns: set[str] = set()
    for original in original_columns:
        localized = _localize_table_column_name(str(original))
        base_name = localized
        suffix = 2
        while localized in used_columns:
            localized = f"{base_name}{suffix}"
            suffix += 1
        used_columns.add(localized)
        localized_columns.append(localized)
        column_map[str(original)] = localized
    localized_rows = []
    for row in rows:
        localized_row: dict[str, Any] = {}
        for key, value in row.items():
            key_text = str(key)
            safe_value = _safe_value(value)
            if _should_format_table_value_as_percent(key_text):
                percent_value = _table_value_to_percent(safe_value)
                if percent_value is not None:
                    safe_value = percent_value
            localized_row[column_map.get(key_text, key_text)] = safe_value
        localized_rows.append(localized_row)
    localized_rows = _dedupe_table_rows(localized_columns, localized_rows)
    table_note = note if note is not None else _table_caption_text(str(title or ""), original_columns, localized_columns, localized_rows)
    return {
        "title": title,
        "columns": localized_columns,
        "rows": localized_rows,
        "note": table_note,
    }


def _table_min_width_px(table: dict[str, Any]) -> int:
    columns = list(table.get("columns") or [])
    title = str(table.get("title") or "").lower()
    width = max(920, min(2600, max(1, len(columns)) * 150))
    if any(token in title for token in ("semantic_metric", "metric_derivation", "metric_opportunity", "action_table")):
        width = max(width, 1600)
    return width


def _metric_artifact_dir_from_report(report: dict[str, Any]) -> Path | None:
    result_path = str(report.get("semantic_metric_result_path") or "").strip()
    if not result_path:
        return None
    try:
        return Path(result_path).parent
    except Exception:
        return None


def _read_metric_artifact_json(report: dict[str, Any], file_name: str) -> dict[str, Any]:
    artifact_dir = _metric_artifact_dir_from_report(report)
    if not artifact_dir:
        return {}
    path = artifact_dir / file_name
    if not path.exists():
        return {}
    try:
        payload = json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return {}
    return payload if isinstance(payload, dict) else {}


def _stringify_metric_cell(value: Any) -> str:
    if value is None:
        return ""
    if isinstance(value, float) and np.isnan(value):
        return ""
    if isinstance(value, (dict, list, tuple, set)):
        return json.dumps(value, ensure_ascii=False, default=str)
    return str(value)


def _semantic_field_list_text(value: Any, *, max_items: int = 8) -> str:
    items: list[str] = []
    if isinstance(value, str):
        raw = value.strip()
        if raw.startswith("[") and raw.endswith("]"):
            try:
                parsed = json.loads(raw)
            except Exception:
                parsed = None
            if isinstance(parsed, list):
                value = parsed
        elif "," in raw:
            value = [part.strip() for part in raw.split(",") if part.strip()]
    if isinstance(value, (list, tuple, set)):
        items = [str(item).strip() for item in value if str(item).strip()]
    elif value is not None:
        text = str(value).strip()
        if text:
            items = [text]
    if not items:
        return ""
    display_items = items[:max_items]
    rendered = "\n".join(display_items)
    if len(items) > max_items:
        rendered += f"\n…共 {len(items)} 项"
    return rendered


def _semantic_pattern_text(value: Any, *, max_items: int = 4) -> str:
    if not isinstance(value, (list, tuple)):
        return _stringify_metric_cell(value)
    blocks: list[str] = []
    for index, item in enumerate(list(value)[:max_items], start=1):
        if not isinstance(item, dict):
            text = str(item).strip()
            if text:
                blocks.append(f"{index}. {text}")
            continue
        role_text = " + ".join(str(role).strip() for role in item.get("required_roles") or [] if str(role).strip()) or "无"
        matched = [str(field).strip() for field in item.get("matched_fields") or [] if str(field).strip()]
        missing = [str(role).strip() for role in item.get("missing_roles") or [] if str(role).strip()]
        feasibility = str(item.get("feasibility") or "").strip() or "unknown"
        matched_text = "、".join(matched[:6]) if matched else "无"
        if len(matched) > 6:
            matched_text += f" 等 {len(matched)} 个字段"
        missing_text = "、".join(missing) if missing else "无"
        blocks.append(
            f"{index}. 角色：{role_text}；命中：{matched_text}；缺失：{missing_text}；可计算性：{feasibility}"
        )
    if len(value) > max_items:
        blocks.append(f"…共 {len(value)} 组模式")
    return "\n".join(blocks)


def _semantic_structured_value_text(value: Any, *, max_items: int = 6) -> str:
    if isinstance(value, str):
        raw = value.strip()
        if raw.startswith("[") and raw.endswith("]"):
            try:
                parsed = json.loads(raw)
            except Exception:
                parsed = None
            if parsed is not None:
                value = parsed
    if isinstance(value, (list, tuple)):
        lines: list[str] = []
        for index, item in enumerate(list(value)[:max_items], start=1):
            if isinstance(item, dict):
                dimension = str(item.get("dimension") or item.get("date") or item.get("label") or item.get("name") or item.get("segment") or f"项{index}").strip()
                item_value = item.get("value")
                share = item.get("share")
                count = item.get("count")
                parts = [f"{index}. {dimension}"]
                if item_value not in (None, ""):
                    parts.append(f"值 {_display_table_value('value', item_value)}")
                if share not in (None, ""):
                    parts.append(f"占比 {_display_table_value('share', share)}")
                if count not in (None, ""):
                    parts.append(f"数量 {_display_table_value('count', count)}")
                lines.append("；".join(parts))
            else:
                text = str(item).strip()
                if text:
                    lines.append(f"{index}. {text}")
        if len(value) > max_items:
            lines.append(f"…共 {len(value)} 项")
        return "\n".join(lines)
    if isinstance(value, dict):
        parts = []
        for key, item_value in list(value.items())[:8]:
            key_text = _localize_table_column_name(str(key))
            parts.append(f"{key_text}：{_display_table_value(str(key), item_value)}")
        if len(value) > 8:
            parts.append(f"…共 {len(value)} 个字段")
        return "\n".join(parts)
    return _stringify_metric_cell(value)


def _semantic_text_wrap(value: Any) -> str:
    text = _stringify_metric_cell(value)
    if not text:
        return ""
    return (
        text.replace("; can also ", "\n可进一步按 ")
        .replace("; ", "\n")
        .replace(" / ", "\n")
    )


def _semantic_metric_table_cell(column_name: str, value: Any) -> str:
    normalized = str(column_name or "").strip().lower()
    if normalized in {"source_fields", "matched_fields", "missing_fields", "candidate_metric_ids", "forbidden_without_roles", "downstream_usage_rules", "allowed_downstream_usage", "forbidden_downstream_usage"}:
        return _semantic_field_list_text(value)
    if normalized in {"matched_patterns"}:
        return _semantic_pattern_text(value)
    if normalized in {"value"}:
        return _semantic_structured_value_text(value)
    if normalized in {"grain", "formula", "formula_or_logic", "calculation_method", "caveat", "reason", "unsupported_reason"}:
        return _semantic_text_wrap(value)
    return _stringify_metric_cell(value)


def _semantic_metric_result_rows(report: dict[str, Any]) -> list[dict[str, Any]]:
    payload = report.get("semantic_metric_result") or {}
    rows: list[dict[str, Any]] = []
    for item in payload.get("results") or []:
        if not isinstance(item, dict):
            continue
        rows.append(
            {
                "metric_id": item.get("metric_id", ""),
                "metric_name_cn": item.get("metric_name_cn") or item.get("metric_name") or "",
                "value": _semantic_metric_table_cell("value", item.get("value")),
                "grain": _semantic_metric_table_cell("grain", item.get("grain", "")),
                "source_fields": _semantic_metric_table_cell("source_fields", item.get("source_fields")),
                "formula": _semantic_metric_table_cell("formula", item.get("formula") or item.get("formula_or_logic") or ""),
                "calculation_method": _semantic_metric_table_cell("calculation_method", item.get("calculation_method", "")),
                "evidence_level": item.get("evidence_level", ""),
                "confidence": item.get("confidence", ""),
                "caveat": _semantic_metric_table_cell("caveat", item.get("caveat", "")),
                "status": item.get("status", ""),
                "unsupported_reason": _semantic_metric_table_cell("unsupported_reason", item.get("unsupported_reason", "")),
            }
        )
    return rows


def _semantic_metric_result_expanded_rows(report: dict[str, Any]) -> list[dict[str, Any]]:
    payload = report.get("semantic_metric_result") or {}
    rows: list[dict[str, Any]] = []
    for item in payload.get("results") or []:
        if not isinstance(item, dict):
            continue
        value = item.get("value")
        if not isinstance(value, list):
            continue
        for index, entry in enumerate(value, start=1):
            if isinstance(entry, dict):
                rows.append(
                    {
                        "metric_id": item.get("metric_id", ""),
                        "metric_name_cn": item.get("metric_name_cn") or item.get("metric_name") or "",
                        "rank": index,
                        "dimension": entry.get("dimension") or entry.get("date") or entry.get("label") or entry.get("name") or entry.get("segment") or f"项{index}",
                        "value": entry.get("value", ""),
                        "share": entry.get("share", ""),
                        "count": entry.get("count", ""),
                    }
                )
            else:
                rows.append(
                    {
                        "metric_id": item.get("metric_id", ""),
                        "metric_name_cn": item.get("metric_name_cn") or item.get("metric_name") or "",
                        "rank": index,
                        "dimension": str(entry),
                        "value": "",
                        "share": "",
                        "count": "",
                    }
                )
    return rows


def _semantic_metric_plan_rows(report: dict[str, Any]) -> list[dict[str, Any]]:
    payload = _read_metric_artifact_json(report, "semantic_metric_plan.json")
    plan_rows = list(payload.get("metric_plans") or [])
    if not plan_rows:
        ai_plan = ((report.get("ai_mandatory") or {}).get("metric_plan") or {}).get("metric_plans") or []
        plan_rows = list(ai_plan)
    rows: list[dict[str, Any]] = []
    for item in plan_rows:
        if not isinstance(item, dict):
            continue
        rows.append(
            {
                "metric_id": item.get("metric_id", ""),
                "metric_name_cn": item.get("metric_name_cn", ""),
                "metric_family": item.get("metric_family", ""),
                "business_object": item.get("business_object", ""),
                "metric_type": item.get("metric_type", ""),
                "matched_fields": _semantic_metric_table_cell("matched_fields", item.get("matched_fields")),
                "missing_fields": _semantic_metric_table_cell("missing_fields", item.get("missing_fields")),
                "formula_or_logic": _semantic_metric_table_cell("formula_or_logic", item.get("formula_or_logic") or item.get("formula") or ""),
                "grain": _semantic_metric_table_cell("grain", item.get("grain", "")),
                "evidence_level": item.get("evidence_level", ""),
                "confidence": item.get("confidence", ""),
                "allowed_downstream_usage": _semantic_metric_table_cell("allowed_downstream_usage", item.get("allowed_downstream_usage") or item.get("downstream_usage") or ""),
                "forbidden_downstream_usage": _semantic_metric_table_cell("forbidden_downstream_usage", item.get("forbidden_downstream_usage") or item.get("forbidden_usage") or ""),
                "caveat": _semantic_metric_table_cell("caveat", item.get("caveat", "")),
                "reason": _semantic_metric_table_cell("reason", item.get("reason", "")),
            }
        )
    return rows


def _metric_derivation_log_rows(report: dict[str, Any]) -> list[dict[str, Any]]:
    log_path = str(report.get("metric_derivation_log_path") or "").strip()
    if not log_path:
        return []
    path = Path(log_path)
    if not path.exists():
        return []
    try:
        frame = pd.read_csv(path)
    except Exception:
        return []
    return [
        {
            str(column): _semantic_metric_table_cell(str(column), row[column])
            for column in frame.columns
        }
        for _, row in frame.iterrows()
    ]


def _metric_opportunity_graph_rows(report: dict[str, Any]) -> list[dict[str, Any]]:
    payload = _read_metric_artifact_json(report, "metric_opportunity_graph.json")
    rows: list[dict[str, Any]] = []
    for node in payload.get("nodes") or []:
        if not isinstance(node, dict):
            continue
        rows.append(
            {
                "metric_family": node.get("metric_family", ""),
                "candidate_metric_ids": _semantic_metric_table_cell("candidate_metric_ids", node.get("candidate_metric_ids")),
                "best_feasibility": node.get("best_feasibility", ""),
                "matched_patterns": _semantic_metric_table_cell("matched_patterns", node.get("matched_patterns")),
                "forbidden_without_roles": _semantic_metric_table_cell("forbidden_without_roles", node.get("forbidden_without_roles")),
                "calculation_executor": node.get("calculation_executor", ""),
                "downstream_usage_rules": _semantic_metric_table_cell("downstream_usage_rules", node.get("downstream_usage_rules")),
            }
        )
    return rows


def _semantic_metric_management_section(report: dict[str, Any]) -> dict[str, Any] | None:
    result_rows = _semantic_metric_result_rows(report)
    plan_rows = _semantic_metric_plan_rows(report)
    if not result_rows and not plan_rows:
        return None
    status_counts = Counter(str(row.get("status") or "unknown") for row in result_rows)
    evidence_counts = Counter(str(row.get("evidence_level") or "unknown") for row in result_rows)
    metric_count = len(result_rows)
    calculated_count = sum(
        count
        for status, count in status_counts.items()
        if status in {"calculated", "proxy_calculated"}
    )
    summary_rows = [
        {"item": "metric_result_count", "value": metric_count},
        {"item": "calculated_or_proxy_count", "value": calculated_count},
        {"item": "status_distribution", "value": _stringify_metric_cell(dict(status_counts))},
        {"item": "evidence_distribution", "value": _stringify_metric_cell(dict(evidence_counts))},
    ]
    return _section(
        "semantic_metric_scorecard",
        "智能指标构建结果",
        "本页把 AI 指标规划和确定性 pandas 计算结果接回正文，管理层看到的指标必须能追溯到 metric_id、证据等级和计算方法。",
        [
            "AI 只负责字段理解和指标规划，数值来自 DeterministicMetricExecutor。",
            "direct / derived 指标可进入核心结论；proxy / diagnostic / unavailable 必须保留边界说明。",
            "完整规划、计算结果、机会图和计算日志在 analyst_appendix 与 Excel 中全量保留。",
        ],
        tables=[
            _table("semantic_metric_summary", summary_rows),
        ],
    )


def _semantic_metric_appendix_sections(report: dict[str, Any]) -> list[dict[str, Any]]:
    result_rows = _semantic_metric_result_rows(report)
    expanded_result_rows = _semantic_metric_result_expanded_rows(report)
    plan_rows = _semantic_metric_plan_rows(report)
    log_rows = _metric_derivation_log_rows(report)
    opportunity_rows = _metric_opportunity_graph_rows(report)
    sections: list[dict[str, Any]] = []
    if result_rows:
        sections.append(
            _section(
                "appendix_semantic_metric_result",
                "智能指标确定性计算结果附录",
                "全量保留 semantic_metric_result.json 中的指标结果，供分析师复核数值、口径、证据等级和状态。",
                ["这张表是智能指标构建进入报告交付物的主表，不再只作为 sidecar JSON。", "结构化列表型指标会在下一张明细表中按逐行记录完整展开。"],
                tables=[_table("semantic_metric_result", result_rows)],
            )
        )
    if expanded_result_rows:
        sections.append(
            _section(
                "appendix_semantic_metric_result_expanded",
                "智能指标结构化明细附录",
                "把 list / groupby / share 型指标按逐行明细展开，避免只在单个单元格里显示前几项摘要。",
                ["需要看完整的类目、卖家、日趋势、集中度明细时，请优先查看这张展开表。"],
                tables=[_table("semantic_metric_result_expanded", expanded_result_rows)],
            )
        )
    if plan_rows:
        sections.append(
            _section(
                "appendix_semantic_metric_plan",
                "AI 指标规划附录",
                "全量保留 semantic_metric_plan.json / AIMetricDerivationPlan 中的指标规划、字段匹配、下游用途和禁止用途。",
                ["这张表用于确认哪些指标可计算、哪些只能代理、哪些只适合诊断问题。"],
                tables=[_table("semantic_metric_plan", plan_rows)],
            )
        )
    if opportunity_rows:
        sections.append(
            _section(
                "appendix_metric_opportunity_graph",
                "指标机会图附录",
                "全量保留 metric_opportunity_graph.json 的指标族机会、字段角色组合和可计算性判断。",
                ["机会图说明系统为什么会规划这些指标，而不是只根据固定字段名猜测。"],
                tables=[_table("metric_opportunity_graph", opportunity_rows)],
            )
        )
    if log_rows:
        sections.append(
            _section(
                "appendix_metric_derivation_log",
                "指标计算日志附录",
                "全量保留 metric_derivation_log.csv，便于审计每个指标的执行状态、失败原因和来源字段。",
                ["计算失败不能静默跳过；失败、不可用和代理计算都会在这里留下记录。"],
                tables=[_table("metric_derivation_log", log_rows)],
            )
        )
    return sections


def _extend_report_with_semantic_metric_sections(report: dict[str, Any]) -> None:
    sections = list(report.get("sections") or [])
    existing_ids = {str(section.get("id") or "") for section in sections}
    management_section = _semantic_metric_management_section(report)
    if management_section and str(management_section.get("id") or "") not in existing_ids:
        _insert_section_after(
            sections,
            management_section,
            anchor_ids=["decision_summary", "business_judgement", "metric_contract"],
        )
        existing_ids.add(str(management_section.get("id") or ""))
    for appendix_section in _semantic_metric_appendix_sections(report):
        section_id = str(appendix_section.get("id") or "")
        if section_id and section_id not in existing_ids:
            sections.append(appendix_section)
            existing_ids.add(section_id)
    report["sections"] = sections


def _extend_variant_with_semantic_metric_sections(
    variant: dict[str, Any] | None,
    report: dict[str, Any],
    *,
    include_management: bool = False,
    include_appendix: bool = False,
) -> dict[str, Any] | None:
    if not variant:
        return variant
    sections = list(variant.get("sections") or [])
    existing_ids = {str(section.get("id") or "") for section in sections}
    if include_management:
        management_section = _semantic_metric_management_section(report)
        if management_section and str(management_section.get("id") or "") not in existing_ids:
            sections.insert(min(2, len(sections)), management_section)
            existing_ids.add(str(management_section.get("id") or ""))
    if include_appendix:
        for appendix_section in _semantic_metric_appendix_sections(report):
            section_id = str(appendix_section.get("id") or "")
            if section_id and section_id not in existing_ids:
                sections.append(appendix_section)
                existing_ids.add(section_id)
    variant["sections"] = sections
    if include_management:
        strategy_ids = list(variant.get("strategy_management_ids") or [])
        if "semantic_metric_scorecard" not in strategy_ids and any(
            str(section.get("id") or "") == "semantic_metric_scorecard" for section in sections
        ):
            strategy_ids.append("semantic_metric_scorecard")
            variant["strategy_management_ids"] = strategy_ids
    return variant


