def _insert_section_after(
    sections: list[dict[str, Any]],
    new_section: dict[str, Any] | None,
    *,
    anchor_ids: list[str] | tuple[str, ...],
) -> None:
    if not new_section:
        return
    new_id = str(new_section.get("id") or "").strip()
    if not new_id or any(str(section.get("id") or "") == new_id for section in sections):
        return
    insert_at = None
    for index, section in enumerate(sections):
        if str(section.get("id") or "") in set(anchor_ids):
            insert_at = index + 1
    if insert_at is None:
        sections.insert(0, new_section)
    else:
        sections.insert(insert_at, new_section)


def _upsert_section_after(
    sections: list[dict[str, Any]],
    new_section: dict[str, Any] | None,
    *,
    anchor_ids: list[str] | tuple[str, ...],
) -> None:
    if not new_section:
        return
    new_id = str(new_section.get("id") or "").strip()
    if new_id:
        sections[:] = [section for section in sections if str(section.get("id") or "").strip() != new_id]
    _insert_section_after(sections, new_section, anchor_ids=anchor_ids)


def _first_section_bullet(sections: list[dict[str, Any]], section_id: str) -> str:
    section = next((item for item in sections if item.get("id") == section_id), None)
    if not section:
        return ""
    bullets = [str(item).strip() for item in section.get("bullets", []) if str(item).strip()]
    if bullets:
        return bullets[0]
    return str(section.get("summary") or "").strip()


def _generic_executive_summary_from_sections(
    *,
    sections: list[dict[str, Any]],
    report_lens: str,
    problem: str,
    object_type: str,
) -> list[str]:
    lens_summary = {
        "performance_benchmark": "这份输出优先回答系统是否稳定、边界在哪里，以及当前瓶颈出现在什么环节。",
        "internet_ops_review": "这份输出优先回答新增、活跃、留存和转化差异，并把重点放在渠道、活动和内容承接上。",
        "foundation_review": "这份输出优先回答项目结构、资金去向、支持对象和执行节奏，而不是停留在表面盘点。",
        "management_accounting_review": "这份输出优先回答利润质量、预算偏差、营运资本和责任中心差异，直接服务经营判断。",
        "procurement_sales_review": "这份输出优先回答商品/SKU结构、卖家协同、履约售后和经营动作，直接服务采销决策。",
        "sales_review": "这份输出优先回答结构、趋势、增长来源和关键切片差异，直接服务经营和销售动作。",
        "consumer_research": "这份输出优先回答样本结构、关键差异、分群和洞察，直接服务研究与策略输入。",
        "brand_listening": "这份输出优先回答主题、情绪、品牌联想和风险变化，直接服务品牌与公关判断。",
        "experiment_review": "这份输出优先回答实验结果、效果边界和下一步动作，直接服务放量或复验决策。",
    }.get(report_lens, "这份输出优先回答当前业务问题，并把结论压成能直接进入会场和动作的表达。")
    candidates = [
        lens_summary,
        f"当前数据更像 `{object_type}`，因此管理层正文会先讲观察单位、总量盘子和关键切片，再进入风险和动作。",
        _first_section_bullet(sections, "decision_summary"),
        _first_section_bullet(sections, "management_story"),
        _first_section_bullet(sections, "ops_topline"),
        _first_section_bullet(sections, "ops_channel_scorecard"),
        _first_section_bullet(sections, "ops_activity_scorecard"),
        _first_section_bullet(sections, "numeric"),
        _first_section_bullet(sections, "market_landscape"),
        _first_section_bullet(sections, "category"),
        _first_section_bullet(sections, "temporal"),
        _first_section_bullet(sections, "risk_alerts"),
        _first_section_bullet(sections, "confidence_boundary"),
        _first_section_bullet(sections, "next_steps"),
        _first_section_bullet(sections, "action_roadmap"),
        _first_section_bullet(sections, "predictive"),
    ]
    bullets: list[str] = []
    for candidate in candidates:
        text = str(candidate or "").strip()
        if not text or text in bullets:
            continue
        if "质量分" in text or "workflow" in text or "自动审计" in text:
            continue
        bullets.append(text)
        if len(bullets) >= 6:
            break
    if not bullets:
        return [
            f"当前输出主要服务于：{_stable_business_text(problem, '形成可执行判断')}。",
            lens_summary,
        ]
    return bullets[:6]


