def _field_dictionary_section(metadata: dict[str, Any], program_bundle: dict[str, Any]) -> dict[str, Any]:
    semantic_mapping = program_bundle.get("semantic_mapping", {})
    role_lookup = {
        item["column"]: (item.get("best_role", "unmapped"), item.get("best_confidence", "low"))
        for item in semantic_mapping.get("columns", [])
    }
    rows = []
    for item in metadata.get("column_summaries", []):
        role, confidence = role_lookup.get(item["name"], ("unmapped", "low"))
        stats = item.get("stats", {})
        summary = (
            f"均值 {item['stats'].get('mean')} / 极值 {item['stats'].get('min')} - {item['stats'].get('max')}"
            if "mean" in stats
            else "；".join(f"{row['label']}({row['count']})" for row in stats.get("top_values", []))
        )
        rows.append(
            {
                "字段": item["name"],
                "角色映射": role,
                "置信度": confidence,
                "类型": item["dtype"],
                "缺失率": _format_percent(item["missing_ratio"]),
                "去重后值数": item["unique_count"],
                "样本值/统计": summary,
            }
        )
    return _section(
        "field_dictionary",
        "字段词典与口径页",
        "这部分把每个字段的业务角色、缺失、唯一值规模和样本值放在一起，方便后续核口径与交接。",
        [
            "大厂市场部报告通常不会默认读者完全懂字段，因此需要一页字段词典来承接后续所有结论。",
            "这一页尤其适合数据复盘、跨团队沟通和后续补数时使用。",
        ],
        tables=[_table("字段词典", rows)],
    )


