def _stats_appendix_section_v3(
    recommended_methods: list[dict[str, Any]],
    recommended_method_runs: list[dict[str, Any]],
) -> dict[str, Any]:
    run_rows = []
    method_notes = []
    for run in recommended_method_runs:
        result = run.get("result", {})
        metrics = result.get("metrics", {})
        request = run.get("request", {})
        run_rows.append(
            {
                "方法": run["method"],
                "method_id": run["method_id"],
                "目标字段": request.get("target") or ",".join(request.get("features", [])[:3]) or "n/a",
                "主要结论": str(result.get("narrative", ""))[:120],
                "样本量": metrics.get("n"),
                "p_value": metrics.get("p_value"),
            }
        )
        method_id = str(run.get("method_id") or "")
        usage = (
            "看多组差异" if method_id in {"anova", "kruskal", "tukey_hsd"}
            else "看变量联动" if method_id == "correlation"
            else "看分布形态" if method_id == "normality"
            else "看结构压缩或分群" if method_id in {"pca", "kmeans"}
            else "看分类结构关系" if method_id in {"chi_square", "fisher_exact"}
            else "看概率或数量驱动" if method_id in {"logit", "poisson_glm"}
            else "辅助检验"
        )
        method_notes.append(
            {
                "方法": run["method"],
                "用途": usage,
                "为什么跑": request.get("target") or ",".join(request.get("features", [])[:3]) or "n/a",
                "怎么用": str(result.get("narrative", ""))[:180],
            }
        )
    return _section(
        "stats_appendix",
        "统计方法附录",
        "这部分把方法目录、实际运行结果、方法用途和解读方式放在一起，方便数分同学、研究同学或复核同学继续往下钻。",
        [
            f"当前推荐方法目录共覆盖 {len(recommended_methods)} 个候选方法，实际已运行 {len(recommended_method_runs)} 个方法。",
            "正文不围绕方法写，但附录保留完整方法与结果，方便复核和继续分析。",
            "这一页不只给方法名，还会明确每个方法为什么跑、结果怎么用。",
        ],
        tables=[
            _table("方法目录", recommended_methods),
            _table("实跑方法结果", run_rows),
            _table("方法解读卡", method_notes),
            *[
                table
                for run in recommended_method_runs
                for table in run.get("result", {}).get("tables", [])[:2]
            ],
        ],
    )


