def _method_ready_frame(frame: pd.DataFrame) -> tuple[pd.DataFrame, list[str]]:
    working = frame.copy()
    derived_dimensions = _derived_dimension_candidates(frame)
    added_columns: list[str] = []
    for key, series in derived_dimensions.items():
        if key not in working.columns:
            working[key] = series
            added_columns.append(key)
    return working, added_columns


def _usable_group_columns(frame: pd.DataFrame, candidates: list[str]) -> list[str]:
    usable: list[str] = []
    for column in candidates:
        counts = frame[column].fillna("Missing").astype(str).value_counts()
        if len(counts) < 2:
            continue
        if len(counts) > 12:
            continue
        if counts.min() < 2:
            continue
        usable.append(column)
    return usable


def _recommended_method_runs(
    *,
    dataset_id: str,
    frame: pd.DataFrame,
    numeric_cols: list[str],
    categorical_cols: list[str],
    recommended_methods: list[dict[str, Any]],
) -> list[dict[str, Any]]:
    working_frame, added_columns = _method_ready_frame(frame)
    usable_categorical = _usable_group_columns(working_frame, categorical_cols + added_columns)
    binary_groups = [column for column in usable_categorical if working_frame[column].fillna("Missing").astype(str).nunique() == 2]
    binary_targets = [
        column
        for column in working_frame.columns.astype(str).tolist()
        if column not in numeric_cols
        and working_frame[column].dropna().nunique() == 2
    ]

    runs: list[dict[str, Any]] = []
    used_ids: set[str] = set()
    for item in recommended_methods:
        method_id = str(item.get("id") or "")
        if method_id in used_ids:
            continue
        try:
            request = None
            if method_id == "correlation" and len(numeric_cols) >= 2:
                request = StatisticRequest(dataset_id=dataset_id, analysis_type="correlation", features=numeric_cols[:6])
            elif method_id == "normality" and numeric_cols:
                request = StatisticRequest(dataset_id=dataset_id, analysis_type="normality", target=numeric_cols[0])
            elif method_id == "pca" and len(numeric_cols) >= 3:
                request = StatisticRequest(dataset_id=dataset_id, analysis_type="pca", features=numeric_cols[:6], components=2)
            elif method_id == "kmeans" and len(numeric_cols) >= 3:
                request = StatisticRequest(dataset_id=dataset_id, analysis_type="kmeans", features=numeric_cols[:5], clusters=3)
            elif method_id == "anova" and usable_categorical and numeric_cols:
                request = StatisticRequest(dataset_id=dataset_id, analysis_type="anova", target=numeric_cols[0], group_column=usable_categorical[0])
            elif method_id == "kruskal" and usable_categorical and numeric_cols:
                request = StatisticRequest(dataset_id=dataset_id, analysis_type="kruskal", target=numeric_cols[0], group_column=usable_categorical[0])
            elif method_id == "tukey_hsd" and usable_categorical and numeric_cols:
                request = StatisticRequest(dataset_id=dataset_id, analysis_type="tukey_hsd", target=numeric_cols[0], group_column=usable_categorical[0])
            elif method_id == "ttest" and binary_groups and numeric_cols:
                groups = working_frame[binary_groups[0]].fillna("Missing").astype(str).value_counts().index.tolist()[:2]
                request = StatisticRequest(
                    dataset_id=dataset_id,
                    analysis_type="ttest",
                    target=numeric_cols[0],
                    group_column=binary_groups[0],
                    group_a=groups[0],
                    group_b=groups[1],
                )
            elif method_id == "mann_whitney" and binary_groups and numeric_cols:
                groups = working_frame[binary_groups[0]].fillna("Missing").astype(str).value_counts().index.tolist()[:2]
                request = StatisticRequest(
                    dataset_id=dataset_id,
                    analysis_type="mann_whitney",
                    target=numeric_cols[0],
                    group_column=binary_groups[0],
                    group_a=groups[0],
                    group_b=groups[1],
                )
            elif method_id == "chi_square" and len(usable_categorical) >= 2:
                request = StatisticRequest(
                    dataset_id=dataset_id,
                    analysis_type="chi_square",
                    target=usable_categorical[1],
                    group_column=usable_categorical[0],
                )
            elif method_id == "fisher_exact" and len(binary_groups) >= 2:
                request = StatisticRequest(
                    dataset_id=dataset_id,
                    analysis_type="fisher_exact",
                    target=binary_groups[1],
                    group_column=binary_groups[0],
                )
            elif method_id == "logit" and binary_targets and len(numeric_cols) >= 2:
                request = StatisticRequest(
                    dataset_id=dataset_id,
                    analysis_type="logit",
                    target=binary_targets[0],
                    features=numeric_cols[:4],
                )
            elif method_id == "random_forest":
                binary_target = _choose_binary_target(working_frame)
                continuous_target, continuous_features = _choose_continuous_target(working_frame, numeric_cols)
                if binary_target and len(numeric_cols) >= 2:
                    request = StatisticRequest(
                        dataset_id=dataset_id,
                        analysis_type="random_forest",
                        target=binary_target,
                        features=[column for column in numeric_cols if column != binary_target][:6],
                        metric_type="binary",
                    )
                elif continuous_target and continuous_features:
                    request = StatisticRequest(
                        dataset_id=dataset_id,
                        analysis_type="random_forest",
                        target=continuous_target,
                        features=continuous_features,
                        metric_type="continuous",
                    )
            elif method_id == "neural_network":
                binary_target = _choose_binary_target(working_frame)
                continuous_target, continuous_features = _choose_continuous_target(working_frame, numeric_cols)
                if binary_target and len(numeric_cols) >= 2:
                    request = StatisticRequest(
                        dataset_id=dataset_id,
                        analysis_type="neural_network",
                        target=binary_target,
                        features=[column for column in numeric_cols if column != binary_target][:6],
                        metric_type="binary",
                    )
                elif continuous_target and continuous_features:
                    request = StatisticRequest(
                        dataset_id=dataset_id,
                        analysis_type="neural_network",
                        target=continuous_target,
                        features=continuous_features,
                        metric_type="continuous",
                    )
            elif method_id == "deep_learning":
                binary_target = _choose_binary_target(working_frame)
                continuous_target, continuous_features = _choose_continuous_target(working_frame, numeric_cols)
                if binary_target and len(numeric_cols) >= 3:
                    request = StatisticRequest(
                        dataset_id=dataset_id,
                        analysis_type="deep_learning",
                        target=binary_target,
                        features=[column for column in numeric_cols if column != binary_target][:8],
                        metric_type="binary",
                    )
                elif continuous_target and len(continuous_features) >= 2:
                    request = StatisticRequest(
                        dataset_id=dataset_id,
                        analysis_type="deep_learning",
                        target=continuous_target,
                        features=continuous_features[:6],
                        metric_type="continuous",
                    )
            elif method_id == "poisson_glm" and len(numeric_cols) >= 3:
                request = StatisticRequest(
                    dataset_id=dataset_id,
                    analysis_type="poisson_glm",
                    target=numeric_cols[0],
                    features=numeric_cols[1:4],
                )
            if request is None:
                continue
            result = run_statistical_analysis(working_frame, request)
            runs.append(
                {
                    "method_id": method_id,
                    "method": item["method"],
                    "request": request.model_dump(),
                    "result": result,
                }
            )
            used_ids.add(method_id)
            if len(runs) >= 12:
                break
        except Exception:
            continue
    return runs


def _method_cn_name(method_id: str, fallback: str) -> str:
    mapping = {
        "correlation": "相关性扫描",
        "normality": "正态性检验",
        "pca": "主成分分析",
        "kmeans": "KMeans 分群",
        "anova": "方差分析",
        "kruskal": "Kruskal-Wallis 检验",
        "tukey_hsd": "Tukey 多重比较",
        "ttest": "Welch 双样本 t 检验",
        "mann_whitney": "Mann-Whitney 检验",
        "chi_square": "卡方检验",
        "fisher_exact": "Fisher 精确检验",
        "logit": "Logistic 回归",
        "random_forest": "随机森林",
        "neural_network": "神经网络",
        "deep_learning": "深度学习网络",
        "poisson_glm": "Poisson GLM",
        "ab_test": "A/B Test",
    }
    return mapping.get(method_id, fallback)


def _recommended_method_bullets(method_runs: list[dict[str, Any]]) -> list[str]:
    bullets: list[str] = []
    for run in method_runs:
        method_id = str(run["method_id"])
        result = run["result"]
        metrics = result.get("metrics", {})
        request = run.get("request", {})
        method_name = _method_cn_name(method_id, run["method"])

        if method_id == "correlation":
            bullets.append(
                f"{method_name}：最强相关对是 {metrics.get('strongest_left')} 与 {metrics.get('strongest_right')}，相关系数约 {metrics.get('strongest_correlation')}。这说明这些指标会同步变化，适合优先进入驱动分析和指标压缩。"
            )
            bullets.append("解读重点：相关性只说明联动，不说明因果，像“新增人数”和“净流入数”这种存在口径推导关系的指标，不能直接当成独立驱动因素。")
        elif method_id == "normality":
            bullets.append(
                f"{method_name}：`{request.get('target')}` 的正态性检验 p 值为 {metrics.get('p_value')}，说明这类分布更像明显偏态而不是标准正态。"
            )
            bullets.append("解读重点：后续做组间比较时，应优先考虑非参数方法、分层比较或分位数分析，而不是默认只看均值。")
        elif method_id == "pca":
            bullets.append(
                f"{method_name}：前两个主成分累计解释了约 {round((metrics.get('variance_pc1') or 0) + (metrics.get('variance_pc2') or 0), 4)} 的方差，说明主要信息可以压缩到少数结构因子里。"
            )
            bullets.append("解读重点：如果第一主成分主要由“新增人数”和“净流入数”驱动，就说明整体更像是规模因子，而不是多个完全独立的业务维度。")
        elif method_id == "kmeans":
            bullets.append(
                f"{method_name}：当前自动分成了 {metrics.get('clusters')} 类，最大簇占比约 {round((metrics.get('largest_cluster_share') or 0) * 100, 2) if metrics.get('largest_cluster_share') is not None else '未提供'}%。这说明样本并不是完全均质的。"
            )
            bullets.append("解读重点：要重点看每个簇分别有哪些代表成员，确认它们是头部爆款、腰部承接品，还是高流动低沉淀的异常商品。")
        elif method_id in {"anova", "kruskal"}:
            bullets.append(
                f"{method_name}：系统已经按 `{request.get('group_column')}` 维度比较了 `{request.get('target')}` 的组间差异。这个方法用来回答“不同品牌/功效/品类之间是否真的有显著差异”。"
            )
            bullets.append(f"结果解读：{result.get('narrative')} 如果差异显著，就应该继续做分组复盘和后续多重比较，而不是只停留在整体平均。")
        elif method_id == "tukey_hsd":
            bullets.append(
                f"{method_name}：这是在方差分析之后继续看“到底是哪几组差异最大”。它比只说“有差异”更适合直接指导运营或市场动作。"
            )
            bullets.append(f"结果解读：{result.get('narrative')} 重点应转成“哪些组更强、哪些组更弱、差异是否足够支撑资源倾斜”。")
        elif method_id in {"ttest", "mann_whitney"}:
            bullets.append(
                f"{method_name}：系统比较了 `{request.get('group_column')}` 两组在 `{request.get('target')}` 上的差异，用来回答“两个细分之间是否真有表现落差”。"
            )
            bullets.append(f"结果解读：{result.get('narrative')} 如果 effect size 或中位数差异明显，就适合继续做成头部/尾部对照分析。")
        elif method_id in {"chi_square", "fisher_exact"}:
            bullets.append(
                f"{method_name}：系统在看 `{request.get('group_column')}` 与 `{request.get('target')}` 是否存在结构性关联。这类方法更适合解释分类结构，而不是数值强弱。"
            )
            bullets.append(f"结果解读：{result.get('narrative')} 如果关联显著，就意味着细分结构不是随机分布，后续可以继续做组合与替代关系分析。")
        elif method_id == "logit":
            bullets.append(
                f"{method_name}：当前把 `{request.get('target')}` 当作结果事件，观察哪些变量会推高或拉低发生概率。"
            )
            bullets.append(f"结果解读：{result.get('narrative')} 重点应看 odds ratio 最大的变量，理解哪些因素最像真正的结果驱动。")
        elif method_id == "poisson_glm":
            bullets.append(
                f"{method_name}：这个方法适合计数型结果，主要回答“哪些变量更像在推动计数规模变化”。"
            )
            bullets.append(f"结果解读：{result.get('narrative')} 如果 rate ratio 很高，就意味着该特征对数量变化更敏感。")
        else:
            bullets.append(f"{method_name}：{result.get('narrative')}")
    return bullets


def _value_from_table(result: dict[str, Any], table_title: str, column_name: str, sort_by: str, descending: bool = True) -> str | None:
    table = next((item for item in result.get("tables", []) if item.get("title") == table_title), None)
    if not table or not table.get("rows"):
        return None
    try:
        ordered = sorted(table["rows"], key=lambda row: float(row.get(sort_by, 0) or 0), reverse=descending)
        value = ordered[0].get(column_name)
        return str(value) if value is not None else None
    except Exception:
        return None


def _method_use_sentence(method_id: str, report_request: SmartReportRequest, lens: str) -> str:
    audience = _stable_business_text(report_request.target_audience, "业务负责人")
    purpose = _stable_business_text(
        report_request.core_purpose.strip() or report_request.problem_to_solve.strip(),
        "当前判断",
    )
    if lens == "performance_benchmark":
        return f"对 {audience} 而言，这个结果用于判断当前压测样本是否稳定，能否继续支撑 {purpose}。"
    return f"对 {audience} 而言，这个结果直接服务于 {purpose}。"


def _recommended_method_bullets(
    method_runs: list[dict[str, Any]],
    report_request: SmartReportRequest,
    lens: str,
) -> list[str]:
    bullets: list[str] = []
    for run in method_runs:
        method_id = str(run["method_id"])
        result = run["result"]
        metrics = result.get("metrics", {})
        method_request = run.get("request", {})
        method_name = _method_cn_name(method_id, run["method"])

        if method_id == "correlation":
            left = metrics.get("strongest_left")
            right = metrics.get("strongest_right")
            corr = metrics.get("strongest_correlation")
            bullets.append(
                f"{method_name}：{_correlation_sentence(str(left), str(right), corr)}{_method_use_sentence(method_id, report_request, lens)}"
            )
            continue

        if method_id == "normality":
            target = method_request.get("target")
            p_value = metrics.get("p_value")
            bullets.append(
                f"{method_name}：`{target}` 的 p 值为 {p_value}。结论：这个指标明显偏态，后续判断应优先看中位数、分位数、头部样本占比和异常区间。{_method_use_sentence(method_id, report_request, lens)}"
            )
            continue

        if method_id == "pca":
            total = round((metrics.get("variance_pc1") or 0) + (metrics.get("variance_pc2") or 0), 4)
            bullets.append(
                f"{method_name}：前两个主成分累计解释约 {total} 的方差。结论：当前指标可以压缩成少数几个主轴，后续汇报适合用“规模维度”和“效率维度”来组织。{_method_use_sentence(method_id, report_request, lens)}"
            )
            continue

        if method_id == "kmeans":
            clusters = metrics.get("clusters")
            largest = round((metrics.get("largest_cluster_share") or 0) * 100, 2)
            bullets.append(
                f"{method_name}：当前样本被分成 {clusters} 类，最大一类占比约 {largest}%。结论：样本内部存在可识别分层，后续应直接看每一类代表对象承担什么角色。{_method_use_sentence(method_id, report_request, lens)}"
            )
            continue

        if method_id == "anova":
            group = method_request.get("group_column")
            target = method_request.get("target")
            p_value = float(metrics.get("p_value") or 0)
            effect = float(metrics.get("effect_share") or 0)
            top_group = _value_from_table(result, "Group means", "group", "mean", True)
            bottom_group = _value_from_table(result, "Group means", "group", "mean", False)
            if p_value < 0.05:
                bullets.append(
                    f"{method_name}：`{group}` 对 `{target}` 有稳定差异，p={p_value:.4f}，效应占比约 {effect:.4f}。结论：`{group}` 可以作为资源拆分的主维度，当前高值组是 `{top_group}`，低值组是 `{bottom_group}`。{_method_use_sentence(method_id, report_request, lens)}"
                )
            else:
                bullets.append(
                    f"{method_name}：`{group}` 对 `{target}` 没有稳定差异，p={p_value:.4f}。结论：当前 `{target}` 的高低主要由局部样本和个别对象拉动，按 `{group}` 直接做资源倾斜依据不足。{_method_use_sentence(method_id, report_request, lens)}"
                )
            continue

        if method_id == "kruskal":
            group = method_request.get("group_column")
            target = method_request.get("target")
            p_value = float(metrics.get("p_value") or 0)
            top_group = _value_from_table(result, "Group median summary", "group", "median", True)
            if p_value < 0.05:
                bullets.append(
                    f"{method_name}：按中位数口径看，`{group}` 对 `{target}` 有稳定差异，p={p_value:.4f}。结论：当前差异是真实结构差异，优先复盘 `{top_group}` 这一组。{_method_use_sentence(method_id, report_request, lens)}"
                )
            else:
                bullets.append(
                    f"{method_name}：按中位数口径看，`{group}` 对 `{target}` 没有稳定差异，p={p_value:.4f}。结论：组间层级不稳定，当前更适合看异常对象和头部样本。{_method_use_sentence(method_id, report_request, lens)}"
                )
            continue

        if method_id == "tukey_hsd":
            significant_pairs = int(metrics.get("significant_pairs") or 0)
            if significant_pairs > 0:
                bullets.append(
                    f"{method_name}：共发现 {significant_pairs} 组显著差异。结论：组间强弱已经形成清晰层级，后续复盘应直接落到具体组对。{_method_use_sentence(method_id, report_request, lens)}"
                )
            else:
                bullets.append(
                    f"{method_name}：显著组对数量为 0。结论：当前没有形成稳定的组间强弱顺序，后续重点应放在对象级复盘和效率指标。{_method_use_sentence(method_id, report_request, lens)}"
                )
            continue

        if method_id in {"ttest", "mann_whitney"}:
            group = method_request.get("group_column")
            target = method_request.get("target")
            p_value = float(metrics.get("p_value") or 0)
            bullets.append(
                f"{method_name}：`{group}` 两组在 `{target}` 上的差异 p={p_value:.4f}。结论：这个结果直接回答这两组是否值得分开制定动作方案。{_method_use_sentence(method_id, report_request, lens)}"
            )
            continue

        if method_id == "chi_square":
            group = method_request.get("group_column")
            target = method_request.get("target")
            p_value = float(metrics.get("p_value") or 0)
            cramers_v = float(metrics.get("cramers_v") or 0)
            if p_value < 0.05:
                bullets.append(
                    f"{method_name}：`{group}` 与 `{target}` 的结构关联显著，p={p_value:.4f}，Cramer's V 约 {cramers_v:.4f}。结论：这两个维度存在稳定组合关系，后续应按组合切片复盘。{_method_use_sentence(method_id, report_request, lens)}"
                )
            else:
                bullets.append(
                    f"{method_name}：`{group}` 与 `{target}` 的结构关联不显著，p={p_value:.4f}。结论：当前分布较均匀，没有必要把这两个维度绑定成固定策略单元。{_method_use_sentence(method_id, report_request, lens)}"
                )
            continue

        if method_id == "fisher_exact":
            p_value = float(metrics.get("p_value") or 0)
            odds_ratio = float(metrics.get("odds_ratio") or 0)
            bullets.append(
                f"{method_name}：2x2 精确检验的 p 值为 {p_value:.4f}，odds ratio 约 {odds_ratio:.4f}。结论：小样本分组关系已经被验证，可直接用于判断关系方向。{_method_use_sentence(method_id, report_request, lens)}"
            )
            continue

        if method_id == "logit":
            strongest_term = metrics.get("strongest_term")
            bullets.append(
                f"{method_name}：当前最强概率信号来自 `{strongest_term}`。结论：这个变量最值得进入结果预测和动作优先级讨论。{_method_use_sentence(method_id, report_request, lens)}"
            )
            continue

        if method_id == "poisson_glm":
            bullets.append(
                f"{method_name}：当前计数模型已经收敛。结论：特征变化会带来结果规模变化，后续可以按 rate ratio 排序识别最敏感的动作杠杆。{_method_use_sentence(method_id, report_request, lens)}"
            )
            continue

        if method_id == "random_forest":
            if metrics.get("accuracy") is not None:
                bullets.append(
                    f"{method_name}：测试集准确率约 {metrics.get('accuracy'):.3f}，F1 约 {metrics.get('f1'):.3f}。结论：当前可以先把特征重要性更高的变量当成第一批复盘和排查对象。{_method_use_sentence(method_id, report_request, lens)}"
                )
            else:
                bullets.append(
                    f"{method_name}：测试集 R² 约 {metrics.get('r_squared'):.3f}，RMSE 约 {metrics.get('rmse'):.3f}。结论：当前可以先把重要性更高的变量当成解释结果差异的高价值因素。{_method_use_sentence(method_id, report_request, lens)}"
                )
            continue

        if method_id == "neural_network":
            if metrics.get("accuracy") is not None:
                bullets.append(
                    f"{method_name}：测试集准确率约 {metrics.get('accuracy'):.3f}，F1 约 {metrics.get('f1'):.3f}。结论：当前目标存在可被非线性模式捕捉的结构，后续应优先复盘敏感度更高的变量。{_method_use_sentence(method_id, report_request, lens)}"
                )
            else:
                bullets.append(
                    f"{method_name}：测试集 R² 约 {metrics.get('r_squared'):.3f}，RMSE 约 {metrics.get('rmse'):.3f}。结论：当前目标存在一定非线性拟合空间，后续应优先复盘敏感度更高的变量。{_method_use_sentence(method_id, report_request, lens)}"
                )
            continue

        if method_id == "deep_learning":
            if metrics.get("accuracy") is not None:
                bullets.append(
                    f"{method_name}：测试集准确率约 {metrics.get('accuracy'):.3f}，F1 约 {metrics.get('f1'):.3f}。结论：更深层的网络结构已经捕捉到更复杂的非线性关系，适合用来筛第一批复杂驱动因素。{_method_use_sentence(method_id, report_request, lens)}"
                )
            else:
                bullets.append(
                    f"{method_name}：测试集 R² 约 {metrics.get('r_squared'):.3f}，RMSE 约 {metrics.get('rmse'):.3f}。结论：更深层的神经网络更适合捕捉深层非线性结构，适合做复杂驱动因素的第一轮筛选。{_method_use_sentence(method_id, report_request, lens)}"
                )
            continue

        bullets.append(f"{method_name}：{result.get('narrative')}")
    return bullets


def _split_constraints(raw_text: str) -> list[str]:
    if not raw_text.strip():
        return []
    parts = [part.strip() for part in raw_text.replace("；", "\n").replace(";", "\n").splitlines()]
    return [part for part in parts if part]


def _infer_report_lens(request: SmartReportRequest, dataset_name: str, program_bundle: dict[str, Any]) -> str:
    requested_profile = str(getattr(request, "business_profile", "") or "").strip()
    if requested_profile and requested_profile != "auto":
        return business_profile_report_lens(requested_profile)
    primary_family = str((program_bundle.get("task_model") or {}).get("primary_family") or "")
    if primary_family and primary_family != "mixed_business_review":
        return primary_family
    joined = " ".join(
        [
            dataset_name,
            request.user_requirement,
            request.problem_to_solve,
            request.target_audience,
            request.core_purpose,
            request.expected_result,
            request.key_constraints,
            str(program_bundle.get("lens", "")),
        ]
    ).lower()
    if any(token in joined for token in ["stress", "benchmark", "load", "压测", "性能", "稳定性", "吞吐"]):
        return "performance_benchmark"
    if any(token in joined for token in ["投放", "媒体", "campaign", "曝光", "点击", "cpm", "cpc", "cpa"]):
        return "media_review"
    object_candidates = program_bundle.get("object_candidates", [])
    primary_object = object_candidates[0]["object_type"] if object_candidates else ""
    if primary_object == "media_performance_log":
        return "media_review"
    if primary_object in {"internet_operations_log", "content_performance_table", "crm_funnel_event_log"}:
        return "internet_ops_review"
    if primary_object == "sales_transaction_panel":
        return "sales_review"
    if primary_object == "nonprofit_project_portfolio":
        return "foundation_review"
    if primary_object == "survey_response_table":
        return "consumer_research"
    if primary_object == "brand_social_listening":
        return "brand_listening"
    if primary_object == "experiment_result_table":
        return "experiment_review"
    if primary_object == "performance_benchmark_table":
        return "performance_benchmark"
    return str(program_bundle.get("lens") or "mixed_business_review")


def _resolve_report_lens_from_router(router_result: dict[str, Any] | None, fallback_lens: str) -> str:
    if not router_result:
        return fallback_lens
    routed_profile = str(router_result.get("business_profile") or "").strip()
    if not routed_profile:
        return fallback_lens
    return business_profile_report_lens(routed_profile)


def _stable_business_text(raw_text: str, fallback: str) -> str:
    cleaned = raw_text.strip()
    if not cleaned:
        return fallback
    if cleaned.count("?") >= max(2, len(cleaned) // 4):
        return fallback
    return cleaned


def _focus_alignment_bullets(request: SmartReportRequest, report_lens: str, program_bundle: dict[str, Any]) -> list[str]:
    task_model = program_bundle.get("task_model", {})
    program = program_bundle.get("program", {})
    requirement_model = program_bundle.get("requirement_model", {})
    object_candidates = program_bundle.get("object_candidates", [])
    primary_object = object_candidates[0]["object_type"] if object_candidates else "generic_business_table"
    audience = _stable_business_text(task_model.get("audience", ""), "业务负责人 / 分析负责人")
    problem = _stable_business_text(task_model.get("problem", ""), "形成可执行判断")
    bullets = [
        f"当前对象识别主候选为 `{primary_object}`，观察单位定义为：{program.get('observation_unit', '单条记录')}。",
        f"当前最重要的问题是：{problem}。",
        f"输出面向的主要角色是：{audience}。",
        f"正文优先围绕这些结果变量组织：{', '.join(program.get('core_outcomes', [])[:4]) or '当前未锁定稳定结果变量'}。",
    ]
    if requirement_model.get("must_answer_questions"):
        bullets.append(f"这版报告必须回答的问题包括：{'; '.join(str(item) for item in requirement_model.get('must_answer_questions', [])[:3])}。")
    if requirement_model.get("non_goals"):
        bullets.append(f"这版报告明确不去做的内容包括：{'; '.join(str(item) for item in requirement_model.get('non_goals', [])[:2])}。")
    if report_lens == "performance_benchmark":
        bullets.append("当前报告类型是压测评估。正文只保留能支持稳定性、边界和系统改造优先级的内容。")
    else:
        bullets.append("当前报告类型是业务分析。正文只保留能支持经营、投放、渠道或品牌判断的内容。")
    return bullets


def _build_requirement_context(request: SmartReportRequest, dataset_name: str, sheet_name: str) -> dict[str, Any]:
    frontend_context_pack = build_frontend_context_pack(request)
    return {
        "dataset_name": dataset_name,
        "sheet_name": sheet_name,
        "user_requirement": request.user_requirement,
        "problem_to_solve": request.problem_to_solve,
        "target_audience": request.target_audience,
        "core_purpose": request.core_purpose,
        "expected_result": request.expected_result,
        "key_constraints": request.key_constraints,
        "business_background_name": request.business_background_name,
        "business_background_text": request.business_background_text[:4000],
        "historical_report_name": request.historical_report_name,
        "historical_report_text": request.historical_report_text[:4000],
        "frontend_context_pack": frontend_context_pack,
        "frontend_context_brief": str(frontend_context_pack.get("context_brief") or ""),
    }


def _resolved_request_from_program(request: SmartReportRequest, program_bundle: dict[str, Any]) -> SmartReportRequest:
    payload = dict(request.model_dump())
    resolved = program_bundle.get("resolved_request_payload") or {}
    for key, value in resolved.items():
        if key in payload and not str(payload.get(key) or "").strip() and str(value or "").strip():
            payload[key] = value
    return SmartReportRequest(**payload)


def _build_requirement_layer(
    request: SmartReportRequest,
    dataset_name: str,
    sheet_name: str,
    requirement_model: dict[str, Any] | None = None,
) -> dict[str, Any]:
    requirement_model = requirement_model or codex_synthesize_requirement(_build_requirement_context(request, dataset_name, sheet_name))
    provided_problem = request.problem_to_solve.strip() or request.user_requirement.strip()
    audience = request.target_audience.strip()
    purpose = request.core_purpose.strip()
    expected = request.expected_result.strip()
    constraints = [str(item).strip() for item in requirement_model.get("explicit_constraints", []) if str(item).strip()] or _split_constraints(request.key_constraints)
    success_criteria = [str(item).strip() for item in requirement_model.get("success_criteria", []) if str(item).strip()][:5]
    must_answer_questions = [str(item).strip() for item in requirement_model.get("must_answer_questions", []) if str(item).strip()][:5]
    non_goals = [str(item).strip() for item in requirement_model.get("non_goals", []) if str(item).strip()][:5]
    output_preferences = [str(item).strip() for item in requirement_model.get("output_preferences", []) if str(item).strip()][:5]
    ambiguity_flags = [str(item).strip() for item in requirement_model.get("ambiguity_flags", []) if str(item).strip()][:5]
    recommended_focus = [str(item).strip() for item in requirement_model.get("recommended_focus", []) if str(item).strip()][:5]

    clear_points: list[str] = []
    ambiguous_points: list[str] = []
    questions: list[str] = []

    if provided_problem:
        clear_points.append("用户希望系统围绕明确问题而不是只做泛泛描述。")
    else:
        ambiguous_points.append("用户想解决的核心问题还没有被明确描述。")
        questions.append("你最想通过这份分析解决什么业务或研究问题？")

    if audience:
        clear_points.append(f"目标受众已给出：{audience}。")
    else:
        ambiguous_points.append("目标受众未明确，暂时只能按通用业务分析受众处理。")
        questions.append("这份结果主要给谁看？例如管理层、运营、研究团队还是客户。")

    if purpose or expected:
        clear_points.append("输出目的和预期结果已有线索。")
    else:
        ambiguous_points.append("输出最终要拿来汇报、决策、复盘还是监控，还不够清楚。")
        questions.append("你希望最后拿它做什么？例如汇报、决策支持、方案比较或长期监控。")

    if constraints:
        clear_points.append("用户已经给出至少一部分约束。")
    else:
        ambiguous_points.append("目前没有明确约束，默认以可读性优先、现有数据优先推进。")
    ambiguous_points.extend(flag for flag in ambiguity_flags if flag not in ambiguous_points)
    questions.extend(question for question in must_answer_questions if question not in questions and question not in {provided_problem, audience, purpose, expected})

    default_assumptions = [
        str(requirement_model.get("refined_problem") or provided_problem or f"默认把 `{dataset_name}` / `{sheet_name}` 视为需要形成一份结构化业务分析报告的数据源。"),
        str(requirement_model.get("refined_audience") or audience or "默认目标受众为业务负责人、分析师与项目协作者。"),
        str(requirement_model.get("refined_purpose") or purpose or expected or "默认核心目的是形成一份可读、可下载、可转发的分析报告。"),
    ]
    if constraints:
        default_assumptions.extend(constraints[:3])
    else:
        default_assumptions.extend(
            [
                "默认优先使用已上传数据，不额外引入外部事实作为结论依据。",
                "默认主交付物应为一份可直接下载和转发的主报告。",
            ]
        )

    return {
        "problem_statement": str(requirement_model.get("refined_problem") or provided_problem or "尚未明确给出，需要系统先按通用分析目标理解。"),
        "target_audience": str(requirement_model.get("refined_audience") or audience or "默认业务负责人 / 分析协作者"),
        "core_purpose": str(requirement_model.get("refined_purpose") or purpose or expected or "默认生成一份可执行、可交付的分析报告"),
        "expected_result": str(requirement_model.get("refined_expected_result") or expected or "主报告 + 分析附录"),
        "constraints": constraints,
        "success_criteria": success_criteria,
        "must_answer_questions": must_answer_questions,
        "non_goals": non_goals,
        "output_preferences": output_preferences,
        "recommended_focus": recommended_focus,
        "clear_points": clear_points,
        "ambiguous_points": ambiguous_points,
        "questions": questions[:3],
        "default_assumptions": default_assumptions[:5],
        "next_action": str(requirement_model.get("next_step") or "若问题足够明确，则直接进入分析；若仍模糊，优先确认目标、受众和用途。"),
        "requirement_model": requirement_model,
    }


def _build_data_understanding(
    *,
    metadata: dict[str, Any],
    sheet: dict[str, Any],
    frame: pd.DataFrame,
    current_profile: dict[str, Any] | None,
    missing_columns: list[dict[str, Any]],
    numeric_cols: list[str],
    categorical_cols: list[str],
    temporal_cols: list[str],
) -> dict[str, Any]:
    bullets = [
        f"当前数据来自 `{metadata['filename']}`，正在分析 `{sheet['name']}` 工作表。",
        f"该工作表共有 {len(frame)} 行、{len(frame.columns)} 列，推断角色为 `{current_profile['role']}`。"
        if current_profile
        else f"该工作表共有 {len(frame)} 行、{len(frame.columns)} 列。",
        f"数值字段 {len(numeric_cols)} 个，分类字段 {len(categorical_cols)} 个，时间字段 {len(temporal_cols)} 个。",
        f"最明显的缺失集中在 {', '.join(item['column'] for item in missing_columns[:3])}。"
        if missing_columns
        else "整体缺失控制较好，没有出现特别突出的缺失字段。",
    ]

    useful_parts = []
    if numeric_cols:
        useful_parts.append(f"数值分析最值得优先用到的字段包括 {', '.join(numeric_cols[:4])}。")
    if categorical_cols:
        useful_parts.append(f"分类结构最值得优先用到的字段包括 {', '.join(categorical_cols[:3])}。")
    if temporal_cols:
        useful_parts.append(f"时间序列切入口在 {', '.join(temporal_cols[:2])}。")

    return {
        "overview": bullets,
        "useful_parts": useful_parts,
        "sample_files": [metadata["filename"]],
        "sample_tables": [sheet["name"]],
    }


def _column_by_keywords(columns: list[str], keyword_groups: list[list[str]]) -> str | None:
    return _first_matching_column(columns, keyword_groups)


def _ops_column_map(frame: pd.DataFrame) -> dict[str, str | None]:
    columns = frame.columns.astype(str).tolist()
    return {
        "date": _column_by_keywords(columns, [["日期"], ["date"]]),
        "channel": _column_by_keywords(columns, [["渠道"], ["channel"]]),
        "activity": _column_by_keywords(columns, [["活动"], ["campaign"], ["activity"]]),
        "content": _column_by_keywords(columns, [["内容主题"], ["内容"], ["title"], ["content"]]),
        "active": _column_by_keywords(columns, [["活跃用户"], ["active", "user"]]),
        "new": _column_by_keywords(columns, [["新增用户"], ["注册数"], ["new", "user"], ["registration"]]),
        "retained": _column_by_keywords(columns, [["留存用户"], ["retained"], ["retention", "user"]]),
        "retention_rate": _column_by_keywords(columns, [["留存率"], ["retention", "rate"]]),
        "conversion_rate": _column_by_keywords(columns, [["转化率"], ["conversion", "rate"]]),
        "orders": _column_by_keywords(columns, [["订单数"], ["order"]]),
    }


def _internet_ops_context_rows(frame: pd.DataFrame, field_registry: dict[str, Any] | None = None) -> dict[str, list[dict[str, Any]]]:
    registry = field_registry or {}
    mapping = _ops_column_map(frame)
    topline_section = _ops_topline_section(frame, registry)
    channel_section = _ops_channel_scorecard_section(frame, registry)
    activity_section = _ops_activity_scorecard_section(frame, registry)
    channel_impact_section = (
        _ops_dimension_effect_section("context", frame, dimension_column=mapping["channel"], label="渠道", section_id="ops_channel_impact", field_registry=registry)
        if mapping.get("channel")
        else None
    )
    activity_impact_section = (
        _ops_dimension_effect_section("context", frame, dimension_column=mapping["activity"], label="活动", section_id="ops_activity_impact", field_registry=registry)
        if mapping.get("activity")
        else None
    )
    content_impact_section = (
        _ops_dimension_effect_section("context", frame, dimension_column=mapping["content"], label="内容主题", section_id="ops_content_impact", field_registry=registry)
        if mapping.get("content")
        else None
    )
    combo_section = _ops_combo_impact_section("context", frame, field_registry=registry)
    combo_action_section = _ops_combo_direct_actions_section("context", frame, field_registry=registry)
    content_rows = _ops_content_scorecard_rows(frame, registry)
    return {
        "topline_rows": ((topline_section or {}).get("tables") or [{}])[0].get("rows", []) if topline_section else [],
        "channel_rows": ((channel_section or {}).get("tables") or [{}])[0].get("rows", []) if channel_section else [],
        "activity_rows": ((activity_section or {}).get("tables") or [{}])[0].get("rows", []) if activity_section else [],
        "content_rows": content_rows,
        "channel_impact_rows": ((channel_impact_section or {}).get("tables") or [{}])[0].get("rows", []) if channel_impact_section else [],
        "activity_impact_rows": ((activity_impact_section or {}).get("tables") or [{}])[0].get("rows", []) if activity_impact_section else [],
        "content_impact_rows": ((content_impact_section or {}).get("tables") or [{}])[0].get("rows", []) if content_impact_section else [],
        "combo_rows": ((combo_section or {}).get("tables") or [{}])[0].get("rows", []) if combo_section else [],
        "combo_action_rows": ((combo_action_section or {}).get("tables") or [{}])[0].get("rows", []) if combo_action_section else [],
    }


def _ops_topline_section(frame: pd.DataFrame, field_registry: dict[str, Any] | None = None) -> dict[str, Any] | None:
    registry = field_registry or {}
    if registry and not any(
        [
            registry.get("has_user_fields"),
            registry.get("has_funnel_fields"),
            registry.get("has_retention_fields"),
            registry.get("has_revenue_fields"),
            registry.get("has_traffic_fields"),
        ]
    ):
        return None
    mapping = _ops_column_map(frame)
    if not mapping["active"]:
        return None
    rows: list[dict[str, Any]] = []
    bullets: list[str] = []
    for label, key in [
        ("活跃用户总量", "active"),
        ("新增用户总量", "new"),
        ("留存用户总量", "retained"),
        ("订单总量", "orders"),
    ]:
        column = mapping[key]
        if not column or column not in frame.columns:
            continue
        series = pd.to_numeric(frame[column], errors="coerce").dropna()
        if series.empty:
            continue
        rows.append(
            {
                "核心指标": label,
                "总量": _display_table_value(label, float(series.sum())),
                "均值": _display_table_value(label, float(series.mean())),
                "中位数": _display_table_value(label, float(series.median())),
            }
        )
    for label, key in [("留存率", "retention_rate"), ("转化率", "conversion_rate")]:
        column = mapping[key]
        if not column or column not in frame.columns:
            continue
        series = pd.to_numeric(frame[column], errors="coerce").dropna()
        if series.empty:
            continue
        rows.append(
            {
                "核心指标": label,
                "总量": "n/a",
                "均值": _format_percent(float(series.mean())),
                "中位数": _format_percent(float(series.median())),
            }
        )
    if mapping["active"] and mapping["new"]:
        active = pd.to_numeric(frame[mapping["active"]], errors="coerce").dropna()
        new_users = pd.to_numeric(frame[mapping["new"]], errors="coerce").dropna()
        if not active.empty and not new_users.empty:
            bullets.append(
                f"当前样本累计活跃用户约 {_display_table_value('活跃用户', float(active.sum()))}，累计新增用户约 {_display_table_value('新增用户', float(new_users.sum()))}，这决定了本轮运营盘子先看规模再看效率。"
            )
    if mapping["retention_rate"]:
        retention = pd.to_numeric(frame[mapping["retention_rate"]], errors="coerce").dropna()
        if not retention.empty:
            bullets.append(
                f"当前留存率均值约 {_format_percent(float(retention.mean()))}、中位数约 {_format_percent(float(retention.median()))}，后续要重点判断高均值是不是被少数峰值样本拉高。"
            )
    if mapping["conversion_rate"]:
        conversion = pd.to_numeric(frame[mapping["conversion_rate"]], errors="coerce").dropna()
        if not conversion.empty:
            bullets.append(
                f"当前转化率均值约 {_format_percent(float(conversion.mean()))}，它决定新增和活跃最终能否转成订单与经营结果。"
            )
    return _section(
        "ops_topline",
        "经营总览主表",
        "先把新增、活跃、留存、转化和订单盘子讲清楚，再决定后面该优先看渠道、活动还是内容。",
        bullets or ["当前经营总览主表用于统一后续所有渠道、活动和内容的阅读基准。"],
        tables=[_table("经营总览主表", rows)],
    )


def _ops_channel_scorecard_section(frame: pd.DataFrame, field_registry: dict[str, Any] | None = None) -> dict[str, Any] | None:
    registry = field_registry or {}
    if registry and not registry.get("has_channel_fields", False):
        return None
    mapping = _ops_column_map(frame)
    if not mapping["channel"] or not mapping["active"]:
        return None
    base_rows = _ops_group_summary_rows(frame, group_column=mapping["channel"], mapping=mapping)
    rows = [
        {
            "渠道": row["对象"],
            "活跃总量": row["活跃总量"],
            "活跃均值": row["活跃均值"],
            "活跃占比": row["活跃占比"],
            **({"新增总量": row["新增总量"], "新增均值": row["新增均值"]} if "新增总量" in row else {}),
            **({"留存总量": row["留存总量"], "留存均值": row["留存均值"]} if "留存总量" in row else {}),
            **({"订单总量": row["订单总量"], "订单均值": row["订单均值"]} if "订单总量" in row else {}),
            **({"留存率": row["留存率"]} if "留存率" in row else {}),
            **({"转化率": row["转化率"]} if "转化率" in row else {}),
        }
        for row in base_rows
    ]
    guard = _ops_priority_guard(base_rows)
    bullets = []
    if rows:
        if guard["status"] == "no_clear_priority":
            bullets.append(
                f"渠道份额和效率差异都没有明显拉开，当前最高的 `{rows[0]['渠道']}` 还不足以被写成“一级优先渠道”。这一步更适合先看留存率、转化率和订单均值的细差，而不是直接排第一。"
            )
        elif guard["status"] == "clear_efficiency_lead":
            bullets.append(
                f"`{rows[0]['渠道']}` 不只是总量靠前，它在活跃均值、留存率、转化率或订单均值上也已经拉开差距，因此可以进入第一轮渠道复盘名单。"
            )
        else:
            bullets.append(
                f"`{rows[0]['渠道']}` 当前只是总量领先，是否值得优先投资源还要继续看留存率、转化率和订单均值是否同步领先。"
            )
    bullets.append("渠道层复盘必须同时看总量、均值和承接率；总量高只能说明盘子大，不能直接说明效率更好。")
    return _section(
        "ops_channel_scorecard",
        "阶段一：渠道经营判断",
        "先看渠道盘子是否真的拉开，再看留存、转化和订单承接是否形成有效差异，避免把总量大误写成渠道更优。",
        bullets or ["渠道经营主表用于统一比较规模、留存和转化。"],
        tables=[_table("渠道经营主表", rows)],
    )


def _ops_activity_scorecard_section(frame: pd.DataFrame, field_registry: dict[str, Any] | None = None) -> dict[str, Any] | None:
    registry = field_registry or {}
    if registry and not registry.get("has_campaign_fields", False):
        return None
    mapping = _ops_column_map(frame)
    if not mapping["activity"] or not mapping["active"]:
        return None
    base_rows = _ops_group_summary_rows(frame, group_column=mapping["activity"], mapping=mapping)
    rows = [
        {
            "活动": row["对象"],
            "活跃总量": row["活跃总量"],
            "活跃均值": row["活跃均值"],
            **({"新增总量": row["新增总量"], "新增均值": row["新增均值"]} if "新增总量" in row else {}),
            **({"订单总量": row["订单总量"], "订单均值": row["订单均值"]} if "订单总量" in row else {}),
            **({"留存率": row["留存率"]} if "留存率" in row else {}),
            **({"转化率": row["转化率"]} if "转化率" in row else {}),
        }
        for row in base_rows
    ]
    guard = _ops_priority_guard(base_rows)
    bullets = []
    if rows:
        if guard["status"] == "no_clear_priority":
            bullets.append(
                f"`{rows[0]['活动']}` 虽然总量最高，但活动之间的活跃均值、留存率、转化率和订单均值差距都不够大，不能直接把它写成“最该优先复盘的活动”。"
            )
        elif guard["status"] == "clear_efficiency_lead":
            bullets.append(
                f"`{rows[0]['活动']}` 在承接效率上已经拉开，说明它不只是样本数多，而是更有机会进入第一轮活动机制复盘。"
            )
        else:
            bullets.append(
                f"`{rows[0]['活动']}` 当前总量领先，但后续要继续验证它是否只是样本覆盖更广，而不是真正更有效率。"
            )
    bullets.append("活动层必须区分总量冠军和效率冠军；样本量最大不等于活动机制最好。")
    return _section(
        "ops_activity_scorecard",
        "阶段二：活动承接判断",
        "这部分专门区分“活动总量高”与“活动承接效率高”，避免因为样本覆盖大就把活动写成最优先对象。",
        bullets or ["活动主表用于区分“带来规模的活动”和“带来结果的活动”，避免只看短期冲高。"],
        tables=[_table("活动承接主表", rows)],
    )


def _ops_content_scorecard_rows(frame: pd.DataFrame, field_registry: dict[str, Any] | None = None) -> list[dict[str, Any]]:
    registry = field_registry or {}
    if registry and not registry.get("has_content_fields", False):
        return []
    mapping = _ops_column_map(frame)
    if not mapping["content"] or not mapping["active"]:
        return []
    base_rows = _ops_group_summary_rows(frame, group_column=mapping["content"], mapping=mapping)
    return [
        {
            "内容主题": row["对象"],
            "活跃总量": row["活跃总量"],
            "活跃均值": row["活跃均值"],
            **({"新增总量": row["新增总量"], "新增均值": row["新增均值"]} if "新增总量" in row else {}),
            **({"订单总量": row["订单总量"], "订单均值": row["订单均值"]} if "订单总量" in row else {}),
            **({"留存率": row["留存率"]} if "留存率" in row else {}),
            **({"转化率": row["转化率"]} if "转化率" in row else {}),
        }
        for row in base_rows
    ]


def _ops_content_scorecard_section(frame: pd.DataFrame, field_registry: dict[str, Any] | None = None) -> dict[str, Any] | None:
    rows = _ops_content_scorecard_rows(frame, field_registry)
    if not rows:
        return None
    base_rows = [{"对象": row["内容主题"], **{key: value for key, value in row.items() if key != "内容主题"}} for row in rows]
    guard = _ops_priority_guard(base_rows)
    bullets: list[str] = []
    if guard["status"] == "no_clear_priority":
        bullets.append(
            f"`{rows[0]['内容主题']}` 虽然当前总量不低，但内容主题之间的活跃均值、转化率和订单均值还没有拉出足够差距，不能直接把它写成“最值得放大的主题”。"
        )
    elif guard["status"] == "clear_efficiency_lead":
        bullets.append(
            f"`{rows[0]['内容主题']}` 不只是曝光或活跃更高，它在转化或订单承接上也更强，因此可以进入第一轮内容机制复盘。"
        )
    else:
        bullets.append(
            f"`{rows[0]['内容主题']}` 当前只是头部主题之一，后续需要继续确认它是拉活内容、留存内容，还是成交内容。"
        )
    bullets.append("内容层不能只按总活跃排优先级，必须区分拉活、承接和成交三种不同内容职责。")
    return _section(
        "ops_content_scorecard",
        "阶段三：内容主题判断",
        "这部分回答内容主题到底在做拉活、做承接，还是在做成交，避免把头部主题直接等同于最优主题。",
        bullets,
        tables=[_table("内容主题判断表", rows)],
    )


def _build_internet_ops_agent_context(
    *,
    frame: pd.DataFrame,
    request: SmartReportRequest,
    program_bundle: dict[str, Any],
    recommended_method_runs: list[dict[str, Any]],
    method_reviews: list[dict[str, Any]] | None = None,
) -> dict[str, Any]:
    resolved_request = _resolved_request_from_program(request, program_bundle)
    internet_ops_registry = program_bundle.get("internet_ops_field_availability_registry") or {}
    context_rows = _internet_ops_context_rows(frame, internet_ops_registry)

    method_findings = []
    for run in recommended_method_runs[:10]:
        request_payload = run.get("request", {}) or {}
        method_findings.append(
            {
                "method": str(run.get("method") or run.get("method_id") or "统计方法"),
                "method_id": str(run.get("method_id") or ""),
                "target": request_payload.get("target"),
                "group_column": request_payload.get("group_column"),
                "metrics": _dedupe_preserve_order(
                    ([str(request_payload.get("target"))] if request_payload.get("target") else [])
                    + [str(item) for item in request_payload.get("features", []) if item]
                ),
                "result": _method_result_sentence(run),
                "business_use": _method_business_use_sentence(run, resolved_request, "internet_ops_review"),
            }
        )

    return {
        "dataset_name": program_bundle.get("dataset_name") or "",
        "sheet_name": program_bundle.get("sheet_name") or "",
        "user_requirement": resolved_request.user_requirement,
        "problem_to_solve": resolved_request.problem_to_solve,
        "target_audience": resolved_request.target_audience,
        "core_purpose": resolved_request.core_purpose,
        "expected_result": resolved_request.expected_result,
        "business_background_name": resolved_request.business_background_name,
        "business_background_text": resolved_request.business_background_text,
        "requirement_model": program_bundle.get("requirement_model") or {},
        "autofilled_request": program_bundle.get("resolved_request_payload") or {},
        "internet_ops_field_availability_registry": internet_ops_registry,
        "internet_operations_analysis_modules": program_bundle.get("internet_operations_analysis_modules") or {},
        "internet_ops_object_decision_registry": program_bundle.get("internet_ops_object_decision_registry") or {},
        "internet_ops_action_table": program_bundle.get("internet_ops_action_table") or [],
        "topline_rows": context_rows["topline_rows"],
        "channel_rows": context_rows["channel_rows"],
        "activity_rows": context_rows["activity_rows"],
        "content_rows": context_rows["content_rows"],
        "channel_impact_rows": context_rows["channel_impact_rows"],
        "activity_impact_rows": context_rows["activity_impact_rows"],
        "content_impact_rows": context_rows["content_impact_rows"],
        "combo_rows": context_rows["combo_rows"],
        "combo_action_rows": context_rows["combo_action_rows"],
        "method_findings": method_findings,
        "method_reviews": (method_reviews or [])[:10],
        "core_outcomes": (program_bundle.get("program") or {}).get("core_outcomes", []),
        "efficiency_metrics": (program_bundle.get("program") or {}).get("efficiency_metrics", []),
        "explanatory_slices": (program_bundle.get("program") or {}).get("explanatory_slices", []),
    }


def _internet_ops_sections_from_agent(context: dict[str, Any] | None) -> list[dict[str, Any]]:
    if not context:
        return []
    sections: list[dict[str, Any]] = []
    if context.get("management_summary") or context.get("key_findings"):
        sections.append(
            _section(
                "ops_specialist_judgement",
                "互联网运营专门结论层",
                "这部分由互联网运营专门 agent 结合已有统计结果、渠道/活动/内容切片和业务背景重新压缩出运营结论，避免正文只停留在通用描述。",
                [
                    context.get("management_summary", ""),
                    *(context.get("key_findings") or [])[:4],
                    *(context.get("metric_interpretations") or [])[:2],
                ],
            )
        )
    if context.get("managerial_actions") or context.get("validation_agenda"):
        rows = [
            {"动作类型": "当前动作", "内容": item}
            for item in (context.get("managerial_actions") or [])[:5]
        ] + [
            {"动作类型": "验证议程", "内容": item}
            for item in (context.get("validation_agenda") or [])[:5]
        ]
        sections.append(
            _section(
                "ops_specialist_actions",
                "增长动作与验证议程",
                "这部分把互联网运营专门 agent 的动作建议和验证议程拆开，帮助团队先执行、再验证，而不是只停留在方向性判断。",
                [
                    *(context.get("risk_flags") or [])[:3],
                ],
                tables=[_table("增长动作与验证议程", rows)],
            )
        )
    return sections


def _build_method_review_context(
    *,
    frame: pd.DataFrame,
    program_bundle: dict[str, Any],
    request: SmartReportRequest,
    recommended_method_runs: list[dict[str, Any]],
) -> dict[str, Any]:
    resolved_request = _resolved_request_from_program(request, program_bundle)
    report_lens = str(program_bundle.get("lens") or "")
    method_runs: list[dict[str, Any]] = []
    for run in recommended_method_runs:
        method_request = run.get("request", {}) or {}
        target = method_request.get("target")
        target_summary: dict[str, Any] | None = None
        if target and target in frame.columns:
            target_series = pd.to_numeric(frame[target], errors="coerce").dropna()
            if not target_series.empty:
                target_summary = {
                    "n": int(target_series.shape[0]),
                    "mean": round(float(target_series.mean()), 4),
                    "median": round(float(target_series.median()), 4),
                    "std": round(float(target_series.std()), 4) if len(target_series) > 1 else 0.0,
                    "min": round(float(target_series.min()), 4),
                    "max": round(float(target_series.max()), 4),
                    "p25": round(float(target_series.quantile(0.25)), 4),
                    "p75": round(float(target_series.quantile(0.75)), 4),
                }
        compact_tables: list[dict[str, Any]] = []
        for table in (run.get("result", {}) or {}).get("tables", [])[:2]:
            compact_tables.append(
                {
                    "title": table.get("title"),
                    "columns": table.get("columns", [])[:10],
                    "rows": (table.get("rows", []) or [])[:6],
                }
            )
        method_runs.append(
            {
                "method": str(run.get("method") or run.get("method_id") or "统计方法"),
                "method_id": str(run.get("method_id") or ""),
                "target": target,
                "group_column": method_request.get("group_column"),
                "features": method_request.get("features", [])[:8],
                "focus_question": _method_focus_question(str(run.get("method_id") or ""), method_request),
                "result_sentence": _method_result_sentence(run),
                "business_use": _method_business_use_sentence(run, resolved_request, report_lens),
                "metrics": (run.get("result", {}) or {}).get("metrics", {}) or {},
                "target_summary": target_summary,
                "tables": compact_tables,
            }
        )

    context: dict[str, Any] = {
        "dataset_name": program_bundle.get("dataset_name") or "",
        "sheet_name": program_bundle.get("sheet_name") or "",
        "report_lens": report_lens,
        "user_requirement": resolved_request.user_requirement,
        "problem_to_solve": resolved_request.problem_to_solve,
        "target_audience": resolved_request.target_audience,
        "core_purpose": resolved_request.core_purpose,
        "expected_result": resolved_request.expected_result,
        "business_background_name": resolved_request.business_background_name,
        "business_background_text": resolved_request.business_background_text,
        "method_runs": method_runs,
        "core_outcomes": (program_bundle.get("program") or {}).get("core_outcomes", [])[:6],
        "efficiency_metrics": (program_bundle.get("program") or {}).get("efficiency_metrics", [])[:6],
        "explanatory_slices": (program_bundle.get("program") or {}).get("explanatory_slices", [])[:6],
    }
    if report_lens == "internet_ops_review":
        internet_ops_registry = program_bundle.get("internet_ops_field_availability_registry") or {}
        context["internet_ops_field_availability_registry"] = internet_ops_registry
        context["internet_ops_object_decision_registry"] = program_bundle.get("internet_ops_object_decision_registry") or {}
        context["internet_ops_action_table"] = program_bundle.get("internet_ops_action_table") or []
        context.update(_internet_ops_context_rows(frame, internet_ops_registry))
    return context


