def _business_judgement_section(layer: dict[str, Any] | None) -> dict[str, Any] | None:
    if not layer:
        return None
    bullets = [str(item).strip() for item in (layer.get("judgement_points") or []) if str(item).strip()]
    if str(layer.get("report_lens") or "") != "procurement_sales_review":
        bullets.extend(str(item).strip() for item in (layer.get("strategic_implications") or [])[:2] if str(item).strip())
    summary_text = " ".join(_flatten_text_items(layer.get("management_summary"))) or "这部分把前面的证据和反证压成真正贴业务的判断。"
    if not bullets and not summary_text.strip():
        return None
    rows = [{"关键决策问题": item} for item in (layer.get("focus_decisions") or [])[:5] if str(item).strip()]
    return {
        "id": "business_judgement",
        "title": "业务判断层",
        "summary": summary_text,
        "bullets": bullets[:6],
        "tables": [
            {
                "title": "关键决策问题",
                "columns": ["关键决策问题"],
                "rows": rows,
            }
        ]
        if rows
        else [],
        "charts": [],
    }


