def _judge_feedback_section(layer: dict[str, Any] | None) -> dict[str, Any] | None:
    if not layer:
        return None
    bullets = [str(item).strip() for item in (layer.get("revise_instructions") or []) if str(item).strip()]
    route_summary = layer.get("route_summary") or []
    if isinstance(route_summary, dict):
        for key in ["summary", "message", "reason", "final_route"]:
            value = str(route_summary.get(key) or "").strip()
            if value:
                bullets.append(value)
    elif isinstance(route_summary, list):
        bullets.extend(str(item).strip() for item in route_summary[:2] if str(item).strip())
    elif str(route_summary).strip():
        bullets.append(str(route_summary).strip())
    rows = [
        {
            "issue_type": item.get("issue_type"),
            "route_to": item.get("route_to"),
            "message": item.get("message"),
            "severity": item.get("severity"),
        }
        for item in (layer.get("issues") or [])[:10]
        if item.get("issue_type")
    ]
    return {
        "id": "judge_feedback",
        "title": "judge_feedback",
        "summary": f"当前推理链质检结果为 `{layer.get('verdict', 'unknown')}`。",
        "bullets": bullets[:6],
        "tables": [
            {
                "title": "judge_feedback_issues",
                "columns": ["issue_type", "route_to", "message", "severity"],
                "rows": rows,
            }
        ] if rows else [],
        "charts": [],
    }

def _recommended_method_bullets_from_reviews(method_reviews: list[dict[str, Any]]) -> list[str]:
    bullets: list[str] = []
    for review in method_reviews:
        method = str(review.get("method") or review.get("method_id") or "统计方法")
        parts = [
            str(review.get("headline") or "").strip(),
            str(review.get("result_meaning") or "").strip(),
            str(review.get("business_takeaway") or "").strip(),
            str(review.get("caution") or "").strip(),
        ]
        joined = " ".join(part for part in parts if part)
        bullets.append(f"{method}：{joined or '已完成实跑，但当前没有拿到可展示的解释结果。'}")
    return bullets


def _method_execution_tables(
    recommended_method_runs: list[dict[str, Any]],
    method_reviews: list[dict[str, Any]],
    report_request: SmartReportRequest,
    lens: str,
    selection_layer: dict[str, Any] | None = None,
) -> list[dict[str, Any]]:
    if not recommended_method_runs:
        return []
    review_lookup = {
        (str(item.get("method_id") or ""), str(item.get("method") or "")): item
        for item in method_reviews
    }
    selection_rows = [
        {
            "优先级": item.get("priority"),
            "方法": item.get("method"),
            "为什么选它": item.get("why"),
            "准备回答的问题": item.get("business_question"),
            "预期输出": item.get("expected_output"),
        }
        for item in ((selection_layer or {}).get("selected_methods") or [])[:8]
        if item.get("method")
    ]
    overview_rows: list[dict[str, Any]] = []
    interpretation_rows: list[dict[str, Any]] = []
    for run in recommended_method_runs:
        method_id = str(run.get("method_id") or "")
        method_name = str(run.get("method") or method_id or "统计方法")
        request_payload = run.get("request", {}) or {}
        result = run.get("result", {}) or {}
        metrics = result.get("metrics", {}) or {}
        review = review_lookup.get((method_id, method_name), {})
        overview_rows.append(
            {
                "方法": method_name,
                "回答问题": _method_focus_question(method_id, request_payload),
                "目标字段": request_payload.get("target") or ",".join(request_payload.get("features", [])[:3]) or "n/a",
                "实跑结果": _method_result_sentence(run),
                "样本量": metrics.get("n", "n/a"),
            }
        )
        interpretation_rows.append(
            {
                "方法": method_name,
                "为什么选它": str(review.get("headline") or _method_focus_question(method_id, request_payload)).strip(),
                "结果怎么读": str(review.get("result_meaning") or _method_result_sentence(run)).strip(),
                "业务含义": str(review.get("business_takeaway") or _method_business_use_sentence(run, report_request, lens)).strip(),
                "使用边界": str(review.get("caution") or "只服务于当前样本内判断，不能越过口径边界写成绝对策略。").strip(),
            }
        )
    tables = []
    if selection_rows:
        tables.append(_table("方法选择理由", selection_rows))
    tables.extend(
        [
            _table("推荐统计方法实跑总览", overview_rows),
            _table("实跑解读卡", interpretation_rows),
        ]
    )
    tables.extend(
        table
        for run in recommended_method_runs
        for table in (run.get("result", {}) or {}).get("tables", [])[:1]
    )
    return tables


def _apply_final_polish_layer(report: dict[str, Any], final_polish_layer: dict[str, Any] | None) -> None:
    if not final_polish_layer:
        return
    polished_summary = [item for item in _flatten_text_items(final_polish_layer.get("polished_executive_summary") or []) if item]
    if polished_summary:
        report["executive_summary"] = _dedupe_preserve_order(polished_summary)[:6]
    overrides = final_polish_layer.get("section_overrides") or []
    if not isinstance(overrides, list):
        return
    section_lookup = {str(section.get("id") or ""): section for section in report.get("sections", [])}
    for override in overrides:
        section_id = str(override.get("section_id") or "").strip()
        if not section_id or section_id not in section_lookup:
            continue
        section = section_lookup[section_id]
        if str(override.get("summary") or "").strip():
            section["summary"] = str(override.get("summary")).strip()
        override_bullets = [str(item).strip() for item in (override.get("bullets") or []) if str(item).strip()]
        if override_bullets:
            section["bullets"] = override_bullets[:6]


def _apply_anti_generic_layer(report: dict[str, Any], anti_generic_layer: dict[str, Any] | None) -> None:
    if not anti_generic_layer:
        return
    executive_summary_overrides = [str(item).strip() for item in (anti_generic_layer.get("executive_summary_overrides") or []) if str(item).strip()]
    if executive_summary_overrides:
        report["executive_summary"] = executive_summary_overrides[:6]
    overrides = anti_generic_layer.get("section_overrides") or []
    if not isinstance(overrides, list):
        return
    section_lookup = {str(section.get("id") or ""): section for section in report.get("sections", [])}
    for override in overrides:
        section_id = str(override.get("section_id") or "").strip()
        if not section_id or section_id not in section_lookup:
            continue
        section = section_lookup[section_id]
        if str(override.get("summary") or "").strip():
            section["summary"] = str(override.get("summary") or "").strip()
        override_bullets = [str(item).strip() for item in (override.get("bullets") or []) if str(item).strip()]
        if override_bullets:
            section["bullets"] = override_bullets[:6]


def _build_business_synthesis_context(
    *,
    request: SmartReportRequest,
    program_bundle: dict[str, Any],
    evidence_digest_layer: dict[str, Any],
    insight_mining_layer: dict[str, Any],
    challenge_layer: dict[str, Any],
    business_background_layer: dict[str, Any],
    business_object_layer: dict[str, Any],
    historical_report_adaptation: dict[str, Any] | None,
    relation_context: dict[str, Any] | None = None,
    judge_feedback_layer: dict[str, Any] | None = None,
    gate_feedback_layer: dict[str, Any] | None = None,
) -> dict[str, Any]:
    resolved_request = _resolved_request_from_program(request, program_bundle)
    fusion_context = program_bundle.get("fusion_context") or {}
    synthesis_context = {
        "report_lens": str(program_bundle.get("lens") or ""),
        "request": resolved_request.model_dump(),
        "business_background_layer": business_background_layer,
        "business_object_layer": business_object_layer,
        "evidence_digest_layer": evidence_digest_layer,
        "insight_mining_layer": insight_mining_layer,
        "challenge_layer": challenge_layer,
        "historical_report_adaptation": historical_report_adaptation or {},
        "judge_feedback_layer": judge_feedback_layer or {},
        "gate_feedback_layer": gate_feedback_layer or {},
        "relation_context": relation_context or {},
    }
    if fusion_context:
        synthesis_context["fusion_context"] = fusion_context
        rows_by_dimension = fusion_context.get("rows_by_dimension") or {}
        synthesis_context["product_rows"] = rows_by_dimension.get("商品", [])
        synthesis_context["sku_rows"] = rows_by_dimension.get("SKU", [])
        synthesis_context["category_rows"] = rows_by_dimension.get("品类", [])
        synthesis_context["supplier_rows"] = rows_by_dimension.get("供应商", [])
    return synthesis_context


def _build_judge_feedback_context(
    *,
    report_lens: str,
    report_style: str,
    business_judgement_layer: dict[str, Any],
    decision_design_layer: dict[str, Any],
    final_polish_layer: dict[str, Any],
    challenge_layer: dict[str, Any],
) -> dict[str, Any]:
    return {
        "report_lens": report_lens,
        "report_style": report_style,
        "business_judgement_layer": business_judgement_layer,
        "decision_design_layer": decision_design_layer,
        "final_polish_layer": final_polish_layer,
        "challenge_layer": challenge_layer,
    }


def _run_reasoning_chain(
    *,
    metadata: dict[str, Any],
    sheet: dict[str, Any],
    frame: pd.DataFrame,
    request: SmartReportRequest,
    report_lens: str,
    program_bundle: dict[str, Any],
    report: dict[str, Any],
    requirement_layer: dict[str, Any],
    data_understanding: dict[str, Any],
    semantic_layer: dict[str, Any],
    metric_interpretation_layer: dict[str, Any],
    method_review_layer: dict[str, Any],
    business_background_layer: dict[str, Any],
    business_object_layer: dict[str, Any],
    codex_layer: dict[str, Any],
    historical_report_adaptation: dict[str, Any] | None,
    relation_context: dict[str, Any] | None = None,
    context_compaction: dict[str, Any] | None = None,
    gate_feedback_layer: dict[str, Any] | None = None,
    coordinator: ReportCoordinator | None = None,
    max_revision_rounds: int = 2,
    fast_runtime_mode: bool = False,
    stage_registry: dict[str, dict[str, Any]] | None = None,
) -> dict[str, Any]:
    def _execute_reasoning_stage(
        *,
        stage_id: str,
        title: str,
        detail: str,
        runner: Any,
        revision_round: int = 0,
    ) -> Any:
        effective_stage_id = stage_id if revision_round <= 0 else f"{stage_id}_rerun_{revision_round}"
        effective_title = title if revision_round <= 0 else f"{title}（回修第 {revision_round} 轮）"
        if coordinator:
            return coordinator.execute_stage(
                stage_id=effective_stage_id,
                title=effective_title,
                detail=detail,
                runner=runner,
            )
        return runner()

    evidence_digest_layer = _execute_reasoning_stage(
        stage_id="evidence_digest",
        title="压缩证据层",
        detail="将需求、语义、方法和业务上下文压成优先证据包。",
        runner=lambda: codex_evidence_digest(
            build_evidence_digest_context(
                dataset_name=metadata["name"],
                sheet_name=sheet["name"],
                report_style=request.report_style,
                report_lens=report_lens,
                request=request.model_dump(),
                requirement_layer=requirement_layer,
                data_understanding=data_understanding,
                semantic_layer=semantic_layer,
                metric_interpretation_layer=metric_interpretation_layer,
                method_review_layer=method_review_layer,
                business_background_layer=business_background_layer,
                business_object_layer=business_object_layer,
                codex_layer=codex_layer,
                relation_context=relation_context,
                context_compaction=context_compaction,
                sections=report.get("sections", []),
            )
        ),
    )
    if fast_runtime_mode:
        insight_mining_layer = {
            "headline": "交互式快速模式已启用，洞察挖掘层暂不单独展开。",
            "deep_insights": [],
            "management_implications": [],
            "drilldown_questions": [],
        }
        challenge_layer = {
            "headline": "交互式快速模式已启用，反证挑战层暂不单独展开。",
            "counterpoints": [],
            "risk_boundaries": [],
        }
    else:
        insight_mining_layer = _execute_reasoning_stage(
            stage_id="insight_mining",
            title="洞察挖掘层",
            detail="从压缩证据里提炼非显而易见、值得进入正文的洞察。",
            runner=lambda: codex_insight_mining(
                build_insight_mining_context(
                    dataset_name=metadata["name"],
                    sheet_name=sheet["name"],
                    report_lens=report_lens,
                    request=request.model_dump(),
                    evidence_digest_layer=evidence_digest_layer,
                    business_background_layer=business_background_layer,
                    business_object_layer=business_object_layer,
                    relation_context=relation_context,
                    context_compaction=context_compaction,
                )
            ),
        )
        challenge_layer = _execute_reasoning_stage(
            stage_id="challenge_review",
            title="反证挑战层",
            detail="挑战过度解释，标记边界与反例。",
            runner=lambda: codex_challenge_review(
                build_challenge_context(
                    dataset_name=metadata["name"],
                    sheet_name=sheet["name"],
                    report_lens=report_lens,
                    request=request.model_dump(),
                    evidence_digest_layer=evidence_digest_layer,
                    insight_mining_layer=insight_mining_layer,
                )
            ),
        )

    def _business_synthesis_runner(current_judge_feedback: dict[str, Any] | None = None) -> Any:
        return codex_business_synthesis(
            _build_business_synthesis_context(
                request=request,
                program_bundle=program_bundle,
                evidence_digest_layer=evidence_digest_layer,
                insight_mining_layer=insight_mining_layer,
                challenge_layer=challenge_layer,
                business_background_layer=business_background_layer,
                business_object_layer=business_object_layer,
                historical_report_adaptation=historical_report_adaptation,
                relation_context=relation_context,
                judge_feedback_layer=current_judge_feedback,
                gate_feedback_layer=gate_feedback_layer,
            )
        )

    def _decision_design_runner(current_business_judgement_layer: dict[str, Any]) -> Any:
        return codex_decision_design(
            build_decision_design_context(
                dataset_name=metadata["name"],
                sheet_name=sheet["name"],
                report_lens=report_lens,
                request=request.model_dump(),
                business_judgement_layer=current_business_judgement_layer,
                challenge_layer=challenge_layer,
            )
        )

    def _anti_generic_runner(
        current_business_judgement_layer: dict[str, Any],
        current_decision_design_layer: dict[str, Any],
    ) -> Any:
        return codex_anti_generic_review(
            _build_anti_generic_context(
                report_lens=report_lens,
                report_style=request.report_style,
                report=report,
                business_judgement_layer=current_business_judgement_layer,
                decision_design_layer=current_decision_design_layer,
                challenge_layer=challenge_layer,
                gate_feedback_layer=gate_feedback_layer,
            )
        )

    def _final_polish_runner(
        current_business_judgement_layer: dict[str, Any],
        current_decision_design_layer: dict[str, Any],
        current_anti_generic_layer: dict[str, Any],
    ) -> Any:
        return codex_final_polish(
            _build_final_polish_context(
                report_lens=report_lens,
                report_style=request.report_style,
                report=report,
                business_judgement_layer=current_business_judgement_layer,
                decision_design_layer=current_decision_design_layer,
                challenge_layer=challenge_layer,
                gate_feedback_layer=gate_feedback_layer,
                anti_generic_layer=current_anti_generic_layer,
            )
        )

    def _judge_feedback_runner(
        current_business_judgement_layer: dict[str, Any],
        current_decision_design_layer: dict[str, Any],
        current_final_polish_layer: dict[str, Any],
    ) -> Any:
        return codex_judge_feedback(
            _build_judge_feedback_context(
                report_lens=report_lens,
                report_style=request.report_style,
                business_judgement_layer=current_business_judgement_layer,
                decision_design_layer=current_decision_design_layer,
                final_polish_layer=current_final_polish_layer,
                challenge_layer=challenge_layer,
            )
        )

    business_judgement_layer = _execute_reasoning_stage(
        stage_id="business_synthesis",
        title="业务综合判断层",
        detail="将洞察与边界翻译成管理层可执行判断。",
        runner=lambda: _business_synthesis_runner(),
    )
    decision_design_layer = _execute_reasoning_stage(
        stage_id="decision_design",
        title="决策设计层",
        detail="把业务判断翻译成优先级、动作和验证路径。",
        runner=lambda: _decision_design_runner(business_judgement_layer),
    )
    anti_generic_layer = _execute_reasoning_stage(
        stage_id="anti_generic_review",
        title="反泛化巡检层",
        detail="识别主报告草稿里的空话、元叙述和重复句，并给出定向重写指令。",
        runner=lambda: _anti_generic_runner(business_judgement_layer, decision_design_layer),
    )
    _apply_anti_generic_layer(report, anti_generic_layer)
    final_polish_layer = _execute_reasoning_stage(
        stage_id="final_polish",
        title="最终润色层",
        detail="压缩表达、 sharpen 结构，但不改证据含义。",
        runner=lambda: _final_polish_runner(business_judgement_layer, decision_design_layer, anti_generic_layer),
    )
    judge_feedback_layer = _execute_reasoning_stage(
        stage_id="judge_feedback",
        title="推理链质检层",
        detail="对 reasoning chain 做质检并给出回修路径。",
        runner=lambda: _judge_feedback_runner(
            business_judgement_layer,
            decision_design_layer,
            final_polish_layer,
        ),
    )

    revision_rounds = 0
    while (
        str(judge_feedback_layer.get("verdict") or "").strip().lower() == "revise"
        and revision_rounds < max(1, int(max_revision_rounds))
    ):
        revision_rounds += 1
        routes = summarize_revision_routes(judge_feedback_layer)
        if coordinator:
            coordinator.record_stage(
                "reasoning_revision_route",
                "推理链回修路由",
                "根据 judge_feedback 结果决定打回哪些推理阶段。",
                payload={
                    "revision_round": revision_rounds,
                    "business_routes": len(routes["business"]),
                    "decision_routes": len(routes["decision"]),
                    "polish_routes": len(routes["polish"]),
                },
            )

        if routes["business"]:
            business_judgement_layer = _execute_reasoning_stage(
                stage_id="business_synthesis",
                title="业务综合判断层",
                detail="根据 judge_feedback 回修业务判断层。",
                runner=lambda current_feedback=judge_feedback_layer: _business_synthesis_runner(current_feedback),
                revision_round=revision_rounds,
            )
            decision_design_layer = _execute_reasoning_stage(
                stage_id="decision_design",
                title="决策设计层",
                detail="根据业务回修结果重跑决策设计层。",
                runner=lambda current_business=business_judgement_layer: _decision_design_runner(current_business),
                revision_round=revision_rounds,
            )
            anti_generic_layer = _execute_reasoning_stage(
                stage_id="anti_generic_review",
                title="反泛化巡检层",
                detail="根据回修后的判断和动作，继续清理主报告中的空话与重复句。",
                runner=lambda current_business=business_judgement_layer, current_decision=decision_design_layer: _anti_generic_runner(
                    current_business,
                    current_decision,
                ),
                revision_round=revision_rounds,
            )
            _apply_anti_generic_layer(report, anti_generic_layer)
            final_polish_layer = _execute_reasoning_stage(
                stage_id="final_polish",
                title="最终润色层",
                detail="根据回修后的业务判断和动作重跑润色层。",
                runner=lambda current_business=business_judgement_layer, current_decision=decision_design_layer, current_anti=anti_generic_layer: _final_polish_runner(
                    current_business,
                    current_decision,
                    current_anti,
                ),
                revision_round=revision_rounds,
            )
        elif routes["decision"]:
            decision_design_layer = _execute_reasoning_stage(
                stage_id="decision_design",
                title="决策设计层",
                detail="根据 judge_feedback 回修决策设计层。",
                runner=lambda current_business=business_judgement_layer: _decision_design_runner(current_business),
                revision_round=revision_rounds,
            )
            anti_generic_layer = _execute_reasoning_stage(
                stage_id="anti_generic_review",
                title="反泛化巡检层",
                detail="根据回修后的动作设计，继续清理主报告中的空话与重复句。",
                runner=lambda current_business=business_judgement_layer, current_decision=decision_design_layer: _anti_generic_runner(
                    current_business,
                    current_decision,
                ),
                revision_round=revision_rounds,
            )
            _apply_anti_generic_layer(report, anti_generic_layer)
            final_polish_layer = _execute_reasoning_stage(
                stage_id="final_polish",
                title="最终润色层",
                detail="根据回修后的动作设计重跑润色层。",
                runner=lambda current_business=business_judgement_layer, current_decision=decision_design_layer, current_anti=anti_generic_layer: _final_polish_runner(
                    current_business,
                    current_decision,
                    current_anti,
                ),
                revision_round=revision_rounds,
            )
        else:
            anti_generic_layer = _execute_reasoning_stage(
                stage_id="anti_generic_review",
                title="反泛化巡检层",
                detail="根据 judge_feedback 回修表达层前，先做一轮反泛化巡检。",
                runner=lambda current_business=business_judgement_layer, current_decision=decision_design_layer: _anti_generic_runner(
                    current_business,
                    current_decision,
                ),
                revision_round=revision_rounds,
            )
            _apply_anti_generic_layer(report, anti_generic_layer)
            final_polish_layer = _execute_reasoning_stage(
                stage_id="final_polish",
                title="最终润色层",
                detail="根据 judge_feedback 回修表达层。",
                runner=lambda current_business=business_judgement_layer, current_decision=decision_design_layer, current_anti=anti_generic_layer: _final_polish_runner(
                    current_business,
                    current_decision,
                    current_anti,
                ),
                revision_round=revision_rounds,
            )

        judge_feedback_layer = _execute_reasoning_stage(
            stage_id="judge_feedback",
            title="推理链质检层",
            detail="对回修后的 reasoning chain 重新判分并决定是否继续回修。",
            runner=lambda current_business=business_judgement_layer, current_decision=decision_design_layer, current_polish=final_polish_layer: _judge_feedback_runner(
                current_business,
                current_decision,
                current_polish,
            ),
            revision_round=revision_rounds,
        )

    judge_feedback_layer["revision_rounds"] = revision_rounds
    return {
        "stage_registry": stage_registry or {},
        "evidence_digest_layer": evidence_digest_layer,
        "insight_mining_layer": insight_mining_layer,
        "challenge_layer": challenge_layer,
        "business_judgement_layer": business_judgement_layer,
        "decision_design_layer": decision_design_layer,
        "anti_generic_layer": anti_generic_layer,
        "final_polish_layer": final_polish_layer,
        "judge_feedback_layer": judge_feedback_layer,
    }


def _media_overview_table_section_from_context(context: dict[str, Any]) -> dict[str, Any] | None:
    overall = (context.get("metrics") or {}).get("overall") or {}
    rows = [
        {"核心指标": "总预算", "数值": _display_table_value("总预算", overall.get("total_spend")), "说明": "整体投入盘子"},
        {"核心指标": "总预估曝光", "数值": _display_table_value("总预估曝光", overall.get("total_estimated_reach")), "说明": "计划口径曝光"},
        {"核心指标": "总监测曝光", "数值": _display_table_value("总监测曝光", overall.get("total_actual_reach")), "说明": "实际监测曝光"},
        {"核心指标": "总预估点击", "数值": _display_table_value("总预估点击", overall.get("total_estimated_interaction")), "说明": "计划口径点击"},
        {"核心指标": "总监测点击", "数值": _display_table_value("总监测点击", overall.get("total_actual_interaction")), "说明": "实际监测点击"},
        {"核心指标": "整体CTR", "数值": _format_percent(overall.get("weighted_ctr")), "说明": "点击效率"},
        {"核心指标": "整体曝光兑现", "数值": _format_percent(overall.get("weighted_exposure_delivery")), "说明": "监测曝光 / 预估曝光"},
        {"核心指标": "整体点击兑现", "数值": _format_percent(overall.get("weighted_click_delivery")), "说明": "监测点击 / 预估点击"},
        {"核心指标": "整体CPM", "数值": _display_table_value("CPM", overall.get("weighted_cpm")), "说明": "预算 / 千次监测曝光"},
        {"核心指标": "整体CPC", "数值": _display_table_value("CPC", overall.get("weighted_cpc")), "说明": "预算 / 监测点击"},
    ]
    if not any(str(row["数值"]).strip() and str(row["数值"]) != "n/a" for row in rows):
        return None
    bullets = [
        "管理层先看总盘子，再看效率和兑现；如果这一页都说不清，后面所有切片判断都不稳。",
    ]
    if overall.get("weighted_exposure_delivery") is not None:
        bullets.append(
            f"当前整体曝光兑现约为 {_format_percent(overall.get('weighted_exposure_delivery'))}，它决定计划与实际执行是否在同一条线上。"
        )
    if overall.get("weighted_ctr") is not None:
        bullets.append(
            f"当前整体CTR约为 {_format_percent(overall.get('weighted_ctr'))}，这是预算换来点击效率的第一层判断。"
        )
    return _section(
        "media_overview",
        "投放经营总览主表",
        "先把预算、曝光、点击、效率和兑现放在同一页说清楚，再决定哪些媒体单元值得进入动作判断。",
        bullets,
        tables=[_table("投放经营总览主表", rows)],
    )


def _media_dimension_scorecards_section(frame: pd.DataFrame, context: dict[str, Any]) -> dict[str, Any] | None:
    columns = context.get("metric_columns") or {}
    actual_reach = columns.get("actual_reach")
    estimated_reach = columns.get("estimated_reach")
    actual_interaction = columns.get("actual_interaction")
    spend = columns.get("spend")
    if not actual_reach or actual_reach not in frame.columns:
        return None

    working = frame.copy()
    for column in [actual_reach, estimated_reach, actual_interaction, spend]:
        if column and column in working.columns:
            working[column] = pd.to_numeric(working[column], errors="coerce")
    working = working.dropna(subset=[actual_reach])
    if working.empty:
        return None

    role_to_title = [
        ("media", "媒体经营对比"),
        ("device", "终端经营对比"),
        ("brand", "品牌经营对比"),
        ("region", "省份经营对比"),
        ("placement", "点位经营对比"),
    ]
    tables: list[dict[str, Any]] = []
    bullets: list[str] = []
    total_reach = float(working[actual_reach].sum()) or 1.0
    role_summary = context.get("role_summary") or {}
    for role, title in role_to_title:
        column_candidates = [str(item.get("column")) for item in role_summary.get(role, []) if item.get("column")]
        dimension = next((item for item in column_candidates if item in working.columns), None)
        if not dimension:
            continue
        grouped = working.groupby(dimension, dropna=False).agg(
            {
                actual_reach: "sum",
                **({actual_interaction: "sum"} if actual_interaction and actual_interaction in working.columns else {}),
                **({estimated_reach: "sum"} if estimated_reach and estimated_reach in working.columns else {}),
                **({spend: "sum"} if spend and spend in working.columns else {}),
            }
        ).reset_index()
        grouped["触达占比"] = grouped[actual_reach] / total_reach
        if actual_interaction and actual_interaction in grouped.columns:
            grouped["CTR"] = np.where(grouped[actual_reach] > 0, grouped[actual_interaction] / grouped[actual_reach], np.nan)
        if estimated_reach and estimated_reach in grouped.columns:
            grouped["曝光兑现"] = np.where(grouped[estimated_reach] > 0, grouped[actual_reach] / grouped[estimated_reach], np.nan)
        if spend and spend in grouped.columns:
            grouped["CPM"] = np.where(grouped[actual_reach] > 0, grouped[spend] * 1000 / grouped[actual_reach], np.nan)
            if actual_interaction and actual_interaction in grouped.columns:
                grouped["CPC"] = np.where(grouped[actual_interaction] > 0, grouped[spend] / grouped[actual_interaction], np.nan)
        grouped = grouped.sort_values(actual_reach, ascending=False)
        top = grouped.iloc[0]
        bullets.append(f"`{top[dimension]}` 当前在 {title} 中承担了更大的触达盘子，占比约 {_format_percent(float(top['触达占比']))}。")
        rows = []
        for _, row in grouped.iterrows():
            rows.append(
                {
                    title.replace("经营对比", ""): str(row[dimension]),
                    "触达占比": _format_percent(float(row["触达占比"])),
                    "监测曝光": _display_table_value("监测曝光", float(row[actual_reach])),
                    **({"监测点击": _display_table_value("监测点击", float(row[actual_interaction]))} if actual_interaction and actual_interaction in grouped.columns else {}),
                    **({"CTR": _format_percent(float(row["CTR"])) if pd.notna(row.get("CTR")) else "n/a"} if "CTR" in grouped.columns else {}),
                    **({"曝光兑现": _format_percent(float(row["曝光兑现"])) if pd.notna(row.get("曝光兑现")) else "n/a"} if "曝光兑现" in grouped.columns else {}),
                    **({"CPM": _display_table_value("CPM", float(row["CPM"])) if pd.notna(row.get("CPM")) else "n/a"} if "CPM" in grouped.columns else {}),
                    **({"CPC": _display_table_value("CPC", float(row["CPC"])) if pd.notna(row.get("CPC")) else "n/a"} if "CPC" in grouped.columns else {}),
                }
            )
        tables.append(_table(title, rows))
    if not tables:
        return None
    return _section(
        "media_dimension_scorecards",
        "媒体/终端/品牌/点位经营对比",
        "这部分把管理层最关心的切片并排列出来，直接回答钱投向了谁、效率差在谁、兑现问题落在谁。",
        bullets[:5] or ["分层经营对比用于回答哪些单元该增投、保留、降投或停投。"],
        tables=tables,
    )


def _media_daily_trend_section_from_context(frame: pd.DataFrame, context: dict[str, Any]) -> dict[str, Any] | None:
    columns = context.get("metric_columns") or {}
    date_column = columns.get("date")
    actual_reach = columns.get("actual_reach")
    actual_interaction = columns.get("actual_interaction")
    spend = columns.get("spend")
    if not date_column or not actual_reach or date_column not in frame.columns or actual_reach not in frame.columns:
        return None
    working = frame[[column for column in [date_column, actual_reach, actual_interaction, spend] if column and column in frame.columns]].copy()
    working[date_column] = pd.to_datetime(working[date_column], errors="coerce", dayfirst=True)
    working[actual_reach] = pd.to_numeric(working[actual_reach], errors="coerce")
    if actual_interaction and actual_interaction in working.columns:
        working[actual_interaction] = pd.to_numeric(working[actual_interaction], errors="coerce")
    if spend and spend in working.columns:
        working[spend] = pd.to_numeric(working[spend], errors="coerce")
    working = working.dropna(subset=[date_column, actual_reach])
    if working.empty:
        return None
    grouped = working.groupby(working[date_column].dt.strftime("%Y-%m-%d")).agg(
        {
            actual_reach: "sum",
            **({actual_interaction: "sum"} if actual_interaction and actual_interaction in working.columns else {}),
            **({spend: "sum"} if spend and spend in working.columns else {}),
        }
    ).reset_index().rename(columns={date_column: "日期"})
    grouped["曝光环比"] = grouped[actual_reach].pct_change()
    if actual_interaction and actual_interaction in grouped.columns:
        grouped["CTR"] = np.where(grouped[actual_reach] > 0, grouped[actual_interaction] / grouped[actual_reach], np.nan)
    rows = []
    for _, row in grouped.tail(14).iterrows():
        rows.append(
            {
                "日期": str(row.iloc[0]),
                "监测曝光": _display_table_value("监测曝光", float(row[actual_reach])),
                **({"监测点击": _display_table_value("监测点击", float(row[actual_interaction]))} if actual_interaction and actual_interaction in grouped.columns else {}),
                **({"预算": _display_table_value("预算", float(row[spend]))} if spend and spend in grouped.columns else {}),
                **({"CTR": _format_percent(float(row["CTR"])) if pd.notna(row.get("CTR")) else "n/a"} if "CTR" in grouped.columns else {}),
                "曝光环比": _format_percent(float(row["曝光环比"])) if pd.notna(row.get("曝光环比")) else "n/a",
            }
        )
    if len(grouped) >= 2:
        latest = grouped.iloc[-1]
        prev = grouped.iloc[-2]
        change = _format_percent(float(latest[actual_reach] - prev[actual_reach]) / float(prev[actual_reach])) if float(prev[actual_reach]) else "n/a"
        bullets = [f"最新一天监测曝光相对前一天变化约 {change}，时间趋势不能只写上涨或下跌，必须同时给出波动幅度。"]
    else:
        bullets = ["日趋势用于识别预算、曝光和点击的峰谷变化以及异常日期。"]
    return _section(
        "media_daily_trend",
        "日趋势与波动主表",
        "既然识别为日报数据，就应该优先展示日预算、日曝光、日点击和环比波动，而不是只停留在一句“上升/下降”。",
        bullets,
        tables=[_table("近14日投放趋势", rows)],
    )

def _business_background_bullets(request: SmartReportRequest) -> list[str]:
    text = (request.business_background_text or "").strip()
    name = (request.business_background_name or "").strip() or "未命名业务背景"
    if not text:
        return []
    lowered = text.lower()
    if any(
        token in lowered
        for token in [
            "asteria analyst",
            "full-stack data analysis agent",
            "next.js",
            "fastapi",
            "openai codex api",
            "monaco editor",
            "duckdb",
            "build_portable",
        ]
    ):
        return [
            f"业务背景来源：`{name}`。",
            "当前上传内容更像系统或产品说明文档，不属于业务背景正文。",
            "系统不会把这类材料写进管理层业务判断，只会保留为背景来源记录。",
        ]
    lines = [line.strip() for line in text.replace("\r\n", "\n").splitlines() if line.strip()]
    bullets = [f"业务背景来源：`{name}`。"]
    bullets.extend(lines[:6])
    return bullets[:7]


def _expert_recall_bullets(program_bundle: dict[str, Any]) -> list[str]:
    bullets: list[str] = []
    for item in program_bundle.get("experts", [])[:3]:
        bullets.append(f"当前召回 `{item['expert']}` 视角，优先处理：{item['focus']}。")
        if item.get("obsession"):
            bullets.append(f"这个专家最在意的是：{item['obsession']}。")
        if item.get("signature_move"):
            bullets.append(f"它的典型动作是：{item['signature_move']}。")
        bullets.append(f"这个专家当前最先回答的问题是：{'; '.join(item.get('priority_questions', [])[:2]) or '优先识别关键问题'}。")
        bullets.append(f"这个专家优先依赖的证据是：{'; '.join(item.get('evidence_preference', [])[:3]) or '关键字段与切片证据'}。")
        bullets.append(f"这个专家最终要给出的动作输出是：{'; '.join(item.get('decision_outputs', [])[:2]) or '形成可执行判断'}。")
        if item.get("anti_pattern"):
            bullets.append(f"它最反感的误判是：{item['anti_pattern']}。")
        if item.get("guardrails"):
            bullets.append(f"这个专家不会越界写成事实的内容包括：{'; '.join(item.get('guardrails', [])[:2])}。")
    return bullets


