def _marketing_dimension_sections_from_context(context: dict[str, Any]) -> list[dict[str, Any]]:
    reviews = context.get("parsed_dimension_reviews") or {}
    measurement_mode = (context.get("measurement_mode") or {}).get("mode")
    sections: list[dict[str, Any]] = []
    mapping = [
        ("product_line", "产品线复盘", "这部分回答不同产品线承接了多少资源，以及哪些产品线值得继续保留或重点复盘。"),
        ("ad_format", "广告形态复盘", "这部分回答不同广告形态在完成率和结构上的差异，帮助判断当前形态组合是否合理。"),
        ("trading_mode", "采买方式复盘", "这部分回答程序化、PDB、PMP 等采买方式各自承担了什么角色，以及完成率是否稳定。"),
        ("platform_tag", "平台标签复盘", "这部分回答平台附加标签对应的资源位结构差异，帮助判断平台内资源选择。"),
    ]
    for key, title, summary in mapping:
        rows = reviews.get(key) or []
        if not rows:
            continue
        top = rows[0]
        bullets = [
            f"`{top['segment']}` 是当前 {title.replace('复盘','')} 中资源占比最高的对象，占比约 {_format_percent(top['reach_share'])}。",
        ]
        if measurement_mode == "cpm_delivery":
            bullets.append(
                f"在 CPM/曝光型采买下，这一层优先看完成率。当前头部对象的曝光完成率约为 {_format_percent(top['delivery_rate']) if top.get('delivery_rate') is not None else 'n/a'}。"
            )
        else:
            bullets.append(
                f"当前头部对象的互动效率约为 {_format_percent(top['ctr']) if top.get('ctr') is not None else 'n/a'}，曝光完成率约为 {_format_percent(top['delivery_rate']) if top.get('delivery_rate') is not None else 'n/a'}。"
            )
        table_rows = [
            {
                "对象": row["segment"],
                "触达占比": _format_percent(row["reach_share"]),
                **({"曝光完成率": _format_percent(row["delivery_rate"]) if row.get("delivery_rate") is not None else "n/a"}),
                **({} if measurement_mode == "cpm_delivery" else {"互动效率": _format_percent(row["ctr"]) if row.get("ctr") is not None else "n/a"}),
            }
            for row in rows
        ]
        sections.append(
            _section(
                f"mkt_{key}",
                title,
                summary,
                bullets,
                tables=[_table(title, table_rows)],
            )
        )
    return sections


def _pdf_font_path() -> str | None:
    candidates = [
        r"C:\Windows\Fonts\simhei.ttf",
        r"C:\Windows\Fonts\msyh.ttc",
        r"C:\Windows\Fonts\simsun.ttc",
    ]
    for candidate in candidates:
        if Path(candidate).exists():
            return candidate
    return None


def _pdf_text_len(value: Any) -> float:
    text = str(value or "")
    score = 0.0
    for char in text[:240]:
        score += 1.7 if ord(char) > 127 else 1.0
    return max(score, 4.0)


def _pdf_table_col_widths(columns: list[str], rows: list[dict[str, Any]], available_width: float) -> list[float]:
    long_tokens = ("对象", "组合", "点位", "说明", "建议", "回答", "判断", "证据", "问题", "segment", "title")
    weights: list[float] = []
    mins: list[float] = []
    for index, column in enumerate(columns):
        sample_values = [column]
        sample_values.extend(row.get(column, "") for row in rows[:12])
        max_len = max(_pdf_text_len(value) for value in sample_values)
        is_long = any(token in str(column) for token in long_tokens) or max_len >= 22
        weight = max_len * (1.35 if is_long else 1.0)
        if index == 0 and len(columns) >= 4:
            weight *= 1.35
            is_long = True
        weights.append(weight)
        mins.append(120 if is_long else 60)

    total_weight = sum(weights) or 1.0
    widths = [available_width * weight / total_weight for weight in weights]
    widths = [max(width, mins[index]) for index, width in enumerate(widths)]
    total_width = sum(widths)
    if total_width > available_width:
        flexible = [max(width - mins[index], 0.0) for index, width in enumerate(widths)]
        flexible_total = sum(flexible)
        overflow = total_width - available_width
        if flexible_total > 0:
            widths = [
                width - overflow * (flexible[index] / flexible_total)
                for index, width in enumerate(widths)
            ]
        else:
            widths = [available_width / max(len(columns), 1)] * len(columns)
    return widths


def _write_pdf_report_cn(report_dir: Path, report_id: str, report: dict[str, Any]) -> Path | None:
    try:
        from reportlab.lib import colors
        from reportlab.lib.enums import TA_LEFT
        from reportlab.lib.pagesizes import A4, landscape
        from reportlab.lib.styles import ParagraphStyle, getSampleStyleSheet
        from reportlab.lib.units import mm
        from reportlab.pdfbase import pdfmetrics
        from reportlab.pdfbase.ttfonts import TTFont
        from reportlab.platypus import Image as RLImage, LongTable, PageBreak, Paragraph, SimpleDocTemplate, Spacer, TableStyle
    except Exception:
        return None

    pdf_path = report_dir / f"{report_id}.pdf"
    font_name = "Helvetica"
    font_path = _pdf_font_path()
    if font_path:
        try:
            font_name = "AsteriaCN"
            pdfmetrics.registerFont(TTFont(font_name, font_path))
        except Exception:
            font_name = "Helvetica"

    styles = getSampleStyleSheet()
    title_style = ParagraphStyle(
        "AsteriaTitle",
        parent=styles["Heading1"],
        fontName=font_name,
        fontSize=20,
        leading=26,
        textColor=colors.HexColor("#1f2430"),
        spaceAfter=10,
        alignment=TA_LEFT,
    )
    section_style = ParagraphStyle(
        "AsteriaSection",
        parent=styles["Heading2"],
        fontName=font_name,
        fontSize=14,
        leading=19,
        textColor=colors.HexColor("#1f2430"),
        spaceBefore=10,
        spaceAfter=6,
    )
    body_style = ParagraphStyle(
        "AsteriaBody",
        parent=styles["BodyText"],
        fontName=font_name,
        fontSize=9.5,
        leading=14,
        textColor=colors.HexColor("#2f3742"),
        spaceAfter=4,
    )
    meta_style = ParagraphStyle(
        "AsteriaMeta",
        parent=styles["BodyText"],
        fontName=font_name,
        fontSize=9,
        leading=13,
        textColor=colors.HexColor("#5b6573"),
        spaceAfter=2,
    )
    table_header_style = ParagraphStyle(
        "AsteriaTableHeader",
        parent=styles["BodyText"],
        fontName=font_name,
        fontSize=7.5,
        leading=9,
        textColor=colors.HexColor("#1f2430"),
        wordWrap="CJK",
    )
    table_body_style = ParagraphStyle(
        "AsteriaTableBody",
        parent=styles["BodyText"],
        fontName=font_name,
        fontSize=7.2,
        leading=9,
        textColor=colors.HexColor("#2f3742"),
        wordWrap="CJK",
    )

    story: list[Any] = []
    story.append(Paragraph(html.escape(str(report["title"])), title_style))
    story.append(Paragraph(f"数据集：{html.escape(str(report['dataset_name']))}", meta_style))
    story.append(Paragraph(f"工作表：{html.escape(str(report['sheet_name']))}", meta_style))
    story.append(Paragraph(f"生成时间：{html.escape(str(report['generated_at']))}", meta_style))
    story.append(Spacer(1, 6 * mm))

    story.append(Paragraph("管理层摘要", section_style))
    for bullet in report.get("executive_summary", [])[:6]:
        story.append(Paragraph(f"• {html.escape(str(bullet))}", body_style))
    story.append(Spacer(1, 3 * mm))

    management_ids = _management_section_ids_for_report(report)
    management_sections = [section for section in report.get("sections", []) if section["id"] in management_ids]
    appendix_sections = [section for section in report.get("sections", []) if section["id"] not in management_ids]

    def append_section(section: dict[str, Any]) -> None:
        if section.get("page_break_before"):
            story.append(PageBreak())
        story.append(Paragraph(html.escape(str(section["title"])), section_style))
        if section.get("summary"):
            story.append(Paragraph(html.escape(str(section["summary"])), body_style))
        for bullet in section.get("bullets", [])[:10]:
            story.append(Paragraph(f"• {html.escape(str(bullet))}", body_style))
        for table in section.get("tables", []):
            columns = [str(column) for column in table.get("columns", [])]
            rows = table.get("rows", [])
            if columns and rows:
                visible_columns = columns[:6] if len(columns) > 6 else columns
                visible_rows = rows[:6]
                if len(visible_columns) < len(columns):
                    story.append(
                        Paragraph(
                            f"表格《{html.escape(str(table.get('title', '未命名表格')))}》列数较多，PDF 仅展示前 {len(visible_columns)} 列；完整表格请查看 HTML 或 XLSX 附件。",
                            meta_style,
                        )
                    )
                doc_width = landscape(A4)[0] - (12 * mm * 2)
                col_widths = _pdf_table_col_widths(visible_columns, visible_rows, doc_width)
                table_data = [[Paragraph(html.escape(column), table_header_style) for column in visible_columns]]
                for row in visible_rows:
                    table_data.append(
                        [
                            Paragraph(
                                html.escape(_pdf_table_value(column, row.get(column, ""))).replace("\n", "<br/>"),
                                table_body_style,
                            )
                            for column in visible_columns
                        ]
                    )
                rendered = LongTable(table_data, repeatRows=1, colWidths=col_widths, splitByRow=1)
                rendered.setStyle(
                    TableStyle(
                        [
                            ("FONTNAME", (0, 0), (-1, -1), font_name),
                            ("FONTSIZE", (0, 0), (-1, -1), 7.2),
                            ("LEADING", (0, 0), (-1, -1), 9),
                            ("BACKGROUND", (0, 0), (-1, 0), colors.HexColor("#EDE7DE")),
                            ("TEXTCOLOR", (0, 0), (-1, 0), colors.HexColor("#1f2430")),
                            ("GRID", (0, 0), (-1, -1), 0.3, colors.HexColor("#D0C7BA")),
                            ("VALIGN", (0, 0), (-1, -1), "TOP"),
                            ("LEFTPADDING", (0, 0), (-1, -1), 4),
                            ("RIGHTPADDING", (0, 0), (-1, -1), 4),
                            ("TOPPADDING", (0, 0), (-1, -1), 3),
                            ("BOTTOMPADDING", (0, 0), (-1, -1), 3),
                        ]
                    )
                )
                story.append(rendered)
                if str(table.get("note") or "").strip():
                    story.append(Paragraph(html.escape(str(table.get("note") or "")), meta_style))
                story.append(Spacer(1, 2 * mm))
        for chart in section.get("rendered_charts", []) or []:
            story.append(Paragraph(html.escape(str(chart.get("title") or "图表")), body_style))
            image = RLImage(str(chart["file_path"]))
            max_width = landscape(A4)[0] - (16 * mm * 2)
            max_height = 70 * mm
            scale = min(max_width / image.imageWidth, max_height / image.imageHeight, 1.0)
            image.drawWidth = image.imageWidth * scale
            image.drawHeight = image.imageHeight * scale
            story.append(image)
            for note in (chart.get("notes") or [])[:4]:
                story.append(Paragraph(f"• {html.escape(str(note))}", body_style))
            story.append(Spacer(1, 2 * mm))
        story.append(Spacer(1, 2 * mm))

    story.append(Paragraph("管理层正文", section_style))
    for section in management_sections:
        append_section(section)

    if appendix_sections:
        story.append(Paragraph("分析附录", section_style))
        for section in appendix_sections:
            append_section(section)

    doc = SimpleDocTemplate(
        str(pdf_path),
        pagesize=landscape(A4),
        leftMargin=12 * mm,
        rightMargin=12 * mm,
        topMargin=12 * mm,
        bottomMargin=12 * mm,
        title=str(report["title"]),
    )
    doc.build(story)
    return pdf_path


def _cluster_member_bullets(cluster_result: dict[str, Any]) -> list[str]:
    member_table = next(
        (table for table in cluster_result.get("tables", []) if table.get("title") == "Cluster members"),
        None,
    )
    if not member_table or not member_table.get("rows"):
        return []
    grouped: dict[int, list[str]] = {}
    for row in member_table["rows"]:
        cluster_id = int(row["cluster"])
        grouped.setdefault(cluster_id, []).append(str(row["member"]))
    bullets: list[str] = []
    for cluster_id in sorted(grouped):
        members = "、".join(grouped[cluster_id][:6])
        bullets.append(f"Cluster {cluster_id} 的代表成员包括：{members}。")
    return bullets[:4]


def _normalized_historical_report_text(raw_text: str) -> str:
    text = (raw_text or "").strip()
    if not text:
        return ""
    return text[:24000]


