def _friendly_required_fields(fields: list[str]) -> str:
    label_map = {
        "gross_profit": "毛利",
        "gross_margin": "毛利率",
        "net_profit": "净利润",
        "stock_qty": "库存",
        "available_stock": "可售库存",
        "inventory_days": "库存可售天数",
        "inventory_turnover": "库存周转",
        "purchase_cost": "采购成本",
        "procurement_price": "采购价",
        "supply_price": "供货价",
        "supplier_delivery_rate": "供应商交付及时率",
        "on_time_delivery_rate": "履约准时率",
        "delay_times": "延迟次数",
        "alternative_supplier": "替代供应商",
        "payment_term": "账期/合同字段",
        "profit": "毛利/利润",
        "inventory": "库存/周转",
        "procurement": "采购价/采购成本",
        "supplier_delivery": "供应商交付字段",
        "return_cost": "退货成本",
    }
    labels = []
    for item in fields:
        label = label_map.get(str(item), str(item))
        if label not in labels:
            labels.append(label)
    return " / ".join(labels) if labels else "无"


def _blocked_action_display(blocked_actions: list[str]) -> str:
    categories: list[str] = []
    for action in blocked_actions:
        if action in {"核心主推", "资源倾斜", "加码", "继续主推", "重点合作", "预算倾斜"}:
            label = "强资源动作"
        elif action in {"补货", "补货放量", "清仓", "清理退场", "停止补货", "并柜", "移出主推池", "停止采购"}:
            label = "库存型硬动作"
        elif action in {"供应商压价", "成本优化", "价格谈判", "账期谈判"}:
            label = "采购/谈判动作"
        elif action in {"直接替换", "直接替换供应商", "淘汰供应商", "替换清理"}:
            label = "供应商强问责动作"
        else:
            label = action
        if label not in categories:
            categories.append(label)
    return " / ".join(categories) if categories else "无"


def _owner_role_for_registry(item: dict[str, Any]) -> str:
    level = str(item.get("object_level") or "")
    action = str(item.get("final_action") or "")
    if level == "category":
        return "品类负责人"
    if level == "product":
        return "商品运营"
    if level == "sku":
        return "SKU运营"
    if level == "supplier" and ("履约" in action or "仓配" in action or "物流" in action):
        return "履约/仓配"
    if level == "supplier" and ("差评" in action or "口碑" in action):
        return "供应商管理"
    if level == "supplier":
        return "供应商管理"
    return "数据分析"


def _time_requirement_for_registry(item: dict[str, Any]) -> str:
    action = str(item.get("final_action") or "")
    if "待补" in action:
        return "T+1 补字段"
    if "差评归因" in action or "履约修复" in action or "拆仓配" in action:
        return "T+3 完成归因"
    if "评估" in action or "复核" in action:
        return "T+7 复核动作"
    if "降权" in action:
        return "T+3 调整并观察"
    return "下一周期验证"


def _validation_metric_for_registry(item: dict[str, Any]) -> str:
    action = str(item.get("final_action") or "")
    if "毛利" in action:
        return "毛利率补齐 / 退货成本补齐"
    if "库存" in action:
        return "库存可售天数补齐 / 库存周转补齐"
    if "差评" in action or "口碑" in action:
        return "低分评价占比下降 / 问题客户数下降"
    if "履约" in action or "仓配" in action or "物流" in action:
        return "逾期率下降 / 平均履约天数下降"
    if "降权" in action:
        return "低分评价占比下降 / 逾期率下降"
    if "评估" in action:
        return "替代供应商证据补齐 / 交付字段补齐"
    return "下一周期复核"


