def _final_management_summary_from_registry(report: dict[str, Any], registry_rows: list[dict[str, Any]], field_registry: dict[str, Any]) -> list[str]:
    key_rows = []
    for object_id in ["category_object", "product_object", "sku_object"]:
        row = next((item for item in registry_rows if str(item.get("object_id") or "") == object_id), None)
        if row:
            key_rows.append(row)

    def _line(row: dict[str, Any]) -> str:
        return clean_report_text_filter(
            f"{row['object_id']} 当前标签为“{row['final_label']}”，证据是 {row['trigger_evidence']}；最终动作是“{row['final_action']}”，结论强度为 {row['action_strength']}，置信度为 {row.get('confidence_level', 'medium')}。"
        )

    return [
        "报告模式：本报告为 sales_fulfillment_product_report，采购侧待补数，不能作为完整采销拍板报告。",
        "当前可判断内容：可判断销售结构、商品承接、SKU履约风险、售后评价风险、供应商销侧表现。",
        "当前不可判断内容：不能判断高优先级资源动作、库存类动作、采购谈判空间、完整供应商替换和完整利润表现。",
        "；".join(item for item in [_line(row) for row in key_rows] if item),
        "三个下一步动作：1. 补字段；2. 归因；3. 复核与修复；必要时做小流量验证。",
    ]


def _legacy_2__final_procurement_sales_management_render(report: dict[str, Any]) -> dict[str, Any] | None:
    registry_payload = report.get("object_decision_registry") or {}
    raw_rows = registry_payload.get("rows") or []
    if not raw_rows:
        return None

    registry_rows = _management_safe_registry_rows(report)
    field_registry = registry_payload.get("field_registry") or {}
    for row in registry_rows:
        object_level = str(row.get("object_level") or "")
        sample_flag = str(row.get("sample_size_flag") or "")
        final_action = str(row.get("final_action") or "")
        if not field_registry.get("has_profit_fields", False) and _contains_any_term(final_action, _MGMT_RESOURCE_TERMS):
            if object_level == "product":
                row["final_label"] = "修复型销售头部" if "修复" in str(row.get("final_label") or "") or "头部" in str(row.get("final_label") or "") else "商品观察候选"
                row["final_action"] = "样本不足人工复核" if "样本不足" in sample_flag else "待补毛利后判断是否放量"
                row["action_strength"] = "observe_only" if "样本不足" in sample_flag else "candidate"
            elif object_level == "category":
                row["final_label"] = "头部品类资源候选" if "category_object" in str(row.get("object_id") or "") else "放量前修复品类"
                row["final_action"] = "待补毛利后判断是否放量"
                row["action_strength"] = "candidate"
            elif object_level == "supplier":
                row["final_label"] = "供应商观察池"
                row["final_action"] = "待补交付与利润字段后判断合作等级"
                row["action_strength"] = "candidate"
    category_rows = [row for row in registry_rows if row["object_level"] == "category"]
    product_rows = [row for row in registry_rows if row["object_level"] == "product"]
    sku_rows = [row for row in registry_rows if row["object_level"] == "sku"]
    supplier_rows = [row for row in registry_rows if row["object_level"] == "supplier"]

    def _pick_many(object_ids: list[str], rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
        picked = []
        for object_id in object_ids:
            row = next((item for item in rows if str(item.get("object_id") or "") == object_id), None)
            if row and row not in picked:
                picked.append(row)
        return picked

    prioritized_rows = []
    prioritized_rows.extend(_pick_many(["category_object"], category_rows))
    prioritized_rows.extend(_pick_many(["product_object"], product_rows))
    prioritized_rows.extend(_pick_many(["sku_object", "sku_object_alt"], sku_rows))
    prioritized_rows.extend(_pick_many(["seller_object_a", "seller_object_b", "seller_object_c"], supplier_rows))
    prioritized_rows.extend(category_rows[:5])
    prioritized_rows.extend(product_rows[:8])
    prioritized_rows.extend(sku_rows[:8])
    prioritized_rows.extend(supplier_rows[:8])

    seen_keys: set[tuple[str, str]] = set()
    compact_rows: list[dict[str, Any]] = []
    for row in prioritized_rows:
        key = (str(row.get("object_level") or ""), str(row.get("object_id") or ""))
        if key in seen_keys:
            continue
        seen_keys.add(key)
        compact_rows.append(row)

    action_table_rows = []
    for index, row in enumerate(compact_rows[:30], start=1):
        action_table_rows.append(
            {
                "优先级": f"P{1 if index <= 5 else 2 if index <= 15 else 3}",
                "对象层级": row["object_level"],
                "对象名称": row["object_id"],
                "最终标签": row["final_label"],
                "触发证据": row["trigger_evidence"],
                "现有证据类型": row.get("conclusion_type", "proxy_based_inference"),
                "缺失字段": _friendly_required_fields_cn(row.get("missing_fields") or row.get("required_missing_fields")),
                "被拦截动作": row.get("blocked_actions_display") or "无",
                "最终动作": row["final_action"],
                "负责人角色": row["owner_role"],
                "时间要求": row["time_requirement"],
                "验证指标": row["validation_metric"],
                "结论强度": row["action_strength"],
                "置信度": row.get("confidence_level", "medium"),
            }
        )

    blocked_rows = [
        {
            "对象": row.get("object", ""),
            "对象层级": row.get("object_level", ""),
            "被拦截动作类型": _sanitize_blocked_actions_for_management({"blocked_actions": str(row.get("attempted_action", "")).split(" / ")}),
            "拦截原因": row.get("blocked_reason", ""),
            "降级后动作": row.get("downgraded_action", ""),
            "需要补充字段": row.get("missing_fields", ""),
        }
        for row in (registry_payload.get("blocked_action_log") or [])
    ]

    field_rows = [
        {"字段组": key, "是否可用": "是" if value else "否", "命中字段": " / ".join((field_registry.get("field_coverage") or {}).get(key, []) or []) or "无"}
        for key, value in [
            ("sales_fields", field_registry.get("has_sales_fields")),
            ("fulfillment_fields", field_registry.get("has_fulfillment_fields")),
            ("review_fields", field_registry.get("has_review_fields")),
            ("profit_fields", field_registry.get("has_profit_fields")),
            ("inventory_fields", field_registry.get("has_inventory_fields")),
            ("procurement_price_fields", field_registry.get("has_procurement_price_fields")),
            ("supplier_delivery_fields", field_registry.get("has_supplier_delivery_fields")),
            ("payment_term_fields", field_registry.get("has_payment_term_fields")),
            ("return_cost_fields", field_registry.get("has_return_cost_fields")),
            ("supplier_contract_fields", field_registry.get("has_supplier_contract_fields")),
            ("competitor_price_fields", field_registry.get("has_competitor_price_fields")),
        ]
    ]
    boundary_rows = [{"当前不可判断内容": item} for item in [
        "不能判断高优先级资源动作",
        "不能判断库存类动作",
        "不能判断采购谈判空间",
        "不能判断完整供应商替换",
        "不能判断完整利润表现",
    ]]
    data_gap_rows = registry_payload.get("data_gap_rows") or []
    low_risk_rows = [
        {
            "对象": row["object_id"],
            "结论类型": row.get("conclusion_type", ""),
            "低风险管理假设": row.get("business_assumption") or row["final_action"],
            "验证动作": row.get("validation_plan") or "补字段验证",
            "置信度": row.get("confidence_level", "medium"),
        }
        for row in compact_rows
        if str(row.get("conclusion_type") or "") in {"proxy_based_inference", "business_hypothesis", "risk_flag", "data_required"}
    ][:10]
    chain_rows = [
        {
            "链路类型": _chain_type_for_registry_row(row),
            "对象层级": row["object_level"],
            "对象名称": row["object_id"],
            "触发证据": row["trigger_evidence"],
            "被拦截动作": row.get("blocked_actions_display") or "无",
            "最终动作": row["final_action"],
            "需要补字段": _friendly_required_fields_cn(row.get("missing_fields") or row.get("required_missing_fields")),
            "负责人角色": row["owner_role"],
            "时间要求": row["time_requirement"],
            "验证指标": row["validation_metric"],
            "结论强度": row["action_strength"],
        }
        for row in _pick_many(["category_object", "product_object", "sku_object", "sku_object_alt", "seller_object_a", "seller_object_b", "seller_object_c"], compact_rows)
    ]

    def _review_section(section_id: str, title: str, rows: list[dict[str, Any]], business_question: str) -> dict[str, Any]:
        bullets = [
            clean_report_text_filter(f"{row['object_id']} 当前标签为“{row['final_label']}”，核心证据是 {row['trigger_evidence']}；最终动作固定为“{row['final_action']}”。")
            for row in rows[:5]
        ]
        table_rows = [
            {
                "对象": row["object_id"],
                "最终标签": row["final_label"],
                "最终动作": row["final_action"],
                "触发证据": row["trigger_evidence"],
                "被拦截动作摘要": row.get("blocked_actions_display") or "无",
                "结论强度": row["action_strength"],
                "置信度": row.get("confidence_level", "medium"),
            }
            for row in rows[:10]
        ]
        return _section(section_id, title, business_question, bullets[:6], tables=[_table(f"{title}动作表", table_rows)] if table_rows else [])

    sections = [
        _section("report_mode_cover", "封面与报告模式", "本页回答：当前报告属于什么模式，哪些边界必须先说明白。", ["当前报告属于 sales_fulfillment_product_report。", "采购侧待补数，因此不能作为完整采销拍板报告。"]),
        _section("management_summary_fixed", "管理层摘要", "本页回答：当前能判断什么、不能判断什么，以及最重要的对象级结论和下一步动作。", _final_management_summary_from_registry(report, registry_rows, field_registry)),
        _section("field_availability", "字段可用性与不可下结论清单", "本页回答：当前字段支持哪些判断，哪些结论必须被压住。", ["可判断销售结构、商品承接、SKU履约风险、售后评价风险、供应商销侧表现。", "不可判断高优先级资源动作、库存类动作、采购谈判空间、完整供应商替换和完整利润表现。", "统计附录显示 Revenue 分布明显偏态，因此正文优先采用分位数、异常对象和对象级复核，不用均值单独下结论。"], tables=[_table("字段可用性", field_rows), _table("不可下结论清单", boundary_rows)]),
        _section("final_action_table", "对象最终动作总表", "本页回答：对象最终动作是什么、由谁负责、何时完成、怎么验证。", ["行动表只读取 object_decision_registry 的 final_label 和 final_action。", "被拦截动作在管理层正文只保留摘要，不再直出原始强动作词。"], tables=[_table("行动表", action_table_rows)]),
        _section("blocked_action_table", "被拦截动作表", "本页回答：哪些强动作被 guardrail 拦下，以及为什么被拦下。", ["这张表只做解释，不再把被拦截动作写成正文建议。"], tables=[_table("被拦截动作", blocked_rows[:20])] if blocked_rows else []),
        _review_section("category_review", "品类经营复核", category_rows, "本页回答：哪些品类只是资源候选，不能直接进入强经营动作。"),
        _review_section("product_review", "商品经营复核", product_rows, "本页回答：哪些商品有销售基础但放量前必须先修履约和口碑。"),
        _review_section("sku_review", "SKU经营复核", sku_rows, "本页回答：哪些 SKU 只是低样本风险，哪些 SKU 需要降权控量。"),
        _review_section("supplier_review", "供应商履约与口碑复核", supplier_rows, "本页回答：哪些供应商需要口碑修复、履约修复或替换评估。"),
        _section("fulfillment_risk_review", "履约与售后风险", "本页回答：当前哪些对象体现出履约和评价风险，应该先修复什么。", ["没有供应商真实交付字段时，逾期和低分只作为履约链路风险信号，不直接归责到供应商责任。", "优先处理低分评价占比、逾期率和平均履约天数偏高的对象，再决定是否进入资源复核。"]),
        _section("data_gap_checklist", "补字段清单", "本页回答：下一步必须补什么字段，补齐后才能升级结论。", ["以下字段缺口会直接限制高优先级资源动作、库存类动作、压价和供应商替换等结论。"], tables=[_table("补字段清单", data_gap_rows[:20])] if data_gap_rows else []),
        _section("low_risk_hypothesis", "低风险管理假设", "本页回答：哪些判断属于代理指标结论、业务假设或风险提示，只能作为待验证管理假设。", ["这部分只保留低风险管理假设，不把缺直接字段的判断伪装成已被数据证实的事实。"], tables=[_table("低风险管理假设", low_risk_rows)] if low_risk_rows else []),
        _section("sales_fulfillment_review_chain", "销售履约复核链", "本页回答：当前哪些对象处于资源候选、修复验证、低样本复核、供应商观察或替换评估阶段。", ["链路只保留安全结论，不再使用旧的强经营链路措辞。"], tables=[_table("销售履约复核链", chain_rows)] if chain_rows else []),
        _section("action_roadmap", "行动路线图", "本页回答：下一步优先做什么。", ["补利润字段、库存/周转、退货/售后成本字段。", "对 product_object做差评归因和履约修复。", "对 sku_object做低样本规格复核并待补库存后再判断。"]),
    ]
    if report.get("_minimal_management_mode"):
        sections = _minimal_management_sections(sections)
    return {"title": clean_report_text_filter(str(report.get("title") or "")), "executive_summary": _final_management_summary_from_registry(report, registry_rows, field_registry), "sections": sections, "action_rows": action_table_rows, "blocked_rows": blocked_rows, "field_registry": field_registry}

