def _auto_repair_internet_ops_management_variant(
    report: dict[str, Any],
    management_variant: dict[str, Any],
    *,
    round_index: int,
    field_registry: dict[str, Any],
) -> dict[str, Any]:
    repaired = _clean_report_variant_texts(copy.deepcopy(management_variant))
    banned_replacements = {
        "registry": "对象动作表",
        "guardrail": "动作边界",
        "schema": "字段结构",
        "validator": "独立验收",
        "raw_action": "原始动作",
        "debug": "",
        "workflow": "流程",
    }
    replacements = {}
    if not field_registry.get("has_cost_fields", False):
        replacements.update({
            "ROI": "投放效率待补成本后复核",
            "CAC": "获客成本待补数",
            "预算加码": "待补成本后复核",
            "砍渠道": "待补成本后复核",
            "加大投放": "待补成本后复核",
            "规模化投放": "待补成本后复核",
        })
    if not field_registry.get("has_retention_fields", False):
        replacements.update({
            "用户质量高": "待补 D1/D7/D30 后判断用户质量",
            "用户黏性强": "待补 D1/D7/D30 后判断用户质量",
            "长期价值高": "待补 D1/D7/D30 后判断用户质量",
            "长期留存好": "待补 D1/D7/D30 后判断用户质量",
        })
    if not field_registry.get("has_revenue_fields", False):
        replacements.update({
            "LTV高": "待补收入、ARPU、LTV 后判断",
            "商业价值高": "待补收入、ARPU、LTV 后判断",
            "高价值用户": "付费潜力待验证用户群",
            "值得规模化投放": "待补收入、ARPU、LTV 后判断",
        })
    if not field_registry.get("has_funnel_fields", False):
        replacements.update({
            "完整转化链路健康": "当前只能判断单点行为，不能判断完整漏斗效率",
            "漏斗效率高": "当前只能判断单点行为，不能判断完整漏斗效率",
            "支付转化好": "当前只能判断单点行为，不能判断完整漏斗效率",
        })
    if not field_registry.get("has_content_fields", False):
        replacements.update({
            "内容策略有效": "内容维度不足，需补字段后复核",
            "内容主推": "内容候选待验证",
            "作者表现最好": "内容维度不足，需补字段后复核",
        })

    for section in repaired.get("sections", []):
        section["title"] = section["title"].replace("采销", "互联网运营")
        section["summary"] = section["summary"].replace("采销", "互联网运营")
        new_bullets = []
        for bullet in section.get("bullets", []):
            text = str(bullet)
            for src, dst in {**banned_replacements, **replacements}.items():
                text = text.replace(src, dst)
            new_bullets.append(text)
        section["bullets"] = new_bullets
        for table in section.get("tables", []):
            cleaned_rows = []
            for row in table.get("rows", []):
                cleaned_row = {}
                for key, value in row.items():
                    text = str(value)
                    for src, dst in {**banned_replacements, **replacements}.items():
                        text = text.replace(src, dst)
                    cleaned_row[key] = text
                cleaned_rows.append(cleaned_row)
            table["rows"] = cleaned_rows

    if round_index >= 8:
        repaired = _minimal_internet_ops_management_variant(repaired)
    return repaired


