def _append_current_turn_export_manifest(
    *,
    report_dir: Path,
    report_id: str,
    report: dict[str, Any],
    artifact_bundle: dict[str, Any],
) -> dict[str, Any]:
    relative_dir = report_dir.relative_to(REPORTS_DIR.parent).as_posix()
    downloadables = list(artifact_bundle.get("downloadables") or [])
    output_inventory: list[dict[str, Any]] = []
    for path in sorted(report_dir.rglob("*")):
        if not path.is_file():
            continue
        output_inventory.append(
            {
                "name": path.name,
                "relative_path": path.relative_to(REPORTS_DIR.parent).as_posix(),
                "size_bytes": int(path.stat().st_size),
            }
        )
    def _public_manifest_path(value: Any) -> str:
        text = str(value or "").strip().replace("\\", "/")
        if not text:
            return ""
        if text.startswith("/storage/") or text.startswith("storage/"):
            return text
        if text.startswith(("/tmp/", "tmp/")) or re.match(r"^[A-Za-z]:/", text):
            return text.rstrip("/").split("/")[-1]
        return text

    manifest = {
        "report_id": report_id,
        "dataset_name": report.get("dataset_name", ""),
        "sheet_name": report.get("sheet_name", ""),
        "business_profile": report.get("business_profile", ""),
        "report_lens": report.get("report_lens", ""),
        "generated_at": report.get("generated_at", ""),
        "generic_long_cli_pipeline_job_id": report.get("generic_long_cli_pipeline_job_id", ""),
        "generic_long_cli_pipeline_status": (
            (report.get("generic_long_cli_pipeline") or {}).get("status", "")
            if isinstance(report.get("generic_long_cli_pipeline"), dict)
            else ""
        ),
        "generic_long_cli_pipeline_current_stage": (
            (report.get("generic_long_cli_pipeline") or {}).get("current_stage_id", "")
            if isinstance(report.get("generic_long_cli_pipeline"), dict)
            else ""
        ),
        "generic_long_cli_final_output": report.get("generic_long_cli_final_output", {}),
        "ecommerce_long_cli_pipeline_job_id": report.get("ecommerce_long_cli_pipeline_job_id", ""),
        "ecommerce_long_cli_pipeline_status": (
            (report.get("ecommerce_long_cli_pipeline") or {}).get("status", "")
            if isinstance(report.get("ecommerce_long_cli_pipeline"), dict)
            else ""
        ),
          "ecommerce_long_cli_pipeline_current_stage": (
              (report.get("ecommerce_long_cli_pipeline") or {}).get("current_stage_id", "")
              if isinstance(report.get("ecommerce_long_cli_pipeline"), dict)
              else ""
          ),
          "ecommerce_long_cli_final_output": report.get("ecommerce_long_cli_final_output", {}),
          "ecommerce_metric_consumption_index_path": report.get("ecommerce_metric_consumption_index_path", ""),
          "ecommerce_metric_coverage_summary": report.get("ecommerce_metric_coverage_summary", {}),
          "ecommerce_metric_universe_count": report.get("ecommerce_metric_universe_count", 0),
          "ecommerce_metric_missing_ids": list(report.get("ecommerce_metric_missing_ids") or []),
          "internet_ops_long_cli_pipeline_job_id": report.get("internet_ops_long_cli_pipeline_job_id", ""),
        "internet_ops_long_cli_pipeline_status": (
            (report.get("internet_ops_long_cli_pipeline") or {}).get("status", "")
            if isinstance(report.get("internet_ops_long_cli_pipeline"), dict)
            else ""
        ),
        "internet_ops_long_cli_pipeline_current_stage": (
            (report.get("internet_ops_long_cli_pipeline") or {}).get("current_stage_id", "")
            if isinstance(report.get("internet_ops_long_cli_pipeline"), dict)
            else ""
        ),
        "internet_ops_long_cli_final_output": report.get("internet_ops_long_cli_final_output", {}),
        "procurement_sales_long_cli_pipeline_job_id": report.get("procurement_sales_long_cli_pipeline_job_id", ""),
        "procurement_sales_long_cli_pipeline_status": (
            (report.get("procurement_sales_long_cli_pipeline") or {}).get("status", "")
            if isinstance(report.get("procurement_sales_long_cli_pipeline"), dict)
            else ""
        ),
        "procurement_sales_long_cli_pipeline_current_stage": (
            (report.get("procurement_sales_long_cli_pipeline") or {}).get("current_stage_id", "")
            if isinstance(report.get("procurement_sales_long_cli_pipeline"), dict)
            else ""
        ),
        "procurement_sales_long_cli_final_output": report.get("procurement_sales_long_cli_final_output", {}),
        "linked_codex_pipeline_job_ids": list(report.get("linked_codex_pipeline_job_ids") or []),
        "current_turn_export": True,
        "main_downloadable": next((item.get("name") for item in downloadables if item.get("is_main")), ""),
        "downloadable_count": len(downloadables),
        "downloadables": [
            {
                "name": item.get("name", ""),
                "path": _public_manifest_path(item.get("path", "")),
                "type": item.get("type", ""),
                "purpose": item.get("purpose", ""),
                "is_main": bool(item.get("is_main")),
            }
            for item in downloadables
        ],
        "output_inventory": output_inventory,
    }
    manifest_path = report_dir / f"{report_id}-current_turn_export_manifest.json"
    manifest_path.write_text(json.dumps(manifest, ensure_ascii=False, indent=2), encoding="utf-8")
    asset = {
        "name": manifest_path.name,
        "path": f"/storage/{relative_dir}/{manifest_path.name}",
        "file_path": str(manifest_path.resolve()),
        "purpose": "current-turn full export manifest.",
        "is_main": False,
        "type": "json",
    }
    if not any(str(item.get("name") or "") == asset["name"] for item in downloadables):
        artifact_bundle.setdefault("downloadables", []).append(asset)
    return asset


def _downloadable_from_report_file(report_dir: Path, path: Path, *, purpose: str = "", is_main: bool = False) -> dict[str, Any]:
    try:
        relative = path.resolve().relative_to(REPORTS_DIR.parent.resolve()).as_posix()
    except Exception:
        relative = path.name
    return {
        "name": path.name,
        "path": f"/storage/{relative}",
        "file_path": str(path.resolve()),
        "purpose": purpose or "Report artifact.",
        "is_main": bool(is_main),
        "type": path.suffix.lstrip(".") or "txt",
    }


def _load_existing_report_downloadables(report_dir: Path, report_id: str) -> list[dict[str, Any]]:
    manifest_path = report_dir / f"{report_id}-current_turn_export_manifest.json"
    downloadables: list[dict[str, Any]] = []
    seen: set[str] = set()
    manifest: dict[str, Any] = {}
    if manifest_path.exists():
        try:
            manifest = json.loads(manifest_path.read_text(encoding="utf-8"))
        except Exception:
            manifest = {}
        manifest_main_name = str(manifest.get("main_downloadable") or "").strip()
        for item in manifest.get("downloadables") or []:
            name = str((item or {}).get("name") or "")
            if not name or name in seen:
                continue
            file_path_text = str((item or {}).get("file_path") or "").strip()
            path = Path(file_path_text) if file_path_text else None
            if path is None or not path.is_file():
                matches = [candidate for candidate in report_dir.rglob(name) if candidate.is_file()]
                if not matches:
                    continue
                path = matches[0]
            seen.add(name)
            downloadables.append(
                _downloadable_from_report_file(
                    report_dir,
                    path,
                    purpose=str((item or {}).get("purpose") or ""),
                    is_main=bool((item or {}).get("is_main")) or name == manifest_main_name,
                )
            )
    if not downloadables:
        for path in sorted(report_dir.rglob("*")):
            if not path.is_file() or "codex_premium" in path.parts:
                continue
            if path.name in seen:
                continue
            seen.add(path.name)
            downloadables.append(_downloadable_from_report_file(report_dir, path, is_main=False))
    if downloadables and not any(bool(item.get("is_main")) for item in downloadables):
        preferred_names = [
            f"{report_id}-management_report.pdf",
            f"{report_id}-management_report.html",
            f"{report_id}.pdf",
            f"{report_id}.html",
        ]
        chosen_name = next(
            (name for name in preferred_names if any(str(item.get("name") or "") == name for item in downloadables)),
            "",
        )
        if chosen_name:
            for item in downloadables:
                item["is_main"] = str(item.get("name") or "") == chosen_name
    return downloadables


def _rewrite_shadow_bundle_html(html_text: str, css_name: str) -> str:
    rewritten = re.sub(
        r'href=(["\'])06_report\.css\1',
        f'href="./{css_name}"',
        html_text,
        count=1,
    )
    return rewritten


def _write_internet_ops_shadow_bundle(
    *,
    report_dir: Path,
    report_id: str,
    html_source: Path,
    css_source: Path,
    chart_source: Path | None,
) -> dict[str, Path]:
    bundle_dir = report_dir / "internet_ops_cli_shadow_bundle"
    bundle_dir.mkdir(parents=True, exist_ok=True)

    html_target = bundle_dir / f"{report_id}-internet_ops_cli_shadow.html"
    css_target = bundle_dir / f"{report_id}-internet_ops_cli_shadow.css"
    chart_target = bundle_dir / f"{report_id}-internet_ops_cli_shadow_chart_insights.json"

    html_text = html_source.read_text(encoding="utf-8")
    html_target.write_text(
        _rewrite_shadow_bundle_html(html_text, css_target.name),
        encoding="utf-8",
    )
    css_target.write_bytes(css_source.read_bytes())

    if chart_source is not None and chart_source.is_file():
        chart_target.write_bytes(chart_source.read_bytes())

    visual_source_dir = html_source.parent / "source_visual_assets"
    visual_target_dir = bundle_dir / "source_visual_assets"
    if visual_source_dir.is_dir():
        shutil.copytree(visual_source_dir, visual_target_dir, dirs_exist_ok=True)

    bundle_paths: dict[str, Path] = {
        "bundle_dir": bundle_dir,
        "html": html_target,
        "css": css_target,
        "visual_dir": visual_target_dir,
    }
    if chart_source is not None and chart_source.is_file():
        bundle_paths["chart_insights"] = chart_target
    return bundle_paths


def register_generic_long_cli_pipeline_output(pipeline_job_id: str) -> dict[str, Any]:
    """Register a completed generic-engine CLI pipeline back into its linked report directory.

    This is used after manual stage retry/continuation. It does not change AI mandatory
    approval; it only refreshes report-directory artifacts and the export manifest.
    """
    pipeline = get_pipeline_job(pipeline_job_id)
    pipeline_type = str(pipeline.get("pipeline_type") or "")
    if pipeline_type not in {"generic_long_cli_pipeline", "media_campaign_cli_pipeline"}:
        raise ValueError("Only generic-long family pipelines can be registered as a generic-engine main report.")
    if str(pipeline.get("status") or "") != "completed":
        raise ValueError(f"Pipeline is not completed: {pipeline.get('status') or 'unknown'}")
    report_id = str(pipeline.get("linked_report_id") or "").strip()
    if not report_id:
        raise ValueError("Pipeline is missing linked_report_id.")
    report_dir = REPORTS_DIR / f"smart-report-{report_id}"
    if not report_dir.exists():
        raise ValueError(f"Linked report directory does not exist: {report_dir}")

    artifact_bundle = {
        "downloadables": _load_existing_report_downloadables(report_dir, report_id),
        "markdown_path": "",
        "html_path": "",
        "pdf_path": "",
    }
    registered = _register_generic_long_cli_pdf(
        artifact_bundle=artifact_bundle,
        report_dir=report_dir,
        report_id=report_id,
        final_output=pipeline.get("final_output") or {},
    )
    if not registered:
        raise ValueError("Pipeline final_output does not contain an existing 07_report.pdf.")

    gate_payload, score_payload, gate_assets = _write_generic_long_cli_release_gate_assets(
        report_dir=report_dir,
        report_id=report_id,
        final_output=pipeline.get("final_output") or {},
    )
    seen_names = {str(item.get("name") or "") for item in artifact_bundle.get("downloadables") or []}
    for item in gate_assets:
        if str(item.get("name") or "") not in seen_names:
            artifact_bundle.setdefault("downloadables", []).append(item)
            seen_names.add(str(item.get("name") or ""))

    report_payload = {
        "report_id": report_id,
        "business_profile": (pipeline.get("context_payload") or {}).get("business_profile") or "generic_long_cli_pipeline",
        "report_lens": (pipeline.get("context_payload") or {}).get("report_lens") or "mixed_business_review",
        "generated_at": datetime.utcnow().isoformat() + "Z",
        "generic_long_cli_pipeline_job_id": pipeline_job_id,
        "generic_long_cli_pipeline": pipeline,
        "generic_long_cli_final_output": pipeline.get("final_output") or {},
        "linked_codex_pipeline_job_ids": [pipeline_job_id],
    }
    manifest_asset = _append_current_turn_export_manifest(
        report_dir=report_dir,
        report_id=report_id,
        report=report_payload,
        artifact_bundle=artifact_bundle,
    )
    main_downloadable = next(
        (item for item in artifact_bundle.get("downloadables", []) if item.get("is_main")),
        registered,
    )
    return {
        "status": "registered",
        "pipeline_type": pipeline_type,
        "report_id": report_id,
        "pipeline_job_id": pipeline_job_id,
        "main_downloadable": main_downloadable,
        "registered_downloadable": registered,
        "downloadables": artifact_bundle.get("downloadables") or [],
        "generic_long_cli_final_output": pipeline.get("final_output") or {},
        "quality_gate_result": gate_payload,
        "report_quality_score": score_payload,
        "manifest_asset": manifest_asset,
    }


