def register_codex_main_report_pipeline_output(pipeline_job_id: str) -> dict[str, Any]:
    """Register a completed CLI main-report pipeline, dispatching by pipeline type."""
    pipeline = get_pipeline_job(pipeline_job_id)
    pipeline_type = str(pipeline.get("pipeline_type") or "")
    if pipeline_type in {"generic_long_cli_pipeline", "media_campaign_cli_pipeline"}:
        return register_generic_long_cli_pipeline_output(pipeline_job_id)
    if pipeline_type == "multi_table_generic_long_cli_pipeline":
        return register_multi_table_generic_long_cli_pipeline_output(pipeline_job_id)
    if pipeline_type == "ecommerce_long_cli_pipeline":
        return register_ecommerce_long_cli_pipeline_output(pipeline_job_id)
    if pipeline_type == "procurement_sales_long_cli_pipeline":
        return register_procurement_sales_long_cli_pipeline_output(pipeline_job_id)
    if pipeline_type == "internet_ops_long_cli_pipeline":
        return register_internet_ops_long_cli_pipeline_output(pipeline_job_id)
    raise ValueError(f"Pipeline type cannot be registered as a main report: {pipeline_type or 'unknown'}")


def _profile_bundle_gate_and_score(
    *,
    report: dict[str, Any],
    business_profile: str,
    management_markdown: str,
    field_registry: dict[str, Any] | None = None,
    action_rows: list[dict[str, Any]] | None = None,
) -> tuple[dict[str, Any], dict[str, Any], dict[str, Any]]:
    base_gate = {
        "passed": bool(report.get("sections")) and bool(report.get("executive_summary")),
        "fail_items": [],
        "affected_sections": [],
        "suggested_fixes": [],
        "business_profile": business_profile,
    }
    if not base_gate["passed"]:
        base_gate["fail_items"] = ["report content incomplete"]
        base_gate["affected_sections"] = ["management_report"]
        base_gate["suggested_fixes"] = ["rebuild management sections before delivery"]
    base_score = {
        "score": 95 if base_gate["passed"] else 60,
        "passed": bool(base_gate["passed"]),
        "breakdown": {
            "content_presence": 30 if report.get("sections") else 0,
            "executive_summary": 20 if report.get("executive_summary") else 0,
            "profile_bundle": 20,
            "artifact_completeness": 25,
        },
        "hard_fail_items": [],
        "business_profile": business_profile,
    }
    gate, score, field_blindness_guardrail = all_report_quality_gate(
        base_gate_result=base_gate,
        base_score_result=base_score,
        business_profile=business_profile,
        management_markdown=management_markdown,
        metric_payload=report.get("universal_metric_mining_result"),
        action_rows=action_rows or [],
        field_registry=field_registry or {},
        extra_context={},
        require_metric_payload=bool(report.get("universal_metric_mining_result")),
    )
    report["universal_field_blindness_guardrail"] = field_blindness_guardrail
    return gate, score or base_score, field_blindness_guardrail


def _downloadable_bundle_cn_media(
    report_dir: Path,
    report_id: str,
    report: dict[str, Any],
    frame: pd.DataFrame,
    market_intelligence: dict[str, Any],
) -> dict[str, Any]:
    artifact_bundle = _downloadable_bundle_cn(report_dir, report_id, report, frame, market_intelligence)
    relative_dir = report_dir.relative_to(REPORTS_DIR.parent).as_posix()
    quality_gate_result_path = report_dir / f"{report_id}-quality_gate_result.json"
    report_quality_score_path = report_dir / f"{report_id}-report_quality_score.json"
    before_after_summary_path = report_dir / f"{report_id}-before_after_summary.md"

    gate, score, _ = _profile_bundle_gate_and_score(
        report=report,
        business_profile="media_campaign_report",
        management_markdown=_report_markdown_cn(report),
        field_registry=report.get("internet_ops_field_availability_registry") or report.get("generic_field_availability_registry") or {},
        action_rows=report.get("internet_ops_action_table") or report.get("generic_action_table") or [],
    )
    quality_gate_result_path.write_text(json.dumps(gate, ensure_ascii=False, indent=2), encoding="utf-8")
    report_quality_score_path.write_text(json.dumps(score, ensure_ascii=False, indent=2), encoding="utf-8")
    before_after_summary_path.write_text(
        "\n".join(
            [
                f"# {report_id} before_after_summary",
                "",
                "- media_campaign_report 已进入独立 bundle 分支，不再回退为通用 base bundle。",
                "- 当前产物会保留 current-turn quality gate、score 和 AI mandatory / metric mining 侧车文件。",
            ]
        )
        + "\n",
        encoding="utf-8",
    )
    for path, purpose in [
        (quality_gate_result_path, "quality_gate_result.json."),
        (report_quality_score_path, "report_quality_score.json."),
        (before_after_summary_path, "before_after_summary.md."),
    ]:
        artifact_bundle.setdefault("downloadables", []).append(
            {
                "name": path.name,
                "path": f"/storage/{relative_dir}/{path.name}",
                "file_path": str(path.resolve()),
                "purpose": purpose,
                "is_main": False,
                "type": path.suffix.lstrip("."),
            }
        )
    artifact_bundle["quality_gate_result"] = gate
    artifact_bundle["report_quality_score"] = score
    return artifact_bundle


