def _report_markdown_cn(report: dict[str, Any]) -> str:
    management_ids = _management_section_ids_for_report(report)
    management_sections = [section for section in report["sections"] if section["id"] in management_ids]
    appendix_sections = [section for section in report["sections"] if section["id"] not in management_ids]
    lines = [
        f"# {report['title']}",
        "",
        f"- 数据集：`{report['dataset_name']}`",
        f"- 工作表：`{report['sheet_name']}`",
        f"- 报告语言：`{report.get('report_language', 'zh-CN')}`",
        f"- 生成时间：`{report['generated_at']}`",
        "",
        "## 管理层摘要",
        "",
    ]
    for bullet in report["executive_summary"]:
        lines.append(f"- {bullet}")
    lines.extend(["", "## 管理层正文", ""])
    for section in management_sections:
        lines.extend(["", f"## {section['title']}", "", section["summary"], ""])
        for bullet in section["bullets"]:
            lines.append(f"- {bullet}")
        for table in section["tables"]:
            lines.extend(["", f"### {table['title']}", ""])
            if table["columns"]:
                lines.append("| " + " | ".join(table["columns"]) + " |")
                lines.append("| " + " | ".join(["---"] * len(table["columns"])) + " |")
                for row in table["rows"]:
                        lines.append("| " + " | ".join(_markdown_table_value(column, row.get(column, "")) for column in table["columns"]) + " |")
            if str(table.get("note") or "").strip():
                lines.extend(["", str(table.get("note") or "")])
        for chart in section.get("rendered_charts", []) or []:
            lines.extend(["", f"### {chart.get('title', '图表')}", ""])
            lines.append(f"![{chart.get('title', '图表')}]({chart.get('filename', '')})")
            notes = [str(item).strip() for item in (chart.get("notes") or []) if str(item).strip()]
            if notes:
                lines.extend(["", "图表解读：", ""])
                lines.extend([f"- {item}" for item in notes])
    if appendix_sections:
        lines.extend(["", "## 分析附录", ""])
        for section in appendix_sections:
            lines.extend(["", f"## {section['title']}", "", section["summary"], ""])
            for bullet in section["bullets"]:
                lines.append(f"- {bullet}")
            for table in section["tables"]:
                lines.extend(["", f"### {table['title']}", ""])
                if table["columns"]:
                    lines.append("| " + " | ".join(table["columns"]) + " |")
                    lines.append("| " + " | ".join(["---"] * len(table["columns"])) + " |")
                    for row in table["rows"]:
                        lines.append("| " + " | ".join(_markdown_table_value(column, row.get(column, "")) for column in table["columns"]) + " |")
                if str(table.get("note") or "").strip():
                    lines.extend(["", str(table.get("note") or "")])
            for chart in section.get("rendered_charts", []) or []:
                lines.extend(["", f"### {chart.get('title', '图表')}", ""])
                lines.append(f"![{chart.get('title', '图表')}]({chart.get('filename', '')})")
                notes = [str(item).strip() for item in (chart.get("notes") or []) if str(item).strip()]
                if notes:
                    lines.extend(["", "图表解读：", ""])
                    lines.extend([f"- {item}" for item in notes])
    if report.get("tool_integrations"):
        lines.extend(["", "## 外部工具补充", ""])
        for item in report["tool_integrations"]:
            lines.append(f"- `{item['tool_name']}` | {item['title']} | {item['path'] or 'no-file'}")
            if item.get("note"):
                lines.append(f"  说明：{item['note']}")
    return "\n".join(lines) + "\n"


def _procurement_sales_judge_context(
    *,
    report: dict[str, Any],
    relation_context: dict[str, Any],
    intelligence_runtime: dict[str, Any],
    context_compaction: dict[str, Any] | None = None,
) -> dict[str, Any]:
    return {
        "report_lens": report.get("report_lens"),
        "dataset_name": report.get("dataset_name"),
        "sheet_name": report.get("sheet_name"),
        "executive_summary": report.get("executive_summary", [])[:6],
        "sections": [
            {
                "id": section.get("id"),
                "title": section.get("title"),
                "summary": section.get("summary"),
                "bullets": (section.get("bullets") or [])[:6],
            }
            for section in report.get("sections", [])[:30]
        ],
        "relation_context": relation_context,
        "intelligence_runtime": intelligence_runtime,
        "context_compaction": context_compaction or {},
    }


def _gate_route_targets(gate: dict[str, Any] | None) -> list[str]:
    if not gate:
        return []
    explicit = [str(item).strip() for item in (gate.get("route_to") or []) if str(item).strip()]
    if explicit:
        return explicit
    routes: list[str] = []
    weaknesses = [str(item).strip() for item in (gate.get("weaknesses") or []) if str(item).strip()]
    for item in weaknesses:
        if "继续深挖" in item:
            routes.append("followup_mining")
        if "供应商层" in item or "三层对象" in item or "Context Compaction" in item:
            routes.append("business_synthesis")
    deduped: list[str] = []
    seen: set[str] = set()
    for item in routes:
        if item in seen:
            continue
        seen.add(item)
        deduped.append(item)
    return deduped[:5]


def _quality_protocol_defaults(report_lens: str) -> dict[str, Any]:
    if report_lens == "procurement_sales_review":
        return {
            "base_threshold": 80,
            "target_score": 90,
            "default_routes": ["business_synthesis", "followup_mining", "sections_finalized"],
            "polish_routes": ["decision_design", "final_polish", "sections_finalized"],
        }
    if report_lens == "mixed_business_review":
        return {
            "base_threshold": 90,
            "target_score": 90,
            "default_routes": ["generic_agent_workflow"],
            "polish_routes": ["generic_agent_workflow"],
        }
    return {
        "base_threshold": 85,
        "target_score": 90,
        "default_routes": ["business_synthesis", "final_polish", "sections_finalized"],
        "polish_routes": ["final_polish", "sections_finalized"],
    }


def _quality_protocol_by_score(score: int, target_score: int) -> dict[str, Any]:
    if score >= max(95, target_score + 5):
        return {
            "tier_id": "excellent",
            "tier_label": "excellent",
            "release_allowed": True,
            "revision_required": False,
            "max_revision_rounds": 0,
            "suggestion_prefix": "继续维持当前高分结构，只做少量证据补强。",
        }
    if score >= target_score:
        return {
            "tier_id": "high_pass",
            "tier_label": "high_pass",
            "release_allowed": True,
            "revision_required": False,
            "max_revision_rounds": 0,
            "suggestion_prefix": "已达到高分放行线，可以直接交付。",
        }
    if score >= 85:
        return {
            "tier_id": "near_pass",
            "tier_label": "near_pass",
            "release_allowed": False,
            "revision_required": True,
            "max_revision_rounds": 2,
            "suggestion_prefix": "已经接近高分，重点补决策表达、深挖密度和结构收束。",
        }
    if score >= 75:
        return {
            "tier_id": "strengthen",
            "tier_label": "strengthen",
            "release_allowed": False,
            "revision_required": True,
            "max_revision_rounds": 3,
            "suggestion_prefix": "主体可用，但关键判断和对象拆解仍需强化。",
        }
    if score >= 60:
        return {
            "tier_id": "rebuild",
            "tier_label": "rebuild",
            "release_allowed": False,
            "revision_required": True,
            "max_revision_rounds": 4,
            "suggestion_prefix": "当前内容仍偏弱，需要重做关键洞察链条。",
        }
    return {
        "tier_id": "critical",
        "tier_label": "critical",
        "release_allowed": False,
        "revision_required": True,
        "max_revision_rounds": 5,
        "suggestion_prefix": "当前质量过低，必须按主问题重建分析与表达。",
    }


def _quality_protocol_suggestions(
    *,
    report_lens: str,
    gate: dict[str, Any],
    protocol: dict[str, Any],
) -> list[str]:
    suggestions = [str(item).strip() for item in (gate.get("improvement_actions") or []) if str(item).strip()]
    if report_lens == "procurement_sales_review":
        defaults = [
            "把商品、SKU、卖家三层对象拆开，避免用同一套判断覆盖不同对象。",
            "把口碑、履约与复购/单客产出/客户承接的关系明确算出来，不要只报评分和逾期率。",
            "把头部、中位、底部对象都说清楚，并且给出明确去留或修复动作。",
        ]
    elif report_lens == "mixed_business_review":
        defaults = [
            "继续补背景理解、结构拆解和模式联动，避免只停在泛化描述。",
            "把代表对象、关键联动和异常字段串成可执行结论，而不是并列罗列信号。",
            "把通用深挖结果重新压成管理层能直接使用的判断与动作。",
        ]
    else:
        defaults = [
            "继续补关键对象、关键联动和关键动作之间的闭环。",
            "把弱证据结论收紧，只保留能落到业务动作的判断。",
        ]
    merged: list[str] = []
    for item in [protocol.get("suggestion_prefix"), *suggestions, *defaults]:
        text = str(item or "").strip()
        if text and text not in merged:
            merged.append(text)
    return merged[:6]


def _normalize_quality_gate(gate: dict[str, Any] | None, report_lens: str) -> dict[str, Any]:
    gate = dict(gate or {})
    defaults = _quality_protocol_defaults(report_lens)
    raw_score = gate.get("total_score", 0)
    try:
        score = int(float(raw_score))
    except Exception:
        score = 0
    base_threshold = int(gate.get("threshold") or defaults["base_threshold"])
    target_score = int(gate.get("target_score") or defaults["target_score"])
    protocol = _quality_protocol_by_score(score, target_score)

    original_verdict = str(gate.get("verdict") or "").strip().lower()
    explicit_routes = [str(item).strip() for item in (gate.get("route_to") or []) if str(item).strip()]
    release_allowed = bool(protocol["release_allowed"]) and original_verdict == "pass" and not explicit_routes
    if release_allowed:
        routes = []
    elif explicit_routes:
        routes = explicit_routes
    elif protocol["tier_id"] == "near_pass":
        routes = list(defaults["polish_routes"])
    else:
        routes = list(defaults["default_routes"])

    suggestions = _quality_protocol_suggestions(report_lens=report_lens, gate=gate, protocol=protocol)
    normalized_verdict = "pass" if release_allowed else "block"

    gate["base_threshold"] = base_threshold
    gate["target_score"] = target_score
    gate["judge_verdict"] = original_verdict or "block"
    gate["verdict"] = normalized_verdict
    gate["route_to"] = routes[:5]
    gate["improvement_actions"] = suggestions
    gate["revision_suggestions"] = suggestions
    gate["quality_protocol"] = {
        "tier_id": protocol["tier_id"],
        "tier_label": protocol["tier_label"],
        "release_allowed": release_allowed,
        "revision_required": not release_allowed,
        "max_revision_rounds": protocol["max_revision_rounds"],
        "base_threshold": base_threshold,
        "target_score": target_score,
        "score_gap": max(0, target_score - score),
    }
    brief = str(gate.get("brief_rationale") or "").strip()
    protocol_text = (
        f"Quality protocol: {protocol['tier_id']} "
        f"(score={score}, base={base_threshold}, target={target_score})."
    )
    gate["brief_rationale"] = f"{brief} {protocol_text}".strip()
    return gate


def _gate_issue_codes(gate: dict[str, Any] | None) -> list[str]:
    if not gate:
        return []
    issue_codes: list[str] = []
    for item in [str(text).strip() for text in (gate.get("weaknesses") or []) if str(text).strip()]:
        lowered = item.lower()
        if ("三层还没有完整拆开" in item) or ("三层对象" in item) or ("商品" in item and "sku" in lowered and "卖家" in item):
            issue_codes.append("missing_object_split")
        if ("供应商层仍缺少口碑与复购/单客产出的关系判断" in item) or ("供应商" in item and "复购" in item and ("单客产出" in item or "单客" in item)):
            issue_codes.append("missing_supplier_relationship")
        if "Context Compaction" in item or "压缩证据包" in item:
            issue_codes.append("incomplete_context_compaction")
        if "fallback" in lowered or "hard_degraded" in lowered:
            issue_codes.append("critical_fallback")
        if "继续深挖" in item:
            issue_codes.append("missing_followup_depth")
        if "sku" in lowered and "正文为空" in item:
            issue_codes.append("missing_sku_body")
        if "泛化" in item or "元叙述" in item:
            issue_codes.append("generic_narrative_leak")
    deduped: list[str] = []
    seen: set[str] = set()
    for item in issue_codes:
        if item in seen:
            continue
        seen.add(item)
        deduped.append(item)
    return deduped


def _build_gate_revision_feedback(gate: dict[str, Any] | None) -> dict[str, Any]:
    if not gate:
        return {}
    revision_suggestions = [str(item).strip() for item in (gate.get("revision_suggestions") or gate.get("improvement_actions") or []) if str(item).strip()]
    route_to = [str(item).strip() for item in (gate.get("route_to") or []) if str(item).strip()]
    issue_codes = _gate_issue_codes(gate)
    lowered_suggestions = " ".join(revision_suggestions).lower()
    if "missing_object_split" not in issue_codes and ("三层" in lowered_suggestions or ("商品" in lowered_suggestions and "sku" in lowered_suggestions and "卖家" in lowered_suggestions)):
        issue_codes.append("missing_object_split")
    if "missing_supplier_relationship" not in issue_codes and (
        ("供应商" in lowered_suggestions and "复购" in lowered_suggestions and ("单客" in lowered_suggestions or "产出" in lowered_suggestions))
        or ("口碑" in lowered_suggestions and "履约" in lowered_suggestions and "复购" in lowered_suggestions)
    ):
        issue_codes.append("missing_supplier_relationship")
    if "missing_followup_depth" not in issue_codes and "followup_mining" in route_to:
        issue_codes.append("missing_followup_depth")
    if "missing_sku_body" not in issue_codes and ("sku" in lowered_suggestions and "正文" in lowered_suggestions):
        issue_codes.append("missing_sku_body")
    return {
        "source": "release_gate",
        "judge_type": str(gate.get("judge_type") or gate.get("judge_verdict") or ""),
        "score": gate.get("total_score"),
        "base_threshold": gate.get("base_threshold", gate.get("threshold")),
        "target_score": gate.get("target_score"),
        "tier_id": ((gate.get("quality_protocol") or {}).get("tier_id") or ""),
        "issue_codes": issue_codes,
        "weaknesses": [str(item).strip() for item in (gate.get("weaknesses") or []) if str(item).strip()],
        "revision_suggestions": revision_suggestions,
        "route_to": route_to,
        "brief_rationale": str(gate.get("brief_rationale") or "").strip(),
    }


def _quality_gate_display_issues(gate: dict[str, Any] | None) -> list[str]:
    if not gate:
        return []
    issue_codes = _gate_issue_codes(gate)
    mapped: list[str] = []
    for code in issue_codes:
        if code == "missing_object_split":
            mapped.append("对象层级分工仍未稳定：商品、SKU、卖家三层动作还没有真正拆开。")
        elif code == "missing_supplier_relationship":
            mapped.append("供应商经营关系链仍未闭合：口碑、履约到复购与单客产出的联动判断还不完整。")
        elif code == "incomplete_context_compaction":
            mapped.append("压缩证据包仍不完整，影响正式报告的稳定决策表达。")
        elif code == "critical_fallback":
            mapped.append("关键智能层仍存在 fallback，当前版本不能作为正式报告放行。")
        elif code == "missing_followup_depth":
            mapped.append("继续深挖层仍不足，结论没有完全下钻到可执行动作。")
        elif code == "missing_sku_body":
            mapped.append("SKU 正文仍未独立成章，规格层动作设计还需要补齐。")
        elif code == "generic_narrative_leak":
            mapped.append("正文里仍混入泛化或元叙述表达，削弱了经营决策主线。")
    if mapped:
        return mapped[:6]
    return [str(item) for item in gate.get("weaknesses", []) if str(item).strip()][:6]


def _gate_requires_high_score_revision(gate: dict[str, Any] | None) -> bool:
    if not gate:
        return False
    protocol = gate.get("quality_protocol") or {}
    return bool(protocol.get("revision_required"))


def _gate_revision_budget(gate: dict[str, Any] | None) -> int:
    if not gate:
        return 0
    protocol = gate.get("quality_protocol") or {}
    try:
        return max(0, int(protocol.get("max_revision_rounds") or 0))
    except Exception:
        return 0


def _effective_gate_revision_budget(
    gate: dict[str, Any] | None,
    *,
    interactive_runtime: bool,
) -> int:
    budget = _gate_revision_budget(gate)
    if interactive_runtime:
        return min(budget, 1)
    return budget


def _quality_gate_assets_cn(report_dir: Path, report_id: str, gate: dict[str, Any]) -> list[dict[str, Any]]:
    title = "质量门禁未通过"
    score = gate.get("total_score", "n/a")
    threshold = gate.get("threshold", 80)
    target_score = gate.get("target_score", threshold)
    protocol = gate.get("quality_protocol", {}) or {}
    tier_label = str(protocol.get("tier_label") or protocol.get("tier_id") or "block")
    score_gap = protocol.get("score_gap", "")
    markdown_path = report_dir / f"{report_id}-quality-gate.md"
    html_path = report_dir / f"{report_id}-quality-gate.html"
    strengths = [str(item) for item in gate.get("strengths", []) if str(item).strip()]
    weaknesses = _quality_gate_display_issues(gate)
    actions = [str(item) for item in gate.get("revision_suggestions", gate.get("improvement_actions", [])) if str(item).strip()]
    markdown = "\n".join(
        [
            f"# {title}",
            "",
            f"- 当前得分：`{score}`",
            f"- 放行线：`{threshold}`",
            f"- 高分目标：`{target_score}`",
            f"- 当前档位：`{tier_label}`",
            f"- 与高分目标差距：`{score_gap}`",
            f"- 结论：`{gate.get('verdict', 'block')}`",
            "",
            "## 为什么被拦截",
            "",
            *[f"- {item}" for item in weaknesses],
            "",
            "## 目前优点",
            "",
            *[f"- {item}" for item in strengths],
            "",
            "## 下一步必须修复",
            "",
            *[f"- {item}" for item in actions],
            "",
            f"说明：{gate.get('brief_rationale', '')}",
            "",
        ]
    )
    markdown_path.write_text(markdown, encoding="utf-8")
    html_body = f"""<!doctype html>
<html lang="zh-CN">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>{html.escape(title)}</title>
  <style>
    body {{ font-family: Arial, 'PingFang SC', 'Microsoft YaHei', sans-serif; margin: 0; padding: 32px; background: #f6f3ee; color: #1f2430; }}
    main {{ max-width: 900px; margin: 0 auto; background: white; border-radius: 18px; padding: 24px 28px; box-shadow: 0 10px 28px rgba(0,0,0,0.06); }}
    h1,h2 {{ margin: 0 0 12px; }}
    ul {{ margin: 0; padding-left: 18px; line-height: 1.8; }}
    .meta {{ color: #5b6573; line-height: 1.8; }}
  </style>
</head>
<body>
  <main>
    <h1>{html.escape(title)}</h1>
    <p class="meta">当前得分：{html.escape(str(score))} / 放行线：{html.escape(str(threshold))} / 高分目标：{html.escape(str(target_score))}</p>
    <p class="meta">当前档位：{html.escape(str(tier_label))} / 与高分目标差距：{html.escape(str(score_gap))}</p>
    <h2>为什么被拦截</h2>
    <ul>{''.join(f"<li>{html.escape(item)}</li>" for item in weaknesses)}</ul>
    <h2>目前优点</h2>
    <ul>{''.join(f"<li>{html.escape(item)}</li>" for item in strengths)}</ul>
    <h2>下一步必须修复</h2>
    <ul>{''.join(f"<li>{html.escape(item)}</li>" for item in actions)}</ul>
    <p class="meta">{html.escape(str(gate.get('brief_rationale', '')))}</p>
  </main>
</body>
</html>"""
    html_path.write_text(html_body, encoding="utf-8")
    return [
        {
            "name": html_path.name,
            "path": f"/storage/{report_dir.relative_to(REPORTS_DIR.parent).as_posix()}/{html_path.name}",
            "file_path": str(html_path.resolve()),
            "purpose": "质量门禁说明，当前作为主交付入口，提示该报告尚未放行。",
            "is_main": True,
            "type": "html",
        },
        {
            "name": markdown_path.name,
            "path": f"/storage/{report_dir.relative_to(REPORTS_DIR.parent).as_posix()}/{markdown_path.name}",
            "file_path": str(markdown_path.resolve()),
            "purpose": "质量门禁说明源稿。",
            "is_main": False,
            "type": "md",
        },
    ]


def _historical_adaptation_assets_cn(
    report_dir: Path,
    report_id: str,
    adaptation: dict[str, Any] | None,
) -> list[dict[str, Any]]:
    if not adaptation or not adaptation.get("adapted_report_markdown"):
        return []

    markdown_path = report_dir / f"{report_id}-historical-style.md"
    html_path = report_dir / f"{report_id}-historical-style.html"
    markdown_text = str(adaptation["adapted_report_markdown"])
    markdown_path.write_text(markdown_text, encoding="utf-8")

    html_body = f"""<!doctype html>
<html lang="zh-CN">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>{html.escape(adaptation.get('title', '历史报告仿写版'))}</title>
  <style>
    body {{ font-family: Arial, 'PingFang SC', 'Microsoft YaHei', sans-serif; margin: 0; padding: 32px; background: #f7f4ef; color: #1f2430; }}
    main {{ max-width: 1040px; margin: 0 auto; background: white; border-radius: 20px; padding: 28px 32px; box-shadow: 0 10px 28px rgba(0,0,0,0.06); }}
    pre {{ white-space: pre-wrap; word-break: break-word; line-height: 1.8; font-family: inherit; }}
  </style>
</head>
<body>
  <main>
    <pre>{html.escape(markdown_text)}</pre>
  </main>
</body>
</html>"""
    html_path.write_text(html_body, encoding="utf-8")

    return [
        {
            "name": markdown_path.name,
            "path": markdown_path.name,
            "file_path": str(markdown_path.resolve()),
            "purpose": "按历史报告风格重写后的中文 Markdown 版本。",
            "is_main": False,
            "type": "md",
        },
        {
            "name": html_path.name,
            "path": html_path.name,
            "file_path": str(html_path.resolve()),
            "purpose": "按历史报告风格重写后的中文 HTML 版本。",
            "is_main": False,
            "type": "html",
        },
    ]


def _historical_adaptation_assets_with_pipeline_cn(
    report_dir: Path,
    report_id: str,
    adaptation: dict[str, Any] | None,
    final_output: dict[str, Any] | None,
) -> list[dict[str, Any]]:
    assets = _historical_adaptation_assets_cn(report_dir, report_id, adaptation)
    final_output = final_output or {}
    html_path = Path(str(final_output.get("html_artifact_path") or "")).expanduser()
    css_path = Path(str(final_output.get("css_artifact_path") or "")).expanduser()
    pdf_path = Path(str(final_output.get("pdf_artifact_path") or "")).expanduser()

    copied_html_path = report_dir / f"{report_id}-historical-style.html"
    copied_css_path = report_dir / f"{report_id}-historical-style.css"
    copied_pdf_path = report_dir / f"{report_id}-historical-style.pdf"
    existing_names = {str(item.get("name") or "") for item in assets}

    if html_path.is_file() and css_path.is_file():
        copied_html_path.write_text(html_path.read_text(encoding="utf-8-sig"), encoding="utf-8")
        copied_css_path.write_text(css_path.read_text(encoding="utf-8-sig"), encoding="utf-8")
        assets = [
            item
            for item in assets
            if str(item.get("name") or "") != copied_html_path.name
        ]
        assets.append(
            {
                "name": copied_html_path.name,
                "path": copied_html_path.name,
                "file_path": str(copied_html_path.resolve()),
                "purpose": "按历史报告视觉风格生成的 HTML 版本。",
                "is_main": False,
                "type": "html",
            }
        )
        if copied_css_path.name not in existing_names:
            assets.append(
                {
                    "name": copied_css_path.name,
                    "path": copied_css_path.name,
                    "file_path": str(copied_css_path.resolve()),
                    "purpose": "按历史报告视觉风格生成的 CSS 版本。",
                    "is_main": False,
                    "type": "css",
                }
            )
    if pdf_path.is_file() and copied_pdf_path.name not in existing_names:
        copied_pdf_path.write_bytes(pdf_path.read_bytes())
        assets.append(
            {
                "name": copied_pdf_path.name,
                "path": copied_pdf_path.name,
                "file_path": str(copied_pdf_path.resolve()),
                "purpose": "按历史报告视觉风格生成的 PDF 版本。",
                "is_main": False,
                "type": "pdf",
            }
        )
    return assets


def _choose_output_strategy(
    *,
    request: SmartReportRequest,
    temporal_cols: list[str],
    numeric_cols: list[str],
    categorical_cols: list[str],
    market_intelligence: dict[str, Any],
) -> dict[str, Any]:
    main_scheme = {
        "name": "HTML 智能分析主报告",
        "why": "主报告需要同时承载结构化结论、长文本解释、图表和下载入口，HTML 最适合做成主交付物。",
        "best_for": "面向管理层、业务负责人和分析团队的主阅读材料。",
    }
    alternatives = [
        {
            "name": "Excel 结果工作簿",
            "why": "适合给分析师继续透视、筛选和二次加工。",
        },
        {
            "name": "Markdown 报告源稿",
            "why": "适合沉淀到知识库、文档系统或继续交给模型润色。",
        },
    ]
    if temporal_cols and numeric_cols:
        main_scheme["why"] += " 当前数据同时有时间和指标结构，HTML 更适合承载趋势与波动分析。"
    if market_intelligence.get("ready"):
        main_scheme["name"] = "HTML 市场分析主报告"
        main_scheme["why"] += " 当前数据可切出市场维度与结果指标，HTML 适合把份额、集中度、增长和机会并排呈现。"
        main_scheme["best_for"] = "面向市场负责人、经营分析、渠道团队和管理层的主交付材料。"
        alternatives = [
            {
                "name": "Tableau/Superset 友好 CSV",
                "why": "适合继续接到 BI 看板、埋点回看或嵌入式 dashboard。",
            },
            {
                "name": "R / Stata 分析脚本",
                "why": "适合继续做计量建模、复算和同行复核。",
            },
        ]
    if request.target_audience.strip() and "管理" in request.target_audience:
        main_scheme["best_for"] = "管理层快速浏览结论，同时保留图表与附件链接。"
    if not categorical_cols:
        alternatives = alternatives[:1]
    return {
        "main": main_scheme,
        "alternatives": alternatives[:2],
    }


def _csv_ready_frame(frame: pd.DataFrame) -> pd.DataFrame:
    export_frame = frame.copy()
    for column in export_frame.columns:
        if pd.api.types.is_datetime64_any_dtype(export_frame[column]):
            export_frame[column] = export_frame[column].dt.strftime("%Y-%m-%d %H:%M:%S")
    return export_frame.where(pd.notnull(export_frame), None)


def _tableau_handoff_assets(
    report_dir: Path,
    report_id: str,
    frame: pd.DataFrame,
    market_intelligence: dict[str, Any],
) -> list[dict[str, Any]]:
    if not (market_intelligence.get("ready") or market_intelligence.get("market_requested")):
        return []

    dimension_column = market_intelligence.get("dimension_column") or ""
    metric_column = market_intelligence.get("metric_column") or ""
    time_column = market_intelligence.get("time_column") or ""

    extract_path = report_dir / f"{report_id}-tableau-extract.csv"
    _csv_ready_frame(frame).to_csv(extract_path, index=False, encoding="utf-8-sig")

    r_script_path = report_dir / f"{report_id}-market-analysis.R"
    r_script = f"""library(readr)
library(dplyr)
library(ggplot2)

market_dim <- "{dimension_column}"
market_metric <- "{metric_column}"
market_time <- "{time_column}"
df <- read_csv("{extract_path.name}", show_col_types = FALSE)

segment_summary <- df |>
  filter(!is.na(.data[[market_dim]]), !is.na(.data[[market_metric]])) |>
  group_by(.data[[market_dim]]) |>
  summarise(metric = sum(as.numeric(.data[[market_metric]]), na.rm = TRUE), .groups = "drop") |>
  arrange(desc(metric))

print(head(segment_summary, 10))

ggplot(head(segment_summary, 10), aes(x = reorder(.data[[market_dim]], metric), y = metric)) +
  geom_col(fill = "#F7A072") +
  coord_flip() +
  labs(
    title = "Market landscape ranking",
    x = market_dim,
    y = market_metric
  )
"""
    r_script_path.write_text(r_script, encoding="utf-8")

    stata_do_path = report_dir / f"{report_id}-market-analysis.do"
    stata_do = f"""clear all
set more off

import delimited using "{extract_path.name}", varnames(1) clear

* Replace the variable names below if Stata renames them during import.
local market_dim "{dimension_column}"
local market_metric "{metric_column}"

capture confirm variable `market_metric'
if _rc == 0 {{
    collapse (sum) `market_metric', by(`market_dim')
    gsort -`market_metric'
    list in 1/10
    graph bar (sum) `market_metric', over(`market_dim', sort(1) descending) ///
        title("Market landscape ranking")
}}
"""
    stata_do_path.write_text(stata_do, encoding="utf-8")

    return [
        {
            "name": extract_path.name,
            "path": extract_path.name,
            "file_path": str(extract_path.resolve()),
            "purpose": "Tableau / Superset / Metabase 友好的原始数据抽取。",
            "is_main": False,
            "type": "csv",
        },
        {
            "name": r_script_path.name,
            "path": r_script_path.name,
            "file_path": str(r_script_path.resolve()),
            "purpose": "R / ggplot2 / Shiny 的市场分析起手脚本。",
            "is_main": False,
            "type": "r",
        },
        {
            "name": stata_do_path.name,
            "path": stata_do_path.name,
            "file_path": str(stata_do_path.resolve()),
            "purpose": "Stata 的市场分析起手 do-file。",
            "is_main": False,
            "type": "do",
        },
    ]


def _downloadable_bundle(
    report_dir: Path,
    report_id: str,
    report: dict[str, Any],
    frame: pd.DataFrame,
    market_intelligence: dict[str, Any],
) -> dict[str, Any]:
    report_dir.mkdir(parents=True, exist_ok=True)
    markdown_path = report_dir / f"{report_id}.md"
    html_path = report_dir / f"{report_id}.html"
    pdf_path = report_dir / f"{report_id}.pdf"
    excel_path = report_dir / f"{report_id}.xlsx"

    markdown_content = _report_markdown(report)
    markdown_path.write_text(markdown_content, encoding="utf-8")

    html_sections = []
    for section in report["sections"]:
        bullet_html = "".join(f"<li>{html.escape(str(item))}</li>" for item in section["bullets"])
        html_sections.append(
            f"<section><h2>{html.escape(section['title'])}</h2><p>{html.escape(section['summary'])}</p><ul>{bullet_html}</ul></section>"
        )
    html_body = f"""<!doctype html>
<html lang="zh-CN">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>{html.escape(report['title'])}</title>
  <style>
    body {{ font-family: Arial, 'PingFang SC', 'Microsoft YaHei', sans-serif; margin: 0; padding: 32px; background: #f6f3ee; color: #1f2430; }}
    main {{ max-width: 1080px; margin: 0 auto; }}
    section {{ background: white; border-radius: 18px; padding: 20px 22px; margin-top: 18px; box-shadow: 0 10px 28px rgba(0,0,0,0.06); }}
    h1, h2 {{ margin: 0 0 12px; }}
    ul {{ margin: 0; padding-left: 18px; line-height: 1.7; }}
    .meta {{ color: #5b6573; line-height: 1.8; }}
  </style>
</head>
<body>
  <main>
    <h1>{html.escape(report['title'])}</h1>
    <p class="meta">Dataset: {html.escape(report['dataset_name'])} / Sheet: {html.escape(report['sheet_name'])}</p>
    <section>
      <h2>管理层摘要</h2>
      <ul>{''.join(f"<li>{html.escape(str(item))}</li>" for item in report['executive_summary'])}</ul>
    </section>
    {''.join(html_sections)}
  </main>
</body>
</html>"""
    html_path.write_text(html_body, encoding="utf-8")
    pdf_generated_path = _write_pdf_report_cn(report_dir, report_id, report)

    with pd.ExcelWriter(excel_path, engine="openpyxl") as writer:
        for section in report["sections"]:
            for table in section["tables"]:
                table_name = f"{section['id'][:10]}_{table['title'][:18]}".replace("/", "_")
                pd.DataFrame(table["rows"]).to_excel(writer, index=False, sheet_name=table_name[:31] or "report")

    relative_dir = report_dir.relative_to(REPORTS_DIR.parent).as_posix()
    handoff_assets = _tableau_handoff_assets(report_dir, report_id, frame, market_intelligence)

    downloadables = [
        {
            "name": html_path.name,
            "path": f"/storage/{relative_dir}/{html_path.name}",
            "file_path": str(html_path.resolve()),
            "purpose": "主报告，适合直接打开阅读与交付。",
            "is_main": True,
            "type": "html",
        },
        {
            "name": excel_path.name,
            "path": f"/storage/{relative_dir}/{excel_path.name}",
            "file_path": str(excel_path.resolve()),
            "purpose": "结果表附件，适合筛选和二次分析。",
            "is_main": False,
            "type": "xlsx",
        },
        {
            "name": markdown_path.name,
            "path": f"/storage/{relative_dir}/{markdown_path.name}",
            "file_path": str(markdown_path.resolve()),
            "purpose": "文本源稿，适合沉淀知识库或继续润色。",
            "is_main": False,
            "type": "md",
        },
        *[
            {
                **item,
                "path": f"/storage/{relative_dir}/{item['path']}",
            }
            for item in handoff_assets
        ],
    ]
    return {
        "markdown_path": str(markdown_path.resolve()),
        "html_path": str(html_path.resolve()),
        "pdf_path": str(pdf_generated_path.resolve()) if pdf_generated_path else "",
        "excel_path": str(excel_path.resolve()),
        "downloadables": downloadables,
    }


def generate_smart_report(
    dataset_id: str,
    request: SmartReportRequest,
    progress_callback: Callable[[dict[str, Any]], None] | None = None,
    report_job_id: str = "",
    runtime_child_task_creator: Callable[..., dict[str, Any]] | None = None,
) -> dict[str, Any]:
    report_id = uuid.uuid4().hex[:12]
    REPORTS_DIR.mkdir(parents=True, exist_ok=True)
    report_dir = REPORTS_DIR / f"smart-report-{report_id}"
    interactive_runtime = progress_callback is not None
    fast_runtime_mode = interactive_runtime and request.report_style == "executive"
    requested_report_parts = normalize_report_part_ids(request.report_part, request.selected_report_parts)
    report_part_contract = {
        "source": "smart_report",
        "request_part": request.report_part,
        "selected_report_parts": list(request.selected_report_parts),
        "requested_report_parts": requested_report_parts,
        "available_report_parts": [
            {"id": part_id, "title": title}
            for part_id, title in REPORT_PART_TITLES.items()
        ],
        "routing_policy": (
            "Formal reports now carry the same report-part contract as Analysis Lab: "
            "field semantics and derived metrics are prepared before method or section routing."
        ),
    }

    def _emit_progress(stage_id: str, title: str, detail: str, status: str = "running", payload: dict[str, Any] | None = None) -> None:
        if not progress_callback:
            return
        event = {
            "stage_id": stage_id,
            "title": title,
            "detail": detail,
            "timestamp": datetime.utcnow().isoformat() + "Z",
            "payload": {"status": status, **(payload or {})},
        }
        try:
            progress_callback(event)
        except Exception:
            pass

    def _emit_pipeline_progress(manifest: dict[str, Any]) -> None:
        pipeline_type = str(manifest.get("pipeline_type") or "")
        if pipeline_type not in {
            "generic_long_cli_pipeline",
            "multi_table_generic_long_cli_pipeline",
            "ecommerce_long_cli_pipeline",
            "internet_ops_long_cli_pipeline",
        }:
            return
        pipeline_job_id = str(manifest.get("pipeline_job_id") or "")
        current_stage_id = str(manifest.get("current_stage_id") or "")
        current_stage_title = str(manifest.get("current_stage_title") or current_stage_id or "Generic Long CLI")
        current_stage_detail = str(manifest.get("current_stage_detail") or "")
        pipeline_progress = int(manifest.get("progress_percent") or 0)
        # The generic CLI chain runs inside the rendering/package tail of the report job.
        # Map its internal 0-100% to a narrow report-job band so the UI keeps moving.
        report_progress = min(98, 94 + int(max(0, min(100, pipeline_progress)) * 0.04))
        event_id = (
            "multi_table_generic_long_cli_pipeline"
            if pipeline_type == "multi_table_generic_long_cli_pipeline"
            else (
                "ecommerce_long_cli_pipeline"
                if pipeline_type == "ecommerce_long_cli_pipeline"
                else (
                    "internet_ops_long_cli_pipeline"
                    if pipeline_type == "internet_ops_long_cli_pipeline"
                    else "generic_long_cli_pipeline"
                )
            )
        )
        title_prefix = (
            "Codex CLI 多表主报告链"
            if pipeline_type == "multi_table_generic_long_cli_pipeline"
            else (
                "Codex CLI 电商影子主报告链"
                if pipeline_type == "ecommerce_long_cli_pipeline"
                else (
                    "Codex CLI 互联网运营影子主报告链"
                    if pipeline_type == "internet_ops_long_cli_pipeline"
                    else "Codex CLI 主报告链"
                )
            )
        )
        _emit_progress(
            event_id,
            f"{title_prefix}：{current_stage_title}",
            current_stage_detail or f"正在执行 {current_stage_id or 'pipeline'}",
            status=str(manifest.get("status") or "running"),
            payload={
                "pipeline_job_id": pipeline_job_id,
                "pipeline_type": pipeline_type,
                "pipeline_status": str(manifest.get("status") or ""),
                "pipeline_progress_percent": pipeline_progress,
                "pipeline_current_stage_id": current_stage_id,
                "linked_codex_run_ids": list(manifest.get("linked_codex_run_ids") or []),
                "report_progress_percent": report_progress,
            },
        )

    _emit_progress("orchestration_start", "开始数据编排", "正在读取数据、构建业务路由和 AI mandatory 基础产物。")
    orchestration = build_report_orchestration(
        dataset_id,
        request,
        ai_trace_output_dir=report_dir,
    )
    _emit_progress(
        "orchestration_ready",
        "完成数据编排",
        "字段画像、业务路由和基础编排结果已生成。",
        status="completed",
        payload={
            "selected_sheet_names": orchestration.get("selected_sheet_names") or [],
            "multi_mode": orchestration.get("multi_mode") or "",
        },
    )
    metadata = orchestration["metadata"]
    selected_sheet_names = orchestration["selected_sheet_names"]
    multi_mode = orchestration["multi_mode"]
    router_result = orchestration.get("business_profile_router") or {}
    ai_mandatory = orchestration.get("ai_mandatory") or {}
    orchestration.setdefault("request", request)
    if multi_mode in {"combined", "separate"} and len(selected_sheet_names) > 1:
        critical_missing = [
            key
            for key in ("metadata", "selected_sheet_names", "blueprint")
            if key not in orchestration or not orchestration.get(key)
        ]
    else:
        critical_missing = [
            key for key in ("frame", "sheet", "program_bundle", "blueprint") if key not in orchestration
        ]
    if (
        ai_mandatory
        and not ai_mandatory.get("formal_pdf_allowed", False)
        and critical_missing
    ):
        primary_sheet_name = selected_sheet_names[0] if selected_sheet_names else (metadata.get("active_sheet") or "Sheet1")
        _emit_progress(
            "failed",
            "AI mandatory 阻断正式主链",
            "AI mandatory 未通过且主编排不完整，当前只能返回 debug / blocked 产物。",
            status="failed",
            payload={
                "failure_code": ai_mandatory.get("failure_code") or "AI_MANDATORY_FAILED",
                "missing_keys": critical_missing,
            },
        )
        return _ai_mandatory_failure_bundle_cn(
            report_dir=report_dir,
            report_id=report_id,
            dataset_name=str(metadata.get("name") or dataset_id),
            sheet_name=str(primary_sheet_name),
            ai_mandatory=ai_mandatory,
        )
    if multi_mode == "separate" and len(selected_sheet_names) > 1:
        child_graph = execute_job_graph(
            [
                JobNode(
                    job_id=f"child_report::{sheet_name}",
                    title=f"逐表子报告 {sheet_name}",
                    detail="将当前工作表作为独立子任务进入完整单表分析。",
                    category="engineering",
                    parallel_group="child_reports",
                    runner=lambda _results, target_sheet=sheet_name: generate_smart_report(
                        dataset_id,
                        request.model_copy(
                            update={
                                "multi_table_mode": "single",
                                "sheet_name": target_sheet,
                                "selected_sheets": [],
                            }
                        ),
                    ),
                    formatter=lambda output: str(output.get("sheet_name") or ""),
                )
                for sheet_name in selected_sheet_names
            ],
            max_workers=min(4, len(selected_sheet_names)),
        )
        child_reports = [child_graph["results"][f"child_report::{sheet_name}"] for sheet_name in selected_sheet_names]
        blueprint = orchestration["blueprint"]
        sheet_frames = _selected_sheet_frames(dataset_id, metadata, selected_sheet_names)
        return _multi_table_master_report(
            dataset_id=dataset_id,
            metadata=metadata,
            request=request,
            selected_sheet_names=selected_sheet_names,
            sheet_frames=sheet_frames,
            blueprint=blueprint,
            mode="separate",
            child_reports=child_reports,
            execution_steps=orchestration.get("execution_steps", []) + [
                {
                    "id": item["id"],
                    "title": item["title"],
                    "status": item["status"],
                    "detail": item["detail"],
                    "output": item.get("output", ""),
                    "category": item["category"],
                    "parallel_group": item.get("parallel_group", ""),
                }
                for item in child_graph["steps"]
                if item["status"] == "completed"
            ],
            thinking_steps=orchestration.get("thinking_steps", []),
        )

    if multi_mode == "combined" and len(selected_sheet_names) > 1:
        blueprint = orchestration["blueprint"]
        sheet_frames = _selected_sheet_frames(dataset_id, metadata, selected_sheet_names)
        report = _multi_table_master_report(
            dataset_id=dataset_id,
            metadata=metadata,
            request=request,
            selected_sheet_names=selected_sheet_names,
            sheet_frames=sheet_frames,
            blueprint=blueprint,
            mode="combined",
            child_reports=[],
            execution_steps=orchestration.get("execution_steps", []),
            thinking_steps=orchestration.get("thinking_steps", []),
        )
        report_dir = REPORTS_DIR / f"smart-report-{report['report_id']}"
        pipeline_enabled = os.getenv("ASTERIA_MULTI_TABLE_GENERIC_LONG_CLI_PIPELINE_ENABLED", "1").strip().lower() not in {
            "0",
            "false",
            "no",
        }
        if not pipeline_enabled:
            report["multi_table_generic_long_cli_pipeline"] = {
                "status": "disabled",
                "reason": "ASTERIA_MULTI_TABLE_GENERIC_LONG_CLI_PIPELINE_ENABLED disabled",
            }
            report["multi_table_generic_long_cli_pipeline_job_id"] = ""
            report["multi_table_generic_long_cli_final_output"] = {}
            report["linked_codex_pipeline_job_ids"] = list(report.get("linked_codex_pipeline_job_ids") or [])
            _append_current_turn_export_manifest(
                report_dir=report_dir,
                report_id=report["report_id"],
                report=report,
                artifact_bundle={"downloadables": report.get("downloadables") or []},
            )
            return report

        pipeline_manifest: dict[str, Any] = {}
        try:
            pipeline_context = {
                "style_preset": getattr(request, "premium_style_preset", DEFAULT_LAYOUT_PRESET_ID) or DEFAULT_LAYOUT_PRESET_ID,
                "language": request.report_language,
                "report_goal": (
                    "multi_table_generic_business_runtime_cli"
                    if bool(getattr(request, "enable_generic_business_runtime", False))
                    else "multi_table_generic_long_business_report"
                ),
                "target_audience": (
                    getattr(request, "target_audience", "")
                    or ("management" if bool(getattr(request, "enable_generic_business_runtime", False)) else "reader of this workbook")
                ),
                "analysis_mode": "multi_table_generic_long_cli_pipeline",
                "enable_generic_business_runtime": bool(getattr(request, "enable_generic_business_runtime", False)),
                "request": request.model_dump(),
                "report_lens": (
                    "business_management"
                    if bool(getattr(request, "enable_generic_business_runtime", False))
                    else "smart_lens"
                ),
                "business_focus": request.user_requirement or request.problem_to_solve or request.core_purpose or "",
                "user_requirement": request.user_requirement,
                "problem_to_solve": request.problem_to_solve,
                "core_purpose": request.core_purpose,
                "raw_user_requirement": getattr(request, "raw_user_requirement", request.user_requirement),
                "visual_style": getattr(request, "visual_style_text", ""),
                "required_detail_dimensions": getattr(request, "required_detail_dimensions_text", ""),
                "dataset_id": dataset_id,
                "dataset_name": metadata.get("name", ""),
                "selected_sheet_names": selected_sheet_names,
                "multi_mode": "combined",
                "report_id": report["report_id"],
                "workflow_blueprint_path": "workflow_blueprint.json",
                "table_inventory_path": "table_inventory.json",
                "relationship_candidates_path": "relationship_candidates.json",
                "multi_table_context_path": "multi_table_context.json",
                "reader_facing_mode": (
                    "business_report"
                    if bool(getattr(request, "enable_generic_business_runtime", False))
                    else "smart_lens_report"
                ),
                "internal_grounding_mode": "guardrail_only",
            }
            pipeline_context = _with_report_design_context(
                pipeline_context,
                request=request,
                requirement_intent=report.get("requirement_intent") if isinstance(report.get("requirement_intent"), dict) else {},
            )
            _emit_progress(
                "multi_table_generic_long_cli_pipeline",
                "启动 Codex CLI 多表 generic long 主报告链",
                "多表 combined 主报告将进入：需求挖掘、表理解、关系建模、跨表指标规划、确定性执行、问题树、长报告、HTML/CSS、review、PDF。",
                status="running",
            )
            pipeline_manifest = create_pipeline_job(
                pipeline_type="multi_table_generic_long_cli_pipeline",
                workspace_path=str(report_dir / "codex_premium" / "multi_table_generic_long" / "{pipeline_job_id}"),
                linked_report_id=report["report_id"],
                context_payload=pipeline_context,
                auto_start=False,
            )
            report["multi_table_generic_long_cli_pipeline"] = pipeline_manifest
            report["multi_table_generic_long_cli_pipeline_job_id"] = str(pipeline_manifest.get("pipeline_job_id") or "")
            report["linked_codex_pipeline_job_ids"] = [
                item
                for item in dict.fromkeys(
                    [
                        *(report.get("linked_codex_pipeline_job_ids") or []),
                        report["multi_table_generic_long_cli_pipeline_job_id"],
                    ]
                )
                if str(item or "").strip()
            ]
            copied_inputs = _prepare_multi_table_generic_long_cli_workspace(
                workspace_dir=Path(str(pipeline_manifest.get("workspace_path") or "")),
                report_dir=report_dir,
                report=report,
                metadata=metadata,
                request=request,
                selected_sheet_names=selected_sheet_names,
                sheet_frames=sheet_frames,
                blueprint=blueprint,
                context_payload={**pipeline_context, "pipeline_job_id": pipeline_manifest.get("pipeline_job_id")},
            )
            pipeline = run_pipeline_job_to_completion(
                str(pipeline_manifest.get("pipeline_job_id") or ""),
                progress_callback=_emit_pipeline_progress,
            )
            pipeline["copied_inputs"] = copied_inputs
            report["multi_table_generic_long_cli_pipeline"] = pipeline
            report["multi_table_generic_long_cli_pipeline_job_id"] = pipeline.get("pipeline_job_id") or pipeline_manifest.get("pipeline_job_id") or ""
            report["multi_table_generic_long_cli_final_output"] = pipeline.get("final_output") or {}
            report["linked_codex_pipeline_job_ids"] = [
                item
                for item in dict.fromkeys(
                    [
                        *(report.get("linked_codex_pipeline_job_ids") or []),
                        str(report.get("multi_table_generic_long_cli_pipeline_job_id") or ""),
                    ]
                )
                if str(item or "").strip()
            ]
            if str(pipeline.get("status") or "") == "completed":
                registered = _register_multi_table_generic_long_cli_pdf(
                    report=report,
                    report_dir=report_dir,
                    final_output=pipeline.get("final_output") or {},
                )
                report["multi_table_generic_long_cli_downloadable"] = registered or {}
                _emit_progress(
                    "multi_table_generic_long_cli_pipeline",
                    "Codex CLI 多表主报告链完成",
                    "11_report.pdf 已注册回当前多表报告下载物，作为多表 generic long 主报告。",
                    status="completed",
                    payload={"pipeline_job_id": report.get("multi_table_generic_long_cli_pipeline_job_id")},
                )
            else:
                _emit_progress(
                    "multi_table_generic_long_cli_pipeline",
                    "Codex CLI 多表主报告链未完成",
                    str(pipeline.get("error") or "pipeline did not complete"),
                    status="failed",
                    payload={"pipeline_job_id": report.get("multi_table_generic_long_cli_pipeline_job_id")},
                )
        except Exception as exc:
            pipeline_job_id = str(
                report.get("multi_table_generic_long_cli_pipeline_job_id")
                or pipeline_manifest.get("pipeline_job_id")
                or ""
            )
            latest_pipeline: dict[str, Any] = {}
            if pipeline_job_id:
                try:
                    latest_pipeline = get_pipeline_job(pipeline_job_id)
                except Exception:
                    latest_pipeline = {}
            report["multi_table_generic_long_cli_pipeline"] = {
                **latest_pipeline,
                "status": "failed",
                "error": str(exc),
            }
            report["multi_table_generic_long_cli_pipeline_job_id"] = pipeline_job_id
            report["multi_table_generic_long_cli_final_output"] = {}
            report["linked_codex_pipeline_job_ids"] = [
                item
                for item in dict.fromkeys([*(report.get("linked_codex_pipeline_job_ids") or []), pipeline_job_id])
                if str(item or "").strip()
            ]
            _emit_progress(
                "multi_table_generic_long_cli_pipeline",
                "Codex CLI 多表主报告链失败",
                str(exc),
                status="failed",
                payload={"pipeline_job_id": pipeline_job_id},
            )
        _append_current_turn_export_manifest(
            report_dir=report_dir,
            report_id=report["report_id"],
            report=report,
            artifact_bundle={"downloadables": report.get("downloadables") or []},
        )
        return json.loads(json.dumps(report, ensure_ascii=False, default=_safe_value))
    frame = orchestration["frame"]
