def _stats_appendix_section_v3(
    recommended_methods: list[dict[str, Any]],
    recommended_method_runs: list[dict[str, Any]],
    report_request: SmartReportRequest | None = None,
    lens: str = "mixed_business_review",
    method_reviews: list[dict[str, Any]] | None = None,
) -> dict[str, Any]:
    effective_request = report_request or SmartReportRequest()
    review_lookup: dict[tuple[str, str], dict[str, Any]] = {
        (str(item.get("method_id") or ""), str(item.get("method") or "")): item
        for item in (method_reviews or [])
    }
    run_rows: list[dict[str, Any]] = []
    method_notes: list[dict[str, Any]] = []
    for run in recommended_method_runs:
        result = run.get("result", {}) or {}
        metrics = result.get("metrics", {}) or {}
        method_request = run.get("request", {}) or {}
        review = review_lookup.get((str(run.get("method_id") or ""), str(run.get("method") or "")), {})
        run_rows.append(
            {
                "\u65b9\u6cd5": run["method"],
                "method_id": run["method_id"],
                "\u76ee\u6807\u5b57\u6bb5": method_request.get("target") or ",".join(method_request.get("features", [])[:3]) or "n/a",
                "\u4e3b\u8981\u7ed3\u8bba": review.get("result_meaning") or _method_result_sentence(run),
                "\u6837\u672c\u91cf": metrics.get("sample_size") or metrics.get("n") or metrics.get("strongest_sample_size"),
                "p\u503c": metrics.get("p_value") or metrics.get("strongest_p_value"),
            }
        )
        method_notes.append(
            {
                "\u65b9\u6cd5": run["method"],
                "\u56de\u7b54\u7684\u95ee\u9898": _method_focus_question(str(run.get("method_id") or ""), method_request),
                "\u7ed3\u679c\u610f\u5473\u7740\u4ec0\u4e48": review.get("result_meaning") or _method_result_sentence(run),
                "\u4e1a\u52a1\u4e0a\u600e\u4e48\u7528": review.get("business_takeaway") or _method_business_use_sentence(run, effective_request, lens),
                "\u8fb9\u754c\u63d0\u9192": review.get("caution") or "\u5982\u679c\u53e3\u5f84\u3001\u5355\u4f4d\u6216\u5206\u6bcd\u8fd8\u6ca1\u6709\u5b8c\u5168\u786e\u8ba4\uff0c\u8fd9\u5c42\u89e3\u91ca\u53ea\u80fd\u670d\u52a1\u4e8e\u6837\u672c\u5185\u5224\u65ad\uff0c\u4e0d\u80fd\u76f4\u63a5\u4e0a\u5347\u6210\u62cd\u677f\u7ed3\u8bba\u3002",
            }
        )
    return _section(
        "stats_appendix",
        "\u7edf\u8ba1\u65b9\u6cd5\u9644\u5f55",
        "\u8fd9\u90e8\u5206\u5b8c\u6574\u4fdd\u7559\u5df2\u5b9e\u8dd1\u65b9\u6cd5\u7684\u7ed3\u679c\u3001\u4e2d\u6587\u89e3\u91ca\u548c\u4e1a\u52a1\u4f7f\u7528\u65b9\u5f0f\uff0c\u65b9\u4fbf\u6570\u5206\u3001\u7814\u7a76\u548c\u590d\u6838\u540c\u5b66\u7ee7\u7eed\u5f80\u4e0b\u94bb\uff0c\u4e0d\u518d\u53ea\u505c\u7559\u5728\u65b9\u6cd5\u540d\u6216\u6a21\u677f\u77ed\u53e5\u3002",
        [
            f"\u5f53\u524d\u5b9e\u9645\u5df2\u8fd0\u884c {len(recommended_method_runs)} \u4e2a\u65b9\u6cd5\u3002",
            f"\u5f53\u524d\u63a8\u8350\u65b9\u6cd5\u76ee\u5f55\u5171\u8986\u76d6 {len(recommended_methods)} \u4e2a\u5019\u9009\u65b9\u6cd5\uff0c\u9644\u5f55\u91cd\u70b9\u4fdd\u7559\u5df2\u7ecf\u771f\u6b63\u8dd1\u5b8c\u7684\u65b9\u6cd5\u7ed3\u679c\u3002",
            "\u6bcf\u4e2a\u5df2\u5b9e\u8dd1\u65b9\u6cd5\u90fd\u8865\u4e00\u5f20\u89e3\u91ca\u5361\uff0c\u660e\u786e\u5b83\u56de\u7b54\u4ec0\u4e48\u95ee\u9898\u3001\u7ed3\u679c\u610f\u5473\u7740\u4ec0\u4e48\u3001\u4e1a\u52a1\u4e0a\u600e\u4e48\u7528\uff0c\u4ee5\u53ca\u5f53\u524d\u8fd8\u4e0d\u80fd\u8d8a\u8fc7\u7684\u8fb9\u754c\u3002",
        ],
        tables=[
            _table("\u5b9e\u8dd1\u65b9\u6cd5\u7ed3\u679c", run_rows),
            _table("\u65b9\u6cd5\u89e3\u8bfb\u5361", method_notes),
            *[
                table
                for run in recommended_method_runs
                for table in run.get("result", {}).get("tables", [])[:2]
            ],
        ],
    )


