def _legacy_6__management_summary_from_registry(report: dict[str, Any], registry_rows: list[dict[str, Any]], field_registry: dict[str, Any]) -> list[str]:
    def _pick(object_id: str) -> dict[str, Any] | None:
        return next((row for row in registry_rows if str(row.get("object_id") or "") == object_id), None)

    def _line(row: dict[str, Any] | None) -> str:
        if not row:
            return ""
        return clean_report_text_filter(
            f"{row['object_id']} 当前标签为“{row['final_label']}”，证据是 {row['trigger_evidence']}；最终动作是“{row['final_action']}”，结论强度为 {row['action_strength']}。"
        )

    registry_mode = str((report.get("procurement_sales_readiness") or {}).get("report_mode") or field_registry.get("report_mode") or "sales_fulfillment_product_report")
    important_rows = [
        _pick("category_object"),
        _pick("product_object"),
        _pick("sku_object"),
    ]
    return [
        clean_report_text_filter(f"报告模式：当前是 {registry_mode}，采购侧待补数，不能作为完整采销拍板报告。"),
        clean_report_text_filter("当前可判断内容：可以判断销售结构、商品承接、SKU履约风险、售后评价风险、供应商销侧表现。"),
        clean_report_text_filter("当前不可判断内容：不能判断正式主推、补货、清仓、采购谈判空间、完整供应商替换和利润表现。"),
        "；".join(item for item in [_line(row) for row in important_rows] if item),
        clean_report_text_filter("三个下一步动作：1. 补利润字段、库存/周转、退货/售后成本；2. 对 product_object做差评归因和履约修复；3. 对 sku_object做低样本规格复核并待补库存后再判断。"),
    ]


def _legacy_7__procurement_sales_management_render(report: dict[str, Any]) -> dict[str, Any] | None:
    registry_payload = report.get("object_decision_registry") or {}
    registry_rows = registry_payload.get("rows") or []
    if not registry_rows:
        return None
    field_registry = registry_payload.get("field_registry") or {}
    category_rows = [row for row in registry_rows if row["object_level"] == "category"]
    product_rows = [row for row in registry_rows if row["object_level"] == "product"]
    sku_rows = [row for row in registry_rows if row["object_level"] == "sku"]
    supplier_rows = [row for row in registry_rows if row["object_level"] == "supplier"]

    def _pick_many(object_ids: list[str], rows: list[dict[str, Any]]) -> list[dict[str, Any]]:
        picked: list[dict[str, Any]] = []
        for object_id in object_ids:
            row = next((item for item in rows if str(item.get("object_id") or "") == object_id), None)
            if row and row not in picked:
                picked.append(row)
        return picked

    prioritized_rows: list[dict[str, Any]] = []
    prioritized_rows.extend(_pick_many(["category_object"], category_rows))
    prioritized_rows.extend(_pick_many(["product_object"], product_rows))
    prioritized_rows.extend(_pick_many(["sku_object", "sku_object_alt"], sku_rows))
    prioritized_rows.extend(_pick_many(["seller_object_a", "seller_object_b", "seller_object_c"], supplier_rows))
    prioritized_rows.extend(category_rows[:5])
    prioritized_rows.extend(product_rows[:8])
    prioritized_rows.extend(sku_rows[:8])
    prioritized_rows.extend(supplier_rows[:8])

    seen_keys: set[tuple[str, str]] = set()
    compact_rows: list[dict[str, Any]] = []
    for row in prioritized_rows:
        key = (str(row.get("object_level") or ""), str(row.get("object_id") or ""))
        if key in seen_keys:
            continue
        seen_keys.add(key)
        compact_rows.append(row)

    action_table_rows = []
    for index, row in enumerate(compact_rows[:30], start=1):
        action_table_rows.append(
            {
                "优先级": f"P{1 if index <= 5 else 2 if index <= 15 else 3}",
                "对象层级": row["object_level"],
                "对象名称": row["object_id"],
                "最终标签": row["final_label"],
                "触发证据": row["trigger_evidence"],
                "被拦截动作": " / ".join(row["blocked_actions"]) if row["blocked_actions"] else "无",
                "最终动作": row["final_action"],
                "需要补充字段": _friendly_required_fields(list(row["required_missing_fields"])),
                "负责人角色": row["owner_role"],
                "时间要求": row["time_requirement"],
                "验证指标": row["validation_metric"],
                "结论强度": row["action_strength"],
            }
        )

    blocked_rows = [
        {
            "对象": row.get("object", ""),
            "对象层级": row.get("object_level", ""),
            "被拦截动作": str(row.get("attempted_action", "")).strip() or "无",
            "拦截原因": row.get("blocked_reason", ""),
            "降级后动作": row.get("downgraded_action", ""),
            "需要补充字段": row.get("missing_fields", ""),
        }
        for row in (registry_payload.get("blocked_action_log") or [])
    ]

    field_rows = [
        {
            "字段组": key,
            "是否可用": "是" if value else "否",
            "命中字段": " / ".join((field_registry.get("field_coverage") or {}).get(key, []) or []) or "无",
        }
        for key, value in [
            ("sales_fields", field_registry.get("has_sales_fields")),
            ("fulfillment_fields", field_registry.get("has_fulfillment_fields")),
            ("review_fields", field_registry.get("has_review_fields")),
            ("profit_fields", field_registry.get("has_profit_fields")),
            ("inventory_fields", field_registry.get("has_inventory_fields")),
            ("procurement_price_fields", field_registry.get("has_procurement_price_fields")),
            ("supplier_delivery_fields", field_registry.get("has_supplier_delivery_fields")),
            ("payment_term_fields", field_registry.get("has_payment_term_fields")),
            ("return_cost_fields", field_registry.get("has_return_cost_fields")),
        ]
    ]
    boundary_rows = [
        {"当前不可判断内容": item}
        for item in [
            "不能判断正式主推",
            "不能判断补货",
            "不能判断清仓",
            "不能判断采购谈判空间",
            "不能判断完整供应商替换",
            "不能判断利润表现",
        ]
    ]

    def _review_section(section_id: str, title: str, rows: list[dict[str, Any]], business_question: str) -> dict[str, Any]:
        bullets = [
            clean_report_text_filter(
                f"{row['object_id']} 当前标签为“{row['final_label']}”，核心证据是 {row['trigger_evidence']}；最终动作固定为“{row['final_action']}”。"
            )
            for row in rows[:5]
        ]
        table_rows = [
            {
                "对象": row["object_id"],
                "最终标签": row["final_label"],
                "最终动作": row["final_action"],
                "触发证据": row["trigger_evidence"],
                "被拦截动作": " / ".join(row["blocked_actions"]) if row["blocked_actions"] else "无",
                "结论强度": row["action_strength"],
            }
            for row in rows[:10]
        ]
        return _section(section_id, title, business_question, bullets[:6], tables=[_table(f"{title}动作表", table_rows)] if table_rows else [])

    sections = [
        _section(
            "report_mode_cover",
            "封面与报告模式",
            "本页回答：当前报告属于什么模式，哪些边界必须先说清。",
            [
                "当前报告属于 sales_fulfillment_product_report。",
                "采购侧待补数，因此不能作为完整采销拍板报告。",
            ],
        ),
        _section(
            "management_summary_fixed",
            "管理层摘要",
            "本页回答：当前能判断什么、不能判断什么，以及最重要的对象级结论和下一步动作。",
            _management_summary_from_registry(report, registry_rows, field_registry),
        ),
        _section(
            "field_availability",
            "字段可用性与不可下结论清单",
            "本页回答：当前字段支持哪些判断，哪些结论必须被压住。",
            [
                "可判断销售结构、商品承接、SKU履约风险、售后评价风险、供应商销侧表现。",
                "不可判断正式主推、补货、清仓、采购谈判空间、完整供应商替换和利润表现。",
                "统计附录显示 Revenue 分布明显偏态，因此正文优先采用分位数、异常对象和对象级复核，不用均值单独下结论。",
            ],
            tables=[_table("字段可用性", field_rows), _table("不可下结论清单", boundary_rows)],
        ),
        _section(
            "final_action_table",
            "对象最终动作总表",
            "本页回答：对象最终动作是什么、由谁负责、何时完成、怎么验证。",
            [
                "行动表只读取 object_decision_registry 的 final_label 和 final_action。",
                "被拦截动作不会再被摘要重写成新的动作。",
            ],
            tables=[_table("行动表", action_table_rows)],
        ),
        _section(
            "blocked_action_table",
            "被拦截动作表",
            "本页回答：哪些强动作被 guardrail 拦下，以及为什么被拦下。",
            ["这张表只做解释，不再把被拦截动作写成正文建议。"],
            tables=[_table("被拦截动作", blocked_rows[:20])] if blocked_rows else [],
        ),
        _review_section("category_review", "品类经营复核", category_rows, "本页回答：哪些品类只是资源候选，不能直接进入强经营动作。"),
        _review_section("product_review", "商品经营复核", product_rows, "本页回答：哪些商品有销售基础但放量前必须先修履约和口碑。"),
        _review_section("sku_review", "SKU 经营复核", sku_rows, "本页回答：哪些 SKU 只是低样本风险，哪些 SKU 需要降权控量。"),
        _review_section("supplier_review", "供应商履约与口碑复核", supplier_rows, "本页回答：哪些供应商需要口碑修复、履约修复或替换评估。"),
        _section(
            "action_roadmap",
            "行动路线图",
            "本页回答：下一步优先做什么。",
            [
                "补利润字段、库存/周转、退货/售后成本字段。",
                "对 product_object做差评归因和履约修复。",
                "对 sku_object做低样本规格复核并待补库存后再判断。",
            ],
        ),
    ]
    return {
        "title": clean_report_text_filter(str(report.get("title") or "")),
        "executive_summary": _management_summary_from_registry(report, registry_rows, field_registry),
        "sections": sections,
        "action_rows": action_table_rows,
        "blocked_rows": blocked_rows,
        "field_registry": field_registry,
    }


def _appendix_report_variant(report: dict[str, Any]) -> dict[str, Any]:
    variant = copy.deepcopy(report)
    management_ids = _management_section_ids_for_report(report)
    sections = [section for section in variant.get("sections", []) if section.get("id") not in management_ids]
    if str(report.get("report_lens") or "") == "procurement_sales_review":
        stats = [section for section in sections if str(section.get("id") or "") in PROCUREMENT_STATS_APPENDIX_IDS]
        other = [section for section in sections if str(section.get("id") or "") not in PROCUREMENT_STATS_APPENDIX_IDS]
        sections = [*stats, *other]
    variant["title"] = f"{report['title']}（analyst_appendix）"
    variant["sections"] = sections
    variant["executive_summary"] = ["本文为分析师附录，保留完整明细表、统计方法、模型表、字段映射和补充图表。"]
    return variant


_MGMT_RESOURCE_TERMS = ("核心主推", "主推", "资源倾斜", "预算倾斜", "继续主推", "加码", "重点合作")
_MGMT_INVENTORY_TERMS = ("补货", "清仓", "清理退场", "停止补货", "并柜", "移出主推池", "补货放量")
_MGMT_PROCUREMENT_TERMS = ("压价", "成本优化", "价格谈判空间")
_MGMT_SUPPLIER_TERMS = ("直接替换", "淘汰", "供应商履约问责", "替换清理")


def _contains_any_term(text: str, terms: tuple[str, ...]) -> bool:
    value = str(text or "")
    return any(term in value for term in terms)


def _friendly_required_fields_cn(value: str | list[str] | None) -> str:
    if isinstance(value, list):
        return _friendly_required_fields(value)
    return str(value or "无")


def _sanitize_blocked_actions_for_management(row: dict[str, Any]) -> str:
    blocked_actions = [str(item).strip() for item in (row.get("blocked_actions") or []) if str(item).strip()]
    if not blocked_actions:
        return "无"
    return " / ".join(f"{label}（已拦截）" for label in _blocked_action_display(blocked_actions).split(" / ") if label.strip()) or "详见 blocked_action_log.csv"

