def _management_safe_registry_rows(report: dict[str, Any]) -> list[dict[str, Any]]:
    registry_payload = report.get("object_decision_registry") or {}
    field_registry = registry_payload.get("field_registry") or {}
    safe_rows: list[dict[str, Any]] = []
    for original in (registry_payload.get("rows") or []):
        row = copy.deepcopy(original)
        object_level = str(row.get("object_level") or "")
        final_label = str(row.get("final_label") or "")
        final_action = str(row.get("final_action") or "")
        sample_flag = str(row.get("sample_size_flag") or "")
        trigger_evidence = clean_report_text_filter(str(row.get("trigger_evidence") or ""))
        low_sample = any(token in sample_flag for token in ("低样本", "样本不足"))

        if not final_label:
            if low_sample:
                final_label = "低样本对象观察"
            elif object_level == "category":
                final_label = "放量前修复品类"
            elif object_level == "supplier":
                final_label = "供应商观察池"
            else:
                final_label = "待人工复核"
        if not final_action:
            if low_sample:
                final_action = "T+7 样本复核"
            elif object_level == "category":
                final_action = "修复后再放量"
            elif object_level == "supplier":
                final_action = "先观察再协同"
            else:
                final_action = "人工复核"

        if not field_registry.get("has_profit_fields", False) and _contains_any_term(final_action, _MGMT_RESOURCE_TERMS):
            final_label = "资源动作已降级" if object_level == "category" else (final_label or "资源动作已降级")
            final_action = "修复后再放量" if object_level == "category" else "先复核再动作"
            row["action_strength"] = "soft_action"
        if not field_registry.get("has_inventory_fields", False) and _contains_any_term(final_action, _MGMT_INVENTORY_TERMS):
            final_action = "补库存字段后判断"
            row["action_strength"] = "observe_only"
        if not field_registry.get("has_supplier_delivery_fields", False) and _contains_any_term(final_action, _MGMT_SUPPLIER_TERMS):
            final_action = "补交付字段后判断"
            row["action_strength"] = "observe_only"
        if low_sample and _contains_any_term(final_action, _MGMT_RESOURCE_TERMS + _MGMT_INVENTORY_TERMS + _MGMT_SUPPLIER_TERMS):
            final_label = "低样本对象观察"
            final_action = "T+7 样本复核"
            row["action_strength"] = "observe_only"

        row["final_label"] = final_label
        row["final_action"] = final_action
        row["blocked_actions_display"] = _sanitize_blocked_actions_for_management(row) or "无"
        row["trigger_evidence"] = trigger_evidence
        row["evidence_summary"] = clean_report_text_filter(str(row.get("evidence_summary") or ""))
        row["owner_role"] = str(row.get("owner_role") or _owner_role_for_registry(row))
        row["time_requirement"] = str(row.get("time_requirement") or ("T+7 样本复核" if low_sample else _time_requirement_for_registry(row)))
        row["validation_metric"] = str(row.get("validation_metric") or _validation_metric_for_registry(row))
        row["confidence_level"] = str(row.get("confidence_level") or ("low" if low_sample else "medium"))
        safe_rows.append(row)

    if "raw_rows" not in registry_payload:
        registry_payload["raw_rows"] = copy.deepcopy(registry_payload.get("rows") or [])
    registry_payload["rows"] = safe_rows
    report["object_decision_registry"] = registry_payload
    return safe_rows

