def _mgmt_confidence_rank(value: str) -> int:
    return {"high": 0, "medium": 1, "low": 2}.get(str(value or "").strip().lower(), 3)

def _mgmt_action_strength_rank(value: str) -> int:
    return {"hard_action": 0, "soft_action": 1, "candidate": 2, "observe_only": 3}.get(str(value or "").strip(), 4)

def _mgmt_focus_rows(rows: list[dict[str, Any]], *, limit: int = 12) -> list[dict[str, Any]]:
    level_order = {"category": 0, "product": 1, "sku": 2, "supplier": 3}
    ordered = sorted(
        rows,
        key=lambda row: (
            _mgmt_action_strength_rank(str(row.get("action_strength") or "")),
            _mgmt_confidence_rank(str(row.get("confidence_level") or "")),
            level_order.get(str(row.get("object_level") or ""), 9),
            str(row.get("object_id") or ""),
        ),
    )
    selected: list[dict[str, Any]] = []
    seen: set[tuple[str, str]] = set()
    for level in ["category", "product", "sku", "supplier"]:
        row = next((item for item in ordered if str(item.get("object_level") or "") == level), None)
        if row:
            key = (str(row.get("object_level") or ""), str(row.get("object_id") or ""))
            if key not in seen:
                selected.append(row)
                seen.add(key)
    for row in ordered:
        if limit is not None and len(selected) >= limit:
            break
        key = (str(row.get("object_level") or ""), str(row.get("object_id") or ""))
        if key in seen:
            continue
        selected.append(row)
        seen.add(key)
    return selected

