def _procurement_field_label_cn(group: str) -> str:
    return {
        "sales_fields": "销售与规模字段",
        "fulfillment_fields": "履约字段",
        "review_fields": "评价字段",
        "profit_fields": "利润字段",
        "inventory_fields": "库存与周转字段",
        "procurement_price_fields": "采购价字段",
        "supplier_delivery_fields": "供应商交付字段",
        "payment_term_fields": "账期字段",
        "return_cost_fields": "退货/售后成本字段",
        "supplier_contract_fields": "供应商合同字段",
        "competitor_price_fields": "竞品价格字段",
    }.get(group, group)


def _procurement_evidence_stat(evidence: str, label: str) -> str:
    import re

    match = re.search(rf"{re.escape(label)}\s*([0-9,]+(?:\.[0-9]+)?%?)", str(evidence or ""))
    return match.group(1) if match else ""


def _management_summary_from_registry(
    report: dict[str, Any],
    registry_rows: list[dict[str, Any]],
    field_registry: dict[str, Any],
    *,
    full_quantity: bool = False,
) -> list[str]:
    registry_mode = str((report.get("procurement_sales_readiness") or {}).get("mode") or field_registry.get("mode") or "sales_fulfillment_product_report")
    focus_rows = _mgmt_focus_rows(registry_rows, limit=None if full_quantity else 4)
    object_briefs = []
    for index, row in enumerate(focus_rows, start=1):
        object_briefs.append(
            clean_report_text_filter(
                f"{row.get('object_level', '对象')} 重点对象{index}："
                f"{row.get('final_label', '')}，核心依据为 {row.get('evidence_summary') or row.get('trigger_evidence') or '对象级证据'}，"
                f"当前动作是 {row.get('final_action', '')}。"
            )
        )
    return [
        f"当前报告模式为 `{registry_mode}`。本次是采购侧待补数的销售履约与商品经营复盘，当前可判断内容包括销售规模、品类/商品/SKU 结构、履约表现、评价风险和卖家承接表现。",
        "当前不可判断内容包括正式毛利、利润率、补货、清仓、库存周转、采购价谈判空间和完整供应商替换结论；这些动作必须等成本、库存和采购字段补齐后再升级。",
        "管理层主报告保留可直接执行的对象级动作、字段边界、关键统计和验证口径；完整对象枚举、智能指标和审计日志继续放在分析师附录与 Excel。",
        "；".join(object_briefs) if object_briefs else "本轮未识别到可进入管理层动作表的对象，需复核对象注册表。",
        "优先顺序：先复核头部类目与商品承接，再处理低评价/履约异常对象，最后补齐成本与库存字段后升级利润和库存类判断。",
    ]


def _procurement_sales_management_render(report: dict[str, Any], *, full_quantity: bool = False) -> dict[str, Any] | None:
    registry_payload = report.get("object_decision_registry") or {}
    raw_rows = registry_payload.get("rows") or []
    if not raw_rows:
        return None

    registry_rows = _management_safe_registry_rows(report)
    field_registry = registry_payload.get("field_registry") or {}
    category_rows = [row for row in registry_rows if row.get("object_level") == "category"]
    product_rows = [row for row in registry_rows if row.get("object_level") == "product"]
    sku_rows = [row for row in registry_rows if row.get("object_level") == "sku"]
    supplier_rows = [row for row in registry_rows if row.get("object_level") == "supplier"]

    prioritized_rows = [
        *_mgmt_focus_rows(category_rows, limit=None if full_quantity else 6),
        *_mgmt_focus_rows(product_rows, limit=None if full_quantity else 8),
        *_mgmt_focus_rows(sku_rows, limit=None if full_quantity else 10),
        *_mgmt_focus_rows(supplier_rows, limit=None if full_quantity else 6),
        *_mgmt_focus_rows(registry_rows, limit=None if full_quantity else 30),
    ]
    seen_keys: set[tuple[str, str]] = set()
    compact_rows: list[dict[str, Any]] = []
    for row in prioritized_rows:
        key = (str(row.get("object_level") or ""), str(row.get("object_id") or ""))
        if not key[1] or key in seen_keys:
            continue
        seen_keys.add(key)
        compact_rows.append(row)
        if not full_quantity and len(compact_rows) >= 30:
            break

    action_rows: list[dict[str, Any]] = []
    for index, row in enumerate(compact_rows, start=1):
        evidence = str(row.get("evidence_summary") or row.get("trigger_evidence") or "")
        action_rows.append(
            {
                "priority": f"P{1 if index <= 6 else 2 if index <= 18 else 3}",
                "object_level": row.get("object_level", ""),
                "object_name": row.get("object_id", ""),
                "final_label": row.get("final_label", ""),
                "final_action": row.get("final_action", ""),
                "trigger_evidence": evidence,
                "sales_total": _procurement_evidence_stat(evidence, "销售额总量"),
                "sales_share": _procurement_evidence_stat(evidence, "销售额占比"),
                "order_coverage": _procurement_evidence_stat(evidence, "订单覆盖"),
                "customer_coverage": _procurement_evidence_stat(evidence, "客户覆盖"),
                "low_rating_rate": _procurement_evidence_stat(evidence, "低分评价占比"),
                "late_rate": _procurement_evidence_stat(evidence, "逾期率"),
                "avg_fulfillment_days": _procurement_evidence_stat(evidence, "平均履约天数"),
                "missing_fields": _friendly_required_fields_cn(row.get("missing_fields") or row.get("required_missing_fields")),
                "blocked_actions": row.get("blocked_actions_display") or _sanitize_blocked_actions_for_management(row),
                "owner_role": row.get("owner_role") or "经营负责人",
                "time_requirement": row.get("time_requirement") or "下一周期验证",
                "validation_metric": row.get("validation_metric") or "下一周期复核",
                "action_strength": row.get("action_strength") or "soft_action",
                "confidence_level": row.get("confidence_level") or "medium",
                "evidence_type": row.get("conclusion_type") or "proxy_based_inference",
            }
        )

    display_rows = [
        {
            "优先级": row["priority"],
            "对象层级": row["object_level"],
            "对象名称": row["object_name"],
            "最终标签": row["final_label"],
            "最终动作": row["final_action"],
            "销售额": row["sales_total"],
            "销售额占比": row["sales_share"],
            "订单覆盖": row["order_coverage"],
            "客户覆盖": row["customer_coverage"],
            "低分评价占比": row["low_rating_rate"],
            "逾期率": row["late_rate"],
            "平均履约天数": row["avg_fulfillment_days"],
            "动作依据": row["trigger_evidence"],
            "缺失字段": row["missing_fields"],
            "被拦截动作": row["blocked_actions"],
            "负责人": row["owner_role"],
            "时间要求": row["time_requirement"],
            "验证指标": row["validation_metric"],
            "结论强度": row["action_strength"],
            "证据等级": row["confidence_level"],
        }
        for row in action_rows
    ]

    field_groups = [
        ("sales_fields", field_registry.get("has_sales_fields")),
        ("fulfillment_fields", field_registry.get("has_fulfillment_fields")),
        ("review_fields", field_registry.get("has_review_fields")),
        ("profit_fields", field_registry.get("has_profit_fields")),
        ("inventory_fields", field_registry.get("has_inventory_fields")),
        ("procurement_price_fields", field_registry.get("has_procurement_price_fields")),
        ("supplier_delivery_fields", field_registry.get("has_supplier_delivery_fields")),
        ("payment_term_fields", field_registry.get("has_payment_term_fields")),
        ("return_cost_fields", field_registry.get("has_return_cost_fields")),
    ]
    field_rows = [
        {
            "字段域": _procurement_field_label_cn(key),
            "是否可用": "是" if value else "否",
            "命中字段": " / ".join((field_registry.get("field_coverage") or {}).get(key, []) or []) or "无",
            "报告处理": "可进入管理层判断" if value else "仅保留边界说明，不升级为强结论",
        }
        for key, value in field_groups
    ]
    boundary_rows = [
        {"当前不可判断内容": "缺少采购成本，因此不能判断正式毛利、利润率、ROI 或 CAC。"},
        {"当前不可判断内容": "缺少库存与期初期末库存，因此不能判断补货、清仓、压货或库存周转。"},
        {"当前不可判断内容": "缺少采购价、账期和退货成本，因此不能判断采购谈判空间和完整供应商替换。"},
        {"当前不可判断内容": "FreightCost 只能用于履约费用观察，不能当成完整成本结构。"},
    ]

    blocked_rows = [
        {
            "对象": row.get("object", ""),
            "对象层级": row.get("object_level", ""),
            "被拦截动作": _sanitize_blocked_actions_for_management({"blocked_actions": str(row.get("attempted_action", "")).split(" / ")}),
            "拦截原因": row.get("blocked_reason", ""),
            "降级后动作": row.get("downgraded_action", ""),
            "缺失字段": row.get("missing_fields", ""),
        }
        for row in (
            (registry_payload.get("blocked_action_log") or [])
            if full_quantity
            else (registry_payload.get("blocked_action_log") or [])[:30]
        )
    ]
    data_gap_rows = registry_payload.get("data_gap_rows") or []

    def _review_section(section_id: str, title: str, rows: list[dict[str, Any]], question: str) -> dict[str, Any]:
        review_rows = _mgmt_focus_rows(rows, limit=None if full_quantity else 12)
        table_rows = [
            {
                "对象": row.get("object_id", ""),
                "最终标签": row.get("final_label", ""),
                "最终动作": row.get("final_action", ""),
                "核心证据": row.get("evidence_summary") or row.get("trigger_evidence") or "",
                "缺失字段": _friendly_required_fields_cn(row.get("missing_fields") or row.get("required_missing_fields")),
                "结论强度": row.get("action_strength", ""),
            }
            for row in review_rows
        ]
        bullets = [
            f"{row.get('object_id', '')} 当前归为“{row.get('final_label', '')}”，动作是“{row.get('final_action', '')}”，依据为 {row.get('evidence_summary') or row.get('trigger_evidence') or '对象级证据'}。"
            for row in (review_rows if full_quantity else review_rows[:5])
        ]
        return _section(section_id, title, question, bullets, tables=[_table(f"{title}表", table_rows)] if table_rows else [])

    sections = [
        _section(
            "report_mode_cover",
            "报告模式与结论边界",
            "本页说明当前报告的业务模式、字段范围和不能越界的判断。",
            [
                "当前报告属于 sales_fulfillment_product_report。",
                "采购侧待补数：当前数据足以支持销售、履约、评价和对象级动作复盘，但不足以支持正式利润、库存和采购谈判结论。",
            ],
        ),
        _section(
            "management_summary_fixed",
            "管理层摘要",
            "本页回答当前可判断内容、当前不可判断内容和第一批经营动作。",
            _management_summary_from_registry(report, registry_rows, field_registry),
        ),
        _section(
            "field_availability",
            "字段可用性与不可下结论清单",
            "本页把字段证据和结论边界放在同一处，防止缺字段时给出过强动作。",
            [
                "可判断内容包括销售结构、履约表现、评价风险、对象贡献和卖家承接表现。",
                "当前不可判断内容必须保留为边界说明，不能改写成正式经营结论。",
            ],
            tables=[_table("field_availability", field_rows), _table("unsupported_boundaries", boundary_rows)],
        ),
        _section(
            "final_action_table",
            "对象最终动作总表",
            "本页直接给出可执行对象动作，并把动作所需的核心统计放在同一张表里。",
            [
                "动作表只读取 object_decision_registry 的最终标签和最终动作。",
                "所有补货、清仓、利润和库存类强动作在缺字段时保持降级或拦截。",
            ],
            tables=[_table("action_table", display_rows)],
        ),
        _section(
            "blocked_action_table",
            "被拦截动作审计表",
            "本页解释哪些强动作被 guardrail 拦下，以及为什么不能进入正式建议。",
            ["被拦截动作只用于审计和补数说明，不会重新包装成正式建议。"],
            tables=[_table("blocked_action_table", blocked_rows)] if blocked_rows else [],
        ),
        _review_section("category_review", "品类经营复核", category_rows, "本页回答哪些品类可先修复承接，哪些只能观察。"),
        _review_section("product_review", "商品经营复核", product_rows, "本页回答哪些商品有销售基础但放量前需要先修履约和口碑。"),
        _review_section("sku_review", "SKU 经营复核", sku_rows, "本页回答哪些 SKU 需要降权、观察或进入下一轮验证。"),
        _review_section("supplier_review", "卖家承接复核", supplier_rows, "本页回答哪些卖家需要履约、评价或承接能力复核。"),
        _section(
            "data_gap_checklist",
            "补数清单",
            "本页列出从销售履约复盘升级为完整采销复盘还需要补齐的字段。",
            ["补齐字段后，系统可以重新打开利润、库存、采购谈判和供应商替换类结论。"],
            tables=[_table("data_gap_checklist", data_gap_rows[:20])] if data_gap_rows else [],
        ),
        _section(
            "action_roadmap",
            "下一轮执行路线",
            "本页把表格中的判断收束成执行顺序。",
            [
                "第一步：复核 P1 对象的履约与评价问题，先处理证据最充分的头部对象。",
                "第二步：对低样本 SKU 保持观察，不直接升级为采购或库存动作。",
                "第三步：补齐成本、库存、采购价、账期和退货成本字段后，重新生成利润与库存类结论。",
            ],
        ),
    ]
    if report.get("_minimal_management_mode"):
        sections = _minimal_management_sections(sections)
    return {
        "title": "中文销售履约与商品经营复盘主报告（采购侧待补数）",
        "executive_summary": _management_summary_from_registry(report, registry_rows, field_registry),
        "sections": sections,
        "action_rows": action_rows,
        "blocked_rows": blocked_rows,
        "field_registry": field_registry,
    }


def _final_procurement_sales_management_render(report: dict[str, Any]) -> dict[str, Any]:
    payload = _procurement_sales_management_render(report)
    if payload:
        return payload
    return {
        "title": "中文销售履约与商品经营复盘主报告（采购侧待补数）",
        "executive_summary": [
            "当前未生成对象级注册表，因此只能输出字段和数据读取诊断。",
            "请先确认数据已成功进入对象识别、指标构建和动作注册链。",
        ],
        "sections": [],
        "action_rows": [],
        "blocked_rows": [],
        "field_registry": (report.get("object_decision_registry") or {}).get("field_registry") or {},
    }


def _procurement_clean_management_variant(report: dict[str, Any]) -> dict[str, Any]:
    management_payload = _final_procurement_sales_management_render(report)
    return _clean_report_variant_texts(
        {
            "title": "中文销售履约与商品经营复盘主报告（采购侧待补数）",
            "dataset_name": report["dataset_name"],
            "sheet_name": report["sheet_name"],
            "report_id": report["report_id"],
            "generated_at": report["generated_at"],
            "report_language": report.get("report_language", "zh-CN"),
            "report_lens": report.get("report_lens", ""),
            "executive_summary": list(management_payload.get("executive_summary") or []),
            "sections": list(management_payload.get("sections") or []),
        }
    )


def _procurement_clean_full_variant(
    report: dict[str, Any],
    management_variant: dict[str, Any],
    appendix_variant: dict[str, Any],
) -> dict[str, Any]:
    management_title = str(management_variant.get("title") or "").strip()
    full_title = (
        "采购卡支出台账治理全量报告"
        if "支出台账" in management_title
        else "中文销售履约与商品经营复盘全量报告（采购侧待补数）"
    )
    return _clean_report_variant_texts(
        {
            "title": full_title,
            "dataset_name": report["dataset_name"],
            "sheet_name": report["sheet_name"],
            "report_id": report["report_id"],
            "generated_at": report["generated_at"],
            "report_language": report.get("report_language", "zh-CN"),
            "report_lens": report.get("report_lens", ""),
            "executive_summary": list(management_variant.get("executive_summary") or []),
            "sections": [
                *(management_variant.get("sections") or []),
                *(appendix_variant.get("sections") or []),
            ],
        }
    )


def _append_procurement_metric_mining_sections(
    management_variant: dict[str, Any],
    metric_payload: dict[str, Any] | None,
    *,
    full_quantity: bool = False,
) -> dict[str, Any]:
    if not metric_payload:
        return management_variant

    variant = copy.deepcopy(management_variant)
    summary_tables = metric_payload.get("summary_tables") or {}
    derived_rows = metric_payload.get("derived_metrics") or []
    opportunity_rows = metric_payload.get("opportunity_risk_rows") or []
    action_rows = metric_payload.get("action_table_rows") or []
    narrative = metric_payload.get("narrative") or {}
    metric_report_mode = str(metric_payload.get("report_mode") or "")
    is_spend_ledger = metric_report_mode == "procurement_spend_ledger_report"
    field_roles = metric_payload.get("field_roles") or {}
    inventory_supported = bool(
        field_roles.get("inventory_field")
        or field_roles.get("beginning_inventory_field")
        or field_roles.get("ending_inventory_field")
    )

    def _first_table_row(table_name: str) -> dict[str, Any]:
        rows = summary_tables.get(table_name) or []
        return rows[0] if isinstance(rows, list) and rows else {}

    def _row_text(row: dict[str, Any], *keys: str) -> str:
        for key in keys:
            value = row.get(key)
            if value is not None and str(value).strip():
                return str(value).strip()
        return ""

    def _row_amount(row: dict[str, Any], *keys: str) -> str:
        for key in keys:
            value = row.get(key)
            if value is None or not str(value).strip():
                continue
            try:
                number = float(str(value).replace(",", ""))
            except Exception:
                continue
            return f"{number:,.2f}"
        return ""

    def _row_percent(row: dict[str, Any], *keys: str) -> str:
        for key in keys:
            formatted = _table_value_to_percent(row.get(key))
            if formatted:
                return formatted
        return ""

    if is_spend_ledger:
        top_supplier = _first_table_row("supplier_contribution")
        top_category = _first_table_row("category_contribution")
        top_tx = _first_table_row("large_transaction_rows")
        total_metric = next((item for item in derived_rows if str(item.get("metric_id") or "") == "total_spend"), {})
        total_spend = _row_amount(total_metric, "value")
        executive_summary = [
            f"本期采购卡支出台账可直接放行的主结论：总支出 {total_spend or '已识别'}，首要动作不是看 SKU/履约，而是立刻压到商户集中、用途结构和大额交易窗口三张治理表。",
            f"头部商户 `{_row_text(top_supplier, 'supplier') or '待识别头部商户'}` 贡献 {_row_percent(top_supplier, 'sales_contribution') or '最高'}，应本周完成授权边界、重复采购原因和替代商户池复核。",
            f"头部用途 `{_row_text(top_category, 'category') or '待识别头部用途'}` 贡献 {_row_percent(top_category, 'sales_contribution') or '最高'}，应拆成长期刚性需求、临时项目入账和预算归口三类处理。",
            f"大额窗口首个样本 `{_row_text(top_tx, 'time') or '待识别日期'}` / `{_row_text(top_tx, 'supplier') or '待识别商户'}` / {_row_amount(top_tx, 'amount') or '待识别金额'} 必须进入当周抽查清单。",
        ]
        variant["title"] = "采购卡支出台账治理报告"
        variant["executive_summary"] = executive_summary

    metric_section_title = "采购支出指标挖掘结果" if is_spend_ledger else "采购指标挖掘结果"
    metric_section_summary = (
        "本页把确定性指标挖掘结果接回主报告，用于支撑支出规模、商户集中、用途结构和大额交易复核。"
        if is_spend_ledger
        else "本页把确定性指标挖掘结果接回主报告，用于支撑销售规模、结构贡献和履约复核。"
    )
    metric_section_bullets = (
        [clean_report_text_filter(str(narrative.get("summary_sentence") or "当前已生成采购卡支出台账指标挖掘结果。"))]
        if not is_spend_ledger
        else [
            clean_report_text_filter(str(narrative.get("summary_sentence") or "当前已生成采购卡支出台账指标挖掘结果。")),
            "这份数据没有 SKU、客户、履约、GMV、运费和评价字段，读者结论必须落在商户、用途、日期和金额窗口上。",
            "可直接执行的本周动作是头部商户复核、头部用途拆账、大额交易抽查，不等待下一轮字段补齐。",
        ]
    )

    sections_to_add: list[dict[str, Any]] = [
        _section(
            "procurement_metric_mining",
            metric_section_title,
            metric_section_summary,
            metric_section_bullets,
            tables=[_table("procurement_sales_derived_metrics", derived_rows if full_quantity else derived_rows[:20])] if derived_rows else [],
        )
    ]

    structure_tables: list[dict[str, Any]] = []
    if summary_tables.get("sku_ranking"):
        structure_tables.append(_table("sku_sales_ranking", summary_tables["sku_ranking"] if full_quantity else summary_tables["sku_ranking"][:20]))
    if summary_tables.get("category_contribution"):
        structure_tables.append(_table("category_contribution", summary_tables["category_contribution"] if full_quantity else summary_tables["category_contribution"][:20]))
    if summary_tables.get("supplier_contribution"):
        structure_tables.append(_table("supplier_contribution", summary_tables["supplier_contribution"] if full_quantity else summary_tables["supplier_contribution"][:20]))
    if summary_tables.get("price_band_summary"):
        structure_tables.append(_table("price_band_summary", summary_tables["price_band_summary"] if full_quantity else summary_tables["price_band_summary"][:16]))
    if summary_tables.get("sales_trend"):
        structure_tables.append(_table("sales_trend", summary_tables["sales_trend"] if full_quantity else summary_tables["sales_trend"][:16]))
    if summary_tables.get("merchant_repeat_rows"):
        structure_tables.append(_table("merchant_repeat_rows", summary_tables["merchant_repeat_rows"] if full_quantity else summary_tables["merchant_repeat_rows"][:16]))
    if summary_tables.get("large_transaction_rows"):
        structure_tables.append(_table("large_transaction_rows", summary_tables["large_transaction_rows"] if full_quantity else summary_tables["large_transaction_rows"][:16]))
    if structure_tables:
        sections_to_add.append(
            _section(
                "procurement_structure_analysis",
                "商品结构与贡献分析",
                "本页用 SKU、品类、供应商、价格带和时间趋势表解释销售结构，而不是只给动作句子。",
                [
                    "先看 SKU 与品类贡献，确认销售是否由少数对象集中贡献。",
                    "再看供应商和价格带结构，判断承接、价格带和履约风险是否需要分开处理。",
                ],
                tables=structure_tables,
            )
        )
        if metric_report_mode == "procurement_spend_ledger_report":
            sections_to_add[-1]["title"] = "采购支出结构与头部对象分析"
            sections_to_add[-1]["summary"] = "本页用商户/供应商、用途/分类、日期窗口和大额支出表解释采购支出结构，而不是把支出台账写成 SKU 或履约复盘。"
            sections_to_add[-1]["bullets"] = [
                "先看商户/供应商支出集中度，确认是否存在头部依赖或需要分散的支出对象。",
                "再看 DESCRIPTION 等用途/分类、时间脉冲和大额交易窗口，判断当期支出重点和异常复核优先级。",
            ]

    if opportunity_rows:
        sections_to_add.append(
            _section(
                "procurement_opportunity_risk",
                "机会与风险对象表",
                "本页把机会、风险和字段边界放在同一张表里，避免缺库存或缺成本时给出过强结论。",
                [
                    "库存字段缺失时，机会风险只能作为销售和履约观察，不升级为补货或清仓。",
                    "benchmark_or_threshold 只用于解释阈值来源，不替代真实业务验收。",
                ],
                tables=[_table("procurement_sales_opportunity_risk_table", opportunity_rows if full_quantity else opportunity_rows[:24])],
            )
        )

    if action_rows:
        action_summary = "本页把可由现有表格直接支持的动作列出来，动作必须保留字段边界和验证口径。"
        action_bullets = [
            "能够由表格直接支持的建议进入动作表；缺字段的强动作继续保留为待补数边界。",
            "P1 对象优先进入下一轮复核，低样本对象不直接升级为强经营动作。",
        ]
        if is_spend_ledger:
            action_summary = "本页把商户、用途和大额交易窗口转成当周可派单动作，动作强度来自确定性支出台账而非电商履约口径。"
            action_bullets = [
                "P1 动作直接指向头部商户和头部用途，必须本周完成归口、授权和持续性判断。",
                "P2 动作锁定大额交易窗口，先做抽查和凭证复核，再决定是否进入长期规则调整。",
            ]
        sections_to_add.append(
            _section(
                "procurement_metric_actions",
                "指标驱动动作表",
                action_summary,
                action_bullets,
                tables=[_table("procurement_sales_action_table", action_rows if full_quantity else action_rows[:24])],
            )
        )

    sections = list(variant.get("sections") or [])
    insert_index = next(
        (index + 1 for index, section in enumerate(sections) if str(section.get("id") or "") == "field_availability"),
        min(3, len(sections)),
    )
    variant["sections"] = [*sections[:insert_index], *sections_to_add, *sections[insert_index:]]
    return variant


